INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (100,'Archiv turnajů v deskových hrách na GameConu 2010','deskovky-2010',64,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (100,'archiv/deskovky-2010');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (100,'Archiv turnajů v deskových hrách na GameConu 2010 — GameCon 2011','gamecon,2011','Archiv turnajů v deskových hrách na GameConu 2010');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (100,'<h1>Archiv turnajů v deskových hrách na GameConu 2010</h1> <!-- Archiv RPG na GameConu 2009 -->

<h2>Bang! (2010)</h2>

<table class="hlavicka">
  <tr>
    <td><img src="/system_styly/side/bang-2010.gif" /></td>
    
  </tr>
</table>

<p>Pravý divoký západ! Šerif pronásleduje bandity. Banditi zkouší sejmout šerifa a jeho pomocníci ho musí bránit a třeba pro něj i zemřít. Pozor ale na podrazáky odpadlíky, kteří to hrají na obě strany a jejich cíl je jasný – sejmi je všechny! Všechno to má ale jeden drobný háček - šerif je jasný, ale kdo je kdo z ostatních?<br /><br />Když se loni sjeli všichni z širokého okolí na zdejší GunCon, byla z toho pěkná střílečka. Místní už se začínají bát, protože další GunCon festival se blíží a je jim jasné, že letos to bude snad ještě horší masakr!<br /><br />Takže, nabijte kolty a nebojte se střílet. Bang párty zase hned první večer je skvělý začátek i letošního GameConu. Kdo loni chyběl o hodně přišel. Svižná cool hra, která Vás hodí do té správné nálady a navíc se můžete stát tím nejlepším šerifem a nebo nejslavnějším banditou celého GameConu.<br /><br />Pokud jste začátečníci a nebo Bang ještě neznáte, nebojte se, není to těžké. Před slavnostním zahájením, po kterém bude turnajová Bang párty následovat, bude otevřená deskoherna a v ní dost času zjistit, jak se Bang hraje a vyzkoušet si ho. Stačí Vám jedna, dvě hry a můžete se přidat. Máte-li rádi zábavné hry, tohle byste neměli minout.<br /><br />Pravidla turnaje budou upřesněna na místě.</p>

<h2>Dominion</h2>

<table class="hlavicka">
  <tr>
    <td><img src="/system_styly/side/dominion.gif" /></td>
    
  </tr>
</table>

<p>Po svých předcích jste zdědili malé panství. Kraj sice nádherný, plný zeleně a řek, ale vám to nestačí. Vaším snem je veliká prosperující říše, krásná a bohatá a se spokojenými obyvateli.<br /><br />Vaši sousedi mají naneštěstí stejné plány.<br /><br />Dominion je struhující hra s jednoduchými pravidly, kterou se zvládnete bez nesnází naučit v deskoherně na GameConu.<br /><br />Turnaj v Dominionu je nejen vyhodnocen jako samostatný turnaj na GameConu, ale je také zapojen do serie turnajů v rámci Dominion Tour. Máte tedy příležitost nejen vyhrát super ceny přímo na GameConu, ale také získat šanci účastnit se velkého finále v Dominionu 10. října v Praze.</p>

<h2>Osadníci z katanu (2010)</h2>

<table class="hlavicka">
  <tr>
    <td><img src="/system_styly/side/osadnici-z-katanu-2010.gif" /></td>
    
  </tr>
</table>

<p>Vylodili jste se právě na neprobádaném ostrově a není čas otálet. Je třeba začít budovat vesnice a města, stavět cesty a hlavně poohlédnout se po potřebných surovinách. Háček je v tom, že jste se nevylodili sami a tak si musíte pospíšit, aby vám ostatní nevybrali všechna lukrativní místa na ostrově. Kdo nebuduje, ten upadá.<br /><br />Ani letos nemůže na GameConu chybět turnaj v Osadnících z Katanu!<br /><br />Pokud náhodou, Osadníky z Katanu neznáte, není to žádný problém. Osadníci jsou hra, kterou se ovládnete bez obtíží krátce před turnajem. Jednou, dvakrát si je vyzkoušíte a jste připraveni porazit své protivníky.<br /><br />Osadníci z Katanu budou nejen vyhodnoceni jako samostatný turnaj na GameConu, ale jsou také kvalifikačním turnajem na Mistrovství ČR. V případě vítězství získáte tedy nejen věcné ceny, ale také body, které vám mohou pomoci zajistit účast na Mistrovství ČR, které se bude konat 17. října 2010 v Praze.<br /><br />Pokud vám pravidla přijdou moc technická, nedělejte si z toho těžkou hlavu :-) Rozhodčí vám vše potřebné řeknou na místě a povedou vás. Vám stačí jen bavit se a hrát.</p>

<h2>Texas Hold\'em</h2>

<table class="hlavicka">
  <tr>
    <td><img src="/system_styly/side/texas-holdem.gif" /></td>
    
  </tr>
</table>

<p>Pojďte vyzkoušet své schopnosti a cit pro hru v nejpopulárnějším pokerovém turnaji Texas Hold\'em!<br /><br />Na GameConu je pro vás připraven pokerový stůl pro 10 hráčů a příležitost zažít atmosféru velké hry. Texas Hold\'em na GameConu bude stejně napínavý jako v casinu, ale nebude to hazard, při kterém můžete přijít o závratné sumy peněz. Naopak. Zaplatíte pouze poplatek za účast jako i v jiných deskovkových turnajích a získáte pro hru žetony se kterými budete hrát.<br /><br />Turnaje se mohou zůčastnit i nezkušení hráči. I ti mohou mít štěstí a probojovat se třeba do finále a kdo ví... a nebo přinejhorším prohrajete svou hromádku žetonů, ale užijete si velkou hru.<br /><br />Organizace turnaje bude upřesněna později, případně na místě, podle počtu hráčů.</p>


        
      </div>
    </div>');
