INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (101,'Archiv larpů na GameConu 2010 — GameCon 2011','gamecon,2011','Archiv larpů na GameConu 2010');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (101,'<h1>Archiv larpů na GameConu 2010</h1> <!-- Archiv RPG na GameConu 2009 -->

<h2>Cez mŕtvoly</h2>

<table class="hlavicka">
  <tr>
    <td><img src="/system_styly/side/cez-mrtvoly.gif" /></td>
    <td><strong>organizátor</strong><br />Andrej „Andrej Tokarčík“ Tokarčík</td>
  </tr>
</table>

<p>Odišiel. Už to jednoducho nemohol vydržať, nechal ich všetkých tak, napospas osudu. Niečo sa deje, nemá čas sa zaoberať ich malichernými problémami... Musí ísť preč, musí odísť, musí sa zachrániť. Ujsť, kým má ešte čas! Bože môj, bodaj by mal!<br /><br />Na svojich rukách vidí krv. Kvôli nemu umreli tí, na ktorých mu najviac záležalo. Áno, kvôli nemu, vraj... Avšak nebola to jeho vina, on nič neurobil, on za nič nemôže. To ON, ten druhý! On si vzal právo vniknúť mu do života a celý ho zničiť. Všetky jeho istoty zahodiť v jednom momente. Ale kto to je? Povedz mi, kto si? Čo chceš?! Človeče, čo odo mňa žiadaš?!<br /><br />Odpovede sa mu však nedostalo. Len jeden výstrel a večné, neľudské ticho...<br /><br />Cez mŕtvoly sú štruktúrovanou rolovou hrou naživo, v rámci ktorej sa budete budete zúčastňovať svojho vlastného príbehu. Príbehu o prenasledovaní nevinného, nutnej vražde a zbytočnej smrti. Na začiatku prebehne prípravná fáza, počas ktorej upresníte prostredie, do ktorého bude celý dej zasadený. Tým pádom dáte hre svoj vlastný nádych. Následne sa odohrá samotná hra o piatich dejstvách.</p>

<h2>Klub sebevrahů</h2>

<table class="hlavicka">
  <tr>
    <td><img src="/system_styly/side/klub-sebevrahu.gif" /></td>
    <td><strong>organizátor</strong><br />Veronika „Lothmíril“ Frankovská</td>
  </tr>
</table>

<p>Je podzim roku 1888. Celý Londýn překryl šedý závoj mlhy a už několik dní slabě mrholí. Z Emersonovy ulice se line nazelenalý svit. Z řady zašlých cihelných fasád tu vyčnívá jedna šedá, kamenná. Špinavá dešťová voda stéká po mosazné cedulce v černých rýhách písmen. Gentlemans Club. Members only. Nic víc.<br /><br />Staň se členem tohoto exkluzivního klubu. Počet míst je omezený a není jich mnoho. Ty však jsi jeden ze šťastlivců, který se může stát doživotním členem. Jediné, co pro to musíš udělat, je říci ano a dostavit se do Emersonovy ulice v době zasedání klubu.<br /><br />Klub sebevrahů je již klasický komorní larp z dílny Court of Moravia. Na začátku hry dostanete své role na listu A4 a po vysvětlení pár pojmů či zodpovězení dotazů se vrhnete do samotné hry z prostředí viktoriánské Anglie. Pokud byste rádi o herním prostředí a o této době věděli něco víc, dřív než začnete hrát, doporučujeme prostudovat si herní informace.<br /><ul><li>Více informací: <a href="http://courtofmoravia.com/larpy/klub-sebevrahu/" onclick="window.open(this.href);return false">http://courtofmoravia.com/larpy/klub-sebevrahu/</a><li>    Materiály ke Klubu sebevrahů: <a href="http://courtofmoravia.com/files/ks_obecne.pdf" onclick="window.open(this.href);return false">http://courtofmoravia.com/files/ks_obecne.pdf</a></li></ul></p>

<h2>Podraz (2010)</h2>

<table class="hlavicka">
  <tr>
    <td><img src="/system_styly/side/podraz-2010.gif" /></td>
    <td><strong>organizátor</strong><br />Pavel „lorgi“ Hamřík</td>
  </tr>
</table>

<p>Pět chlapíků. Tři pistole. Jeden kufřík připoutaný k zápěstí. A samozřejmě pila. Pro pětici členů londýnského podsvětí je tohle opravdu nepříjemný den... Bude to chtít všechen um, dostat se z tohohle se zdravou kůží.<br /><br />Podraz je krátký larp pro 5 hráčů. Ti se na hodinu stanou londýnskými gangstery v nezáviděníhodné situaci. Rychlá, dynamická hra plná zvratů, pistolí, držení se v šachu a především podrazů čeká na ty správné chlapy.<br /><br />Specialitou této hry je, že jsou ze pouze mužské role. Dívky si ji samozřejmě mohou zahrát také, ale musí se připravit na to, že od nich bude očekáván skutečně chlapský přístup.<br /><ul><li>Více informací: <a href="http://courtofmoravia.com/larpy/podraz/" onclick="window.open(this.href);return false">http://courtofmoravia.com/larpy/podraz/</a></li></ul></p>

<h2>Previous Occupants</h2>

<table class="hlavicka">
  <tr>
    <td><img src="/system_styly/side/previous-occupants.gif" /></td>
    <td><strong>organizátor</strong><br />Andrej „Andrej Tokarčík“ Tokarčík</td>
  </tr>
</table>

<p>Leží na posteli. Objíma ju, kým pokojne odpočíva na jeho hrudi, cíti jej jemné oddychovanie. Zhliada na jej krk a ramená. Možno keby sa zrazu zobudila, zbadala by akýsi čudný lesk v jeho očiach. Zbadala by, že spôsob, akým sa na ňu pozerá, je iný. Taký, akým sa mäsiar pozerá na čerstvý kus vo svojom bitúnku...<br /><br />Je to akoby bol mimo svojho tela a pozeral sa sám na seba. Na svoje vlastné ruky, ako sa pomaly hýbu a iste nadobúdajú tvar zveráku okolo jej krku. Zdesený zakričí, ako len dokáže, no bezvýsledne. Ona sa len letmo dotkne jeho ruky, oči stále zatvorené. Chce ju zachrániť, pustiť ju. Odísť od nej. Bodaj by mohol. Jeho ruka ale už nie je jeho. Chce si pozrieť do očí. Nespoznáva sa v nich.<br /><br />Previous Occupants sú jeepformovou hrou o duchoch a o zmene v ľuďoch. Hráči budú paralelne odohrávať dve príbehové línie. Jedna je o mladej láske plnej vzájomnej dôvery, zatiaľčo druhá o horkom manželstve, z ktorého sa dôvera už úplne vytratila a končí sa tým najhorším.<br /><br />Druhá časť hry je však úplne v rukách hráčov. Duchovia minulosti útočia na prítomnosť a život je tým, čo je v stávke...<br /><br />Hra je pre tých z vás, ktorí majú záľubu v intenzívnej dráme a neboja sa hry &quot;na telo&quot;. Pre tých, ktorí si užívajú slobodu v načrtnutých príbehoch, no nemajú zábrany vybúriť sa v daných obmedzeniach. Myslíte si, že ľudia sú desivejší ako duchovia. A ste pripravení stať sa týmito ľuďmi.<br /><br />Určeno pro 2 muže a 2 ženy.</p>

<h2>Seance</h2>

<table class="hlavicka">
  <tr>
    <td><img src="/system_styly/side/seance.gif" /></td>
    <td><strong>organizátor</strong><br />Antonín „smejko“ Novák</td>
  </tr>
</table>

<p>Nemusíte věřit na duchy – oni věří na vás.<br /><br />Seance je tradiční komorní larp pro deset hráčů. Pro rodinu Veselých zbývá poslední šance na záchranu života jejich malé dcerky – a tou je spiritistická seance. Za bouřlivé noci se však do našeho světa proderou duchové, které nikdo nevolal. Pro pětici živých tak začíná nejdelší noc v jejich životě.<br /><br />Odvážíte se přijmout role živých, troufnete si na role mrtvých? Rozhodujte se rychle, již se stmívá.<br /><ul><li>Více informací: <a href="http://courtofmoravia.com/larpy/seance/" onclick="window.open(this.href);return false">http://courtofmoravia.com/larpy/seance/</a><li>    Materiály k Seanci: <a href="http://courtofmoravia.com/files/com-seance-vytah.pdf" onclick="window.open(this.href);return false">http://courtofmoravia.com/files/com-seance-vytah.pdf</a></li></ul></p>


        
      </div>
    </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (101,'Archiv larpů na GameConu 2010','Archiv larpů na GameConu 2010 Cez mŕtvoly organizátor Andrej „Andrej Tokarčík“ Tokarčík Odišiel. Už to jednoducho nemohol vydržať, nechal ich všetkých tak, napospas osudu. Niečo sa deje, nemá čas sa zaoberať ich malichernými problémami... Musí ísť preč, musí odísť, musí sa zachrániť. Ujsť, kým má ešte čas! Bože môj, bodaj by mal! Na svojich rukách vidí krv. Kvôli nemu umreli tí, na ktorých mu najviac záležalo. Áno, kvôli nemu, vraj... Avšak nebola to jeho vina, on nič neurobil, on za nič nemôže. To ON, ten druhý! On si vzal právo vniknúť mu do života a celý ho zničiť. Všetky jeho istoty zahodiť v jednom momente. Ale kto to je? Povedz mi, kto si? Čo chceš?! Človeče, čo odo mňa žiadaš?! Odpovede sa mu však nedostalo. Len jeden výstrel a večné, neľudské ticho... Cez mŕtvoly sú štruktúrovanou rolovou hrou naživo, v rámci ktorej sa budete budete zúčastňovať svojho vlastného príbehu. Príbehu o prenasledovaní nevinného, nutnej vražde a zbytočnej smrti. Na začiatku prebehne prípravná fáza, počas ktorej upresníte prostredie, do ktorého bude celý dej zasadený. Tým pádom dáte hre svoj vlastný nádych. Následne sa odohrá samotná hra o piatich dejstvách. Klub sebevrahů organizátor Veronika „Lothmíril“ Frankovská Je podzim roku 1888. Celý Londýn překryl šedý závoj mlhy a už několik dní slabě mrholí. Z Emersonovy ulice se line nazelenalý svit. Z řady zašlých cihelných fasád tu vyčnívá jedna šedá, kamenná. Špinavá dešťová voda stéká po mosazné cedulce v černých rýhách písmen. Gentlemans Club. Members only. Nic víc. Staň se členem tohoto exkluzivního klubu. Počet míst je omezený a není jich mnoho. Ty však jsi jeden ze šťastlivců, který se může stát doživotním členem. Jediné, co pro to musíš udělat, je říci ano a dostavit se do Emersonovy ulice v době zasedání klubu. Klub sebevrahů je již klasický komorní larp z dílny Court of Moravia. Na začátku hry dostanete své role na listu A4 a po vysvětlení pár pojmů či zodpovězení dotazů se vrhnete do samotné hry z prostředí viktoriánské Anglie. Pokud byste rádi o herním prostředí a o této době věděli něco víc, dřív než začnete hrát, doporučujeme prostudovat si herní informace. Více informací: http://courtofmoravia.com/larpy/klub-sebevrahu/ Materiály ke Klubu sebevrahů: http://courtofmoravia.com/files/ks_obecne.pdf Podraz (2010) organizátor Pavel „lorgi“ Hamřík Pět chlapíků. Tři pistole. Jeden kufřík připoutaný k zápěstí. A samozřejmě pila. Pro pětici členů londýnského podsvětí je tohle opravdu nepříjemný den... Bude to chtít všechen um, dostat se z tohohle se zdravou kůží. Podraz je krátký larp pro 5 hráčů. Ti se na hodinu stanou londýnskými gangstery v nezáviděníhodné situaci. Rychlá, dynamická hra plná zvratů, pistolí, držení se v šachu a především podrazů čeká na ty správné chlapy. Specialitou této hry je, že jsou ze pouze mužské role. Dívky si ji samozřejmě mohou zahrát také, ale musí se připravit na to, že od nich bude očekáván skutečně chlapský přístup. Více informací: http://courtofmoravia.com/larpy/podraz/ Previous Occupants organizátor Andrej „Andrej Tokarčík“ Tokarčík Leží na posteli. Objíma ju, kým pokojne odpočíva na jeho hrudi, cíti jej jemné oddychovanie. Zhliada na jej krk a ramená. Možno keby sa zrazu zobudila, zbadala by akýsi čudný lesk v jeho očiach. Zbadala by, že spôsob, akým sa na ňu pozerá, je iný. Taký, akým sa mäsiar pozerá na čerstvý kus vo svojom bitúnku... Je to akoby bol mimo svojho tela a pozeral sa sám na seba. Na svoje vlastné ruky, ako sa pomaly hýbu a iste nadobúdajú tvar zveráku okolo jej krku. Zdesený zakričí, ako len dokáže, no bezvýsledne. Ona sa len letmo dotkne jeho ruky, oči stále zatvorené. Chce ju zachrániť, pustiť ju. Odísť od nej. Bodaj by mohol. Jeho ruka ale už nie je jeho. Chce si pozrieť do očí. Nespoznáva sa v nich. Previous Occupants sú jeepformovou hrou o duchoch a o zmene v ľuďoch. Hráči budú paralelne odohrávať dve príbehové línie. Jedna je o mladej láske plnej vzájomnej dôvery, zatiaľčo druhá o horkom manželstve, z ktorého sa dôvera už úplne vytratila a končí sa tým najhorším. Druhá časť hry je však úplne v rukách hráčov. Duchovia minulosti útočia na prítomnosť a život je tým, čo je v stávke... Hra je pre tých z vás, ktorí majú záľubu v intenzívnej dráme a neboja sa hry "na telo". Pre tých, ktorí si užívajú slobodu v načrtnutých príbehoch, no nemajú zábrany vybúriť sa v daných obmedzeniach. Myslíte si, že ľudia sú desivejší ako duchovia. A ste pripravení stať sa týmito ľuďmi. Určeno pro 2 muže a 2 ženy. Seance organizátor Antonín „smejko“ Novák Nemusíte věřit na duchy – oni věří na vás. Seance je tradiční komorní larp pro deset hráčů. Pro rodinu Veselých zbývá poslední šance na záchranu života jejich malé dcerky – a tou je spiritistická seance. Za bouřlivé noci se však do našeho světa proderou duchové, které nikdo nevolal. Pro pětici živých tak začíná nejdelší noc v jejich životě. Odvážíte se přijmout role živých, troufnete si na role mrtvých? Rozhodujte se rychle, již se stmívá. Více informací: http://courtofmoravia.com/larpy/seance/ Materiály k Seanci: http://courtofmoravia.com/files/com-seance-vytah.pdf');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (102,'Archiv přednášek na GameConu 2010','prednasky-2010',64,0,0);
