INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (105,'Hon na Rudý říjen','hon-na-rudy-rijen',60,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (105,'bonusove-hry/hon-na-rudy-rijen');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (105,'Hon na Rudý říjen — GameCon 2011','gamecon,2011','Hon na Rudý říjen');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (105,'<h1>Hon na Rudý říjen</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/hon-na-rudy-rijen.gif" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>organizátor</strong><br />Petr "Jezevec" Pouchlý<br />
  
 <strong>další akce organizátora</strong> <br /><div style = "text-align: left;"><a href = "/bonusove-hry/spina">Špína</a>, <a href = "/bonusove-hry/mixer">Mixér</a>, <a href = "/prednasky/jsem-hrac-a-nestydim-se-za-to">Jsem hráč a nestydím se za to!</a></div>
</div>
</p>
   <p style = "clear: both;">
Balistická ponorka první třídy Rudý říjen se nevrátila! Nejvyšší velení obou znepřátelených gobliních klanů se distancuje od jejího potopení. Nalezla snad posádka v korálových útesech zatím neprozkoumaných Třebových útesů nového nepřítele? Nebo legendární obří krakatici? Oba klany vysílají na místo nové ponorky, aby zajistili stabilitu v oblasti. Všichni kapitáni ví, že toto je šance, jak dosáhnout legendárního označení Rudý říjen právě pro svou ponorku. Strýček Gob tě potřebuje! 
</p>
<p>
Gobliní ponorky jsou hra, kterou na minulém ročníku Gameconu neminul snad nikdo. Recesní ačkní hra pro čtyřčlenné týmy, které se stanou obávanými gobliními ponorkami, aby ovládnuly podmořský svět. Za pomoci papírových koulí mohou jednotlivé ponorky jasně ukázat druhé straně, zač je toho kaboom! Dvě znepřátelené strany, desítky bojechtivých goblinů a především šance stát se posádkou legendárního Rudého října.
</p>


          <!--<li>
              </li>-->
    </ul>
  </p>
  <div style = "width: 100%; float: left;">
        <div style = "width: 50%; text-align: right; float: right; padding-top: 20px; padding-bottom: 15px;"><a href = "/bonusove-hry/mixer">Mixér</a> &raquo;</div>  </div>
  
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (105,'Hon na Rudý říjen','Hon na Rudý říjen organizátor Petr "Jezevec" Pouchlý další akce organizátora Špína , Mixér , Jsem hráč a nestydím se za to! Balistická ponorka první třídy Rudý říjen se nevrátila! Nejvyšší velení obou znepřátelených gobliních klanů se distancuje od jejího potopení. Nalezla snad posádka v korálových útesech zatím neprozkoumaných Třebových útesů nového nepřítele? Nebo legendární obří krakatici? Oba klany vysílají na místo nové ponorky, aby zajistili stabilitu v oblasti. Všichni kapitáni ví, že toto je šance, jak dosáhnout legendárního označení Rudý říjen právě pro svou ponorku. Strýček Gob tě potřebuje! Gobliní ponorky jsou hra, kterou na minulém ročníku Gameconu neminul snad nikdo. Recesní ačkní hra pro čtyřčlenné týmy, které se stanou obávanými gobliními ponorkami, aby ovládnuly podmořský svět. Za pomoci papírových koulí mohou jednotlivé ponorky jasně ukázat druhé straně, zač je toho kaboom! Dvě znepřátelené strany, desítky bojechtivých goblinů a především šance stát se posádkou legendárního Rudého října. --> Mixér »');

