INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (109,'GameCon 2011 se blíží','tartas---sermirske-vystoupeni',60,0,0);
