INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (117,'Carcassonne','carcassonne',39,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (117,'deskove-hry/carcassonne');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (117,'Carcassonne — GameCon 2011','gamecon,2011','Carcassonne');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (117,'kapacita 6/30<br />
<h1>Carcassonne</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/carcassonne.jpg" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>organizátor</strong><br />MindOK<br />
  <strong>čas akce</strong><br />pátek 22.7 - 19:00 až 23:00  <br />
 <strong>další akce organizátora</strong> <br /><div style = "text-align: left;"><a href = "/deskove-hry/duch">Duch!</a>, <a href = "/deskove-hry/times-up">Time´s Up!</a>, <a href = "/deskove-hry/vladci-podzemi">Vládci podzemí</a>, <a href = "/deskove-hry/kaleidoskop">Kaleidoskop</a></div>
</div>
</p>
   <p style = "clear: both;">
Vydáváš se svou družinou na cesty, do měst a klášterů, abys hledal štěstí kolem jihofrancouzské města Carcassonne, které je pověstné svým jedinečným opevněním. Vzhled krajiny je v je v tvých rukou a strategické rozmístění družiníků, ať už sedláků, lupičů, mnichů nebo rytířů, určuje cestu k úspěchu.
</p>
<p>
Carcassonne je jednoduchá desková hra. Pokud neznáš pravidla, stačí si hru jednou zahrát v deskoherně a můžeš jít zkusit své štěstí na turnaj.
</p>
<p>Turnaj v Carcassonne je vyhodnocen nejen v rámci GameConu, ale je také zapojen do serie turnajů v rámci Carcassonne Tour. Máte tedy příležitost nejen vyhrát super ceny přímo na GameConu, ale také postup na mistrovství ČR, které se uskuteční v průběhů října na Deskohraní. Více informaci o Carcassonne Tour najdete na: http://www.carcassonne-tour.cz/ 
</p>
Pravidla turnaje budou upřesněna na místě. 
<p>    <ul>                  <!--<li>
        <a href = "/deskove-hry/prehled-deskovych-her-na-gc2010">Přehled turnajů v deskových hrách na GameConu 2010</a>      </li>-->
    </ul>
  </p>
  <div style = "width: 100%; float: left;">
    <div style = "width: 50%; text-align: left; float: left; padding-top: 20px; padding-bottom: 15px;">&laquo; <a href = "/deskove-hry/battlestar-galactica">Battlestar Galactica</a></div>    <div style = "width: 50%; text-align: right; float: right; padding-top: 20px; padding-bottom: 15px;"><a href = "/deskove-hry/colossal-arena">Colossal Arena</a> &raquo;</div>  </div>
  
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (117,'Carcassonne','kapacita 6/30 Carcassonne organizátor MindOK čas akce pátek 22.7 - 19:00 až 23:00 další akce organizátora Duch! , Time´s Up! , Vládci podzemí , Kaleidoskop Vydáváš se svou družinou na cesty, do měst a klášterů, abys hledal štěstí kolem jihofrancouzské města Carcassonne, které je pověstné svým jedinečným opevněním. Vzhled krajiny je v je v tvých rukou a strategické rozmístění družiníků, ať už sedláků, lupičů, mnichů nebo rytířů, určuje cestu k úspěchu. Carcassonne je jednoduchá desková hra. Pokud neznáš pravidla, stačí si hru jednou zahrát v deskoherně a můžeš jít zkusit své štěstí na turnaj. Turnaj v Carcassonne je vyhodnocen nejen v rámci GameConu, ale je také zapojen do serie turnajů v rámci Carcassonne Tour. Máte tedy příležitost nejen vyhrát super ceny přímo na GameConu, ale také postup na mistrovství ČR, které se uskuteční v průběhů října na Deskohraní. Více informaci o Carcassonne Tour najdete na: http://www.carcassonne-tour.cz/ Pravidla turnaje budou upřesněna na místě. Přehled turnajů v deskových hrách na GameConu 2010 --> « Battlestar Galactica Colossal Arena »');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (118,'Ceny pro vítěze turnajů','ceny-pro-viteze-turnaju',39,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (118,'deskove-hry/ceny-pro-viteze-turnaju');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (118,'Ceny pro vítěze turnajů — GameCon 2011','gamecon,2011','Ceny pro vítěze turnajů');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (118,'<h1>Ceny pro vítěze turnajů</h1>
<p>Ceny pro vítěze turnajů v deskových a karetních hrách věnují příslušní vydavatelé a distributoři dané hry a stojí za to - posuďte sami.</p>
   <p>Vždy se jedná o jednu hru pro každého vítězného hráče:</p>
</p><p>
<ul>
  <li>1. místo – hra v hodnotě 800 – 1.000 Kč</li>
  <li>2. místo – hra v hodnotě 500 – 600 Kč</li>
  <li>3. místo – hra v hodnotě 200 – 300 Kč</li>
</ul>
</p>
<p>V případě, že se turnaje účastní 9 a méně hráčů, získá cenu pro vítěze pouze hráč na prvním místě.</p>

    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (118,'Ceny pro vítěze turnajů','Ceny pro vítěze turnajů Ceny pro vítěze turnajů v deskových a karetních hrách věnují příslušní vydavatelé a distributoři dané hry a stojí za to - posuďte sami. Vždy se jedná o jednu hru pro každého vítězného hráče: 1. místo – hra v hodnotě 800 – 1.000 Kč 2. místo – hra v hodnotě 500 – 600 Kč 3. místo – hra v hodnotě 200 – 300 Kč V případě, že se turnaje účastní 9 a méně hráčů, získá cenu pro vítěze pouze hráč na prvním místě.');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (119,'Colossal Arena','colossal-arena',39,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (119,'deskove-hry/colossal-arena');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (119,'Colossal Arena — GameCon 2011','gamecon,2011','Colossal Arena');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (119,'kapacita 6/30<br />
<h1>Colossal Arena</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/colossal-arena.gif" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>organizátor</strong><br />Altar<br />
  <strong>čas akce</strong><br />neděle 24.7 - 9:00 až 13:00  <br />
 <strong>další akce organizátora</strong> <br /><div style = "text-align: left;"><a href = "/deskove-hry/proroctvi">Proroctví</a></div>
</div>
</p>
   <p style = "clear: both;">Starověká aréna se otřásá v základech, když davy šílí a na písek vstupují strašní gladiátoři - drak, jednorožec, titán, mág... Všichni jsou mocní, ale nemohou všichni zvítězit.</p>
<p>Ještě před začátkem souboje všichni uzavírají sázky a snaží se rozmnožit své zlato sázkou na svého favorita. Je lepší sázet takticky na všechny nebo se stát mecenášem svého favorita?</p>
<p>V Colossal Areně je vaším cílem vydělat zlato sázkami na gladiátory. Kromě toho také můžete používat některé akční karty a schopnosti gladiátorů, abyste "štěstí" přiklonili na svou stranu.</p>
<p>Colossal Arena je jednoduchá svižná hra. Nemusíte ji dopředu znát - můžete se ji naučit až na místě a bez ohledu na původní neznalost zvítězit.</p>
<p>Pravidla turnaje budou upřesněna na místě.</p>

<p>      <!--<li>
        <a href = "/deskove-hry/prehled-deskovych-her-na-gc2010">Přehled turnajů v deskových hrách na GameConu 2010</a>      </li>-->
    </ul>
  </p>
  <div style = "width: 100%; float: left;">
    <div style = "width: 50%; text-align: left; float: left; padding-top: 20px; padding-bottom: 15px;">&laquo; <a href = "/deskove-hry/carcassonne">Carcassonne</a></div>    <div style = "width: 50%; text-align: right; float: right; padding-top: 20px; padding-bottom: 15px;"><a href = "/deskove-hry/dominion">Dominion</a> &raquo;</div>  </div>
  
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (119,'Colossal Arena','kapacita 6/30 Colossal Arena organizátor Altar čas akce neděle 24.7 - 9:00 až 13:00 další akce organizátora Proroctví Starověká aréna se otřásá v základech, když davy šílí a na písek vstupují strašní gladiátoři - drak, jednorožec, titán, mág... Všichni jsou mocní, ale nemohou všichni zvítězit. Ještě před začátkem souboje všichni uzavírají sázky a snaží se rozmnožit své zlato sázkou na svého favorita. Je lepší sázet takticky na všechny nebo se stát mecenášem svého favorita? V Colossal Areně je vaším cílem vydělat zlato sázkami na gladiátory. Kromě toho také můžete používat některé akční karty a schopnosti gladiátorů, abyste "štěstí" přiklonili na svou stranu. Colossal Arena je jednoduchá svižná hra. Nemusíte ji dopředu znát - můžete se ji naučit až na místě a bez ohledu na původní neznalost zvítězit. Pravidla turnaje budou upřesněna na místě. Přehled turnajů v deskových hrách na GameConu 2010 --> « Carcassonne Dominion »');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (120,'Deskoherna','deskoherna',39,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (120,'deskove-hry/deskoherna');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (120,'Deskoherna — GameCon 2011','gamecon,2011','Deskoherna');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (120,'<h1>Deskoherna</h1>
<p>Neskládáme jenom plané sliby. Po dobu celého trvání GameConu je pro vás k dispozici ve velkém sále deskoherna, do které vydavatelé a dovozci deskových a jiných stolních her zapůjčili desítky svých produktů. Máte tak možnost si, kdykoli budete mít volnou chvilku a chuť, zahrát svou oblíbenou hru a nebo vyzkoušet nějakou novou. </p>
<p>
Po zkušenostech s loňským zájmem o hraní deskovek jsme pro Vás letos zajistili obrovský a vzdušný sál, který bude fungovat jako deskoherna a bude k dispozici dlouho do noci podle zájmu. Jako důkaz přikládáme pár fotografií z naší objevné výpravy do České Třebové - no nebude to krása, až to bude plné deskových her?
</p> 

<div class = "galerie"> 
<a href = "/galerie/deskoherna/deskoherna-1.jpg" rel = "lightbox[galerie]" title = "Deskoherna"><img src = "/galerie/deskoherna/deskoherna-1a.jpg" /></a>
<a href = "/galerie/deskoherna/deskoherna-2.jpg" rel = "lightbox[galerie]" title = "Deskoherna"><img src = "/galerie/deskoherna/deskoherna-2a.jpg" /></a>
</div>

<p>V herně jsou na vás také připraveni prezentátoři, kteří vám každou hru rádi vysvětlí a pomohou vám, tak abyste si ji mohli opravdu vychutnat bez pročítání nebo tápání v pravidlech. Vydavatelé deskových her si pro vás také připravili prezentace některých zajímavých her a novinek.</p>

    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (120,'Deskoherna','Deskoherna Neskládáme jenom plané sliby. Po dobu celého trvání GameConu je pro vás k dispozici ve velkém sále deskoherna, do které vydavatelé a dovozci deskových a jiných stolních her zapůjčili desítky svých produktů. Máte tak možnost si, kdykoli budete mít volnou chvilku a chuť, zahrát svou oblíbenou hru a nebo vyzkoušet nějakou novou. Po zkušenostech s loňským zájmem o hraní deskovek jsme pro Vás letos zajistili obrovský a vzdušný sál, který bude fungovat jako deskoherna a bude k dispozici dlouho do noci podle zájmu. Jako důkaz přikládáme pár fotografií z naší objevné výpravy do České Třebové - no nebude to krása, až to bude plné deskových her? V herně jsou na vás také připraveni prezentátoři, kteří vám každou hru rádi vysvětlí a pomohou vám, tak abyste si ji mohli opravdu vychutnat bez pročítání nebo tápání v pravidlech. Vydavatelé deskových her si pro vás také připravili prezentace některých zajímavých her a novinek.');

