INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (122,'Dominion','dominion',39,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (122,'deskove-hry/dominion');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (122,'Dominion — GameCon 2011','gamecon,2011','Dominion');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (122,'kapacita 6/30<br />
<h1>Dominion</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/dominion.gif" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>organizátor</strong><br />Miloš Čeřovský<br />
  <strong>čas akce</strong><br />sobota 23.7 - 15:00 až 20:00  <br />
 <strong>další akce organizátora</strong> <br /><div style = "text-align: left;"><a href = "/deskove-hry/osadnici-z-katanu">Osadníci z Katanu</a></div>
</div>
</p>
   <p style = "clear: both;">
Po svých předcích jsi zdědil malé panství. Kraj sice nádherný, plný zeleně a řek, ale vám to nestačí. Tvým snem je veliká prosperující říše, krásná a bohatá a se spokojenými obyvateli.
</p>
<p>
Tvoji sousedi mají naneštěstí stejné plány.
</p>
<p>
Dominion je struhující hra s jednoduchými pravidly, kterou se zvládnete bez nesnází naučit v deskoherně na GameConu. Turnaj v Dominionu se hraje se <strong>základní sadou a sadou Intriky</strong>
</p>
<p>
Turnaj v Dominionu je nejen vyhodnocen jako samostatný turnaj na GameConu, ale je také zapojen do serie turnajů v rámci Dominion Tour. Máte tedy příležitost nejen vyhrát super ceny přímo na GameConu, ale také získat šanci účastnit se velkého finále v Dominionu v Praze na Deskohraní.
Více informaci o Dominion Tour najdete na: http://www.dominiontour.cz/
</p>
<p>Pravidla turnaje budou upřesněna na místě.  Turnaj v Dominionu začne asi půl hodiny po konci turnaje v Osadnicích, předpokládáme, že to bude kolem 15:00.          </p>
<p><ul>                    <!--<li>
        <a href = "/deskove-hry/prehled-deskovych-her-na-gc2010">Přehled turnajů v deskových hrách na GameConu 2010</a>      </li>-->
    </ul>
  </p>
  <div style = "width: 100%; float: left;">
    <div style = "width: 50%; text-align: left; float: left; padding-top: 20px; padding-bottom: 15px;">&laquo; <a href = "/deskove-hry/colossal-arena">Colossal Arena</a></div>    <div style = "width: 50%; text-align: right; float: right; padding-top: 20px; padding-bottom: 15px;"><a href = "/deskove-hry/duch">Duch!</a> &raquo;</div>  </div>
  
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (122,'Dominion','kapacita 6/30 Dominion organizátor Miloš Čeřovský čas akce sobota 23.7 - 15:00 až 20:00 další akce organizátora Osadníci z Katanu Po svých předcích jsi zdědil malé panství. Kraj sice nádherný, plný zeleně a řek, ale vám to nestačí. Tvým snem je veliká prosperující říše, krásná a bohatá a se spokojenými obyvateli. Tvoji sousedi mají naneštěstí stejné plány. Dominion je struhující hra s jednoduchými pravidly, kterou se zvládnete bez nesnází naučit v deskoherně na GameConu. Turnaj v Dominionu se hraje se základní sadou a sadou Intriky Turnaj v Dominionu je nejen vyhodnocen jako samostatný turnaj na GameConu, ale je také zapojen do serie turnajů v rámci Dominion Tour. Máte tedy příležitost nejen vyhrát super ceny přímo na GameConu, ale také získat šanci účastnit se velkého finále v Dominionu v Praze na Deskohraní. Více informaci o Dominion Tour najdete na: http://www.dominiontour.cz/ Pravidla turnaje budou upřesněna na místě. Turnaj v Dominionu začne asi půl hodiny po konci turnaje v Osadnicích, předpokládáme, že to bude kolem 15:00. Přehled turnajů v deskových hrách na GameConu 2010 --> « Colossal Arena Duch! »');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (123,'Duch!','duch',39,0,0);
