INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (123,'kapacita 4/30<br />
<h1>Duch!</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/duch.gif" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>organizátor</strong><br />MindOK<br />
  <strong>čas akce</strong><br />pátek 22.7 - 10:00 až 12:00  <br />
 <strong>další akce organizátora</strong> <br /><div style = "text-align: left;"><a href = "/deskove-hry/carcassonne">Carcassonne</a>, <a href = "/deskove-hry/times-up">Time´s Up!</a>, <a href = "/deskove-hry/vladci-podzemi">Vládci podzemí</a>, <a href = "/deskove-hry/kaleidoskop">Kaleidoskop</a></div>
</div>
</p>
   <p style = "clear: both;">
Myš! Kniha! Křeslo! Láhev! Duch! Pomozte veselému zámeckému strašidlu při fotografování kouzelným fotoaparátem.</p>
<ul>
<li>Bleskurychlá postřehová hra pro 2 - 8 hráčů od osmi let. </li>
<li>2 varianty hry - jednodušší a náročnější</li>
<p>
Příklad: Na kartě je modrý duch a červená myš. Ve hře žádný modrý duch,
ani červená myš nejsou. Cílem je tedy vzít (zelenou) láhev, protože na kartě
není zobrazena ani láhev, ani zelená barva.</p>
<p>Hru nemusíš vůbec znát, stačí si ji na pár minut zahrát v deskoherně a už budeš vedět, co a jak. Pak už stačí jen příjít a zahrát rychloturnaj.</p>

<p>Pravidla turnaje budou upřesněna při začátku turnaje.</p>
            <p><ul>      <!--<li>
        <a href = "/deskove-hry/prehled-deskovych-her-na-gc2010">Přehled turnajů v deskových hrách na GameConu 2010</a>      </li>-->
    </ul>
  </p>
  <div style = "width: 100%; float: left;">
    <div style = "width: 50%; text-align: left; float: left; padding-top: 20px; padding-bottom: 15px;">&laquo; <a href = "/deskove-hry/dominion">Dominion</a></div>    <div style = "width: 50%; text-align: right; float: right; padding-top: 20px; padding-bottom: 15px;"><a href = "/deskove-hry/duna">Duna</a> &raquo;</div>  </div>
  
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (123,'Duch!','kapacita 4/30 Duch! organizátor MindOK čas akce pátek 22.7 - 10:00 až 12:00 další akce organizátora Carcassonne , Time´s Up! , Vládci podzemí , Kaleidoskop Myš! Kniha! Křeslo! Láhev! Duch! Pomozte veselému zámeckému strašidlu při fotografování kouzelným fotoaparátem. Bleskurychlá postřehová hra pro 2 - 8 hráčů od osmi let. 2 varianty hry - jednodušší a náročnější Příklad: Na kartě je modrý duch a červená myš. Ve hře žádný modrý duch, ani červená myš nejsou. Cílem je tedy vzít (zelenou) láhev, protože na kartě není zobrazena ani láhev, ani zelená barva. Hru nemusíš vůbec znát, stačí si ji na pár minut zahrát v deskoherně a už budeš vedět, co a jak. Pak už stačí jen příjít a zahrát rychloturnaj. Pravidla turnaje budou upřesněna při začátku turnaje. Přehled turnajů v deskových hrách na GameConu 2010 --> « Dominion Duna »');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (124,'Duna','duna',39,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (124,'deskove-hry/duna');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (124,'Duna — GameCon 2011','gamecon,2011','Duna');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (124,'kapacita 6/6<br />
<h1>Duna</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/duna.gif" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>organizátor</strong><br />Jan "Thaddeus" Vaněček<br />
  <strong>čas akce</strong><br />pátek 22.7 - 19:00 až 23:00  <br />
 
</div>
</p>
   <p style = "clear: both;">
Koření musí proudit!
</p>
<p>
Hra se odehrává ve vesmíru podle románu Franka Herberta Duna, kde galaktické velkorody soupeří o  vyprahlou planetu Arrakis, zvanou Duna. Tato pouštní planeta jediná v galaxii obsahuje substanci melanž, též zvanou koření. Koření prodlužuje život, koření rozšiřuje vědomí, koření umožňuje cestování vesmírem ... Koření musí proudit!</p>
<p>Každý z hráčů se vžije do role vládce jedné frakce soupeřící o
kontrolu arrakis. Každá strana má odlišné nesymetrické schopnosti a
různé informace o hře. Hra obsahuje málo náhody, dražby, obchod s
informacemi, intriky a zrady.</p>
<p>Máš na to být vládce Duny?
Hraní je součástí programu EPIC hraní - určena je tedy hlavně hráčům, kteří se hrou nemají žádné zkušenosti.</p>
<p>
Hra je kompletně v češtině.</p>
<p>          <!--<li>
        <a href = "/deskove-hry/prehled-deskovych-her-na-gc2010">Přehled turnajů v deskových hrách na GameConu 2010</a>      </li>-->
    </ul>
  </p>
  <div style = "width: 100%; float: left;">
    <div style = "width: 50%; text-align: left; float: left; padding-top: 20px; padding-bottom: 15px;">&laquo; <a href = "/deskove-hry/duch">Duch!</a></div>    <div style = "width: 50%; text-align: right; float: right; padding-top: 20px; padding-bottom: 15px;"><a href = "/deskove-hry/galaxy-trucker">Galaxy Trucker</a> &raquo;</div>  </div>
  
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (124,'Duna','kapacita 6/6 Duna organizátor Jan "Thaddeus" Vaněček čas akce pátek 22.7 - 19:00 až 23:00 Koření musí proudit! Hra se odehrává ve vesmíru podle románu Franka Herberta Duna, kde galaktické velkorody soupeří o vyprahlou planetu Arrakis, zvanou Duna. Tato pouštní planeta jediná v galaxii obsahuje substanci melanž, též zvanou koření. Koření prodlužuje život, koření rozšiřuje vědomí, koření umožňuje cestování vesmírem ... Koření musí proudit! Každý z hráčů se vžije do role vládce jedné frakce soupeřící o kontrolu arrakis. Každá strana má odlišné nesymetrické schopnosti a různé informace o hře. Hra obsahuje málo náhody, dražby, obchod s informacemi, intriky a zrady. Máš na to být vládce Duny? Hraní je součástí programu EPIC hraní - určena je tedy hlavně hráčům, kteří se hrou nemají žádné zkušenosti. Hra je kompletně v češtině. Přehled turnajů v deskových hrách na GameConu 2010 --> « Duch! Galaxy Trucker »');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (125,'Epické hraní','epicke-hrani',39,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (125,'deskove-hry/epicke-hrani');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (125,'Epické hraní — GameCon 2011','gamecon,2011','Epické hraní');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (125,'<h1>Epické hraní</h1>
<p>Obrovský herní plán, spousty figurek, žetonů a karet různých
velikostí, druhů a barev. K tomu pravidla aspoň na 30 stránek. Tuhle
hru že si prostě musíš zahrát?</p>
<p><strong>Tak to jsi na GameConu správně!</strong></p>
<p>Stačí se jen přihlásit na některé z epických hraní. Nejedná se o
turnaje, ale o představení a hraní jedné konkrétní hry na motivy
slavné knižní ságy, seriálu nebo počítačové hry.</p>
<ul>
<li><strong>Neznáš pravidla?</strong> V pořádku, my ano a rádi ti je
vysvětlíme.</li>
<li><strong>Znáš svět a příběh?</strong> Výborně, přesně to
předpokládáme, ale ani to není nutné pro hraní…</li>
<li><strong>Chceš si tuhle hru prohlédnout?</strong> Stačí se zastavit v
<a href="/deskove-hry/deskoherna">deskoherně</a>, v průběhu celého GameConu budou hry k dispozici k nahlédnutí a hraní (pokud hru již umíš). Pokud hru vůbec neznáš a chceš si zahrát, tak se přihlaš! Právě na tebe čeká náš organizátor, který se ti bude věnovat po celou dobou hraní.</li>
<li><strong>Chceš znát každý detail pravidel ve hře ještě než začneš
hrát?</strong> Ne, je nám líto, ale to si raději přečti pravidla.
Nabízíme odehrání epického příběhu, ne instruktáž o tom, jak se hra
přesně hraje. Na začátku vysvětlíme základní mechaniky a principy, na
kterých hra stojí s důrazem na to, aby bylo možné co nejdříve rozehrát
hru.</li>
<li>Většina her obsahuje texty v angličtině.</li>
</ul>

<h2>A co se bude hrát?</h2>
<ul>
<li><strong>A Game of Thrones</strong> - kdo bude sedět na železném
trůnu? Přežije říše nájezd divokých? Dobudou Starkové Lannisport?</li>
<li><strong>Battlestar Galactica</strong> - prezident Gaius Baltar,
Admirál Adama nebo Chief Tyrol? Kdo z nich jen může být Cylon?</li>
<li><strong>Duna</strong> - Fremeni, Harkonneni, Gilda nebo Císař?
Všichni chtějí koření.</li>
<li><strong>War of Rings</strong> - dobude Sauron Středozem, nebo se
povede společenstvu zničit Jeden prsten? A nebo snad zkorumpuje Sauron
Froda, aby mu prsten odevzdal dobrovolně?</li>
<li><strong>Arkham Horror</strong> - Prastarý se probouzí, městem se
prohání nevídaná mostra, otevírají se brány do cizích světů.</li>
<li><strong>Starcraft</strong> - Zergovský "rush". Templáři se spojují
v Archony. Siege tank právě sestřelil několi SCV, ale marně pálí na
Science vessel. Starcraft, tak jak ho znáte z monitorů.</li>
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (125,'Epické hraní','Epické hraní Obrovský herní plán, spousty figurek, žetonů a karet různých velikostí, druhů a barev. K tomu pravidla aspoň na 30 stránek. Tuhle hru že si prostě musíš zahrát? Tak to jsi na GameConu správně! Stačí se jen přihlásit na některé z epických hraní. Nejedná se o turnaje, ale o představení a hraní jedné konkrétní hry na motivy slavné knižní ságy, seriálu nebo počítačové hry. Neznáš pravidla? V pořádku, my ano a rádi ti je vysvětlíme. Znáš svět a příběh? Výborně, přesně to předpokládáme, ale ani to není nutné pro hraní… Chceš si tuhle hru prohlédnout? Stačí se zastavit v deskoherně , v průběhu celého GameConu budou hry k dispozici k nahlédnutí a hraní (pokud hru již umíš). Pokud hru vůbec neznáš a chceš si zahrát, tak se přihlaš! Právě na tebe čeká náš organizátor, který se ti bude věnovat po celou dobou hraní. Chceš znát každý detail pravidel ve hře ještě než začneš hrát? Ne, je nám líto, ale to si raději přečti pravidla. Nabízíme odehrání epického příběhu, ne instruktáž o tom, jak se hra přesně hraje. Na začátku vysvětlíme základní mechaniky a principy, na kterých hra stojí s důrazem na to, aby bylo možné co nejdříve rozehrát hru. Většina her obsahuje texty v angličtině. A co se bude hrát? A Game of Thrones - kdo bude sedět na železném trůnu? Přežije říše nájezd divokých? Dobudou Starkové Lannisport? Battlestar Galactica - prezident Gaius Baltar, Admirál Adama nebo Chief Tyrol? Kdo z nich jen může být Cylon? Duna - Fremeni, Harkonneni, Gilda nebo Císař? Všichni chtějí koření. War of Rings - dobude Sauron Středozem, nebo se povede společenstvu zničit Jeden prsten? A nebo snad zkorumpuje Sauron Froda, aby mu prsten odevzdal dobrovolně? Arkham Horror - Prastarý se probouzí, městem se prohání nevídaná mostra, otevírají se brány do cizích světů. Starcraft - Zergovský "rush". Templáři se spojují v Archony. Siege tank právě sestřelil několi SCV, ale marně pálí na Science vessel. Starcraft, tak jak ho znáte z monitorů.');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (126,'Galaxy Trucker','galaxy-trucker',39,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (126,'deskove-hry/galaxy-trucker');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (126,'Galaxy Trucker — GameCon 2011','gamecon,2011','Galaxy Trucker');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (126,'kapacita 2/30<br />
<h1>Galaxy Trucker</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/galaxy-trucker.jpg" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>organizátor</strong><br />Czech Games Edition<br />
  <strong>čas akce</strong><br />sobota 23.7 - 14:00 až 18:00  <br />
 <strong>další akce organizátora</strong> <br /><div style = "text-align: left;"><a href = "/deskove-hry/novinky-cge">Novinky CGE</a></div>
</div>
</p>
   <p style = "clear: both;">
Společnost, s.r.o., jednička na trhu v oblasti stavby kanalizací a nízkorozpočtového bydlení, hledá všeho schopné muže či dívky na nebezpečné trasy do odlehlých částí Galaxie. Ochota potýkat se s meteory, piráty či pašeráky podmínkou. Praxe ve spolupráci s mimozemšťany výhodou. Vysoké výdělky, bonusy za rychlé a kvalitní doručení materiálu.</p>
<p>
Dej se ke galaktickým tirákům a užij si hromadu kosmické zábavy.</p>
<p>
Hra sestává ze tří etap. V každé etapě se nejdříve hráči vrhnou do skladu, aby si pro sebe urvali co nejlepší součástky a postavili z nich co nejlepší loď. Tu pak připraví na cestu a odstartují. Cestou k cíli se snaží přestát četná nebezpečí a překonat překážky, chytře využít možností na výdělek, a pokud možno doletět první a s nepoškozenou lodí.</p>
<p>
Když budete mít smůlu, do konce života se nevyhrabete z dluhů. Když se však na vás cestou usměje štěstí, vyděláte balík a vyhoupnete se mezi horních deset miliard.</p>
<p>
Galaxy Trucker je zábavná hra českého světoznámého tvůrce Vládi Chvátila.</p>
<p>
Pravidla turnaje budou ještě upřesněna podle počtu účastníků.
</p>      <!--<li>
        <a href = "/deskove-hry/prehled-deskovych-her-na-gc2010">Přehled turnajů v deskových hrách na GameConu 2010</a>      </li>-->
    </ul>
  </p>
  <div style = "width: 100%; float: left;">
    <div style = "width: 50%; text-align: left; float: left; padding-top: 20px; padding-bottom: 15px;">&laquo; <a href = "/deskove-hry/duna">Duna</a></div>    <div style = "width: 50%; text-align: right; float: right; padding-top: 20px; padding-bottom: 15px;"><a href = "/deskove-hry/hra-o-truny">Hra o trůny</a> &raquo;</div>  </div>
  
    </div>
  </div>');
