INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (127,'Hra o Trůny LCG','hra-o-truny-lcg',39,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (127,'deskove-hry/hra-o-truny-lcg');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (127,'Hra o Trůny LCG — GameCon 2011','gamecon,2011','Hra o Trůny LCG');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (127,'kapacita 4/20<br />
<h1>Hra o Trůny LCG</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/hra-o-truny-lcg.gif" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>organizátor</strong><br />Karel "Shako" Nejedlík<br />
  <strong>čas akce</strong><br />sobota 23.7 - 14:00 až 18:00  <br />
 <strong>další akce organizátora</strong> <br /><div style = "text-align: left;"><a href = "/deskove-hry/hra-o-truny">Hra o trůny</a>, <a href = "/deskove-hry/battlestar-galactica">Battlestar Galactica</a>, <a href = "/deskove-hry/armada-game">Armada Game</a></div>
</div>
</p>
   <p style = "clear: both;">
Mocný rod Targaryenů byl poražen… Nyní ve Westerosu vládnou Baratheoni, avšak i ostatní rody mají zájem o moc. Podaří se proradným Lannisterům zachvátit trůn svými pletichami? Čestný rod Starků sice po moci netouží, ale odplata vůči intrikám ostatních je jistá. Na západě se bouří Greyjoyové, vládci moří. Na jihu takticky vyčkávají jako hadi Martellové a za mořem na východě sbírá armádu poslední potomek rodu Targaryenů. Hra o Trůny právě začíná…</p>
<p>A Game of Thrones LCG, česky také karetní Hra o Trůny, je pro 2-4 hráče. Hra je založena na příběhu z knih George R. R. Martina z dílny Fantasy Flight Games. Pokud ještě neznáte, tak na Gameconu máte možnost si tuto hru vyzkoušet v pátek večer a sobotu dopoledne. Pokud už hru znáte, tak se můžete v sobotu zůčastnit turnaje.</p>

Přesná pravidla turnaje ještě upřesníme.

              <!--<li>
        <a href = "/deskove-hry/prehled-deskovych-her-na-gc2010">Přehled turnajů v deskových hrách na GameConu 2010</a>      </li>-->
    </ul>
  </p>
  <div style = "width: 100%; float: left;">
    <div style = "width: 50%; text-align: left; float: left; padding-top: 20px; padding-bottom: 15px;">&laquo; <a href = "/deskove-hry/hra-o-truny">Hra o trůny</a></div>    <div style = "width: 50%; text-align: right; float: right; padding-top: 20px; padding-bottom: 15px;"><a href = "/deskove-hry/kaleidoskop">Kaleidoskop</a> &raquo;</div>  </div>
  
    </div>
  </div>');
