INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (128,'Hra o trůny','hra-o-truny',39,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (128,'deskove-hry/hra-o-truny');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (128,'Hra o trůny — GameCon 2011','gamecon,2011','Hra o trůny');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (128,'kapacita 6/6<br />kapacita 6/6<br />kapacita 6/6<br />
<h1>Hra o trůny</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/hra-o-truny.gif" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>organizátor</strong><br />Klub deskových her Paluba<br />
  <strong>čas akce</strong><br />pátek 22.7 - 14:00 až 18:00  <br />neděle 24.7 - 9:00 až 13:00  <br />pátek 22.7 - 19:00 až 23:00  <br />
 <strong>další akce organizátora</strong> <br /><div style = "text-align: left;"><a href = "/deskove-hry/battlestar-galactica">Battlestar Galactica</a>, <a href = "/deskove-hry/arkham-horror">Arkham Horror</a>, <a href = "/deskove-hry/valka-o-prsten">Válka o Prsten</a>, <a href = "/deskove-hry/republic-of-rome">Republic of Rome</a></div>
</div>
</p>
   <p style = "clear: both;">Robert Baratheon dobyl Královo přístaviště. Starkové shromaždují jednotky na Kailinské šíji .Lannisteři přepočítávají své zlato. Greyjové chystají povstání proti novému králi.  Tyrrellové se snaží získat vliv na trůn, ať už na něm sedí kdokoli.</p>
<p>
Hraní je součastní programu EPIC hraní - určena je tedy hlavně hráčům, kteří se hrou nemají žádné zkušenosti.
</p>
<p>
Strategická hra z prostřední ságy ledu a ohně pro 3-5 hráčů, ideálně hraná v 5 hráčích (s rozšíření v 6 hráčích). Každý z hráčů se ujme jednoho z rodů ve Westerosu - Stark, Greyjoy, Lannister, Tyrel, Baratheon nebo Martel. Všichni chtějí získat moc jen pro sebe a sjednotit tak říší pod svoji zástavou, ale povést se to může jen jednomu. Usednout na železný trůn nebo dobýt Královo přístaviště však ještě neznamená vítězství</p>
<p>
Hra je postavena na tajném plánování pohybu jednotek a komunikaci mezi hráči.</p>
<p>
Hra je původně v angličtině, nicméně většina herního materiálu je bez textu. Zbylé anglické texty jsou veřejné, takže s překladem pomůže náš organizátor.</p>

Mrkněte na <a href = "http://www.youtube.com/watch?v=8gEM_3v6g-E&feature=player_embedded">ukázku hry</a>.          <!--<li>
        <a href = "/deskove-hry/prehled-deskovych-her-na-gc2010">Přehled turnajů v deskových hrách na GameConu 2010</a>      </li>-->
    </ul>
  </p>
  <div style = "width: 100%; float: left;">
    <div style = "width: 50%; text-align: left; float: left; padding-top: 20px; padding-bottom: 15px;">&laquo; <a href = "/deskove-hry/galaxy-trucker">Galaxy Trucker</a></div>    <div style = "width: 50%; text-align: right; float: right; padding-top: 20px; padding-bottom: 15px;"><a href = "/deskove-hry/hra-o-truny-lcg">Hra o Trůny LCG</a> &raquo;</div>  </div>
  
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (128,'Hra o trůny','kapacita 6/6 kapacita 6/6 kapacita 6/6 Hra o trůny organizátor Klub deskových her Paluba čas akce pátek 22.7 - 14:00 až 18:00 neděle 24.7 - 9:00 až 13:00 pátek 22.7 - 19:00 až 23:00 další akce organizátora Battlestar Galactica , Arkham Horror , Válka o Prsten , Republic of Rome Robert Baratheon dobyl Královo přístaviště. Starkové shromaždují jednotky na Kailinské šíji .Lannisteři přepočítávají své zlato. Greyjové chystají povstání proti novému králi. Tyrrellové se snaží získat vliv na trůn, ať už na něm sedí kdokoli. Hraní je součastní programu EPIC hraní - určena je tedy hlavně hráčům, kteří se hrou nemají žádné zkušenosti. Strategická hra z prostřední ságy ledu a ohně pro 3-5 hráčů, ideálně hraná v 5 hráčích (s rozšíření v 6 hráčích). Každý z hráčů se ujme jednoho z rodů ve Westerosu - Stark, Greyjoy, Lannister, Tyrel, Baratheon nebo Martel. Všichni chtějí získat moc jen pro sebe a sjednotit tak říší pod svoji zástavou, ale povést se to může jen jednomu. Usednout na železný trůn nebo dobýt Královo přístaviště však ještě neznamená vítězství Hra je postavena na tajném plánování pohybu jednotek a komunikaci mezi hráči. Hra je původně v angličtině, nicméně většina herního materiálu je bez textu. Zbylé anglické texty jsou veřejné, takže s překladem pomůže náš organizátor. Mrkněte na ukázku hry . Přehled turnajů v deskových hrách na GameConu 2010 --> « Galaxy Trucker Hra o Trůny LCG »');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (129,'Kaleidoskop','kaleidoskop',39,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (129,'deskove-hry/kaleidoskop');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (129,'Kaleidoskop — GameCon 2011','gamecon,2011','Kaleidoskop');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (129,'kapacita 2/30<br />
<h1>Kaleidoskop</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/kaleidoskop.gif" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>organizátor</strong><br />MindOK<br />
  <strong>čas akce</strong><br />pátek 22.7 - 14:00 až 18:00  <br />
 <strong>další akce organizátora</strong> <br /><div style = "text-align: left;"><a href = "/deskove-hry/carcassonne">Carcassonne</a>, <a href = "/deskove-hry/duch">Duch!</a>, <a href = "/deskove-hry/times-up">Time´s Up!</a>, <a href = "/deskove-hry/vladci-podzemi">Vládci podzemí</a></div>
</div>
</p>
   <p style = "clear: both;">
K barevným symbolům, které jsou vytištěné na herním plánu, postupně přibývají další na dílcích, které hráči přikládají. Pokud přiložíte dílek tak, že spolu sousedí symboly stejné barvy, získáte body v této barvě. Čím více dílků na herním plánu leží, tím více bodů můžete získat. Za každý získaný bod posuňte bodovací kolíček v příslušné barvě na své bodovací tabulce o 1 políčko doprava.
</p>
<p>Hráči tímto způsobem v průběhu hry získávají body v šesti různých barvách. Na konci hry se hráči započte právě tolik bodů, kolik jich získal ve své „nejslabší“ barvě – v té, ve které získal nejméně bodů.</p>
<p> Hráči se tedy musejí snažit o rovnoměrné získávání bodů ve všech barvách, aby žádná z nich nezůstala moc pozadu. Zvítězí hráč, který tímto způsobem získá nejvíce bodů.
</p>
<p>Pravidla turnaje budou upřesněna na místě.         <!--<li>
        <a href = "/deskove-hry/prehled-deskovych-her-na-gc2010">Přehled turnajů v deskových hrách na GameConu 2010</a>      </li>-->
    </ul>
  </p>
  <div style = "width: 100%; float: left;">
    <div style = "width: 50%; text-align: left; float: left; padding-top: 20px; padding-bottom: 15px;">&laquo; <a href = "/deskove-hry/hra-o-truny-lcg">Hra o Trůny LCG</a></div>    <div style = "width: 50%; text-align: right; float: right; padding-top: 20px; padding-bottom: 15px;"><a href = "/deskove-hry/mini-hry">Mini-hry</a> &raquo;</div>  </div>
  
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (129,'Kaleidoskop','kapacita 2/30 Kaleidoskop organizátor MindOK čas akce pátek 22.7 - 14:00 až 18:00 další akce organizátora Carcassonne , Duch! , Time´s Up! , Vládci podzemí K barevným symbolům, které jsou vytištěné na herním plánu, postupně přibývají další na dílcích, které hráči přikládají. Pokud přiložíte dílek tak, že spolu sousedí symboly stejné barvy, získáte body v této barvě. Čím více dílků na herním plánu leží, tím více bodů můžete získat. Za každý získaný bod posuňte bodovací kolíček v příslušné barvě na své bodovací tabulce o 1 políčko doprava. Hráči tímto způsobem v průběhu hry získávají body v šesti různých barvách. Na konci hry se hráči započte právě tolik bodů, kolik jich získal ve své „nejslabší“ barvě – v té, ve které získal nejméně bodů. Hráči se tedy musejí snažit o rovnoměrné získávání bodů ve všech barvách, aby žádná z nich nezůstala moc pozadu. Zvítězí hráč, který tímto způsobem získá nejvíce bodů. Pravidla turnaje budou upřesněna na místě. Přehled turnajů v deskových hrách na GameConu 2010 --> « Hra o Trůny LCG Mini-hry »');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (130,'GameCon 2011 se blíží','magic-tg-allcommon-draft',39,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (130,'deskove-hry/magic-tg-allcommon-draft');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (130,'GameCon 2011 se blíží — GameCon 2011','gamecon,2011','GameCon 2011 se blíží');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (130,'<h1>GameCon 2011 se blíží</h1>

<!--<h2>Organizační změny</h2>
<p>
Dovolte nám seznámit vás s velkou organizační novinkou. Petr „Gandalf“ Holub, který stál v čele organizačního týmu GameConu poslední dva roky, ještě v průběhu letošního GameConu v České Třebové předal post hlavního organizátora Matouši „Erricu“ Ježkovi. Jelikož se mu totiž letos narodily dvě holčičky, po důkladném uvážení se musel rozhodnout k tomuto kroku, neboť vedení organizačního týmu a nově rozrostlou rodinu a normální práci by nebylo možné skloubit tak, aby jedno netrpělo.
</p>
<p>
Nic to však nemění na tom, že další ročník GameConu už pro vás připravujeme a o novinkách vás budeme průběžně informovat jak tady, tak na <a href = "http://www.facebook.com/group.php?sid=1a65342dd9cba753975=bb963632e2a7&gid=93879753711&ref=search#!/gamecon" onclick = "window.open(this.href,\'_blank\'); return false">facebooku</a>.
</p>
<p>
Organizační tým GameConu
</p>

<h2>GameCon Teaser</h2>
<object width="470" height="265"><param name="allowfullscreen" value="true" /><param name="allowscriptaccess" value="always" /><param name="movie" value="http://vimeo.com/moogaloop.swf?clip_id=12709571&amp;server=vimeo.com&amp;show_title=1&amp;show_byline=1&amp;show_portrait=0&amp;color=&amp;fullscreen=1" /><embed src="http://vimeo.com/moogaloop.swf?clip_id=12709571&amp;server=vimeo.com&amp;show_title=1&amp;show_byline=1&amp;show_portrait=0&amp;color=&amp;fullscreen=1" type="application/x-shockwave-flash" allowfullscreen="true" allowscriptaccess="always" width="470" height="265"></embed></object>-->

<h2>Čtyři dny plné zábavy a napětí nad hrami všeho druhu</h2>
<p>Ve dnech <strong>21.-24.7.2011</strong> se v <strong>České Třebové</strong> uskuteční již 17. ročník herního setkání <strong>GameCon</strong>. Je to příležitost pro všechny hráče a fanoušky nepočítačových her z České republiky a Slovenska setkat se s ostatními, zahrát si hry, vyměnit zkušenosti a pobavit se. Co vás během čtyř dnů na GameConu čeká?
<ul>
<li><a href="/deskove-hry/o-deskovych-hrach-na-gc">Deskové hry</a> (Osadníci z Katanu, Carcassonne a mnohé další)</li>
<li>Velké množství her na hraní rolí neboli <a href="/rpg/o-rpg-na-gc">RPG</a>. Můžete si vyzkoušet i herní systémy, které doma ani nemáte.</li>
<li>Hry naživo neboli <a href = "/larp/o-larpech-na-gc">LARP</a>, kdy prožitky své postavy vyzkoušíte na vlastní kůži.</li>
<li><a href = "/mistrovstvi-v-drd/o-mistrovstvi-v-drd">Mistrovství v Dračím doupěti</a>, letos pro změnu z pozice obyčejných obyvatel Císařství.</li>
<li>A spousta dalších aktivit, jako třeba bitva miniaturních armád ve <a href = "/wargaming/o-wargamingu-na-gc">Wargamingu</a>, nebo poutavé <a href = "/prednasky/o-prednaskach-na-gc">přednášky</a>.</li>
<li>Sobotní party</li>
</ul>
</p>

<p>Že neznáte žádnou z těchto her? Nevadí.<strong>Pravidla vám rádi vysvětlíme na místě</strong> a poradíme i s výběrem her nebo naplánováním programu. <strong>Neváhejte tedy a přijeďte.</strong> Slibujeme vám spoustu her, zábavy a přátelské atmosféry. Nemáte volné celé čtyři dny? Nevadí! <strong>GameCon</strong> má co nabídnout každý den.</strong></p>
<!--<p>Jednoduchý návod jak se <strong>přihlásit na GameCon</strong> a všechny důležité informace o <strong>registraci</strong>, možnostech <strong>ubytování</strong> a <strong>platbách</strong> naleznete <a href="/navod/">zde</a>.</p>-->
<p>O novinkách vás budeme průběžně informovat jak zde, tak na <a href = "http://www.facebook.com/gamecon" onclick = "window.open(this.href,\'_blank\'); return false">Facebooku</a>.</p>

<a name=novinky></a>
<h2>Letošní novinky</h2>
<p>Tak jako každý rok se snažíme, aby GameCon i letos nabídl něco nového. Loni se con přestěhoval do České Třebové, což přineslo mimo jiné možnost nabídnout všechny aktivity pod jednou střechou, prostornou a dobře větratelnou místnost pro deskohernu a levnější ubytování. Na co se můžete těšit letos?</p>
<ul>
<li>Pro účastníky GameConu ze Slovenska jsme připravili <strong>možnost platit v eurech</strong>.</li>
<li>Všem budou přístupné <strong>kuchyňky</strong>, ve kterých si bude možné uvařit jídlo.</li>
<li>GameCon se bude odehrávat <strong>ve znamení Antiky</strong>.</li>
<li>Je pro vás připravena <strong>spousta nových her</strong> na všech frontách.</li>
<li>Na programu bude také <strong>křest Dračího doupěte II</strong>.</li>
</ul>

<!--<p>
Patrně nejvýraznější změnou je přestěhování conu do České Třebové. Tento manévr nám poskytl hned několik výhod:
<ul>
	<li>Předně jsou to <strong>všechny aktivity pod jednou střechou</strong>, nebude potřeba kamkoliv přebíhat nebo složitě bloudit mezi jednotlivými komplexy budov.</li>
	<li>Zároveň jsou místnosti pro jednotlivé aktivity dostatečně velké a vzdušné.</li>
	<li>Především místnost <a href = "/deskove-hry/deskoherna">deskoherny</a> je úchvatně prostorná a dobře větratelná. Už nehrozí, že bychom se v dobré víře ušlapávali nebo letním parnu dusili. Tento rok to bude konečně ta <strong>dobře přístupná aréna plná deskových her</strong> připravená na lačné hráče. Pro zvědavce jsme jako důkaz připravili alespoň dvě fotografie z naších průzkumných výprav – více v <a href = "/deskove-hry/deskoherna">deskoherně</a>.</li>
	<li>Vítanou změnou bude určitě i <strong>levnější ubytování</strong>. Letos bude stát jedna noc v třílůžkovém pokoji pouhých 170 Kč (oproti loňským dvěma stovkám, takže za tři noci nakonec ušetříte téměř stokorunu).</li>
	<li>Přijde vám lůžkový pokoj příliš drahý a komfortní? Pak jistě uvítáte další zlepšení a tím je <strong>možnost spát hromadně ve třídě ve vlastním spacáku</strong> a to za pouhých 60 Kč. Více o ubytovacích možnostech se dočtete v <a href = "/gamecon/ubytovani">ubytování</a>.</li>
	<li>Přesunem do jiného města jsme také získali kousek od naší budovy velkou nafukovací halu, kterou budeme moci využít v nepřízni počasí na nějakou velmi hromadnou akci. No není takový bonus skvělý?</li>
	<li>A snad některé z vás potěší i dobrá dopravní dostupnost pro celou republiku. Jsme uprostřed státu, tak snad to má každý kousek. :-)</li>
</ul>
</p>

<p>
Jak můžete vidět, přesun na nové místo pro vás znamená samé výhody. Nespokojíme se však jen s novým územím a jeho přidanými hodnotami, pokračujeme dál ve zpestřujících zlepšovácích:
</p>
<p>
<ul>
	<li>Velká novinka hned rovnou na začátek: <strong>popré</strong> bude <strong>celý GameCon v duchu nějakého tématu</strong>, tentokrát to bude <strong>exodus</strong> a spíše než vyhnání z ráje to bude jeho hledání. V následujících dnech vám přineseme bližší informace a vy se můžete těšit, že s tím bude spojena spousta her a zábavné atmosféry.</li>
	<li><strong>Mistrovství v Dračím doupěti</strong> bude zase o něco blíž vám hráčům. Vyslyšeli jsme vaše dobré připomínky a rady, důkladně si přečetli reakce ve <a href = "/forum/mistrovstvi_v_drd">fóru</a> a vyšli vám vstříc.<br />
Do odkrývání tajů dobrodružství se můžete pustit již nyní a každý týden Vám přineseme další indicii. Na úvod začínáme jedním výtiskem <a href = "/mistrovstvi-v-drd/sluncesvit-cisarske-noviny">Sluncesvitu</a> - populárního císařského plátku.<br />
Také jsme pro vás připravili <strong>dvě výrazná zlepšení postav</strong> a <strong>jedno velmi poutavé zpestření</strong>. Obě novinky se týkají <a href = "/mistrovstvi-v-drd/pravidla-pro-tvorbu-postav">tvorby postav</a> a brzy vás o těchto změnách budeme informovat více. Zatím můžete ve <a href = "/forum/mistrovstvi_v_drd">fóru</a> tipovat, co by to tak mohlo být.</li>
	<li><strong>Trojboj</strong> bude v tomto roce trvat jen jeden blok, takže o důvod více zapojit se do této týmové aktivity, kdy za jednu cenu si zahrajete tři hry. Více na <a href = "/gamecon-trojboj/o-gamecon-trojboji">samostatné stránce</a>.</li>
	<li><strong>Špína</strong> bude letos ve znamení „Osídlení nového města“ a <strong>gobliní ponorky</strong> budou bojovat o nová naleziště drahokamů.</li>
	<li>Určitě se bude hodit i trénink ve velení armádám, tudíž jistě přijde vhod <a href = "/wargaming/wargaming-tour-2010">Wargaming Tour 2010</a>.</li>
	<li>A lahodný zákusek na závěr: <strong>na sobotní večer</strong> pro vás plánujeme <strong>hromadné pobavení</strong>, jehož součástí by mělo být i <strong>klání v duchu televizních soutěží</strong> v režii týmu z Court of Moravia.</li>
</ul>
</p>

<p>
Snad vás to množství novinek a jednotlivé zlepšováky těší a přijedete na GameCon. Koná se <strong>15.-18.7.2010 v&nbsp;České Třebové</strong>.
</p>-->

<h3>GameCon je tu pro vás, tak si přijďte zahrát!</h3>
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (130,'GameCon 2011 se blíží','GameCon 2011 se blíží Organizační změny Dovolte nám seznámit vás s velkou organizační novinkou. Petr „Gandalf“ Holub, který stál v čele organizačního týmu GameConu poslední dva roky, ještě v průběhu letošního GameConu v České Třebové předal post hlavního organizátora Matouši „Erricu“ Ježkovi. Jelikož se mu totiž letos narodily dvě holčičky, po důkladném uvážení se musel rozhodnout k tomuto kroku, neboť vedení organizačního týmu a nově rozrostlou rodinu a normální práci by nebylo možné skloubit tak, aby jedno netrpělo. Nic to však nemění na tom, že další ročník GameConu už pro vás připravujeme a o novinkách vás budeme průběžně informovat jak tady, tak na facebooku . Organizační tým GameConu GameCon Teaser --> Čtyři dny plné zábavy a napětí nad hrami všeho druhu Ve dnech 21.-24.7.2011 se v České Třebové uskuteční již 17. ročník herního setkání GameCon . Je to příležitost pro všechny hráče a fanoušky nepočítačových her z České republiky a Slovenska setkat se s ostatními, zahrát si hry, vyměnit zkušenosti a pobavit se. Co vás během čtyř dnů na GameConu čeká? Deskové hry (Osadníci z Katanu, Carcassonne a mnohé další) Velké množství her na hraní rolí neboli RPG . Můžete si vyzkoušet i herní systémy, které doma ani nemáte. Hry naživo neboli LARP , kdy prožitky své postavy vyzkoušíte na vlastní kůži. Mistrovství v Dračím doupěti , letos pro změnu z pozice obyčejných obyvatel Císařství. A spousta dalších aktivit, jako třeba bitva miniaturních armád ve Wargamingu , nebo poutavé přednášky . Sobotní party Že neznáte žádnou z těchto her? Nevadí. Pravidla vám rádi vysvětlíme na místě a poradíme i s výběrem her nebo naplánováním programu. Neváhejte tedy a přijeďte. Slibujeme vám spoustu her, zábavy a přátelské atmosféry. Nemáte volné celé čtyři dny? Nevadí! GameCon má co nabídnout každý den. Jednoduchý návod jak se přihlásit na GameCon a všechny důležité informace o registraci , možnostech ubytování a platbách naleznete zde . --> O novinkách vás budeme průběžně informovat jak zde, tak na Facebooku . Letošní novinky Tak jako každý rok se snažíme, aby GameCon i letos nabídl něco nového. Loni se con přestěhoval do České Třebové, což přineslo mimo jiné možnost nabídnout všechny aktivity pod jednou střechou, prostornou a dobře větratelnou místnost pro deskohernu a levnější ubytování. Na co se můžete těšit letos? Pro účastníky GameConu ze Slovenska jsme připravili možnost platit v eurech . Všem budou přístupné kuchyňky , ve kterých si bude možné uvařit jídlo. GameCon se bude odehrávat ve znamení Antiky . Je pro vás připravena spousta nových her na všech frontách. Na programu bude také křest Dračího doupěte II . Patrně nejvýraznější změnou je přestěhování conu do České Třebové. Tento manévr nám poskytl hned několik výhod: Předně jsou to všechny aktivity pod jednou střechou , nebude potřeba kamkoliv přebíhat nebo složitě bloudit mezi jednotlivými komplexy budov. Zároveň jsou místnosti pro jednotlivé aktivity dostatečně velké a vzdušné. Především místnost deskoherny je úchvatně prostorná a dobře větratelná. Už nehrozí, že bychom se v dobré víře ušlapávali nebo letním parnu dusili. Tento rok to bude konečně ta dobře přístupná aréna plná deskových her připravená na lačné hráče. Pro zvědavce jsme jako důkaz připravili alespoň dvě fotografie z naších průzkumných výprav – více v deskoherně . Vítanou změnou bude určitě i levnější ubytování . Letos bude stát jedna noc v třílůžkovém pokoji pouhých 170 Kč (oproti loňským dvěma stovkám, takže za tři noci nakonec ušetříte téměř stokorunu). Přijde vám lůžkový pokoj příliš drahý a komfortní? Pak jistě uvítáte další zlepšení a tím je možnost spát hromadně ve třídě ve vlastním spacáku a to za pouhých 60 Kč. Více o ubytovacích možnostech se dočtete v ubytování . Přesunem do jiného města jsme také získali kousek od naší budovy velkou nafukovací halu, kterou budeme moci využít v nepřízni počasí na nějakou velmi hromadnou akci. No není takový bonus skvělý? A snad některé z vás potěší i dobrá dopravní dostupnost pro celou republiku. Jsme uprostřed státu, tak snad to má každý kousek. :-) Jak můžete vidět, přesun na nové místo pro vás znamená samé výhody. Nespokojíme se však jen s novým územím a jeho přidanými hodnotami, pokračujeme dál ve zpestřujících zlepšovácích: Velká novinka hned rovnou na začátek: popré bude celý GameCon v duchu nějakého tématu , tentokrát to bude exodus a spíše než vyhnání z ráje to bude jeho hledání. V následujících dnech vám přineseme bližší informace a vy se můžete těšit, že s tím bude spojena spousta her a zábavné atmosféry. Mistrovství v Dračím doupěti bude zase o něco blíž vám hráčům. Vyslyšeli jsme vaše dobré připomínky a rady, důkladně si přečetli reakce ve fóru a vyšli vám vstříc. Do odkrývání tajů dobrodružství se můžete pustit již nyní a každý týden Vám přineseme další indicii. Na úvod začínáme jedním výtiskem Sluncesvitu - populárního císařského plátku. Také jsme pro vás připravili dvě výrazná zlepšení postav a jedno velmi poutavé zpestření . Obě novinky se týkají tvorby postav a brzy vás o těchto změnách budeme informovat více. Zatím můžete ve fóru tipovat, co by to tak mohlo být. Trojboj bude v tomto roce trvat jen jeden blok, takže o důvod více zapojit se do této týmové aktivity, kdy za jednu cenu si zahrajete tři hry. Více na samostatné stránce . Špína bude letos ve znamení „Osídlení nového města“ a gobliní ponorky budou bojovat o nová naleziště drahokamů. Určitě se bude hodit i trénink ve velení armádám, tudíž jistě přijde vhod Wargaming Tour 2010 . A lahodný zákusek na závěr: na sobotní večer pro vás plánujeme hromadné pobavení , jehož součástí by mělo být i klání v duchu televizních soutěží v režii týmu z Court of Moravia. Snad vás to množství novinek a jednotlivé zlepšováky těší a přijedete na GameCon. Koná se 15.-18.7.2010 v České Třebové . --> GameCon je tu pro vás, tak si přijďte zahrát!');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (131,'Vítej ve světě Magic: The Gathering!','magic-the-gathering',39,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (131,'deskove-hry/magic-the-gathering');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (131,'Vítej ve světě Magic: The Gathering! — GameCon 2011','gamecon,2011','Vítej ve světě Magic: The Gathering!');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (131,'<h1>Vítej ve světě Magic: The Gathering!</h1>
<p>
  <div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;">
    <img src = "/system_styly/side/mtg.gif" style = "float: left; "/ />
  </div>
</p>   
<p style = "clear: both;"><strong>Magic je nejstarší a také nejúspěšnější sběratelskou karetní hrou na světě. Již od roku 1993 ovlivňuje tato hra životy milionů lidí po celém světě… a její obliba stále stoupá! V roce 2006 měl Magic přes 6 000 000 aktivních hráčů ze všech koutů planety!</strong></p>

<p>V České republice hraje tuto hru bezmála 20 000 hráčů a další přibývají doslova každým dnem. V čem je tato hra tak zajímavá? Jak to, že si i v dnešní době plné počítačů a videoher najdou mladí lidé chuť hrát s kamarády karty?</p>

<h2>Stovky nových kamarádů</h2>
<p>Magic není o tom sedět doma. Magic se hraje všude, tak proč někam nejít a nezahrát si s novými kamarády? Prostě vezmeš svůj balíček a najdeš soupeře v nejbližším klubu nebo ve škole. Každý má jiné karty i jiné zkušenosti, každá hra je tak jiná a zajímavá!</p>

<h2>Super zábava kdekoliv zrovna chceš</h2>
<p>K Magicu potřebuješ jen balíček karet, nic víc. Měj ho stále u sebe a můžeš si zahrát kdekoliv budeš chtít. Protihráči jsou všude, stačí se jen zeptat: „Hraješ Magic?“ Budeš překvapen, kolik lidí od tebe ze školy nebo klubu Magic hraje!</p>

<h2>Každá hra je jiná</h2>
Magic, to je tvůj balíček, který sis sám sestavil. Karty, které sis sám vybral a vyměnil s kamarády! Celkem najdeš v Magicu téměř 10 000 různých karet. Do balíčku si můžeš dát karty, jaké chceš, a tak vybírej důsledně! Je jen na tobě, jakou strategii si zvolíš a jaké karty budeš mít při hře k dispozici. Každý hráč tak hraje s úplně jiným balíčkem, jinou strategii i jinou úroveň.</p>

<h2>Magic s tebou roste</h2>
<p>Když začínáš s Magicem, hraješ s jednoduchými kartami a základní strategie. Jak do hry ale pronikáš stále více a více, budou tě napadat další možnosti, budeš získávat další karty i zkušenosti od protihráčů i kamarádů. Nebude to trvat dlouho a budeš doma vymýšlet vlastní herní styly, kombinovat karty a překvapovat ostatní soupeře originálními kombinacemi a porážet je. Magic s tebou roste. Je to hra, u které se výborně baví 8letý kluk i 30letý táta od rodiny. Je to hra, kde se tihle dva mohu setkat u stolu a nad Magicem se společně výborně bavit.</p>
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (131,'Vítej ve světě Magic: The Gathering!','Vítej ve světě Magic: The Gathering! Magic je nejstarší a také nejúspěšnější sběratelskou karetní hrou na světě. Již od roku 1993 ovlivňuje tato hra životy milionů lidí po celém světě… a její obliba stále stoupá! V roce 2006 měl Magic přes 6 000 000 aktivních hráčů ze všech koutů planety! V České republice hraje tuto hru bezmála 20 000 hráčů a další přibývají doslova každým dnem. V čem je tato hra tak zajímavá? Jak to, že si i v dnešní době plné počítačů a videoher najdou mladí lidé chuť hrát s kamarády karty? Stovky nových kamarádů Magic není o tom sedět doma. Magic se hraje všude, tak proč někam nejít a nezahrát si s novými kamarády? Prostě vezmeš svůj balíček a najdeš soupeře v nejbližším klubu nebo ve škole. Každý má jiné karty i jiné zkušenosti, každá hra je tak jiná a zajímavá! Super zábava kdekoliv zrovna chceš K Magicu potřebuješ jen balíček karet, nic víc. Měj ho stále u sebe a můžeš si zahrát kdekoliv budeš chtít. Protihráči jsou všude, stačí se jen zeptat: „Hraješ Magic?“ Budeš překvapen, kolik lidí od tebe ze školy nebo klubu Magic hraje! Každá hra je jiná Magic, to je tvůj balíček, který sis sám sestavil. Karty, které sis sám vybral a vyměnil s kamarády! Celkem najdeš v Magicu téměř 10 000 různých karet. Do balíčku si můžeš dát karty, jaké chceš, a tak vybírej důsledně! Je jen na tobě, jakou strategii si zvolíš a jaké karty budeš mít při hře k dispozici. Každý hráč tak hraje s úplně jiným balíčkem, jinou strategii i jinou úroveň. Magic s tebou roste Když začínáš s Magicem, hraješ s jednoduchými kartami a základní strategie. Jak do hry ale pronikáš stále více a více, budou tě napadat další možnosti, budeš získávat další karty i zkušenosti od protihráčů i kamarádů. Nebude to trvat dlouho a budeš doma vymýšlet vlastní herní styly, kombinovat karty a překvapovat ostatní soupeře originálními kombinacemi a porážet je. Magic s tebou roste. Je to hra, u které se výborně baví 8letý kluk i 30letý táta od rodiny. Je to hra, kde se tihle dva mohu setkat u stolu a nad Magicem se společně výborně bavit.');

