INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (135,'deskove-hry/novinky-cge');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (135,'Novinky CGE — GameCon 2011','gamecon,2011','Novinky CGE');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (135,'kapacita 0/0<br />
<h1>Novinky CGE</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/novinky-cge.gif" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>organizátor</strong><br />Czech Games Edition<br />
  <strong>as akce</strong><br />akce na přání (viz níže)   <br />
 <strong>další akce organizátora</strong> <br /><div style = "text-align: left;"><a href = "/deskove-hry/galaxy-trucker">Galaxy Trucker</a></div>
</div>
</p>
   <p style = "clear: both;">
Přijď si zahrát nejnovější hry. Deskové hry tak nové, že ještě oficialně nespatřili světlo světa. Ano, můžes si zahrát prototyp hry, která teprve výjde. Czech Games Edition přiveze hned čtyři kousky:
<ul>
<li>Galaxy Trucker: Druhé rozšíření</li>
<li>Dungeon Petz</li>
<li>Dědictví</li>
<li>Pictomania</li>
Všechny hry je možné zahrát si v deskoherně v průběhu celého GameConu.
<br>
<strong>Galaxy Trucker: Druhé rozšíření</strong>
<br>
Stejně velké jako to předchozí. Nové
dílky, nové tvary lodí, zcela nové podpůrné týmy, které vám pomohou
při stavbě lodi. A k tomu ještě extra kolo hry navíc.
Ano můžete lítat i IV kolo a můžete si být jisti, že karty z tohoto
balíčku jsou extra šťavnaté. Hlavně vetřelci co vám vlezou na loď -
odpalují její části nebo žerou posádku, pokud se jim tedy někteří
hrdinně nepostaví na odpor. Počkat... to je jiná hra, ne? Nemluvíme
náhodou o Space Alertu? Vypadá to, že tento trend "obsaďme loď a
snězme její posádku" se šíří známým vesmírem pěkně rychle. Protože teď
se vám to může přihodit i s novým rozšířením do Galaxy Truckera!
</p>

<p><strong>Dungeon Petz</strong> (samostatná hra navazující na oblíbené Vládce Podzemí)
<br>
Staňte se vůdci impí rodinky, která začala podnikat v novém odvětví:
šlechtění a prodávání domácích mazlíčků. Zdá se vám to jednoduché a
bezpečné? Asi jsme zapomněli zmínit, že to jsou mazlíčci pro Vládce
podzemí. To znamená vypiplat tu magické, tu hravé a jindy agresivní
nestvůrky, které neustále vyžadují pozornost a když je zrovna chcete
ukázat kupcům, tak místo aby předvedli své kvality, jsou nastydlí a
pouze vylučují exkrementy. Ale jinak je to prý opravdu výdělečný
byznys!</p>
<p><strong>Dědictví</strong>
<br>
Zemřel vám strýček. Radujte se! Máte totiž šanci přijít k bohatství.
Se strýčkem jste se nikdy neviděli, pouze jste o něm slyšeli. V
idylické době druhé poloviny 19. století Viktoriánské Anglie patřil
mezi řadu podnikavců, kteří využili rozvoje a domohli se závratného
majetku.  Strýček se s nikým nestýkal jen podnikal a šetřil.  Na
smrtelném loži se ohlédl za svým životem a zjistil, že si ho vůbec
neužil, jen hamounil majetek. Proto se rozhodl, že svůj majetek odkáže
příbuznému, který je nejen schopný, ale umí si užít života a řádně
roztočit svoje peníze. V poslední vůli strýček stanovil, že po jeho
smrti všichni potomci dostanou určitou částku Liber. Kdo tuto částku
utratí jako první, získá celé dědictví.</p>

<p><strong>Pictomania</strong>
<br>
Víte jak vypadá veverka? A umíte ji nakreslit? Pokud ne tak tato hra
je přesně pro vás. Ono totiž stačí, aby jí ostatní poznali od jízdního
kola :)
Nová kreslící hra od Vlaadi Chvátila ve které na umění kreslit nezáleží.
</p> 
<p><ul>                                                         <!--<li>
        <a href = "/deskove-hry/prehled-deskovych-her-na-gc2010">Přehled turnajů v deskových hrách na GameConu 2010</a>      </li>-->
    </ul>
  </p>
  <div style = "width: 100%; float: left;">
    <div style = "width: 50%; text-align: left; float: left; padding-top: 20px; padding-bottom: 15px;">&laquo; <a href = "/deskove-hry/mtg-highlander">MtG: Highlander</a></div>    <div style = "width: 50%; text-align: right; float: right; padding-top: 20px; padding-bottom: 15px;"><a href = "/deskove-hry/osadnici-z-katanu">Osadníci z Katanu</a> &raquo;</div>  </div>
  
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (135,'Novinky CGE','kapacita 0/0 Novinky CGE organizátor Czech Games Edition as akce akce na přání (viz níže) další akce organizátora Galaxy Trucker Přijď si zahrát nejnovější hry. Deskové hry tak nové, že ještě oficialně nespatřili světlo světa. Ano, můžes si zahrát prototyp hry, která teprve výjde. Czech Games Edition přiveze hned čtyři kousky: Galaxy Trucker: Druhé rozšíření Dungeon Petz Dědictví Pictomania Všechny hry je možné zahrát si v deskoherně v průběhu celého GameConu. Galaxy Trucker: Druhé rozšíření Stejně velké jako to předchozí. Nové dílky, nové tvary lodí, zcela nové podpůrné týmy, které vám pomohou při stavbě lodi. A k tomu ještě extra kolo hry navíc. Ano můžete lítat i IV kolo a můžete si být jisti, že karty z tohoto balíčku jsou extra šťavnaté. Hlavně vetřelci co vám vlezou na loď - odpalují její části nebo žerou posádku, pokud se jim tedy někteří hrdinně nepostaví na odpor. Počkat... to je jiná hra, ne? Nemluvíme náhodou o Space Alertu? Vypadá to, že tento trend "obsaďme loď a snězme její posádku" se šíří známým vesmírem pěkně rychle. Protože teď se vám to může přihodit i s novým rozšířením do Galaxy Truckera! Dungeon Petz (samostatná hra navazující na oblíbené Vládce Podzemí) Staňte se vůdci impí rodinky, která začala podnikat v novém odvětví: šlechtění a prodávání domácích mazlíčků. Zdá se vám to jednoduché a bezpečné? Asi jsme zapomněli zmínit, že to jsou mazlíčci pro Vládce podzemí. To znamená vypiplat tu magické, tu hravé a jindy agresivní nestvůrky, které neustále vyžadují pozornost a když je zrovna chcete ukázat kupcům, tak místo aby předvedli své kvality, jsou nastydlí a pouze vylučují exkrementy. Ale jinak je to prý opravdu výdělečný byznys! Dědictví Zemřel vám strýček. Radujte se! Máte totiž šanci přijít k bohatství. Se strýčkem jste se nikdy neviděli, pouze jste o něm slyšeli. V idylické době druhé poloviny 19. století Viktoriánské Anglie patřil mezi řadu podnikavců, kteří využili rozvoje a domohli se závratného majetku. Strýček se s nikým nestýkal jen podnikal a šetřil. Na smrtelném loži se ohlédl za svým životem a zjistil, že si ho vůbec neužil, jen hamounil majetek. Proto se rozhodl, že svůj majetek odkáže příbuznému, který je nejen schopný, ale umí si užít života a řádně roztočit svoje peníze. V poslední vůli strýček stanovil, že po jeho smrti všichni potomci dostanou určitou částku Liber. Kdo tuto částku utratí jako první, získá celé dědictví. Pictomania Víte jak vypadá veverka? A umíte ji nakreslit? Pokud ne tak tato hra je přesně pro vás. Ono totiž stačí, aby jí ostatní poznali od jízdního kola :) Nová kreslící hra od Vlaadi Chvátila ve které na umění kreslit nezáleží. Přehled turnajů v deskových hrách na GameConu 2010 --> « MtG: Highlander Osadníci z Katanu »');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (136,'O deskových hrách na GameConu','o-deskovych-hrach-na-gc',39,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (136,'deskove-hry/o-deskovych-hrach-na-gc');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (136,'O deskových hrách na GameConu — GameCon 2011','gamecon,2011','O deskových hrách na GameConu');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (136,'<h1>O deskových hrách na GameConu</h1>
<p>
Máte odvahu postavit se šerifovi? Nebo bojovníkům v aréně? Či snad máte chuť spíše obhospodařovat plantáže, stavět vesnice a města, nebo třeba bojovat s nákazou hrozící vyhubit lidstvo? A co takhle vyrazit na obchodní cesty vesmírem nebo naopak do doby kamenné?
</p><p>
Jinak řečeno, na GameConu, festivalu veškerého hraní, nemůže chybět bohatá nabídka moderních deskových a jiných stolních her. Dávno pryč jsou ty doby kdy jste se mohli rozhodovat pouze, jestli si zahrajete Člověče, nezlob se!, Dostihy a sázky a nebo Monopoly. Na GameConu si v naší velké <a href = "/deskove-hry/deskoherna">deskoherně</a> můžete zahrát spousty svých oblíbených her a nebo, pokud máte chuť, můžete si vyzkoušet a naučit se jakoukoli novou hru.
</p><p>
Volné chvilky na GameConu tak můžete vyplnit krátkou hrou se svými přáteli a nebo se zúčastnit některého z turnajů v deskových hrách. Pravidla jsou obvykle jednoduchá a zkusit to může každý. Nemusíte z toho mít strach. Jde přece o zábavu.
</p>

    </div>
  </div>');
