INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (137,'Osadníci z Katanu','osadnici-z-katanu',39,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (137,'deskove-hry/osadnici-z-katanu');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (137,'Osadníci z Katanu — GameCon 2011','gamecon,2011','Osadníci z Katanu');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (137,'kapacita 7/30<br />
<h1>Osadníci z Katanu</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/osadnici-z-katanu.gif" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>organizátor</strong><br />Miloš Čeřovský<br />
  <strong>čas akce</strong><br />sobota 23.7 - 9:00 až 15:00  <br />
 <strong>další akce organizátora</strong> <br /><div style = "text-align: left;"><a href = "/deskove-hry/dominion">Dominion</a></div>
</div>
</p>
   <p style = \\"clear: both;\\">
Vylodil jsi se právě na neprobádaném ostrově a není čas otálet. Je třeba začít budovat vesnice a města, stavět cesty a hlavně poohlédnout se po potřebných surovinách. Háček je v tom, že jste se nevylodili sami a tak si musíte pospíšit, aby vám ostatní nevybrali všechna lukrativní místa na ostrově. Kdo nebuduje, ten upadá.
</p>
<p>
Ani letos nemůže na GameConu chybět turnaj v Osadnících z Katanu.
</p>
<p>
Pokud náhodou, Osadníky z Katanu neznáš, není to žádný problém. Osadníci jsou hra, kterou se ovládneš bez obtíží krátce před turnajem. Jednou, dvakrát si je vyzkoušíš a jsi připraven porazit své protivníky.
</p>
<p>
Osadníci z Katanu budou nejen vyhodnoceni jako samostatný turnaj na GameConu, ale jsou také kvalifikačním turnajem na Mistrovství ČR. V případě vítězství získáte tedy nejen věcné ceny, ale také body, které vám mohou pomoci zajistit účast na Mistrovství ČR, které se bude konat 16. října na Deskohraní v Praze.
</p>
<p>
Pokud ti pravidla přijdou moc technická, nedělej si z toho těžkou hlavu :-) Rozhodčí ti vše potřebné řeknou na místě a povedou tě. Ty se pak můžeš jen bavit a hrát si.
</p>
<p>Po skončení turnaje bude probíhat turnaj v Dominionu.</p>
<p><ul>              <!--<li>
        <a href = "/deskove-hry/prehled-deskovych-her-na-gc2010">Přehled turnajů v deskových hrách na GameConu 2010</a>      </li>-->
    </ul>
  </p>
  <div style = "width: 100%; float: left;">
    <div style = "width: 50%; text-align: left; float: left; padding-top: 20px; padding-bottom: 15px;">&laquo; <a href = "/deskove-hry/novinky-cge">Novinky CGE</a></div>    <div style = "width: 50%; text-align: right; float: right; padding-top: 20px; padding-bottom: 15px;"><a href = "/deskove-hry/proroctvi">Proroctví</a> &raquo;</div>  </div>
  
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (137,'Osadníci z Katanu','kapacita 7/30 Osadníci z Katanu organizátor Miloš Čeřovský čas akce sobota 23.7 - 9:00 až 15:00 další akce organizátora Dominion Vylodil jsi se právě na neprobádaném ostrově a není čas otálet. Je třeba začít budovat vesnice a města, stavět cesty a hlavně poohlédnout se po potřebných surovinách. Háček je v tom, že jste se nevylodili sami a tak si musíte pospíšit, aby vám ostatní nevybrali všechna lukrativní místa na ostrově. Kdo nebuduje, ten upadá. Ani letos nemůže na GameConu chybět turnaj v Osadnících z Katanu. Pokud náhodou, Osadníky z Katanu neznáš, není to žádný problém. Osadníci jsou hra, kterou se ovládneš bez obtíží krátce před turnajem. Jednou, dvakrát si je vyzkoušíš a jsi připraven porazit své protivníky. Osadníci z Katanu budou nejen vyhodnoceni jako samostatný turnaj na GameConu, ale jsou také kvalifikačním turnajem na Mistrovství ČR. V případě vítězství získáte tedy nejen věcné ceny, ale také body, které vám mohou pomoci zajistit účast na Mistrovství ČR, které se bude konat 16. října na Deskohraní v Praze. Pokud ti pravidla přijdou moc technická, nedělej si z toho těžkou hlavu :-) Rozhodčí ti vše potřebné řeknou na místě a povedou tě. Ty se pak můžeš jen bavit a hrát si. Po skončení turnaje bude probíhat turnaj v Dominionu. Přehled turnajů v deskových hrách na GameConu 2010 --> « Novinky CGE Proroctví »');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (138,'Představení Hry o Trůny LCG','predstaveni-hry-o-truny-lcg',39,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (138,'deskove-hry/predstaveni-hry-o-truny-lcg');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (138,'Představení Hry o Trůny LCG — GameCon 2011','gamecon,2011','Představení Hry o Trůny LCG');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (138,'<h1>Představení Hry o Trůny LCG</h1>
<p>
  <div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;">
    <img src = "/system_styly/side/hra-o-truny-lcg.gif" style = "float: left; "/ />
  </div>
</p>   
<p style = "clear: both;"><em>Mocný rod Targaryenů byl poražen… Nyní ve Westerosu vládnou Baratheoni, avšak i ostatní rody mají zájem o moc. Podaří se proradným Lannisterům zachvátit trůn svými pletichami? Čestný rod Starků sice po moci netouží, ale odplata vůči intrikám ostatních je jistá. Na západě se bouří Greyjoyové, vládci moří. Na jihu takticky vyčkávají jako hadi Martellové a za mořem na východě sbírá armádu poslední potomek rodu Targaryenů. Hra o Trůny právě začíná…</em></p>

<p>Karetní hra o Trůny, přesněji tedy živá karetní hra Hra o Trůny, v anglickém orginálu A Game of Thrones Live Card Game, je populární karetní hra založená na příběhu z knih George R. R. Martina z dílny Fantasy Flight Games. V České republice bohužel zatím její popularita nedosahuje ani zdaleka takové oblíbenosti jako v zahraničí, zejména
díky malé distribuci. V současnosti je v ČR jen jediný dodavatel, který má aktuální nabídku všech karet.</p>

<p>A Game of Thrones LCG se vyvinula z A Game of Thrones CCG, klasické karetní hry, v roce 2008. Tehdy se vývojáři rozhodli zkusit nový systém Living Card Game a začali právě s touto hrou. A Game of Thrones, která byla na trhu již od roku 2002 tak prodělala velkou změnu a místo klasické distribuce v boosterech (1 vzácná karta, 3 neobvyklé, a 7
normálních) se hra začala distribuovat v tzv. Chapter pacích – CP (20 různých karet – 10 po jedné kopii a 10 po 3 kopiích). Tato změna byla celkem násilně vynucena a kvůli různým dalším okolnostem (např. dočasné znemožnění hrát 2 rody – Greyjoy a Martell) měla za následek velký odliv hráčů.</p>
<p>A Game of Thrones LCG se ze začátku začala prezentovat jako „polodeskovka“ zaměřená na multiplayer, tedy hru více hráčů, oproti původní myšlence singleplayeru. I přesto, že multiplayer byl již v minulosti vítaným zpestřením, ono násilné tlačení na hráče nemělo dobrý vliv. V současnosti je už ale vše opět v normálu. FFG zjistilo, že i přes tyto změny se hra ujala a získala si řadu nových fanoušků i u nás. Jedním z velmi dobrých kroků FFG, díky velkému odběru karet a dobrým ziskům, byla změna distribuce, kdy od 5. cyklu CP jsou všechny karty v baleních již ve třech kopiích a tedy odpadá „nutnost“ kupovat si některé CP vícekrát kvůli potřebným kartám.</p>
<p>Nyní se lze tedy do hry připojit za velmi příznivé ceny a kompetitivní balík vhodný i na turnaj není problém postavit za dobrou cenu. Což hodnotím jako velký klad celé hry. Bohužel ty, kteří by si chtěli koupit již hotový balík jako např. v Magicu, musím zklamat – díky fixnímu prodeji karet se s ničím takovým asi nesetkáte. Kdo by se
ale také chtěl ochudit o deckbuilding, jednu z nejzábavnějších částí hry.</p>
<p><strong>Představení hry bude probíhat v pátek a sobotu dopoledne. Odpoledne bude možnost zúčastnit se turnaje.</strong></p>
<p><ul><li><a href="/deskove-hry/hra-o-truny-lcg">Hra o Trůny LCG</a></li></ul></p>
    </div>
  </div>');
