INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (141,'Republic of Rome','republic-of-rome',39,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (141,'deskove-hry/republic-of-rome');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (141,'Republic of Rome — GameCon 2011','gamecon,2011','Republic of Rome');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (141,'kapacita 6/6<br />
<h1>Republic of Rome</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/republic-of-rome.gif" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>organizátor</strong><br />Klub deskových her Paluba<br />
  <strong>čas akce</strong><br />pátek 22.7 - 19:00 až 24:00  <br />
 <strong>další akce organizátora</strong> <br /><div style = "text-align: left;"><a href = "/deskove-hry/hra-o-truny">Hra o trůny</a>, <a href = "/deskove-hry/battlestar-galactica">Battlestar Galactica</a>, <a href = "/deskove-hry/arkham-horror">Arkham Horror</a>, <a href = "/deskove-hry/valka-o-prsten">Válka o Prsten</a></div>
</div>
</p>
   <p style = "clear: both;">
Řím je ohrožován punskou válkou, lidé jsou nespokojení a státní kasa
zeje prázdnotou ! Dokáží senátoři vymyslet řešení všech problémů, nebo
se budou v senátu jen hádat, navzájem se obviňovat a hrabat si do
vlastní kapsy ?</p><p>
Přijď nám to v roli jednoho z nich ukázat ty !
</p>
<p>Hraní je součástí programu EPIC hraní, určena je tedy hlavně hráčům, kteří se hrou nemají žádné zkušenosti. Nicméně díky její složitosti je potřeba se na hru  předem připravit - viz dále.</p>
<p>Republic of Rome je hra na politické téma ve starověkém Římě až pro 6 hráčů. Hráč se
stává vůdcem jedné z frakcí (politických stran), které v senátu
soupeří o moc, ale zároveň musí spolupracovat, protože jejich
společným zájmem je blaho a prosperita římské republiky. Hra je vhodná
zejména pro hráče, kteří mají rádi hraní rolí.</p>
<p>
Protože je hra poměrně složitá, předpokládá se aspoň minimální přehled o tom, co se ve hře děje. Pokud o hře nic nevíš a přesto si ji chceš zahrát, tak se přihlaš na hraní a my ti pošleme na tvůj email "krátké" povídání (3 stránky), které pro získání počátečního přehledu stačí.</p>
<p>Hra je kompletně v anglickém jazyce.
</p>                  <!--<li>
        <a href = "/deskove-hry/prehled-deskovych-her-na-gc2010">Přehled turnajů v deskových hrách na GameConu 2010</a>      </li>-->
    </ul>
  </p>
  <div style = "width: 100%; float: left;">
    <div style = "width: 50%; text-align: left; float: left; padding-top: 20px; padding-bottom: 15px;">&laquo; <a href = "/deskove-hry/proroctvi">Proroctví</a></div>    <div style = "width: 50%; text-align: right; float: right; padding-top: 20px; padding-bottom: 15px;"><a href = "/deskove-hry/texas-holdem">Texas Hold\'em</a> &raquo;</div>  </div>
  
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (141,'Republic of Rome','kapacita 6/6 Republic of Rome organizátor Klub deskových her Paluba čas akce pátek 22.7 - 19:00 až 24:00 další akce organizátora Hra o trůny , Battlestar Galactica , Arkham Horror , Válka o Prsten Řím je ohrožován punskou válkou, lidé jsou nespokojení a státní kasa zeje prázdnotou ! Dokáží senátoři vymyslet řešení všech problémů, nebo se budou v senátu jen hádat, navzájem se obviňovat a hrabat si do vlastní kapsy ? Přijď nám to v roli jednoho z nich ukázat ty ! Hraní je součástí programu EPIC hraní, určena je tedy hlavně hráčům, kteří se hrou nemají žádné zkušenosti. Nicméně díky její složitosti je potřeba se na hru předem připravit - viz dále. Republic of Rome je hra na politické téma ve starověkém Římě až pro 6 hráčů. Hráč se stává vůdcem jedné z frakcí (politických stran), které v senátu soupeří o moc, ale zároveň musí spolupracovat, protože jejich společným zájmem je blaho a prosperita římské republiky. Hra je vhodná zejména pro hráče, kteří mají rádi hraní rolí. Protože je hra poměrně složitá, předpokládá se aspoň minimální přehled o tom, co se ve hře děje. Pokud o hře nic nevíš a přesto si ji chceš zahrát, tak se přihlaš na hraní a my ti pošleme na tvůj email "krátké" povídání (3 stránky), které pro získání počátečního přehledu stačí. Hra je kompletně v anglickém jazyce. Přehled turnajů v deskových hrách na GameConu 2010 --> « Proroctví Texas Hold\'em »');

