INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (142,'kapacita 0/6<br />
<h1>Starcraft</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/starcraft.gif" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>organizátor</strong><br />Klub deskových her Paluba<br />
  <strong>čas akce</strong><br /> prozatím není k dispozici<br />
 <strong>další akce organizátora</strong> <br /><div style = "text-align: left;"><a href = "/deskove-hry/hra-o-truny">Hra o trůny</a>, <a href = "/deskove-hry/battlestar-galactica">Battlestar Galactica</a>, <a href = "/deskove-hry/arkham-horror">Arkham Horror</a>, <a href = "/deskove-hry/valka-o-prsten">Válka o Prsten</a>, <a href = "/deskove-hry/republic-of-rome">Republic of Rome</a></div>
</div>
</p>
   <p style = "clear: both;">
Starcraft, tak jak ho znáte z monitorů.
</p>
<p>
Součást EPIc hraní.
</p>
