INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (144,'kapacita 16/30<br />
<h1>Time´s Up!</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/times-up.gif" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>organizátor</strong><br />MindOK<br />
  <strong>čas akce</strong><br />pátek 22.7 - 23:00 až 24:00  <br />
 <strong>další akce organizátora</strong> <br /><div style = "text-align: left;"><a href = "/deskove-hry/carcassonne">Carcassonne</a>, <a href = "/deskove-hry/duch">Duch!</a>, <a href = "/deskove-hry/vladci-podzemi">Vládci podzemí</a>, <a href = "/deskove-hry/kaleidoskop">Kaleidoskop</a></div>
</div>
</p>
   <p style = "clear: both;">
Zelený plešoun? To je přece Rákosníček. Slavík? Kája Gott.<p>
Takovátlustá, slavná herečka... Hraje ve slunce, seno... Aaano!
Jiřina Jirásková! Ne, ta přece není tlustá, tak vem dalši. Ale
rychle!<p>
</p>
Už jsi po celem dnu znavený, ale nechce se ti ještě spát, ale ani hrát
nic seriozního? Time\'s up! Vem kamaráda a přijďte se večer pobavit.
Třeba vám to půjde nejlíp ze všech a dokonce iněco vyhrajete.</p>

<ul>
<li>Popisujte nebo předvádějte pantomimou různé známé osobnosti a
postavy -  Od Leonarda da Vinci a Alberta Einsteina, přes Jamese Bonda
až po Včelku
Máju..</li>
<li> Aktivní společenská hra pro aktivní společenské lidi.</li>
<li>Legendární party hra oblíbená na celém světě.</li>
<li>Jasná volba pro všechny fanoušky hry Activity.</li>
</p>
<p>Noční party turnaj pro dvojice - buď přijdte rovnou dva, nebo se
dáte dohromady až na místě.</p>
Turnaj začne kolem 23:00 (po skončení Carcassonne) a bude trvat asi 2
hodiny.
<p>                        <!--<li>
        <a href = "/deskove-hry/prehled-deskovych-her-na-gc2010">Přehled turnajů v deskových hrách na GameConu 2010</a>      </li>-->
    </ul>
  </p>
  <div style = "width: 100%; float: left;">
    <div style = "width: 50%; text-align: left; float: left; padding-top: 20px; padding-bottom: 15px;">&laquo; <a href = "/deskove-hry/texas-holdem">Texas Hold\'em</a></div>    <div style = "width: 50%; text-align: right; float: right; padding-top: 20px; padding-bottom: 15px;"><a href = "/deskove-hry/ubongo">Ubongo</a> &raquo;</div>  </div>
  
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (144,'Time´s Up!','kapacita 16/30 Time´s Up! organizátor MindOK čas akce pátek 22.7 - 23:00 až 24:00 další akce organizátora Carcassonne , Duch! , Vládci podzemí , Kaleidoskop Zelený plešoun? To je přece Rákosníček. Slavík? Kája Gott. Takovátlustá, slavná herečka... Hraje ve slunce, seno... Aaano! Jiřina Jirásková! Ne, ta přece není tlustá, tak vem dalši. Ale rychle! Už jsi po celem dnu znavený, ale nechce se ti ještě spát, ale ani hrát nic seriozního? Time\'s up! Vem kamaráda a přijďte se večer pobavit. Třeba vám to půjde nejlíp ze všech a dokonce iněco vyhrajete. Popisujte nebo předvádějte pantomimou různé známé osobnosti a postavy - Od Leonarda da Vinci a Alberta Einsteina, přes Jamese Bonda až po Včelku Máju.. Aktivní společenská hra pro aktivní společenské lidi. Legendární party hra oblíbená na celém světě. Jasná volba pro všechny fanoušky hry Activity. Noční party turnaj pro dvojice - buď přijdte rovnou dva, nebo se dáte dohromady až na místě. Turnaj začne kolem 23:00 (po skončení Carcassonne) a bude trvat asi 2 hodiny. Přehled turnajů v deskových hrách na GameConu 2010 --> « Texas Hold\'em Ubongo »');

