INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (145,'kapacita 4/30<br />
<h1>Ubongo</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/ubongo.gif" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>organizátor</strong><br />Albi<br />
  <strong>čas akce</strong><br />sobota 23.7 - 10:00 až 12:00  <br />
 <strong>další akce organizátora</strong> <br /><div style = "text-align: left;"><a href = "/deskove-hry/texas-holdem">Texas Hold\'em</a>, <a href = "/deskove-hry/bang-">Bang! </a></div>
</div>
</p>
   <p style = "clear: both;">
Stanete se objeviteli a přenesete se do světa šamanů, džungle a tajemných pokladů. Rychlé vyřešení záhadných hlavolamů vede k nalezení cesty k ukrytým diamantům.
</p>
<p>
Ubongo je jednoduchá desková hra, kterou se naučíte za pár minut přimo v deskoherně.</p>
Hráči se snaží sestavit skládačku z barevných dílků, posunout svou figurku na hrací desce a vzít si drahokamy. To vše musí stihnout dříve, než se přesypou hodiny. Vítězí hráč s největším počtem kamenů jedné barvy. 
</p>
Pravidla turnaje budou upřesněna před začátkem turnaje podle počtu hráčů.
<p>    <ul>          <!--<li>
        <a href = "/deskove-hry/prehled-deskovych-her-na-gc2010">Přehled turnajů v deskových hrách na GameConu 2010</a>      </li>-->
    </ul>
  </p>
  <div style = "width: 100%; float: left;">
    <div style = "width: 50%; text-align: left; float: left; padding-top: 20px; padding-bottom: 15px;">&laquo; <a href = "/deskove-hry/times-up">Time´s Up!</a></div>    <div style = "width: 50%; text-align: right; float: right; padding-top: 20px; padding-bottom: 15px;"><a href = "/deskove-hry/valka-o-prsten">Válka o Prsten</a> &raquo;</div>  </div>
  
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (145,'Ubongo','kapacita 4/30 Ubongo organizátor Albi čas akce sobota 23.7 - 10:00 až 12:00 další akce organizátora Texas Hold\'em , Bang! Stanete se objeviteli a přenesete se do světa šamanů, džungle a tajemných pokladů. Rychlé vyřešení záhadných hlavolamů vede k nalezení cesty k ukrytým diamantům. Ubongo je jednoduchá desková hra, kterou se naučíte za pár minut přimo v deskoherně. Hráči se snaží sestavit skládačku z barevných dílků, posunout svou figurku na hrací desce a vzít si drahokamy. To vše musí stihnout dříve, než se přesypou hodiny. Vítězí hráč s největším počtem kamenů jedné barvy. Pravidla turnaje budou upřesněna před začátkem turnaje podle počtu hráčů. Přehled turnajů v deskových hrách na GameConu 2010 --> « Time´s Up! Válka o Prsten »');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (146,'Válka o Prsten','valka-o-prsten',39,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (146,'deskove-hry/valka-o-prsten');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (146,'Válka o Prsten — GameCon 2011','gamecon,2011','Válka o Prsten');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (146,'kapacita 1/4<br />
<h1>Válka o Prsten</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/valka-o-prsten.gif" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>organizátor</strong><br />Klub deskových her Paluba<br />
  <strong>čas akce</strong><br /> prozatím není k dispozici<br />
 <strong>další akce organizátora</strong> <br /><div style = "text-align: left;"><a href = "/deskove-hry/hra-o-truny">Hra o trůny</a>, <a href = "/deskove-hry/battlestar-galactica">Battlestar Galactica</a>, <a href = "/deskove-hry/arkham-horror">Arkham Horror</a>, <a href = "/deskove-hry/republic-of-rome">Republic of Rome</a></div>
</div>
</p>
   <p style = "clear: both;">
<em>Společenstvo vyráží z Roklinky. V železném pásu Saruman povolává další vrky. Dain II., železná noha právě přivedl další trpaslíky do Ered Luin. Moudrý Elrond dává poslední rady. Umbarští korzáři brousí své šavle. Faramir se dosuď neobjevil, Denethor šílí. Enti čekají.<p></p>
Válka o Prsten právě začíná!
<p></p>
Chceš putovat se společenstvem nebo raději budeš velet skřetím armádám pod vedením nazgulů? Gondor nebo Rohan - kdo vydrží déle nápor temonty? Vrátí se Gandalf včas? Dáváš přednost rychlému útoku nebo raději bys Osgiliath obešel? A jak dopadne bitva v Helmově žlebu?<br>
Vyber si stranu a rozhodni o osudu Středozemě!</em>
</p><p>
Hraní je součastní programu EPIC hraní - určena je tedy hlavně hráčům, kteří se hrou nemají žádné zkušenosti.</p>
<p>
Válka o prsten je strategická válečná hra pro 2-4 hráče, z prostřední slavné Tolkienovi středozemě. Dva hráči hrají za světlou stranu a snaží se unikout Saurově moci a vhodit Jeden prsten do Hory osudu. Naopak dva hráči se postaví do čela Sauronových a Sarumanových armád a snaží se podrobit si národy Středozemě.<br>
Hra je od začátku do konce nevyrovnaná, aspoň se to tak zdá - temných nepřátel je téměř nekonečně, zatímco hrdinové západu postupně umírají. Každá ze stran má však jiné vítězné podmínky. Ale vítězství nebude snadné.
</p><p>
Hra je kompletně v angličtině.</p>
<em>Pozn.: Kdo si chce užít epické stavění figurek na herní plán, něcht se dostaví na místo konaní 30 minut předem.:) Znalců zeměpisu Středozěmě stačí 20 minut před zahájení hraní.</em>                  <!--<li>
        <a href = "/deskove-hry/prehled-deskovych-her-na-gc2010">Přehled turnajů v deskových hrách na GameConu 2010</a>      </li>-->
    </ul>
  </p>
  <div style = "width: 100%; float: left;">
    <div style = "width: 50%; text-align: left; float: left; padding-top: 20px; padding-bottom: 15px;">&laquo; <a href = "/deskove-hry/ubongo">Ubongo</a></div>    <div style = "width: 50%; text-align: right; float: right; padding-top: 20px; padding-bottom: 15px;"><a href = "/deskove-hry/vladci-podzemi">Vládci podzemí</a> &raquo;</div>  </div>
  
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (146,'Válka o Prsten','kapacita 1/4 Válka o Prsten organizátor Klub deskových her Paluba čas akce prozatím není k dispozici další akce organizátora Hra o trůny , Battlestar Galactica , Arkham Horror , Republic of Rome Společenstvo vyráží z Roklinky. V železném pásu Saruman povolává další vrky. Dain II., železná noha právě přivedl další trpaslíky do Ered Luin. Moudrý Elrond dává poslední rady. Umbarští korzáři brousí své šavle. Faramir se dosuď neobjevil, Denethor šílí. Enti čekají. Válka o Prsten právě začíná! Chceš putovat se společenstvem nebo raději budeš velet skřetím armádám pod vedením nazgulů? Gondor nebo Rohan - kdo vydrží déle nápor temonty? Vrátí se Gandalf včas? Dáváš přednost rychlému útoku nebo raději bys Osgiliath obešel? A jak dopadne bitva v Helmově žlebu? Vyber si stranu a rozhodni o osudu Středozemě! Hraní je součastní programu EPIC hraní - určena je tedy hlavně hráčům, kteří se hrou nemají žádné zkušenosti. Válka o prsten je strategická válečná hra pro 2-4 hráče, z prostřední slavné Tolkienovi středozemě. Dva hráči hrají za světlou stranu a snaží se unikout Saurově moci a vhodit Jeden prsten do Hory osudu. Naopak dva hráči se postaví do čela Sauronových a Sarumanových armád a snaží se podrobit si národy Středozemě. Hra je od začátku do konce nevyrovnaná, aspoň se to tak zdá - temných nepřátel je téměř nekonečně, zatímco hrdinové západu postupně umírají. Každá ze stran má však jiné vítězné podmínky. Ale vítězství nebude snadné. Hra je kompletně v angličtině. Pozn.: Kdo si chce užít epické stavění figurek na herní plán, něcht se dostaví na místo konaní 30 minut předem.:) Znalců zeměpisu Středozěmě stačí 20 minut před zahájení hraní. Přehled turnajů v deskových hrách na GameConu 2010 --> « Ubongo Vládci podzemí »');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (147,'Vládci podzemí','vladci-podzemi',39,0,0);
