INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (147,'Vládci podzemí — GameCon 2011','gamecon,2011','Vládci podzemí');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (147,'kapacita 8/30<br />
<h1>Vládci podzemí</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/vladci-podzemi.gif" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>organizátor</strong><br />MindOK<br />
  <strong>čas akce</strong><br />sobota 23.7 - 13:00 až 19:00  <br />
 <strong>další akce organizátora</strong> <br /><div style = "text-align: left;"><a href = "/deskove-hry/carcassonne">Carcassonne</a>, <a href = "/deskove-hry/duch">Duch!</a>, <a href = "/deskove-hry/times-up">Time´s Up!</a>, <a href = "/deskove-hry/kaleidoskop">Kaleidoskop</a></div>
</div>
</p>
   <p style = "clear: both;"> Pohled dobrodruhův již znáte. Co takhle druhá strana mince?</p>
<p>Vydali jste se někdy s družinou dobrodruhů do podzemních chodeb dobývat slávu, zkušenosti a získat nějaký ten poklad? Určitě ano.</p>
<p>A zamysleli jste se někdy nad tím, jak složité je takové podzemí plné chodeb a nestvůr vybudovat a provozovat? Ne? Tak nyní si to budete moci zkusit.</p>
<p>Vžijte se do role vládce podzemí, svolejte své služebníčky, vybudujte síť chodeb a místností, nastražte v nich pasti, najměte nestvůry, a zkuste zabránit chamtivým hrdinům, aby vám vaše dílo poničili a vyrabovali. Uvidíte, že se od nynějška budete na temná zákoutí různých doupat a jejich obyvatele dívat úplně jiným pohledem!</p>
<p>Navíc při turnaji ve Vládcích podzemí se možná budete moci potkat s jejich autorem Vlaadou Chvátilem a kluky z Czech Games Edition.</p>
<p>Základní informace k pravidlům:
<ul>
<li>pravidla vás naučíme předem v herně</li>
<li>hrát budou 3 nebo 4 hráči u stolu</li>
<li>cca 120 minut na hru, budou se hrát 2 hry</li>                          <!--<li>
        <a href = "/deskove-hry/prehled-deskovych-her-na-gc2010">Přehled turnajů v deskových hrách na GameConu 2010</a>      </li>-->
    </ul>
  </p>
  <div style = "width: 100%; float: left;">
    <div style = "width: 50%; text-align: left; float: left; padding-top: 20px; padding-bottom: 15px;">&laquo; <a href = "/deskove-hry/valka-o-prsten">Válka o Prsten</a></div>      </div>
  
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (147,'Vládci podzemí','kapacita 8/30 Vládci podzemí organizátor MindOK čas akce sobota 23.7 - 13:00 až 19:00 další akce organizátora Carcassonne , Duch! , Time´s Up! , Kaleidoskop Pohled dobrodruhův již znáte. Co takhle druhá strana mince? Vydali jste se někdy s družinou dobrodruhů do podzemních chodeb dobývat slávu, zkušenosti a získat nějaký ten poklad? Určitě ano. A zamysleli jste se někdy nad tím, jak složité je takové podzemí plné chodeb a nestvůr vybudovat a provozovat? Ne? Tak nyní si to budete moci zkusit. Vžijte se do role vládce podzemí, svolejte své služebníčky, vybudujte síť chodeb a místností, nastražte v nich pasti, najměte nestvůry, a zkuste zabránit chamtivým hrdinům, aby vám vaše dílo poničili a vyrabovali. Uvidíte, že se od nynějška budete na temná zákoutí různých doupat a jejich obyvatele dívat úplně jiným pohledem! Navíc při turnaji ve Vládcích podzemí se možná budete moci potkat s jejich autorem Vlaadou Chvátilem a kluky z Czech Games Edition. Základní informace k pravidlům: pravidla vás naučíme předem v herně hrát budou 3 nebo 4 hráči u stolu cca 120 minut na hru, budou se hrát 2 hry Přehled turnajů v deskových hrách na GameConu 2010 --> « Válka o Prsten');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (148,'Archiv dílny 2008','archiv-dilny-2008',43,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (148,'dilny/archiv-dilny-2008');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (148,'Archiv dílny 2008 — GameCon 2011','gamecon,2011','Archiv dílny 2008');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (148,'<h1>Archiv dílny 2008</h1>
<div class="akce-archiv">
<div>Zajímá vás, jak hrát vaši postavu, aby byla pro ostatní zajímavější, měla svůj vlastní osud a život? Chcete se dozvědět, co udělat pro to, abyste opustili stereotypy, které vás svazují při vymýšlení postav? Jak vdechnout charakteru jiskru nejen na papír, ale i při hraní? Máte chuť posunout své hry k hrám více prožitkovým a atmosférickým? Na tyto odpovědi vám můžou odpovědět dílny, které jsme pro vás připravili.</div>
<div>Dílny nejsou přednáškou, ale skupinovou činností, při níž bude prostor především pro experimenty a praktické vyzkoušení toho, co se dozvíte teoreticky. Na dílnách jste to především vy, kdo se aktivně podílí a prohlubuje vlastní dovednosti a vědomosti. Letos jsme pro vás připravili následující dílny:</div>
</div>

<a name="soucast_pribehu"></a>
<h2>Být součástí příběhu aneb Divadelní vypravěčské techniky pro hráče i vypravěče - Ondřej &quot;Grob&quot; Netík</h2>
<div class="akce-archiv">
<div>Dílna je praktickou ukázkou i ochutnávkou toho, jak velký rozdíl může být mezi hraním u stolu a divadelním pojetím vypravěčské hry. A to nejen pro vypravěče, ale hlavně hráče. Prakticky ukážu techniky a metody, které vám v tomto pomůžou. Stejně jako i mnohé nástroje, o kterých teoreticky přednáším v &quot;Nástrojích, srdci a duši příběhu&quot; Několik z vás tak vtáhnu na pár desítek minut do &quot;Sanatoria podvržených&quot; &ndash; světa, který jsem vydal knižně v &quot;Zeleném skřítkovi&quot; a &quot;Meluzíně&quot;.</div>
</div>

<a name="tvurci_psani"></a>
<h2>Dílna tvůrčího psaní aneb Jak zpracovat všední zážitek do dramatického příběhu - Jana &quot;Lorelei&quot; Jevická</h2>
<div class="akce-archiv">
<div>Dílna je určena nejen pro zájemce o tvůrčí psaní, ale také pro vypravěče, kteří chtějí hledat inspiraci pro své příběhy v každodenním životě. V několika krocích si budete moci vyzkoušet práci se všedním každodenním zážitkem tak, aby z něj mohl vzniknout dramatický příběh.</div>
</div>

<a name="budovani_pribehu"></a>
<h2>Příprava před hrou a budování příběhu - Matouš &quot;Erric&quot; Ježek</h2>

<div class="akce-archiv">
<div>Je pro vás příběh ve hře opravdu důležitý, potřebujete, aby se něco dělo a aby do toho pěkně zapadaly vaše postavy? Přijďte na dílnu, kde se budeme zabývat výběrem vhodného settingu, přípravou pozadí rozvíjením příběhů postav a následným spojením v komplexní herní přípravu. Protože příběh není jen záležitostí vypravěče, mohou se účastnit i hráči, protože i oni mají svůj podíl na příběhu.</div>
</div>

<a name="rozvoj_hrace"></a>
<h2>Rozvoj hráče v rolových hrách - Jana &quot;Lorelei&quot; Jevická</h2>
<div class="akce-archiv">
<div>Jak zlepšovat svoji hru v roli? Jak bojovat proti stereotypům v projevu? Jak si pomoci, abych nevypadával z role? A co vám hraní v roli může dát? Také si kladete tyto otázky při hraní larpů? Pokud ano, chtěla bych vás pozvat na moji dílnu. Přijďte si vyzkoušet nové cesty ke ztvárnění charakteru a načerpat inspiraci pro zajímavé hraní postavy, které vaše spoluhráče nadchne.</div>
<div>Dílna vyžaduje aktivní zapojení všech účastníků, doporučujeme pohodlné oblečení, ve kterém se budete moci hýbat.</div>
</div>

<a name="tvorba_postavy"></a>
<h2>Tvorba postavy - Matouš &quot;Erric&quot; Ježek</h2>
<div class="akce-archiv">
<div>Pojďme se na chvíli zastavit a začít s přístupem k postavám úplně od začátku. Pojďme se zabývat tvorbou postav pro hru, kde podstatný je příběh, kde na postavách opravdu záleží, kde je to jejich příběh. Opravdu jsou nutné rozsáhlé historie? Opravdu je potřeba mít přesně vykreslen charakter postavy? Myslím, že nikoliv.</div>
<div>V průběhu této dílny si sami vytvoříte postavu, která má potenciál zažít svůj vlastní pořádný příběh.</div>
</div>

<a name="zdroje_inspirace"></a>
<h2>Zdroje tvůrčí inspirace pro tvorbu role - Jana &quot;Lorelei&quot; Jevická</h2>
<div class="akce-archiv">
<div>V této dílně se pokusíme společně shrnout možné zdroje inspirace pro tvorbu příběhu a postav. Pokud chcete ozvláštnit vaši hru originálním způsobem tvorby postav s hráči, přijďte se inspirovat.</div>
<div>Dílna je vhodná spíše pro vypravěče než pro hráče. Metody budou vybrané z technik tvůrčího psaní, improvizace, relaxačních technik a herecké tvorby.</div>
</div>
    </div>
  </div>');
