INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (149,'O dílnách na GameConu','o-dilnach-na-gc',43,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (149,'dilny/o-dilnach-na-gc');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (149,'O dílnách na GameConu — GameCon 2011','gamecon,2011','O dílnách na GameConu');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (149,'<h1>O dílnách na GameConu</h1>
<p>
Zatímco na přednáškách se o hrách budete dozvídat, v dílnách si přímo prakticky své poznatky vyzkoušíte.
</p><p>
Nabyté dovednosti se vám budou hodit nejen ke hraní RPG her. Sami budete zkoušet tvořit, případně spolupracovat s ostatními a určitě si užijete spoustu legrace. Pokud máte nějaké dotazy k tématu, trápí vás při hraní nějaký problém, či máte jen nápad, který chcete rozebrat s ostatními, stačí si vybrat tu správnou dílnu.   
</p><p>
Dílny pomáhají návštěvníkům Gameconu se zvládnutím vyprávění, s hraním rolí postav, nebo samotné přípravě hry, ať už je to RPG nebo larp.
</p>
<p>
Jaké dílny byly na GameConu 2008, najdete v <a href = "/dilny/archiv-dilny-2008">archivu dílen</a>.
</p>
</p><p>
Chcete se s návštěvníky podělit o vaše zkušenosti a připravit pro ně tematickou dílnu? Pošlete nám koncept dílny a napište něco o sobě na <a href = \\"mailto:info@gamecon.cz\\">info@gamecon.cz</a>.
</p>

<ul> 
 <li> 
  <a href = "/prednasky/seznam-prednasek-na-gc2009">Minulý rok byly dílny zařazeny mezi přednášky. Podívejte se, co se minulý rok konalo.</a> 
 </li> 
</ul>
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (149,'O dílnách na GameConu','O dílnách na GameConu Zatímco na přednáškách se o hrách budete dozvídat, v dílnách si přímo prakticky své poznatky vyzkoušíte. Nabyté dovednosti se vám budou hodit nejen ke hraní RPG her. Sami budete zkoušet tvořit, případně spolupracovat s ostatními a určitě si užijete spoustu legrace. Pokud máte nějaké dotazy k tématu, trápí vás při hraní nějaký problém, či máte jen nápad, který chcete rozebrat s ostatními, stačí si vybrat tu správnou dílnu. Dílny pomáhají návštěvníkům Gameconu se zvládnutím vyprávění, s hraním rolí postav, nebo samotné přípravě hry, ať už je to RPG nebo larp. Jaké dílny byly na GameConu 2008, najdete v archivu dílen . Chcete se s návštěvníky podělit o vaše zkušenosti a připravit pro ně tematickou dílnu? Pošlete nám koncept dílny a napište něco o sobě na info@gamecon.cz . Minulý rok byly dílny zařazeny mezi přednášky. Podívejte se, co se minulý rok konalo.');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (150,'Vypravěčská dílna','vypravecska-dilna',43,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (150,'dilny/vypravecska-dilna');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (150,'Vypravěčská dílna — GameCon 2011','gamecon,2011','Vypravěčská dílna');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (150,'kapacita 8/10<br />kapacita 4/10<br />
<h1>Vypravěčská dílna</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/vypravecska-dilna.gif" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>vypravěč</strong><br />Ondřej Netík<br />
  <strong>čas akce</strong><br />pátek 22.7 - 14:00 až 18:00  <br />sobota 23.7 - 8:00 až 12:00  <br />
 <strong>další akce organizátora</strong> <br /><div style = "text-align: left;"><a href = "/rpg/rpg-a-svet-ondreje-netika">RPG a svět Ondřeje Netíka</a></div>
</div>
</p>
   <p style = "clear: both;">
Pro začátečníky i pokročilé otevírá autor několika knih a vypravěč s 20letou zkušeností s RPG dílnu vypravěčství, kde vám ukáže jednoduché a přitom účinné metody, které vám usnadní vaší vypravěčskou tvorbu.
</p>
<p>
Čeká vás intenzivní a praktická zkušenost. Počet aktivních účastníků dílny je omezen a bude nabírán před začátkem dle příchodu. Ostatní se mohou zúčastnit jako posluchači.
</p>
<p>
              <!--<li>
        <a href = "/rpg/seznam-rpg-na-gc2010">Přehled všech RPG na GameConu 2010</a>      </li>-->
    </ul>
  </p>
  <div style = "width: 100%; float: left;">
    <div style = "width: 50%; text-align: left; float: left; padding-top: 20px; padding-bottom: 15px;">&laquo; <a href = "/rpg/volna-hra">Volná hra</a></div>    <div style = "width: 50%; text-align: right; float: right; padding-top: 20px; padding-bottom: 15px;"><a href = "/rpg/wargames">Wargames</a> &raquo;</div>  </div>
  
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (150,'Vypravěčská dílna','kapacita 8/10 kapacita 4/10 Vypravěčská dílna vypravěč Ondřej Netík čas akce pátek 22.7 - 14:00 až 18:00 sobota 23.7 - 8:00 až 12:00 další akce organizátora RPG a svět Ondřeje Netíka Pro začátečníky i pokročilé otevírá autor několika knih a vypravěč s 20letou zkušeností s RPG dílnu vypravěčství, kde vám ukáže jednoduché a přitom účinné metody, které vám usnadní vaší vypravěčskou tvorbu. Čeká vás intenzivní a praktická zkušenost. Počet aktivních účastníků dílny je omezen a bude nabírán před začátkem dle příchodu. Ostatní se mohou zúčastnit jako posluchači. Přehled všech RPG na GameConu 2010 --> « Volná hra Wargames »');

