INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (161,'GameCon Trojboj – Akční hra','akcni-hra',45,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (161,'gamecon-trojboj/akcni-hra');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (161,'GameCon Trojboj – Akční hra — GameCon 2011','gamecon,2011','GameCon Trojboj – Akční hra');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (161,'<h1>GameCon Trojboj – Akční hra </h1>
<p>
  <div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;">
    <img src = "/system_styly/side/akcni-hra2011.gif" style = "float: left; "/ />
  </div>
  <!--<div style = "padding-bottom: 20px; width: 280px; float: left;"> <strong>organizátor</strong><br />Milan "Errikson" Tomeš, Tomáš "Žako" Jakoubek<br />  <strong>čas akce</strong><br />pátek 16.7 - 14:00 až 18:00<br />sobota 17.7 - 14:00 až 18:00<br />
  </div>-->
</p>   

<p style = "clear: both;"></p>

<h2>Po stopách argonautů</h2>
<p><em>Kdo z nás by neznal Jásona a jeho argonauty Herkula, Orfea, Thésea a další? Tolik bájí, pověstí a příběhů je napsáno o jejich slavných činech, místech, která navštívili, a nebezpečenstvích, kterými během své cesty za Zlatým rounem prošli.</em></p>
<p>Ale je to vůbec pravda? Dá se všem pověstem věřit? Co když si Jáson jenom najal posádky lodí a ty jeho jménem podnikaly tyto krušné cesty za bohatstvím a slávou. Naše letošní akční hra je právě o nich.</p>

<p>Vaše skupina se stane posádkou jedné takové lodi. Bude se snažit navštívit co nejvíce ostrovů, splnit maximum úkolů a získat tak co nejvíce pokladů. Ale pozor nebude to jenom klidná projížďka po moři, budou zde čekat i nástrahy v podobě bájných tvorů, které potkával i Jáson, ať už to byla Medůza, Minotaur, Hydra a dalších.</p>

<p>Kromě nepřátelsky naladěných bájných tvorů jsou na moři i další posádky plavící se za stejným cílem. Rozhodně se od nich nedá čekat, že vám cestu za poklady usnadní a že vám část svého úspěchu přenechají a proto se vám budou snažit znepříjemňovat život. Nebojte se jim to oplácet stejnou mincí.</p>

<p>Kdo se nakonec stane tou nejslavnější posádkou, o které budou vznikat nové báje a psát se knihy? Budete to VY?</p>

<p>Místo: akční hra bude v prostorách městského parku Javorka, kam vás organizátoři navedou.</p>

<!--<p>Každý tým bude potřebovat s sebou: seznam věcí ke hře</p>-->

<p>
  <ul>
    <li><a href = "/gamecon-trojboj/prihlaska-na-gc-trojboj">Registrace na GameCon Trojboj</a></li>
  </ul>  
</p>
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (161,'GameCon Trojboj – Akční hra','GameCon Trojboj – Akční hra organizátor Milan "Errikson" Tomeš, Tomáš "Žako" Jakoubek čas akce pátek 16.7 - 14:00 až 18:00 sobota 17.7 - 14:00 až 18:00 --> Po stopách argonautů Kdo z nás by neznal Jásona a jeho argonauty Herkula, Orfea, Thésea a další? Tolik bájí, pověstí a příběhů je napsáno o jejich slavných činech, místech, která navštívili, a nebezpečenstvích, kterými během své cesty za Zlatým rounem prošli. Ale je to vůbec pravda? Dá se všem pověstem věřit? Co když si Jáson jenom najal posádky lodí a ty jeho jménem podnikaly tyto krušné cesty za bohatstvím a slávou. Naše letošní akční hra je právě o nich. Vaše skupina se stane posádkou jedné takové lodi. Bude se snažit navštívit co nejvíce ostrovů, splnit maximum úkolů a získat tak co nejvíce pokladů. Ale pozor nebude to jenom klidná projížďka po moři, budou zde čekat i nástrahy v podobě bájných tvorů, které potkával i Jáson, ať už to byla Medůza, Minotaur, Hydra a dalších. Kromě nepřátelsky naladěných bájných tvorů jsou na moři i další posádky plavící se za stejným cílem. Rozhodně se od nich nedá čekat, že vám cestu za poklady usnadní a že vám část svého úspěchu přenechají a proto se vám budou snažit znepříjemňovat život. Nebojte se jim to oplácet stejnou mincí. Kdo se nakonec stane tou nejslavnější posádkou, o které budou vznikat nové báje a psát se knihy? Budete to VY? Místo: akční hra bude v prostorách městského parku Javorka, kam vás organizátoři navedou. Každý tým bude potřebovat s sebou: seznam věcí ke hře --> Registrace na GameCon Trojboj');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (162,'Archiv Trojboje na GameConu 2010','archiv-trojboj-2010',45,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (162,'gamecon-trojboj/archiv-trojboj-2010');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (162,'Archiv Trojboje na GameConu 2010 — GameCon 2011','gamecon,2011','Archiv Trojboje na GameConu 2010');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (162,'<h1>Archiv Trojboje na GameConu 2010</h1>
<h2>Akční hra &ndash; Po stopách Českotřebovského kohouta…</h2>
<p>
  <div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;">
    <img src = "/system_styly/side/akcni-hra.gif" style = "float: left; "/ />
  </div>
  <div style = "padding-bottom: 20px; width: 280px; float: left;"> <strong>organizátor</strong><br />Milan "Errikson" Tomeš, Tomáš "Žako" Jakoubek<br />
  </div>
</p>   
<p style = "clear: both;"></p>
<p>Vydejte se po stopách Českotřebovského kohouta zachránit hlavu písaři, jenž ztratil svou pečeť</p>
<h3>Úvod (setting)</h3>
<p>
<em>Za panování  Krále Václava IV bývala Česká  Třebová malým městečkem, o které  se staral rychtář s několika konšely, kteří měli ku pomoci městského písaře. Ten měl na starosti i městskou pečeť, za níž ručil svou hlavou, není tedy divu, že ji pečlivě opatroval, aby se neztratila.<br />
A přece jednoho dne pečeť  zmizela, jakoby se nad ní zem zavřela. Písař  i jeho žena všechno prohledali, ale pečeť  nenalezli. Písař byl předveden před soud, jenž  jej odsoudil k smrti. Za ranního rozbřesku smutně zazněl nad probouzejícím se městečkem hlas zvonku – umíráčku, aby oznámil občanům, že bude popraven muž, jenž málo dbal svých povinností.<br />
Na popravišti bylo již  vše připraveno. Uprostřed stálo popraviště, kolem něhož  se tlačily davy lidu. Rychtář ještě  jednou přečetl ortel smrti nad odsouzencem, jenž  naposledy zabloudil kalným zrakem svým po přítomných, hledaje mezi nimi svou milovanou ženu. Ale marně, nebylo jí  zde.<br />
Ta zatím hledala doma, majíc do poslední chvíle naději, že zachrání  svého muže. V zoufalství vyhlédla oknem a spatřila průvod, jenž se již blížil k popravišti. V tom zrakem zavadila o smetiště, kde se právě hrabal sousedův kohout. A hle! Pojednou spatřila pod jeho nohama jakýsi předmět. Rychle vyběhla ze světnice, zvedla předmět a stanula jako zkamenělá. Byla to hledaná pečeť. Rychle se vzpamatovala, dala se v běh s větrem o závod. Když přiběhla udýchaná a znavená a ukázala rychtáři i konšelům městskou pečeť, zrušili rozsudek a propustili písaře na svobodu.<br />
Od té  doby, přes 500 let je znakem města Česká Třebová kohout s lidskou hlavou a třírohým kloboukem.</em><br /><br />
Převzato [Štangler, 1947]<br /><br /><img src = "http://www.ceskatrebova.cz/images/ct-znak-st.gif " /><br /><br />
</p>
<h3>Informace pro hráče</h3>
<p>
Bohužel co čert nechtěl, našemu milému konšelovi se podařilo pečeť ztratit a teď  čeká v městské šatlavě na popravu. Čas běží, poprava se blíží a pečeť stále nikde …<br />  
Hráči se ocitají v rolích přátel nešťastného konšela a musí najít ztracenou pečeť během posledních dvou hodin zbývajících do popravy. Do rukou dostávají všechny informace o pečeti, na které  si konšel dokázal vzpomenout a pak už začíná závod s časem. Jedinou pomocí jim je stručná mapka, jejich rychlé nohy a v neposlední řadě jejich břitká mysl. Pak už je pouze na nich, jestli vyřeší všechny úkoly, vyluští všechny hádanky a dostanou se na místo, kde je ztracená pečeť.<br />  
Jedná se o akční  venkovní hru, která vyzkouší schopnost orientace v terénu a plnění logických a jiných úkolů. Cílem hry je v co nejkratším čas nalézt pečeť a vrátit ji na stanovené místo.<br /> 
</p>

<h2>Mexický Pat</h2>
<p>
  <div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;">
    <img src = "/system_styly/side/mexicky-pat.gif" style = "float: left; "/ />
  </div>
  <div style = "padding-bottom: 20px; width: 280px; float: left;"> <strong>organizátor</strong><br />Adéla "Egwain" Kyselová, Pavel "Rannik" Zahradil<br />
  </div>
</p>   
<p style = "clear: both;">Hromada peněz, několik gangsterů  kolem stolu, napřažené pistole a neklidné ruce. Je po vloupačce, ale někdo zradil a všem je v patách policie. Jak rozdělíte lup? Koho přivrátíte na svou stranu a koho pošlete pod stůl? To ať zodpoví váš kolt.</p> 
<p>Jedná se o velmi jednoduchou vyprávěcí hru. Vtělíte se do kůže gangsterů, kteří se vracejí z nepodařené loupeže, míří na sebe pistolemi a hádají se o rozdělení lupu. Pistolníci se navzájem osočují z chyb a zrad, které při akci zavinili, a cílem je svést na někoho vinu a zbavit se ho, aby se peníze dělily na co možná nejméně částí. Příběh se vypráví retrospektivně svalováním viny. Vše, co bylo řečeno, se stává faktem. Protože zbraně jsou neklidné a pistolníci také, čas od času vystřelí, několik mrtvých padne k zemi a hádka pokračuje, dokud se všichni nedomluví na dělení, nebo nezbude jen jeden.</p>

<h2>6 bere! </h2>
<p>
  <div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;">
    <img src = "/system_styly/side/6-bere.gif" style = "float: left; "/ />
  </div>
  <div style = "padding-bottom: 20px; width: 280px; float: left;"> <strong>organizátor</strong><br />Albi, 
Pavel "Rannik" Zahradil<br />
  </div>
</p>   
<p style = "clear: both;">Nechcete být za vola? Tak dokažte, že na to máte! Cílem téhle hry rozhodně není  nasbírat nejvíce býčích hlav.</p>
<p>6 bere je svižná a překvapivě  zábavná karetní hra s jednoduchými pravidly, která  se naučíte za pár minut během jediného přečtení.</p>
<p>Cílem hry je zbavit se všech očíslovaných karet v ruce. Hráči začínají s deseti kartami a zbavují se jich pečlivým vykládáním do řad. Ale pozor! Šestá karta v řadě bere celou řadu. Hra končí ve chvíli, kdy některý z hráčů posbírá 66 býčích hlav, vítězem se stává hráč, který jich má na konci hry nejméně.</p>
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (162,'Archiv Trojboje na GameConu 2010','Archiv Trojboje na GameConu 2010 Akční hra – Po stopách Českotřebovského kohouta… organizátor Milan "Errikson" Tomeš, Tomáš "Žako" Jakoubek Vydejte se po stopách Českotřebovského kohouta zachránit hlavu písaři, jenž ztratil svou pečeť Úvod (setting) Za panování Krále Václava IV bývala Česká Třebová malým městečkem, o které se staral rychtář s několika konšely, kteří měli ku pomoci městského písaře. Ten měl na starosti i městskou pečeť, za níž ručil svou hlavou, není tedy divu, že ji pečlivě opatroval, aby se neztratila. A přece jednoho dne pečeť zmizela, jakoby se nad ní zem zavřela. Písař i jeho žena všechno prohledali, ale pečeť nenalezli. Písař byl předveden před soud, jenž jej odsoudil k smrti. Za ranního rozbřesku smutně zazněl nad probouzejícím se městečkem hlas zvonku – umíráčku, aby oznámil občanům, že bude popraven muž, jenž málo dbal svých povinností. Na popravišti bylo již vše připraveno. Uprostřed stálo popraviště, kolem něhož se tlačily davy lidu. Rychtář ještě jednou přečetl ortel smrti nad odsouzencem, jenž naposledy zabloudil kalným zrakem svým po přítomných, hledaje mezi nimi svou milovanou ženu. Ale marně, nebylo jí zde. Ta zatím hledala doma, majíc do poslední chvíle naději, že zachrání svého muže. V zoufalství vyhlédla oknem a spatřila průvod, jenž se již blížil k popravišti. V tom zrakem zavadila o smetiště, kde se právě hrabal sousedův kohout. A hle! Pojednou spatřila pod jeho nohama jakýsi předmět. Rychle vyběhla ze světnice, zvedla předmět a stanula jako zkamenělá. Byla to hledaná pečeť. Rychle se vzpamatovala, dala se v běh s větrem o závod. Když přiběhla udýchaná a znavená a ukázala rychtáři i konšelům městskou pečeť, zrušili rozsudek a propustili písaře na svobodu. Od té doby, přes 500 let je znakem města Česká Třebová kohout s lidskou hlavou a třírohým kloboukem. Převzato [Štangler, 1947] Informace pro hráče Bohužel co čert nechtěl, našemu milému konšelovi se podařilo pečeť ztratit a teď čeká v městské šatlavě na popravu. Čas běží, poprava se blíží a pečeť stále nikde … Hráči se ocitají v rolích přátel nešťastného konšela a musí najít ztracenou pečeť během posledních dvou hodin zbývajících do popravy. Do rukou dostávají všechny informace o pečeti, na které si konšel dokázal vzpomenout a pak už začíná závod s časem. Jedinou pomocí jim je stručná mapka, jejich rychlé nohy a v neposlední řadě jejich břitká mysl. Pak už je pouze na nich, jestli vyřeší všechny úkoly, vyluští všechny hádanky a dostanou se na místo, kde je ztracená pečeť. Jedná se o akční venkovní hru, která vyzkouší schopnost orientace v terénu a plnění logických a jiných úkolů. Cílem hry je v co nejkratším čas nalézt pečeť a vrátit ji na stanovené místo. Mexický Pat organizátor Adéla "Egwain" Kyselová, Pavel "Rannik" Zahradil Hromada peněz, několik gangsterů kolem stolu, napřažené pistole a neklidné ruce. Je po vloupačce, ale někdo zradil a všem je v patách policie. Jak rozdělíte lup? Koho přivrátíte na svou stranu a koho pošlete pod stůl? To ať zodpoví váš kolt. Jedná se o velmi jednoduchou vyprávěcí hru. Vtělíte se do kůže gangsterů, kteří se vracejí z nepodařené loupeže, míří na sebe pistolemi a hádají se o rozdělení lupu. Pistolníci se navzájem osočují z chyb a zrad, které při akci zavinili, a cílem je svést na někoho vinu a zbavit se ho, aby se peníze dělily na co možná nejméně částí. Příběh se vypráví retrospektivně svalováním viny. Vše, co bylo řečeno, se stává faktem. Protože zbraně jsou neklidné a pistolníci také, čas od času vystřelí, několik mrtvých padne k zemi a hádka pokračuje, dokud se všichni nedomluví na dělení, nebo nezbude jen jeden. 6 bere! organizátor Albi, Pavel "Rannik" Zahradil Nechcete být za vola? Tak dokažte, že na to máte! Cílem téhle hry rozhodně není nasbírat nejvíce býčích hlav. 6 bere je svižná a překvapivě zábavná karetní hra s jednoduchými pravidly, která se naučíte za pár minut během jediného přečtení. Cílem hry je zbavit se všech očíslovaných karet v ruce. Hráči začínají s deseti kartami a zbavují se jich pečlivým vykládáním do řad. Ale pozor! Šestá karta v řadě bere celou řadu. Hra končí ve chvíli, kdy některý z hráčů posbírá 66 býčích hlav, vítězem se stává hráč, který jich má na konci hry nejméně.');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (163,'GameCon Trojboj – Bobří banda','bobri-banda',45,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (163,'gamecon-trojboj/bobri-banda');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (163,'GameCon Trojboj – Bobří banda — GameCon 2011','gamecon,2011','GameCon Trojboj – Bobří banda');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (163,'<h1>GameCon Trojboj – Bobří banda </h1>
<p>
  <div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;">
    <img src = "/system_styly/side/bobri-banda.gif" style = "float: left; "/ />
  </div>
  <!--<div style = "padding-bottom: 20px; width: 280px; float: left;"> <strong>organizátor</strong><br />Albi, 
Pavel "Rannik" Zahradil<br />  <strong>čas akce</strong><br />pátek 16.7 - 14:00 až 18:00<br />sobota 17.7 - 14:00 až 18:00<br />
  </div>-->
</p>   
<p style = "clear: both;"><em>Mladí bobři jsou velice hravá a neposedná banda. Neustále se vodě potápějí, dovádějí a každou chvíli se objevují jinde. Navíc se do hry čas od času připlete i vodní krysa, kterou tam rozhodně nepotřebujete.</em></p>
<p>Bobří banda se hraje na několik kol, jako většina podobných rychlovek. Na začátku každého kola dostanou hráči čtyři náhodně vylosované karty, které si rozloží před sebe rubem nahoru. Podívat
se mohou však pouze na dvě krajní karty a pouze jednou. Musí si tedy dobře zapamatovat, jaké hodnoty na kartách jsou. Účelem hry je mít před sebou karty s nejnižší bodovou hodnotou. Nejzajímavější na hře je, že nemá pevně určený konec kola. Konec kola nastává ve chvíli, kdy si
některý z hráčů myslí, že má před sebou nízkou kombinaci čísel.</p>
<p>Ti z vás, kdo sledují National Geographic asi ví, že bobři mají velmi dobrou paměť. Jestlipak jste na tom stejně?</p>
<p>
  <ul>
    <li><a href = "/gamecon-trojboj/prihlaska-na-gc-trojboj">Registrace na GameCon Trojboj</a></li>
  </ul>  
</p>
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (163,'GameCon Trojboj – Bobří banda','GameCon Trojboj – Bobří banda organizátor Albi, Pavel "Rannik" Zahradil čas akce pátek 16.7 - 14:00 až 18:00 sobota 17.7 - 14:00 až 18:00 --> Mladí bobři jsou velice hravá a neposedná banda. Neustále se vodě potápějí, dovádějí a každou chvíli se objevují jinde. Navíc se do hry čas od času připlete i vodní krysa, kterou tam rozhodně nepotřebujete. Bobří banda se hraje na několik kol, jako většina podobných rychlovek. Na začátku každého kola dostanou hráči čtyři náhodně vylosované karty, které si rozloží před sebe rubem nahoru. Podívat se mohou však pouze na dvě krajní karty a pouze jednou. Musí si tedy dobře zapamatovat, jaké hodnoty na kartách jsou. Účelem hry je mít před sebou karty s nejnižší bodovou hodnotou. Nejzajímavější na hře je, že nemá pevně určený konec kola. Konec kola nastává ve chvíli, kdy si některý z hráčů myslí, že má před sebou nízkou kombinaci čísel. Ti z vás, kdo sledují National Geographic asi ví, že bobři mají velmi dobrou paměť. Jestlipak jste na tom stejně? Registrace na GameCon Trojboj');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (164,'Návod - přihlášení na GameCon Trojboj','navod---prihlaseni-na-gamecon-trojboj',45,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (164,'gamecon-trojboj/navod---prihlaseni-na-gamecon-trojboj');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (164,'Návod - přihlášení na GameCon Trojboj — GameCon 2011','gamecon,2011','Návod - přihlášení na GameCon Trojboj');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (164,'<h1>Návod - přihlášení na GameCon Trojboj</h1>
<h2>Přihlášení na Trojboj</h2>
<p>Na stránce přihláška se kliknutím na možnost "Přihlásit se na GameCon Trojboj" přihlásíte na letošní ročník trojboje. I po přihlášení zde máte možnost se kdykoliv také odhlásit.</p>
<p>Pokud jste přihlášeni na GC Trojboj, objeví se vám na stránce přihlášky nové možnosti:
<ul>
  <li>můj tým</li>
  <li>výpis mých žádostí o členství v týmu</li>
  <li>výpis týmů</li>
</ul>
<p><strong>Můj tým</strong><br />
  V sekci můj tým vidíte informace o týmu, jehož jste členem. Pokud nejste členem žádného, máte možnost si zde založit vlastní.</p>
<p><strong>Výpis mých žádostí o členství v týmu</strong><br />
Pokud jste požádali některý tým, aby vás přijal za člena, pak v sekci výpis mých žádostí o členství v týmu vidíte přehled všech těchto týmů a máte zde také možnost svou žádost o členství kdykoli zrušit. Podat žádost můžete u jednotlivých týmů ve výpisu družin níže. Jakmile vás správce týmu přijme za člena, všechny ostatní žádosti budou automaticky zrušeny.</p>
<p><strong>Výpis týmů</strong><br />
Ve výpisu týmů je uveden přehled všech dosud založených týmů. Důležité je, že v této části máte možnost podat přihlášku do jakéhokoli týmu (nebo i více najednou). Záleží pak na správci, jestli vás do něj přijme.</p>
<p><strong>Veřejný/neveřejný tým</strong><br />
  Množství informací o týmu záleží na tom, jestli správce označil tým za veřejnou nebo neveřejnou. U neveřejných vidíte číslo a název, správce, počet členů a poznámku, kterou správce uvedl. U veřejného týmu navíc také vidíte přehled členů.</p>

<h2>Přihlášení se do existujícího týmu</h2>
<p>U každého týmu ze seznamu máte prostřednictvím odkazu "podat přihlášku" možnost zaslat žádost o to přijetí. Spolu s touto žádostí můžete poslat krátký komentář, ve kterém třeba uvedete něco o sobě, proč byste chtěli hrát s tímto týmem a nebo jakoukoli jinou poznámku. O přijetí do týmu rozhoduje vždy správce, který bude mít k dispozici váš login, text poznámky, který jste uvedli a také váš email, aby se s vámi mohl případně nějak domluvit. V případě, že bude vaše žádost zamítnuta, zmizí i z přehledu vašich podaných žádostí (viz výše).</p>

<h2>Založení nového týmu</h2>
<p>Pokud v menu můj tým kliknete na odkaz "založit vlastní", objeví se vám formulář, ve kterém vyplníte název vašeho týmu, jestli je veřejný nebo neveřejný (viz výše) a pole pro zadání poznámky, která se bude u týmu v přehledu vždy zobrazovat (např. informace o tom, že hledáte členy apod.). Poznámku, jméno i status veřejný/neveřejný máte možnost kdykoli změnit.</p>

<h2>Můj tým</h2>
<p>Jakmile jste členy týmu, objeví se vám v části "můj tým" informace o něm:<br />
<ul>
  <li>správce</li>
  <li>v jakém herním bloku hrajete (pátek nebo sobota)</li>
  <li>kdo jsou členové týmu a kontakt na ně</li>
</ul>
<p>V části můj tým máte taky možnost kdykoli tým opustit.</p>

<h2>Možnosti správce</h2>
<p>Správce je ten, kdo tým založil nebo člen na kterého správcovství přešlo potom, co předchozí správce tým opustil (nebo správcovství předal). Správce spravuje tým a má následující možnosti:<br />
<ul>
  <li>kdykoli měnit poznámku, status a jméno týmu zobrazující se ve výpisu (např. informaci o  tom, že tým již nikoho nepřijímá)</li>
  <li>přijímat žádosti o členství, zamítat žádosti a vylučovat stávající členy</li>
  <li>vybrat a měnit výběr herních bloků</li>
</ul>
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (164,'Návod - přihlášení na GameCon Trojboj','Návod - přihlášení na GameCon Trojboj Přihlášení na Trojboj Na stránce přihláška se kliknutím na možnost "Přihlásit se na GameCon Trojboj" přihlásíte na letošní ročník trojboje. I po přihlášení zde máte možnost se kdykoliv také odhlásit. Pokud jste přihlášeni na GC Trojboj, objeví se vám na stránce přihlášky nové možnosti: můj tým výpis mých žádostí o členství v týmu výpis týmů Můj tým V sekci můj tým vidíte informace o týmu, jehož jste členem. Pokud nejste členem žádného, máte možnost si zde založit vlastní. Výpis mých žádostí o členství v týmu Pokud jste požádali některý tým, aby vás přijal za člena, pak v sekci výpis mých žádostí o členství v týmu vidíte přehled všech těchto týmů a máte zde také možnost svou žádost o členství kdykoli zrušit. Podat žádost můžete u jednotlivých týmů ve výpisu družin níže. Jakmile vás správce týmu přijme za člena, všechny ostatní žádosti budou automaticky zrušeny. Výpis týmů Ve výpisu týmů je uveden přehled všech dosud založených týmů. Důležité je, že v této části máte možnost podat přihlášku do jakéhokoli týmu (nebo i více najednou). Záleží pak na správci, jestli vás do něj přijme. Veřejný/neveřejný tým Množství informací o týmu záleží na tom, jestli správce označil tým za veřejnou nebo neveřejnou. U neveřejných vidíte číslo a název, správce, počet členů a poznámku, kterou správce uvedl. U veřejného týmu navíc také vidíte přehled členů. Přihlášení se do existujícího týmu U každého týmu ze seznamu máte prostřednictvím odkazu "podat přihlášku" možnost zaslat žádost o to přijetí. Spolu s touto žádostí můžete poslat krátký komentář, ve kterém třeba uvedete něco o sobě, proč byste chtěli hrát s tímto týmem a nebo jakoukoli jinou poznámku. O přijetí do týmu rozhoduje vždy správce, který bude mít k dispozici váš login, text poznámky, který jste uvedli a také váš email, aby se s vámi mohl případně nějak domluvit. V případě, že bude vaše žádost zamítnuta, zmizí i z přehledu vašich podaných žádostí (viz výše). Založení nového týmu Pokud v menu můj tým kliknete na odkaz "založit vlastní", objeví se vám formulář, ve kterém vyplníte název vašeho týmu, jestli je veřejný nebo neveřejný (viz výše) a pole pro zadání poznámky, která se bude u týmu v přehledu vždy zobrazovat (např. informace o tom, že hledáte členy apod.). Poznámku, jméno i status veřejný/neveřejný máte možnost kdykoli změnit. Můj tým Jakmile jste členy týmu, objeví se vám v části "můj tým" informace o něm: správce v jakém herním bloku hrajete (pátek nebo sobota) kdo jsou členové týmu a kontakt na ně V části můj tým máte taky možnost kdykoli tým opustit. Možnosti správce Správce je ten, kdo tým založil nebo člen na kterého správcovství přešlo potom, co předchozí správce tým opustil (nebo správcovství předal). Správce spravuje tým a má následující možnosti: kdykoli měnit poznámku, status a jméno týmu zobrazující se ve výpisu (např. informaci o tom, že tým již nikoho nepřijímá) přijímat žádosti o členství, zamítat žádosti a vylučovat stávající členy vybrat a měnit výběr herních bloků');

