INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (165,'GameCon Trojboj — GameCon 2011','gamecon,2011','GameCon Trojboj');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (165,'<h1>GameCon Trojboj</h1>
<p>Po loňském úspěšném ročníku pokračujeme v Trojbové krasojízdě.
</p>
<p>Trojboj je prestižní turnaj tříčlenných týmů, které se spolu utkají ve třech různých disciplínách:</p>
<ul>
  <li>skvělé <strong><a href = "/gamecon-trojboj/akcni-hra">Akční hře</a></strong></li>
  <li>napínavých <strong><a href = "/gamecon-trojboj/olympijske-rosady">Olympijských rošádách</a></strong></li>
  <li>zábavné karetní hře <strong><a href = "/gamecon-trojboj/bobri-banda">Bobří banda</a></strong></li>
</ul>  
<p>Každý člen týmu se počítá a společně mohou dosáhnout na stupně nejvyšší. Vítězství je super, ale je to hlavně účast, co stojí za to. Trojboj je stejně jako všechno ostatní na GameConu hlavně o zábavě.</p>
<p>Konkrétní pravidla jednotlivých disciplín budou vysvětlena organizátory před příslušnou hrou. <strong>Všechna pravidla jsou natolik jednoduchá, že nemusíte mít zkušenost s žádnou z her Trojboje a naučíte se je na místě.</strong></p>
<p>Tady jsou základní principy hry:</p>
<ul>
  <li>Trojboje se účastní tříčlenné týmy.</li>
  <li>Každý tým musí projít všechny disciplíny, aby mohl být vyhodnocen.</li>
  <li><strong>Tento rok zabere Trojboj jen jeden blok.</strong> Pro nabitost akcí v Trojboji je však možné, že trochu přesáhne do přestávky. Nebude vám ale zasahovat do dalšího herního bloku.</li>
  <li>Trojboj je v programu uveden dvakrát, ale vždy se jedná o jednu a tu samou akci – odehrajete pouze jeden z těch dvou bloků. Je to proto, abyste měli více možností, jak si rozvrhnout váš čas a sladit to s ostatními aktivitami.</li>
  <li>Při stejném výsledku rozhoduje výsledek v akční hře a pokud ten nerozhodne, pak výsledek Olympijských rošád a následně Bobří banda!</li>
</ul>
<p><strong>I pokud jste žádnou z her Trojboje nikdy nehráli, vůbec se ho nemusíte bát.</strong>
</p>
<p>Na stránce jednotlivých částí Trojboje (<a href = "/gamecon-trojboj/akcni-hra">Akční hra</a></strong>, <a href = "/gamecon-trojboj/olympijske-rosady">Olympijské rošády</a>, <a href = "/gamecon-trojboj/bobri-banda">Bobří banda</a>) získáte bližší informace o jeho náplni. Přihlásit se pak můžete na stránce <a href = "/gamecon-trojboj/prihlaska-na-gc-trojboj">Přihláška</a></p>
<!--
<p>
<strong><a href = "/forum/gamecon-trojboj">Řekněte na fóru, co si o GameCon Trojboji myslíte.</a></strong>
</p>-->

    </div>
  </div>');
