INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (166,'GameCon Trojboj – Olympijské rošády — GameCon 2011','gamecon,2011','GameCon Trojboj – Olympijské rošády');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (166,'<h1>GameCon Trojboj – Olympijské rošády</h1>
<p>
  <!--<div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;">
    <img src = "/system_styly/side/olympske-rosady.gif" style = "float: left; "/ />
  </div>
  <div style = "padding-bottom: 20px; width: 280px; float: left;"> <strong>organizátor</strong><br />Adéla "Egwain" Kyselová, Pavel "Rannik" Zahradil<br />  <strong>čas akce</strong><br />pátek 16.7 - 14:00 až 18:00<br />sobota 17.7 - 14:00 až 18:00<br />
  </div>-->
</p>   
<p style = "clear: both;"><em>Perseus, jeden z největších hrdinů dějin, se vydává na svou slavnou pouť. Obyvatelé Olympu v tom ale nevidí nic menšího, než další příležitost vyřídit si své staré i nové spory, a tak osud této výpravy asi nebude úplně v Perseových rukou. Po raději nevzpomínaných událostech kolem Herkula a Tróji však Zeus zakázal zasahovat přímo, a tak bohům nezbývá, než zasednout k jednomu stolu a dohodnout se, jak to s Perseem vlastně dopadne&hellip;</em></p>
<p>&hellip;akční, napínavá, roleplayingová hra plná emocí, hádek, lhaní, starých křivd, nových spiknutí, podvodů a intrik! Jak dopadne snaha znesvářených bohů o kompromis? Jak se jim podaří vyřídit si skrze Persea své vzájemné účty? Bude na Olympu konečně klid, nebo tento další Diův pokus o zklidnění rodiny dopadne opět šílenou katastrofou? Který z bohů se bude tentokrát smát jako poslední a &ndash; což je podstatnější &ndash; na čí účet?</p>
<p>Unikátní hra po vzoru her skutečných diplomatů, vytvořená pouze pro vás &ndash; Gamecon 2011</p>
<p>
  <ul>
    <li><a href = "/gamecon-trojboj/prihlaska-na-gc-trojboj">Registrace na GameCon Trojboj</a></li>
  </ul>  
</p>
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (166,'GameCon Trojboj – Olympijské rošády','GameCon Trojboj – Olympijské rošády organizátor Adéla "Egwain" Kyselová, Pavel "Rannik" Zahradil čas akce pátek 16.7 - 14:00 až 18:00 sobota 17.7 - 14:00 až 18:00 --> Perseus, jeden z největších hrdinů dějin, se vydává na svou slavnou pouť. Obyvatelé Olympu v tom ale nevidí nic menšího, než další příležitost vyřídit si své staré i nové spory, a tak osud této výpravy asi nebude úplně v Perseových rukou. Po raději nevzpomínaných událostech kolem Herkula a Tróji však Zeus zakázal zasahovat přímo, a tak bohům nezbývá, než zasednout k jednomu stolu a dohodnout se, jak to s Perseem vlastně dopadne… …akční, napínavá, roleplayingová hra plná emocí, hádek, lhaní, starých křivd, nových spiknutí, podvodů a intrik! Jak dopadne snaha znesvářených bohů o kompromis? Jak se jim podaří vyřídit si skrze Persea své vzájemné účty? Bude na Olympu konečně klid, nebo tento další Diův pokus o zklidnění rodiny dopadne opět šílenou katastrofou? Který z bohů se bude tentokrát smát jako poslední a – což je podstatnější – na čí účet? Unikátní hra po vzoru her skutečných diplomatů, vytvořená pouze pro vás – Gamecon 2011 Registrace na GameCon Trojboj');

