INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (171,'gamecon/gamecon-v-nekolika-snadnych-krocich');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (171,'GameCon 2011 v několika snadných krocích aneb Stručný návod pro nováčky a osvěžení pro ostřílené návštěvníky — GameCon 2011','gamecon,2011','GameCon 2011 v několika snadných krocích aneb Stručný návod pro nováčky a osvěžení pro ostřílené návštěvníky');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (171,'<h1>GameCon 2011 v několika snadných krocích<br />
<span style="font-weight:normal;font-size:14px">aneb<br /></span>
Stručný návod pro nováčky a osvěžení pro ostřílené návštěvníky</h1>

<h2>Před GameConem</h2>

<ol>
<li> Nejprve je třeba se <b>přihlásit na samotný GameCon</b>. Jednoduchý návod naleznete <a href="http://www.gamecon.cz/gamecon/prihlasovani-na-aktivity">zde</a><br />
Nezapomeňte si na památku objednat placku, kostky a tričko!
<li> Potom si můžete <b>přihlásit aktivity a ubytování</b>. I pro to nalezne návod <a href="http://www.gamecon.cz/gamecon/prihlasovani-na-aktivity">zde</a><br />
Nezapomeňte nám napsat, pokud chcete být ubytováni na pokoji s někým konkrétním!<br />
Plánování vám usnadní <a href="http://www.gamecon.cz/program-tabulka"><b>tabulkový program</b> GameConu</a>
<li> Poznačte si v kalendáři datum <b>10.7.2011</b>. Pokud máte přihlášené aktivity, musíte je mít do tohoto data zaplacené, jinak vás odhlásíme a aktivity nabídneme ostatním. Odhlášení proběhne během jednoho až dvou dní, tak abychom nikoho neodhlásili neprávem. Pokud jste se nemohli přihlásit z kapacitních důvodů, krátce po 10.7. tedy budete mít šanci se přihlásit na uvolněná místa.
<li> Sbalte si podle toho, jaké ubytování jste si vybrali:<br />
- <b>pokoj</b>: stačí vám pyžamo a hygienické potřeby podle potřeby :) Peřiny i povlečení najdete na pokoji.<br /> 
- <b>třída</b>: spartánské ubytování ve větší společnosti znamená dvě věci: 1) vezměte si <b>spacák a karimatku</b>, 2) počítejte s tím, že třída není ideálním místem pro skladování věcí, o které byste neradi přišli. Proto si vezměte visací zámek k uzamykatelným skříňkám na chodbě, které můžete využít.
<li> Podívejte se do mapy, kam se vlastně chystáte :)<br />
GameCon se bude konat v areálu SOŠ a SOU v České Třebové, adresa:<br />
Střední odborná škola a Střední odborné učiliště technických oborů<br />
Skalka 1692<br />
560 18, Česká Třebová<br />
Mapku s popisem cesty najdete tady: <a href="http://www.gamecon.cz/gamecon/kde-se-gamecon-kona">http://www.gamecon.cz/gamecon/kde-se-gamecon-kona</a>

<h2>Na GameConu</h2>
<li> Nejprve se <b>zaregistrujte</b>. V areálu školy v deskoherně (největší místnost školy), kam vás navedou šipky, naleznete registrační pult, kde se přihlásíte (pro jistotu s sebou mějte doklad o platbě, studentský průkaz pro prokázání slevy a nějaký doklad totožnosti) a dostanete (pokud jste si je v kroku 1 objednali) tričko, placku a kostky.<br />
Pokud jste si něco z toho zatím neobjednali, tak to můžete napravit ve své <a href="http://www.gamecon.cz/gamecon/prihlaska">přihlášce</a>. Každý účastník také dostane vytištěný program a sadu informačních materiálů.
<li> Dojděte se <b>ubytovat</b>. Klíče a potřebné informace jste už dostali při registraci, takže to bude hračka. 
<li> Pro snazší orientaci v areálu vám poslouží mapka, kterou jste dostali mezi informačními materiály při registraci... 
<li> Na přihlášené aktivity <b>choďte včas</b>. Jednak nenecháte čekat ostatní, jednak neriskujete, že se začne bez vás.
<li> Sledujte, které aktivity se uvolnily, nebo které nepotřebují registraci. Neujde vám tak nic důležitého. Potřebné informace dostanete na infopultu v deskoherně. 
<li> Pokud vás přepadne na GameConu <b>hlad</b>, máte několik možností, jak ho zahnat:<br />
- budou pro vás připraveny <b>kuchyňky</b>, kde si budete moci sami uvařit. V kuchyňkách není žádné vybavení, a proto si <b>nezapomeňte vzít vlastní</b>, pokud plánujete vařit<br />
- kromě toho jsme opět zajistili i bufet přímo u vchodu do budovy, kde bude možné nakoupit rychlou svačinu (sekanou, řízky, párky, bagety, obložené chlebíčky, smaženky, koláče a koblihy)<br />
- navíc jsme pro vás připravili také <a href="/gamecon/restaurace-a-obchody">seznam restaurací a obchodů v blízkém okolí GameConu</a>, kam si můžete odskočit na normální jídlo.
<li> GameCon se odehrává v areálu školy, takže je potřeba ctít místní pravidla: <b>zákaz kouření</b> ve všech prostorách školy, <b>noční klid</b> a také základní pravidla společenského chování. Pokud by nastal nějaký problém, jehož řešení by nebylo ve vašich silách, obraťte se na organizátory.
<li> Nudu nechte zavřenou doma ve sklepě, sbalte si dobrou náladu a <b>parádně si GameCon užijte!</b>
</ol>
    </div>
  </div>');
