INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (172,'<h1>Kde se GameCon koná a cesta na GameCon</h1>
<h2>Kde se GameCon koná?</h2>
<h3>Adresa</h3>
<p>
Střední odborná škola a Střední odborné učiliště technických oborů<br />
Skalka 1692<br />
560 18 Česká Třebová<br />
</p>
<h3>Cesta z nádraží</h3>
<p>
 Od nádraží ČD nejlépe pěšky podle přiložené mapky (1,5 km). 
</p>
<h3>Mapka</h3>
<p>
<a href = "/galerie/materialy-2010/mapa-2010.jpg" rel = "lightbox[]"><img src = "/galerie/materialy-2010/mapa-2010-s.jpg" /></a>
</p>
<h3>Společná cesta na GameCon</h3>
<p>
 Pokud nechcete jet na GameCon sami (třeba protože chcete využít levnější skupinovou jízdenku nebo se nechcete nudit), <strong>můžete si na fóru v sekci <a href = "/forum/spolecna-cesta-na-gamecon">Společná cesta na GameCon</a> dohodnout společnou cestu s dalšími lidmi</strong>. 
</p>
