INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (173,'Napsali o nás','Napsali o nás GameCon 2010 GameCon 2010 očima KoRH, jaký byl? Orlický deník - GameCon našel nové bydliště Orlický deník - OBRAZEM: Festival her ovládl Skalku Orlický deník - GameCon startuje! Reportáž o GameConu 2010 na Topzine.cz O GameConu v Českotřebovském deníku GameCon 2009 12. června 2009 - Článek na www.topzine.cz GameCon 2008 Reportáž o Czech Open a GameConu na ČT 24, 11. 7. (od času 48:45) Rozhovor o GameConu v ČRo Pardubice (vysíláno 13. 7. dopoledne) RomiKova reportáž Majova reportáž RomiKovy fotky');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (47,'GameCon 2011 se blíží','o-gameconu',33,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (47,'gamecon/o-gameconu');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (47,'GameCon 2011 se blíží — GameCon 2011','gamecon,2011','GameCon 2011 se blíží');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (47,'<h1>GameCon 2011 se blíží</h1>

<!--<h2>Organizační změny</h2>
<p>
Dovolte nám seznámit vás s velkou organizační novinkou. Petr „Gandalf“ Holub, který stál v čele organizačního týmu GameConu poslední dva roky, ještě v průběhu letošního GameConu v České Třebové předal post hlavního organizátora Matouši „Erricu“ Ježkovi. Jelikož se mu totiž letos narodily dvě holčičky, po důkladném uvážení se musel rozhodnout k tomuto kroku, neboť vedení organizačního týmu a nově rozrostlou rodinu a normální práci by nebylo možné skloubit tak, aby jedno netrpělo.
</p>
<p>
Nic to však nemění na tom, že další ročník GameConu už pro vás připravujeme a o novinkách vás budeme průběžně informovat jak tady, tak na <a href = "http://www.facebook.com/group.php?sid=1a65342dd9cba753975=bb963632e2a7&gid=93879753711&ref=search#!/gamecon" onclick = "window.open(this.href,\'_blank\'); return false">facebooku</a>.
</p>
<p>
Organizační tým GameConu
</p>

<h2>GameCon Teaser</h2>
<object width="470" height="265"><param name="allowfullscreen" value="true" /><param name="allowscriptaccess" value="always" /><param name="movie" value="http://vimeo.com/moogaloop.swf?clip_id=12709571&amp;server=vimeo.com&amp;show_title=1&amp;show_byline=1&amp;show_portrait=0&amp;color=&amp;fullscreen=1" /><embed src="http://vimeo.com/moogaloop.swf?clip_id=12709571&amp;server=vimeo.com&amp;show_title=1&amp;show_byline=1&amp;show_portrait=0&amp;color=&amp;fullscreen=1" type="application/x-shockwave-flash" allowfullscreen="true" allowscriptaccess="always" width="470" height="265"></embed></object>-->

<h2>Čtyři dny plné zábavy a napětí nad hrami všeho druhu</h2>
<p>Ve dnech <strong>21.-24.7.2011</strong> se v <strong>České Třebové</strong> uskuteční již 17. ročník herního setkání <strong>GameCon</strong>. Je to příležitost pro všechny hráče a fanoušky nepočítačových her z České republiky a Slovenska setkat se s ostatními, zahrát si hry, vyměnit zkušenosti a pobavit se. Co vás během čtyř dnů na GameConu čeká?
<ul>
<li><a href="/deskove-hry/o-deskovych-hrach-na-gc">Deskové hry</a> (Osadníci z Katanu, Carcassonne a mnohé další)</li>
<li>Velké množství her na hraní rolí neboli <a href="/rpg/o-rpg-na-gc">RPG</a>. Můžete si vyzkoušet i herní systémy, které doma ani nemáte.</li>
<li>Hry naživo neboli <a href = "/larp/o-larpech-na-gc">LARP</a>, kdy prožitky své postavy vyzkoušíte na vlastní kůži.</li>
<li><a href = "/mistrovstvi-v-drd/o-mistrovstvi-v-drd">Mistrovství v Dračím doupěti</a>, letos pro změnu z pozice obyčejných obyvatel Císařství.</li>
<li>A spousta dalších aktivit, jako třeba bitva miniaturních armád ve <a href = "/wargaming/o-wargamingu-na-gc">Wargamingu</a>, nebo poutavé <a href = "/prednasky/o-prednaskach-na-gc">přednášky</a>.</li>
<li>Sobotní party</li>
</ul>
</p>

<p>Že neznáte žádnou z těchto her? Nevadí.<strong>Pravidla vám rádi vysvětlíme na místě</strong> a poradíme i s výběrem her nebo naplánováním programu. <strong>Neváhejte tedy a přijeďte.</strong> Slibujeme vám spoustu her, zábavy a přátelské atmosféry. Nemáte volné celé čtyři dny? Nevadí! <strong>GameCon</strong> má co nabídnout každý den.</strong></p>
<!--<p>Jednoduchý návod jak se <strong>přihlásit na GameCon</strong> a všechny důležité informace o <strong>registraci</strong>, možnostech <strong>ubytování</strong> a <strong>platbách</strong> naleznete <a href="/navod/">zde</a>.</p>-->
<p>O novinkách vás budeme průběžně informovat jak zde, tak na <a href = "http://www.facebook.com/gamecon" onclick = "window.open(this.href,\'_blank\'); return false">Facebooku</a>.</p>

<a name=novinky></a>
<h2>Letošní novinky</h2>
<p>Tak jako každý rok se snažíme, aby GameCon i letos nabídl něco nového. Loni se con přestěhoval do České Třebové, což přineslo mimo jiné možnost nabídnout všechny aktivity pod jednou střechou, prostornou a dobře větratelnou místnost pro deskohernu a levnější ubytování. Na co se můžete těšit letos?</p>
<ul>
<li>Pro účastníky GameConu ze Slovenska jsme připravili <strong>možnost platit v eurech</strong>.</li>
<li>Všem budou přístupné <strong>kuchyňky</strong>, ve kterých si bude možné uvařit jídlo.</li>
<li>GameCon se bude odehrávat <strong>ve znamení Antiky</strong>.</li>
<li>Je pro vás připravena <strong>spousta nových her</strong> na všech frontách.</li>
<li>Na programu bude také <strong>křest Dračího doupěte II</strong>.</li>
</ul>

<!--<p>
Patrně nejvýraznější změnou je přestěhování conu do České Třebové. Tento manévr nám poskytl hned několik výhod:
<ul>
	<li>Předně jsou to <strong>všechny aktivity pod jednou střechou</strong>, nebude potřeba kamkoliv přebíhat nebo složitě bloudit mezi jednotlivými komplexy budov.</li>
	<li>Zároveň jsou místnosti pro jednotlivé aktivity dostatečně velké a vzdušné.</li>
	<li>Především místnost <a href = "/deskove-hry/deskoherna">deskoherny</a> je úchvatně prostorná a dobře větratelná. Už nehrozí, že bychom se v dobré víře ušlapávali nebo letním parnu dusili. Tento rok to bude konečně ta <strong>dobře přístupná aréna plná deskových her</strong> připravená na lačné hráče. Pro zvědavce jsme jako důkaz připravili alespoň dvě fotografie z naších průzkumných výprav – více v <a href = "/deskove-hry/deskoherna">deskoherně</a>.</li>
	<li>Vítanou změnou bude určitě i <strong>levnější ubytování</strong>. Letos bude stát jedna noc v třílůžkovém pokoji pouhých 170 Kč (oproti loňským dvěma stovkám, takže za tři noci nakonec ušetříte téměř stokorunu).</li>
	<li>Přijde vám lůžkový pokoj příliš drahý a komfortní? Pak jistě uvítáte další zlepšení a tím je <strong>možnost spát hromadně ve třídě ve vlastním spacáku</strong> a to za pouhých 60 Kč. Více o ubytovacích možnostech se dočtete v <a href = "/gamecon/ubytovani">ubytování</a>.</li>
	<li>Přesunem do jiného města jsme také získali kousek od naší budovy velkou nafukovací halu, kterou budeme moci využít v nepřízni počasí na nějakou velmi hromadnou akci. No není takový bonus skvělý?</li>
	<li>A snad některé z vás potěší i dobrá dopravní dostupnost pro celou republiku. Jsme uprostřed státu, tak snad to má každý kousek. :-)</li>
</ul>
</p>

<p>
Jak můžete vidět, přesun na nové místo pro vás znamená samé výhody. Nespokojíme se však jen s novým územím a jeho přidanými hodnotami, pokračujeme dál ve zpestřujících zlepšovácích:
</p>
<p>
<ul>
	<li>Velká novinka hned rovnou na začátek: <strong>popré</strong> bude <strong>celý GameCon v duchu nějakého tématu</strong>, tentokrát to bude <strong>exodus</strong> a spíše než vyhnání z ráje to bude jeho hledání. V následujících dnech vám přineseme bližší informace a vy se můžete těšit, že s tím bude spojena spousta her a zábavné atmosféry.</li>
	<li><strong>Mistrovství v Dračím doupěti</strong> bude zase o něco blíž vám hráčům. Vyslyšeli jsme vaše dobré připomínky a rady, důkladně si přečetli reakce ve <a href = "/forum/mistrovstvi_v_drd">fóru</a> a vyšli vám vstříc.<br />
Do odkrývání tajů dobrodružství se můžete pustit již nyní a každý týden Vám přineseme další indicii. Na úvod začínáme jedním výtiskem <a href = "/mistrovstvi-v-drd/sluncesvit-cisarske-noviny">Sluncesvitu</a> - populárního císařského plátku.<br />
Také jsme pro vás připravili <strong>dvě výrazná zlepšení postav</strong> a <strong>jedno velmi poutavé zpestření</strong>. Obě novinky se týkají <a href = "/mistrovstvi-v-drd/pravidla-pro-tvorbu-postav">tvorby postav</a> a brzy vás o těchto změnách budeme informovat více. Zatím můžete ve <a href = "/forum/mistrovstvi_v_drd">fóru</a> tipovat, co by to tak mohlo být.</li>
	<li><strong>Trojboj</strong> bude v tomto roce trvat jen jeden blok, takže o důvod více zapojit se do této týmové aktivity, kdy za jednu cenu si zahrajete tři hry. Více na <a href = "/gamecon-trojboj/o-gamecon-trojboji">samostatné stránce</a>.</li>
	<li><strong>Špína</strong> bude letos ve znamení „Osídlení nového města“ a <strong>gobliní ponorky</strong> budou bojovat o nová naleziště drahokamů.</li>
	<li>Určitě se bude hodit i trénink ve velení armádám, tudíž jistě přijde vhod <a href = "/wargaming/wargaming-tour-2010">Wargaming Tour 2010</a>.</li>
	<li>A lahodný zákusek na závěr: <strong>na sobotní večer</strong> pro vás plánujeme <strong>hromadné pobavení</strong>, jehož součástí by mělo být i <strong>klání v duchu televizních soutěží</strong> v režii týmu z Court of Moravia.</li>
</ul>
</p>

<p>
Snad vás to množství novinek a jednotlivé zlepšováky těší a přijedete na GameCon. Koná se <strong>15.-18.7.2010 v&nbsp;České Třebové</strong>.
</p>-->

<h3>GameCon je tu pro vás, tak si přijďte zahrát!</h3>
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (47,'GameCon 2011 se blíží','GameCon 2011 se blíží Organizační změny Dovolte nám seznámit vás s velkou organizační novinkou. Petr „Gandalf“ Holub, který stál v čele organizačního týmu GameConu poslední dva roky, ještě v průběhu letošního GameConu v České Třebové předal post hlavního organizátora Matouši „Erricu“ Ježkovi. Jelikož se mu totiž letos narodily dvě holčičky, po důkladném uvážení se musel rozhodnout k tomuto kroku, neboť vedení organizačního týmu a nově rozrostlou rodinu a normální práci by nebylo možné skloubit tak, aby jedno netrpělo. Nic to však nemění na tom, že další ročník GameConu už pro vás připravujeme a o novinkách vás budeme průběžně informovat jak tady, tak na facebooku . Organizační tým GameConu GameCon Teaser --> Čtyři dny plné zábavy a napětí nad hrami všeho druhu Ve dnech 21.-24.7.2011 se v České Třebové uskuteční již 17. ročník herního setkání GameCon . Je to příležitost pro všechny hráče a fanoušky nepočítačových her z České republiky a Slovenska setkat se s ostatními, zahrát si hry, vyměnit zkušenosti a pobavit se. Co vás během čtyř dnů na GameConu čeká? Deskové hry (Osadníci z Katanu, Carcassonne a mnohé další) Velké množství her na hraní rolí neboli RPG . Můžete si vyzkoušet i herní systémy, které doma ani nemáte. Hry naživo neboli LARP , kdy prožitky své postavy vyzkoušíte na vlastní kůži. Mistrovství v Dračím doupěti , letos pro změnu z pozice obyčejných obyvatel Císařství. A spousta dalších aktivit, jako třeba bitva miniaturních armád ve Wargamingu , nebo poutavé přednášky . Sobotní party Že neznáte žádnou z těchto her? Nevadí. Pravidla vám rádi vysvětlíme na místě a poradíme i s výběrem her nebo naplánováním programu. Neváhejte tedy a přijeďte. Slibujeme vám spoustu her, zábavy a přátelské atmosféry. Nemáte volné celé čtyři dny? Nevadí! GameCon má co nabídnout každý den. Jednoduchý návod jak se přihlásit na GameCon a všechny důležité informace o registraci , možnostech ubytování a platbách naleznete zde . --> O novinkách vás budeme průběžně informovat jak zde, tak na Facebooku . Letošní novinky Tak jako každý rok se snažíme, aby GameCon i letos nabídl něco nového. Loni se con přestěhoval do České Třebové, což přineslo mimo jiné možnost nabídnout všechny aktivity pod jednou střechou, prostornou a dobře větratelnou místnost pro deskohernu a levnější ubytování. Na co se můžete těšit letos? Pro účastníky GameConu ze Slovenska jsme připravili možnost platit v eurech . Všem budou přístupné kuchyňky , ve kterých si bude možné uvařit jídlo. GameCon se bude odehrávat ve znamení Antiky . Je pro vás připravena spousta nových her na všech frontách. Na programu bude také křest Dračího doupěte II . Patrně nejvýraznější změnou je přestěhování conu do České Třebové. Tento manévr nám poskytl hned několik výhod: Předně jsou to všechny aktivity pod jednou střechou , nebude potřeba kamkoliv přebíhat nebo složitě bloudit mezi jednotlivými komplexy budov. Zároveň jsou místnosti pro jednotlivé aktivity dostatečně velké a vzdušné. Především místnost deskoherny je úchvatně prostorná a dobře větratelná. Už nehrozí, že bychom se v dobré víře ušlapávali nebo letním parnu dusili. Tento rok to bude konečně ta dobře přístupná aréna plná deskových her připravená na lačné hráče. Pro zvědavce jsme jako důkaz připravili alespoň dvě fotografie z naších průzkumných výprav – více v deskoherně . Vítanou změnou bude určitě i levnější ubytování . Letos bude stát jedna noc v třílůžkovém pokoji pouhých 170 Kč (oproti loňským dvěma stovkám, takže za tři noci nakonec ušetříte téměř stokorunu). Přijde vám lůžkový pokoj příliš drahý a komfortní? Pak jistě uvítáte další zlepšení a tím je možnost spát hromadně ve třídě ve vlastním spacáku a to za pouhých 60 Kč. Více o ubytovacích možnostech se dočtete v ubytování . Přesunem do jiného města jsme také získali kousek od naší budovy velkou nafukovací halu, kterou budeme moci využít v nepřízni počasí na nějakou velmi hromadnou akci. No není takový bonus skvělý? A snad některé z vás potěší i dobrá dopravní dostupnost pro celou republiku. Jsme uprostřed státu, tak snad to má každý kousek. :-) Jak můžete vidět, přesun na nové místo pro vás znamená samé výhody. Nespokojíme se však jen s novým územím a jeho přidanými hodnotami, pokračujeme dál ve zpestřujících zlepšovácích: Velká novinka hned rovnou na začátek: popré bude celý GameCon v duchu nějakého tématu , tentokrát to bude exodus a spíše než vyhnání z ráje to bude jeho hledání. V následujících dnech vám přineseme bližší informace a vy se můžete těšit, že s tím bude spojena spousta her a zábavné atmosféry. Mistrovství v Dračím doupěti bude zase o něco blíž vám hráčům. Vyslyšeli jsme vaše dobré připomínky a rady, důkladně si přečetli reakce ve fóru a vyšli vám vstříc. Do odkrývání tajů dobrodružství se můžete pustit již nyní a každý týden Vám přineseme další indicii. Na úvod začínáme jedním výtiskem Sluncesvitu - populárního císařského plátku. Také jsme pro vás připravili dvě výrazná zlepšení postav a jedno velmi poutavé zpestření . Obě novinky se týkají tvorby postav a brzy vás o těchto změnách budeme informovat více. Zatím můžete ve fóru tipovat, co by to tak mohlo být. Trojboj bude v tomto roce trvat jen jeden blok, takže o důvod více zapojit se do této týmové aktivity, kdy za jednu cenu si zahrajete tři hry. Více na samostatné stránce . Špína bude letos ve znamení „Osídlení nového města“ a gobliní ponorky budou bojovat o nová naleziště drahokamů. Určitě se bude hodit i trénink ve velení armádám, tudíž jistě přijde vhod Wargaming Tour 2010 . A lahodný zákusek na závěr: na sobotní večer pro vás plánujeme hromadné pobavení , jehož součástí by mělo být i klání v duchu televizních soutěží v režii týmu z Court of Moravia. Snad vás to množství novinek a jednotlivé zlepšováky těší a přijedete na GameCon. Koná se 15.-18.7.2010 v České Třebové . --> GameCon je tu pro vás, tak si přijďte zahrát!');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (174,'Návod - placení a slevy','placeni',33,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (174,'gamecon/placeni');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (174,'Návod - placení a slevy — GameCon 2011','gamecon,2011','Návod - placení a slevy');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (174,'<h1>Návod - placení a slevy</h1>

<h2>GameCoruny</h2>

<p>Peníze, které pošlete na účet, převedeme v poměru 1:1 na GameCoruny, z nichž budete hradit jednotlivé aktivity a ubytování. Před GameConem se můžete přihlašovat i bez dostatečného množství GameCorun na vašem GC účtu. Jednotlivé položky se vám tak budou odečítat do mínusu a nejpozději první den conu musíte nedoplatek uhradit (nebo si s námi dohodnout výjimku).</p>

<p><b>Číslo účtu:</b><br />
2800035147/2010<br />
2800035147/8330 - Pro Slovenskou Republiku (Platba v Eurech)</p>

<p><b>Jako Variabilní symbol použijte vaše ID uvedené v pravém horním rohu webu.</b></p>

<h2>Slevy</h2>

<p>Pokud si pošlete na svůj GC účet peníze do 10. července, získáte výraznou slevu na aktivity na GameConu: bude vám poskytnut Bonus, který budete moci využívat na aktivity na GameConu. <strong>Bonus NEBUDE možné použít na úhradu ubytování, placek, kostek a triček, které se musí hradit v plné ceně.</strong></p>

<ul>
  <li>Student získá Bonus rovnající se počtu jeho GameCorun (tedy pošle na účet 100 Kč a má tak 100 GameCorun a Bonus také 100).</li>
  <li>Ostatní získají jako Bonus 1/3 z počtu svých GameCorun zaokrouhleno nahoru (tedy pošlou 100 Kč a mají tak 100 GameCorun a Bonus 34).</li>
  <li>Kolik GameCorun a Bonusu máte na svém účtu, uvidíte vždy po přihlášení na našich stránkách v pravém horním poli. Přehled bude vždy uváděn jako "GCoruny: GameCoruny / Bonus" (tzn. např. "GCoruny: 100 / 100").</li>
  <li>GameCoruny pro vás tedy představují skutečně zaplacenou částku v penězích a Bonus znamená částku navíc poskytnutou vám organizátory místo slevy.</li>
</ul>

<p><strong>Praktické fungování slevy pak bude vypadat tak, že pokud si zaregistrujete aktivitu, bude se vám její cena odečítat jak z GameCorun, tak z Bonusu. Pokud jste studenti, bude se vám odečítat 50 % z GameCorun a 50 % z Bonusu. Pokud nejste studenti, pak 75 % z GameCorun a 25 % z Bonusu (ve výsledku tedy studenti mají 50% slevu, ostatní slevu 25%).</strong></p>

<p>Pokud nebudete mít žádný Bonus, budou se vám všechny aktivity odečítat jen ze standardních GameCorun. Aktivity nelze nikdy platit jen Bonusem – vždy musíte mít dostatek GameCorun.</p>

<p>Jedna rada - pokud si chcete na svůj účet poslat peníze před 10. červencem  a chcete poslat opravdu jen tolik, kolik potřebujete na ubytování, materiály a přihlášené aktivity, pošlete tolik, kolik máte GameCorun v mínusu (položka před lomítkem).</p>

<p>Pokud je vám na tomto systému cokoli nejasného, zeptejte se nás na fóru nebo nám napište email <a href="mailto:info@gamecon.cz">info@gamecon.cz</a>.</p>

<h2>Vyplacení zbývajících GameCorun</h2>

<p>GameCoruny si můžete ze svého účtu kdykoliv vybrat, a to buď v hotovosti na GameConu, nebo vám je můžeme vrátit na účet. Pokud je budete chtít vrátit na účet, napište nám to ze své emailové adresy, kterou jste uvedli při registraci na stránkách, na náš email info@gamecon.cz a my vám zbylé GameCoruny převedeme na účet, odkud jste je posílali.</p>

<p>Plná hodnota GameCorun se vrací jako Kč. Bonus se však nevyplácí a, v případě vyplacení GameCorun, propadá. Bonus nelze převést do dalšího roku a po skončení GameConu propadá.</p>

<p>Pokud ale pouze GameCoruny vyčerpáte, můžete je kdykoli doplnit vložením další částky na svůj účet. V takovém případě pak můžete dále využívat i zbývající Bonus (Bonus se bude na váš účet přičítat pouze při zaslání peněz do 10. července 2011).</p>

<h2>Odhlášení aktivit / nedostavení se na aktivitu</h2>

<p>V případě odhlášení aktivity nebo nedostavení se na ni mohou nastat čtyři situace a podle nich se aplikují případné storno poplatky. Pokud si aktivitu:</p>

<ul>
  <li>odhlásíte kdykoli do prezence na GameConu, přičtou se vám zpět na účet všechny GameCoruny i Bonus</li>
  <li>odhlásíte po své prezenci na GameConu, ale více než 6 hodin před začátkem přihlášené aktivity, vrátí se vám pouze 50 % odečtených GameCorun a Bonusu</li>
  <li>odhlásíte méně než 6 hodin, ale více než hodinu před jejím začátkem, vrátí se vám pouze 25 % odečtených GameCorun a Bonusu</li>
  <li>odhlásíte méně než hodinu před jejím začátkem nebo neodhlásíte vůbec, odečtené GameCoruny ani Bonus se vám nevrátí</li>
</ul>

<p>Tyto storno poplatky jsou nutné, protože pozdní odhlašování/neodhlašování z aktivit ztěžuje/znemožňuje jejich využití jinými zájemci a znepříjemňuje práci vypravěčům a organizátorům.</p>
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (174,'Návod - placení a slevy','Návod - placení a slevy GameCoruny Peníze, které pošlete na účet, převedeme v poměru 1:1 na GameCoruny, z nichž budete hradit jednotlivé aktivity a ubytování. Před GameConem se můžete přihlašovat i bez dostatečného množství GameCorun na vašem GC účtu. Jednotlivé položky se vám tak budou odečítat do mínusu a nejpozději první den conu musíte nedoplatek uhradit (nebo si s námi dohodnout výjimku). Číslo účtu: 2800035147/2010 2800035147/8330 - Pro Slovenskou Republiku (Platba v Eurech) Jako Variabilní symbol použijte vaše ID uvedené v pravém horním rohu webu. Slevy Pokud si pošlete na svůj GC účet peníze do 10. července, získáte výraznou slevu na aktivity na GameConu: bude vám poskytnut Bonus, který budete moci využívat na aktivity na GameConu. Bonus NEBUDE možné použít na úhradu ubytování, placek, kostek a triček, které se musí hradit v plné ceně. Student získá Bonus rovnající se počtu jeho GameCorun (tedy pošle na účet 100 Kč a má tak 100 GameCorun a Bonus také 100). Ostatní získají jako Bonus 1/3 z počtu svých GameCorun zaokrouhleno nahoru (tedy pošlou 100 Kč a mají tak 100 GameCorun a Bonus 34). Kolik GameCorun a Bonusu máte na svém účtu, uvidíte vždy po přihlášení na našich stránkách v pravém horním poli. Přehled bude vždy uváděn jako "GCoruny: GameCoruny / Bonus" (tzn. např. "GCoruny: 100 / 100"). GameCoruny pro vás tedy představují skutečně zaplacenou částku v penězích a Bonus znamená částku navíc poskytnutou vám organizátory místo slevy. Praktické fungování slevy pak bude vypadat tak, že pokud si zaregistrujete aktivitu, bude se vám její cena odečítat jak z GameCorun, tak z Bonusu. Pokud jste studenti, bude se vám odečítat 50 % z GameCorun a 50 % z Bonusu. Pokud nejste studenti, pak 75 % z GameCorun a 25 % z Bonusu (ve výsledku tedy studenti mají 50% slevu, ostatní slevu 25%). Pokud nebudete mít žádný Bonus, budou se vám všechny aktivity odečítat jen ze standardních GameCorun. Aktivity nelze nikdy platit jen Bonusem – vždy musíte mít dostatek GameCorun. Jedna rada - pokud si chcete na svůj účet poslat peníze před 10. červencem a chcete poslat opravdu jen tolik, kolik potřebujete na ubytování, materiály a přihlášené aktivity, pošlete tolik, kolik máte GameCorun v mínusu (položka před lomítkem). Pokud je vám na tomto systému cokoli nejasného, zeptejte se nás na fóru nebo nám napište email info@gamecon.cz . Vyplacení zbývajících GameCorun GameCoruny si můžete ze svého účtu kdykoliv vybrat, a to buď v hotovosti na GameConu, nebo vám je můžeme vrátit na účet. Pokud je budete chtít vrátit na účet, napište nám to ze své emailové adresy, kterou jste uvedli při registraci na stránkách, na náš email info@gamecon.cz a my vám zbylé GameCoruny převedeme na účet, odkud jste je posílali. Plná hodnota GameCorun se vrací jako Kč. Bonus se však nevyplácí a, v případě vyplacení GameCorun, propadá. Bonus nelze převést do dalšího roku a po skončení GameConu propadá. Pokud ale pouze GameCoruny vyčerpáte, můžete je kdykoli doplnit vložením další částky na svůj účet. V takovém případě pak můžete dále využívat i zbývající Bonus (Bonus se bude na váš účet přičítat pouze při zaslání peněz do 10. července 2011). Odhlášení aktivit / nedostavení se na aktivitu V případě odhlášení aktivity nebo nedostavení se na ni mohou nastat čtyři situace a podle nich se aplikují případné storno poplatky. Pokud si aktivitu: odhlásíte kdykoli do prezence na GameConu, přičtou se vám zpět na účet všechny GameCoruny i Bonus odhlásíte po své prezenci na GameConu, ale více než 6 hodin před začátkem přihlášené aktivity, vrátí se vám pouze 50 % odečtených GameCorun a Bonusu odhlásíte méně než 6 hodin, ale více než hodinu před jejím začátkem, vrátí se vám pouze 25 % odečtených GameCorun a Bonusu odhlásíte méně než hodinu před jejím začátkem nebo neodhlásíte vůbec, odečtené GameCoruny ani Bonus se vám nevrátí Tyto storno poplatky jsou nutné, protože pozdní odhlašování/neodhlašování z aktivit ztěžuje/znemožňuje jejich využití jinými zájemci a znepříjemňuje práci vypravěčům a organizátorům.');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (175,'Přehled registrace','prehled-registrace',33,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (175,'gamecon/prehled-registrace');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (175,'Přehled registrace — GameCon 2011','gamecon,2011','Přehled registrace');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (175,'<h1>Přehled registrace</h1>

<p>Na následujících řádcích jsme připravili přehled všech registrací a jejich stav. Pokud tě zajímají finanční informace, můžeš je získat na stránce <a href = "/gamecoruny">GameCoruny</a>.</p>

<strong>Registrace na GameCon 2011</strong>
<p>Pro zobrazení stavu své registrace se nejdříve přihlaš na svůj účet.</p>
 

    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (175,'Přehled registrace','Přehled registrace Na následujících řádcích jsme připravili přehled všech registrací a jejich stav. Pokud tě zajímají finanční informace, můžeš je získat na stránce GameCoruny . Registrace na GameCon 2011 Pro zobrazení stavu své registrace se nejdříve přihlaš na svůj účet.');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (176,'GameCon začal, veškeré registrace přes internet jsou ukončeny','prihlaska',33,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (176,'gamecon/prihlaska');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (176,'GameCon začal, veškeré registrace přes internet jsou ukončeny — GameCon 2011','gamecon,2011','GameCon začal, veškeré registrace přes internet jsou ukončeny');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (176,'<!--<h1 style = "color: red;">GameCon začal, veškeré registrace přes internet jsou ukončeny</h1>
<h2 style = "color: red;">Jakékoliv další změny jsou možné u infopultu v deskoherně</h2>-->
<h1>Přihláška</h1>
<p>Na této stránce se můžete přihlásit na GameCon 2011. V rámci přihlášky si vyberete ubytování a můžete si objednat GameCon tričko a placku. Pokud zaškrtnete, že jste student, ovlivní to výši vaší slevy a při prezenci na GameConu nám předložíte nějaký studentský průkaz nebo doklad o studiu.</p>
<p>Přihlášku budete moci přibližně až do konce června měnit. Na zastavení této možnosti vás včas upozorníme. V případě, že budete chtít GameCon tričko, budete muset alespoň toto tričko zaplatit nejpozději do konce června.</p>
<p>Před samotným přihlášením vám doporučujeme pročíst si článek k <a href = "/gamecon/prihlasovani-na-aktivity">přihlašování</a> a <a href = "/gamecon/placeni">placení</a>. Oba články důkladně popisují fungování nového systému - může se jevit složitější, ale jakmile si oba články pročtete, zjistíte, že přihlašovat se na aktivity na GameConu je hračka a můžete si jednoduše vytvářet a měnit vlastní program.</p>
<p><strong>Pro přihlášení se na GameCon musíte být zaregistrováni a přihlášeni na tomto webu!</strong></p>


    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (176,'GameCon začal, veškeré registrace přes internet jsou ukončeny','GameCon začal, veškeré registrace přes internet jsou ukončeny Jakékoliv další změny jsou možné u infopultu v deskoherně --> Přihláška Na této stránce se můžete přihlásit na GameCon 2011. V rámci přihlášky si vyberete ubytování a můžete si objednat GameCon tričko a placku. Pokud zaškrtnete, že jste student, ovlivní to výši vaší slevy a při prezenci na GameConu nám předložíte nějaký studentský průkaz nebo doklad o studiu. Přihlášku budete moci přibližně až do konce června měnit. Na zastavení této možnosti vás včas upozorníme. V případě, že budete chtít GameCon tričko, budete muset alespoň toto tričko zaplatit nejpozději do konce června. Před samotným přihlášením vám doporučujeme pročíst si článek k přihlašování a placení . Oba články důkladně popisují fungování nového systému - může se jevit složitější, ale jakmile si oba články pročtete, zjistíte, že přihlašovat se na aktivity na GameConu je hračka a můžete si jednoduše vytvářet a měnit vlastní program. Pro přihlášení se na GameCon musíte být zaregistrováni a přihlášeni na tomto webu!');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (177,'Přihlašování na GameConu','prihlasovani-na-aktivity',33,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (177,'gamecon/prihlasovani-na-aktivity');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (177,'Přihlašování na GameConu — GameCon 2011','gamecon,2011','Přihlašování na GameConu');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (177,'<h1>Přihlašování na GameConu</h1>

<h2>Jak se přihlásit na GameCon?</h2>

<ol>
  <li>Přihlaste se na web GameConu</li>
  <li>Nyní je vám přístupná možnost se přihlásit na GC2011</li>
  <li>Studenti zaškrtnou pole „student“</li>
</ol>

<p>Tím je vaše přihláška na GameCon 2011 hotová. Nyní můžete:</p>

<ul>
  <li>Zapisovat si jednotlivé aktivity (z důvodu kapacity doporučujeme přihlásit se co nejdříve)</li>
  <li>Objednat si ubytování</li>
  <li>Objednat si placku a triko GC 2011</li>
  <li>Objednat si kostku GC 2011</li>
</ul>

<h2>Jak se přihlásit na jednotlivé aktivity v rámci GC?</h2>

<p><strong>Mistrovství v Dračím doupěti</strong> – v menu Mistrovství v DrD. Zde můžete rovněž provést volbu herního bloku a PJ pro první část dobrodružství.</p> 

<p><strong>GameCon Trojboj</strong> – v menu GameCon Trojboj. Jakmile přihlásíte svůj tým, budete si moci vybrat blok, ve kterém odehrajete jednotlivé disciplíny.</p>

<p><strong>Volné hraní RPG, larpy a turnaje v deskových hrách</strong> – buď na stránce jednotlivé aktivity, nebo v programu.</p> 

<p><strong>Přednášky a dílny</strong> – účast na nich je zdarma. Registrace na ně není povinná a je zde pouze proto, abyste měli lepší přehled o svém programu.</p>

<h2>Jaké jsou možnosti ubytování?</h2>

<p>Pro Váš pobyt na GameConu si můžete vybrat ze dvou možností ubytování: ve třílůžkových pokojích internátu a ve vlastním spacáku ve třídách SOŠ a SOU v České Třebové. <strong>Obě varianty lze objednávat pouze do vyčerpání jejich kapacity.</strong></p>

<h3>Ubytování na třílůžkových pokojích</h3>
<p>Cena je letos 180 Kč za osobu a noc. Budete moci předem napsat, s kým chcete být na pokoji (pokud to bude možné, vyhovíme vám).</p>

<h3>Ubytování ve třídě a spaní ve vlastním spacáku</h3>
<p>Cena spacákového místa ve třídě je 70 Kč za osobu a noc. Spacáky nezajišťujeme, je potřeba mít vlastní.</p>

<h2>Možnosti placení</h2> 

<p>POZOR! KDYŽ ZAPLATÍTE DO 10. 7. 2011, DOSTANETE VÝRAZNOU SLEVU! Více informací <a href="/gamecon/placeni">zde</a>.</p> 

<p>Zaplatit můžete zaplatit předem převodem na náš účet nebo v hotovosti na místě. Při platbě předem proveďte platbu na náš účet číslo <strong>2800035147/2010</strong> nebo 2800035147/8330 (pro platby ze Slovenské Republiky v eurech) a jako <strong>variabilní symbol uveďte své ID</strong>, které vám bylo přiděleno při registraci na našich stránkách (po nalogování na stránkách se zobrazuje v pravém horním poli pod vaším loginem (přihlašovacím jménem)). Pokud své ID neuvedete, bude obtížné vaši platbu dohledat a přičíst vám peníze (<a href="/gamecon/placeni">GameCoruny</a>).</p>

<h2>Důležité upozornění:</h2>

<p>Nebudete-li mít aktivity, které už máte přihlášené, zaplaceny do 10. července 2011, budete z nich během několika dní po tomto datu (jakmile ověříme došlé platby) odhlášeni, aby byly uvolněny pro ostatní zájemce. <strong>Proto se vyplatí sledovat i již obsazené aktivity po tomto termínu – můžete získat uvolněné místo.</strong></p> 

<p>Pokud se na aktivity přihlásíte po 10. červenci 2011, bude nutné je zaplatit nejpozději v první den conu.</p>
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (177,'Přihlašování na GameConu','Přihlašování na GameConu Jak se přihlásit na GameCon? Přihlaste se na web GameConu Nyní je vám přístupná možnost se přihlásit na GC2011 Studenti zaškrtnou pole „student“ Tím je vaše přihláška na GameCon 2011 hotová. Nyní můžete: Zapisovat si jednotlivé aktivity (z důvodu kapacity doporučujeme přihlásit se co nejdříve) Objednat si ubytování Objednat si placku a triko GC 2011 Objednat si kostku GC 2011 Jak se přihlásit na jednotlivé aktivity v rámci GC? Mistrovství v Dračím doupěti – v menu Mistrovství v DrD. Zde můžete rovněž provést volbu herního bloku a PJ pro první část dobrodružství. GameCon Trojboj – v menu GameCon Trojboj. Jakmile přihlásíte svůj tým, budete si moci vybrat blok, ve kterém odehrajete jednotlivé disciplíny. Volné hraní RPG, larpy a turnaje v deskových hrách – buď na stránce jednotlivé aktivity, nebo v programu. Přednášky a dílny – účast na nich je zdarma. Registrace na ně není povinná a je zde pouze proto, abyste měli lepší přehled o svém programu. Jaké jsou možnosti ubytování? Pro Váš pobyt na GameConu si můžete vybrat ze dvou možností ubytování: ve třílůžkových pokojích internátu a ve vlastním spacáku ve třídách SOŠ a SOU v České Třebové. Obě varianty lze objednávat pouze do vyčerpání jejich kapacity. Ubytování na třílůžkových pokojích Cena je letos 180 Kč za osobu a noc. Budete moci předem napsat, s kým chcete být na pokoji (pokud to bude možné, vyhovíme vám). Ubytování ve třídě a spaní ve vlastním spacáku Cena spacákového místa ve třídě je 70 Kč za osobu a noc. Spacáky nezajišťujeme, je potřeba mít vlastní. Možnosti placení POZOR! KDYŽ ZAPLATÍTE DO 10. 7. 2011, DOSTANETE VÝRAZNOU SLEVU! Více informací zde . Zaplatit můžete zaplatit předem převodem na náš účet nebo v hotovosti na místě. Při platbě předem proveďte platbu na náš účet číslo 2800035147/2010 nebo 2800035147/8330 (pro platby ze Slovenské Republiky v eurech) a jako variabilní symbol uveďte své ID , které vám bylo přiděleno při registraci na našich stránkách (po nalogování na stránkách se zobrazuje v pravém horním poli pod vaším loginem (přihlašovacím jménem)). Pokud své ID neuvedete, bude obtížné vaši platbu dohledat a přičíst vám peníze ( GameCoruny ). Důležité upozornění: Nebudete-li mít aktivity, které už máte přihlášené, zaplaceny do 10. července 2011, budete z nich během několika dní po tomto datu (jakmile ověříme došlé platby) odhlášeni, aby byly uvolněny pro ostatní zájemce. Proto se vyplatí sledovat i již obsazené aktivity po tomto termínu – můžete získat uvolněné místo. Pokud se na aktivity přihlásíte po 10. červenci 2011, bude nutné je zaplatit nejpozději v první den conu.');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (178,'Program','program',33,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (178,'gamecon/program');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (178,'Program — GameCon 2011','gamecon,2011','Program');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (178,'<h1>Program</h1>
<p>
Prostřednictvím programu se můžete přihlašovat na jednotlivé aktivity, odhlašovat z nich a zjistit, jak volnou mají kapacitu (<a href = "/gamecon/prihlasovani-na-aktivity">informace o přihlašování</a> se nacházejí na vlastní stránce).<br />
</p>
<p>
<a href = "/program---tabulka.php" onclick = "window.open(this.href,\'_blank\'); return false">Celkový program GameConu 2010</a> naleznete na separátní stránce.
</p>
<p>
Pro lepší přehlednost vašich vlastních aktivit jsme pro vás připravili váš <a href = "/program-vlastni.php" onclick = "window.open(this.href,\'_blank\'); return false">vlastní program</a>, kde si můžete zkontrolovat a vytisknout, co všechno vás čeká.
</p>

<div class = "chyba_ramecek">
<p>
Program GameConu 2010 dáváme nyní dohromady a jak se bude postupně plnit, budeme jej odhalovat zde na stránkách.
</p>
</div>

<p>
Pokud vás samotné napadne, co byste v programu rádi uvítali nebo chtěli přispět vlastní aktivitou, neváhejte a ozvěte se nám na mail <a href = "mailto:info@gamecon.cz">info@gamecon.cz</a>, budeme rádi za každý nápad a nabídku. Děláme to přece pro vás. :-)
</p>
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (178,'Program','Program Prostřednictvím programu se můžete přihlašovat na jednotlivé aktivity, odhlašovat z nich a zjistit, jak volnou mají kapacitu ( informace o přihlašování se nacházejí na vlastní stránce). Celkový program GameConu 2010 naleznete na separátní stránce. Pro lepší přehlednost vašich vlastních aktivit jsme pro vás připravili váš vlastní program , kde si můžete zkontrolovat a vytisknout, co všechno vás čeká. Program GameConu 2010 dáváme nyní dohromady a jak se bude postupně plnit, budeme jej odhalovat zde na stránkách. Pokud vás samotné napadne, co byste v programu rádi uvítali nebo chtěli přispět vlastní aktivitou, neváhejte a ozvěte se nám na mail info@gamecon.cz , budeme rádi za každý nápad a nabídku. Děláme to přece pro vás. :-)');

