INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (180,'Ubytování','ubytovani',33,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (180,'gamecon/ubytovani');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (180,'Ubytování — GameCon 2011','gamecon,2011','Ubytování');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (180,'<h1>Ubytování</h1>
<p>
Máte možnost vybrat si z následujících alternativ ubytování (pokud nebude vyčerpána jejich kapacita).
</p>

<h2>Ubytování na třílůžkových pokojích</h2> 
<p>
Veškeré aktivity GameConu (až na venkovní) se odehrávají v budově SOŠ a SOU v České Třebové, kde mají také internát, ve kterém Vám nabízíme ubytování. Jinak řečeno, můžete bydlet přímo v epicentru dění.
</p>
<p>
Pokoje jsou třílůžkové a cena je letos pouze 180 Kč za osobu a noc. Přiřazování pokojů budeme zajišťovat my a tak si budete moci předem napsat s kým chcete být na pokoji (pokud to bude možné, vyhovíme vám). 
</p>
<p>
Pokud dojde k vyčerpání lůžkové kapacity internátu, budeme zajišťovat ubytování v nedaleké ubytovně, případně ve třídách ve vlastním spacáku. 
</p>

<h2>Ubytování ve třídě a spaní ve spacáku</h2> 
<p>
Pokud bude využita s internátem dohodnutá ubytovací kapacita lůžkových pokojů, připravili jsme pro vás i variantu dobrodružnější a to hromadné přespání ve třídách SOŠ a SOU v České Třebové ve vlastním spacáku.
</p>
<p>
Již v průběhu registrace můžete zatrhnout možnost, že pokud se tato varianta uvolní, dáváte ji přednost před ubytováním na lůžkovém pokoji. Vzhledem k tomu, že spacákových míst bude omezené množství, budeme upřednostňovat lidi, kteří tuto volbu ve svém nastavení zatrhli dříve.
</p>
<p>
Cena spacákového místa ve třídě je 70 Kč za osobu a noc. Spacáky nezajišťujeme, je potřeba mít vlastní.
</p>
    </div>
  </div>');
