INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (182,'Archiv LARP 2008','archiv-larp-2008',38,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (182,'larp/archiv-larp-2008');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (182,'Archiv LARP 2008 — GameCon 2011','gamecon,2011','Archiv LARP 2008');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (182,'<h1>Archiv LARP 2008</h1>
<a name="cela"></a>
<h2>Cela - fantasy LARP</h2>
<div class="akce-archiv">
<div><i>Místodržící byl zabit. Před desítkami svědků přímo v průvodu a před očima vlastní gardy. Když se jim rovnou pod nohama převrhl vozík se zeleninou a na chvíli tak upoutal jejich pozornost, místodržící padl bez dechu na ulici. Všichni to viděli.</i></div>
<div><i>Jiné místo, pár hodin poté. Chodbou se nese jen prskání a hukot pochodní. V tichu, které kolem panuje, se zdá být až neuvěřitelně hlasité. Nebo to něco hučí v mé hlavě? Na spánku troška zaschlé krve. Za zády chladná a cizí kamenná stěna, pod sebou vrstvička žluklé slámy. Trocha světla prosvítá z chodby přes mříže. Přes...mříže. Oči přivykají temnotě a odhalují, že tu nejsem sám.</i></div>
<div><i>Hlava padla a já byl při tom; tak mysl zaplavilo náhlé poznání. Zatraceně.</i></div>
<div>Cela je krátký LARP postavený na volném motivu fantastického města, jehož složitosti hru nikterak výrazně nezasáhnou. Devět až dvanáct hráčských postav v průběhu čtyř hodin odhalí tajemství, která snad nikdy neměla být odhalena a možná zjistí, kdo stál za spiknutím proti hlavě města. To vše se jim podaří v jedné jediné cele, kde jsou uvězněni, protože byli příliš blízko atentátu, protože jsou vrahy, zloději, násilníky, žebráky, prostitutkami nebo prostě jen vypadají podezřele. A všichni do jednoho jsou samozřejmě nevinní jako lilie. Nejméně do chvíle, než se ukáže opak.</div>
<div>Pokud si chcete udělat bližší obrázek, nahlédněte do <a onclick = "window.open(this.href,\'_blank\'); return false" href="http://www.courtofmoravia.com/files/com-cela-vytah.pdf">stručného popisu světa</a>. Ušetříte si tak čtení před samotnou hrou. Pokud to však nestihnete, nezoufejte, na místě bude popis světa volně k dispozici.</div>
</div>

<a name="spina"></a>
<h2>Špína</h2>
<div class="akce-archiv">
<div>Akční městská hra s prvky hraní role a spoustou vodních pistolí.</div>
<div>Konečně… po tolika letech. Mexicos, Niggas a Yakuze se v krajně nestabilní spolupráci konečně podařilo vypráskat poslední zbytky Originals gangu z předměstí. Jenže tím tohle spojenectví taky skončilo – někdo to musí vzít pevně do rukou, správně? Žádný nablblý triumvirát nepřichází v úvahu a ustoupit samozřejmě nikdo nechce. Padlo pár výstřelů a pár hlav. Vlastně se proslýchá, že padlo víc hlav než výstřelů z místních hlavní, ale po záhadách teď nikdo nepátrá. Všichni mají na krku daleko větší problém – vlastní kejhák, jehož ochrana se může velice snadno překřížit s plány vlastního šéfa.</div>
<div>Špína je akční městská hra na tři slunečné hodiny plná stříkajících vodních pistolí, necenzurovaného zločineckého výraziva, nebezpečí a euforie z jeho odvracení. Jako hráči ztvárníte jednoduché postavy stoupenců jedné ze tří znepřátelených stran a vydáte se do ulic (pro naše účely trochu přesunutého) San Diega, abyste zapíchli trn konkurenci přinejmenším do oka. Špína se bude ve hře přehazovat hned na několika úrovních, takže můžete sledovat příběhovou linii plněním akcí zadaných vaším bossem, vyžívat se ve shromažďování peněz a moci, nebo prostě jen vzít (stříkací) bouchačku a někoho odprásknout.</div>
<div>Pro vyjádření příslušnosti k jedné ze stran si s sebou dovezte červenou kšiltovku nebo šátek, chcete-li být členem černošských Niggas, žlutý šátek pro Mexicos a něco černého, alespoň tričko, jestliže aspirujete na člena Yakuzy. Stříkací pistole nechte doma, budou na místě.</div>
</div>

    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (182,'Archiv LARP 2008','Archiv LARP 2008 Cela - fantasy LARP Místodržící byl zabit. Před desítkami svědků přímo v průvodu a před očima vlastní gardy. Když se jim rovnou pod nohama převrhl vozík se zeleninou a na chvíli tak upoutal jejich pozornost, místodržící padl bez dechu na ulici. Všichni to viděli. Jiné místo, pár hodin poté. Chodbou se nese jen prskání a hukot pochodní. V tichu, které kolem panuje, se zdá být až neuvěřitelně hlasité. Nebo to něco hučí v mé hlavě? Na spánku troška zaschlé krve. Za zády chladná a cizí kamenná stěna, pod sebou vrstvička žluklé slámy. Trocha světla prosvítá z chodby přes mříže. Přes...mříže. Oči přivykají temnotě a odhalují, že tu nejsem sám. Hlava padla a já byl při tom; tak mysl zaplavilo náhlé poznání. Zatraceně. Cela je krátký LARP postavený na volném motivu fantastického města, jehož složitosti hru nikterak výrazně nezasáhnou. Devět až dvanáct hráčských postav v průběhu čtyř hodin odhalí tajemství, která snad nikdy neměla být odhalena a možná zjistí, kdo stál za spiknutím proti hlavě města. To vše se jim podaří v jedné jediné cele, kde jsou uvězněni, protože byli příliš blízko atentátu, protože jsou vrahy, zloději, násilníky, žebráky, prostitutkami nebo prostě jen vypadají podezřele. A všichni do jednoho jsou samozřejmě nevinní jako lilie. Nejméně do chvíle, než se ukáže opak. Pokud si chcete udělat bližší obrázek, nahlédněte do stručného popisu světa . Ušetříte si tak čtení před samotnou hrou. Pokud to však nestihnete, nezoufejte, na místě bude popis světa volně k dispozici. Špína Akční městská hra s prvky hraní role a spoustou vodních pistolí. Konečně… po tolika letech. Mexicos, Niggas a Yakuze se v krajně nestabilní spolupráci konečně podařilo vypráskat poslední zbytky Originals gangu z předměstí. Jenže tím tohle spojenectví taky skončilo – někdo to musí vzít pevně do rukou, správně? Žádný nablblý triumvirát nepřichází v úvahu a ustoupit samozřejmě nikdo nechce. Padlo pár výstřelů a pár hlav. Vlastně se proslýchá, že padlo víc hlav než výstřelů z místních hlavní, ale po záhadách teď nikdo nepátrá. Všichni mají na krku daleko větší problém – vlastní kejhák, jehož ochrana se může velice snadno překřížit s plány vlastního šéfa. Špína je akční městská hra na tři slunečné hodiny plná stříkajících vodních pistolí, necenzurovaného zločineckého výraziva, nebezpečí a euforie z jeho odvracení. Jako hráči ztvárníte jednoduché postavy stoupenců jedné ze tří znepřátelených stran a vydáte se do ulic (pro naše účely trochu přesunutého) San Diega, abyste zapíchli trn konkurenci přinejmenším do oka. Špína se bude ve hře přehazovat hned na několika úrovních, takže můžete sledovat příběhovou linii plněním akcí zadaných vaším bossem, vyžívat se ve shromažďování peněz a moci, nebo prostě jen vzít (stříkací) bouchačku a někoho odprásknout. Pro vyjádření příslušnosti k jedné ze stran si s sebou dovezte červenou kšiltovku nebo šátek, chcete-li být členem černošských Niggas, žlutý šátek pro Mexicos a něco černého, alespoň tričko, jestliže aspirujete na člena Yakuzy. Stříkací pistole nechte doma, budou na místě.');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (183,'GameCon 2011 se blíží','cez-mrtvoly',38,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (183,'larp/cez-mrtvoly');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (183,'GameCon 2011 se blíží — GameCon 2011','gamecon,2011','GameCon 2011 se blíží');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (183,'<h1>GameCon 2011 se blíží</h1>

<!--<h2>Organizační změny</h2>
<p>
Dovolte nám seznámit vás s velkou organizační novinkou. Petr „Gandalf“ Holub, který stál v čele organizačního týmu GameConu poslední dva roky, ještě v průběhu letošního GameConu v České Třebové předal post hlavního organizátora Matouši „Erricu“ Ježkovi. Jelikož se mu totiž letos narodily dvě holčičky, po důkladném uvážení se musel rozhodnout k tomuto kroku, neboť vedení organizačního týmu a nově rozrostlou rodinu a normální práci by nebylo možné skloubit tak, aby jedno netrpělo.
</p>
<p>
Nic to však nemění na tom, že další ročník GameConu už pro vás připravujeme a o novinkách vás budeme průběžně informovat jak tady, tak na <a href = "http://www.facebook.com/group.php?sid=1a65342dd9cba753975=bb963632e2a7&gid=93879753711&ref=search#!/gamecon" onclick = "window.open(this.href,\'_blank\'); return false">facebooku</a>.
</p>
<p>
Organizační tým GameConu
</p>

<h2>GameCon Teaser</h2>
<object width="470" height="265"><param name="allowfullscreen" value="true" /><param name="allowscriptaccess" value="always" /><param name="movie" value="http://vimeo.com/moogaloop.swf?clip_id=12709571&amp;server=vimeo.com&amp;show_title=1&amp;show_byline=1&amp;show_portrait=0&amp;color=&amp;fullscreen=1" /><embed src="http://vimeo.com/moogaloop.swf?clip_id=12709571&amp;server=vimeo.com&amp;show_title=1&amp;show_byline=1&amp;show_portrait=0&amp;color=&amp;fullscreen=1" type="application/x-shockwave-flash" allowfullscreen="true" allowscriptaccess="always" width="470" height="265"></embed></object>-->

<h2>Čtyři dny plné zábavy a napětí nad hrami všeho druhu</h2>
<p>Ve dnech <strong>21.-24.7.2011</strong> se v <strong>České Třebové</strong> uskuteční již 17. ročník herního setkání <strong>GameCon</strong>. Je to příležitost pro všechny hráče a fanoušky nepočítačových her z České republiky a Slovenska setkat se s ostatními, zahrát si hry, vyměnit zkušenosti a pobavit se. Co vás během čtyř dnů na GameConu čeká?
<ul>
<li><a href="/deskove-hry/o-deskovych-hrach-na-gc">Deskové hry</a> (Osadníci z Katanu, Carcassonne a mnohé další)</li>
<li>Velké množství her na hraní rolí neboli <a href="/rpg/o-rpg-na-gc">RPG</a>. Můžete si vyzkoušet i herní systémy, které doma ani nemáte.</li>
<li>Hry naživo neboli <a href = "/larp/o-larpech-na-gc">LARP</a>, kdy prožitky své postavy vyzkoušíte na vlastní kůži.</li>
<li><a href = "/mistrovstvi-v-drd/o-mistrovstvi-v-drd">Mistrovství v Dračím doupěti</a>, letos pro změnu z pozice obyčejných obyvatel Císařství.</li>
<li>A spousta dalších aktivit, jako třeba bitva miniaturních armád ve <a href = "/wargaming/o-wargamingu-na-gc">Wargamingu</a>, nebo poutavé <a href = "/prednasky/o-prednaskach-na-gc">přednášky</a>.</li>
<li>Sobotní party</li>
</ul>
</p>

<p>Že neznáte žádnou z těchto her? Nevadí.<strong>Pravidla vám rádi vysvětlíme na místě</strong> a poradíme i s výběrem her nebo naplánováním programu. <strong>Neváhejte tedy a přijeďte.</strong> Slibujeme vám spoustu her, zábavy a přátelské atmosféry. Nemáte volné celé čtyři dny? Nevadí! <strong>GameCon</strong> má co nabídnout každý den.</strong></p>
<!--<p>Jednoduchý návod jak se <strong>přihlásit na GameCon</strong> a všechny důležité informace o <strong>registraci</strong>, možnostech <strong>ubytování</strong> a <strong>platbách</strong> naleznete <a href="/navod/">zde</a>.</p>-->
<p>O novinkách vás budeme průběžně informovat jak zde, tak na <a href = "http://www.facebook.com/gamecon" onclick = "window.open(this.href,\'_blank\'); return false">Facebooku</a>.</p>

<a name=novinky></a>
<h2>Letošní novinky</h2>
<p>Tak jako každý rok se snažíme, aby GameCon i letos nabídl něco nového. Loni se con přestěhoval do České Třebové, což přineslo mimo jiné možnost nabídnout všechny aktivity pod jednou střechou, prostornou a dobře větratelnou místnost pro deskohernu a levnější ubytování. Na co se můžete těšit letos?</p>
<ul>
<li>Pro účastníky GameConu ze Slovenska jsme připravili <strong>možnost platit v eurech</strong>.</li>
<li>Všem budou přístupné <strong>kuchyňky</strong>, ve kterých si bude možné uvařit jídlo.</li>
<li>GameCon se bude odehrávat <strong>ve znamení Antiky</strong>.</li>
<li>Je pro vás připravena <strong>spousta nových her</strong> na všech frontách.</li>
<li>Na programu bude také <strong>křest Dračího doupěte II</strong>.</li>
</ul>

<!--<p>
Patrně nejvýraznější změnou je přestěhování conu do České Třebové. Tento manévr nám poskytl hned několik výhod:
<ul>
	<li>Předně jsou to <strong>všechny aktivity pod jednou střechou</strong>, nebude potřeba kamkoliv přebíhat nebo složitě bloudit mezi jednotlivými komplexy budov.</li>
	<li>Zároveň jsou místnosti pro jednotlivé aktivity dostatečně velké a vzdušné.</li>
	<li>Především místnost <a href = "/deskove-hry/deskoherna">deskoherny</a> je úchvatně prostorná a dobře větratelná. Už nehrozí, že bychom se v dobré víře ušlapávali nebo letním parnu dusili. Tento rok to bude konečně ta <strong>dobře přístupná aréna plná deskových her</strong> připravená na lačné hráče. Pro zvědavce jsme jako důkaz připravili alespoň dvě fotografie z naších průzkumných výprav – více v <a href = "/deskove-hry/deskoherna">deskoherně</a>.</li>
	<li>Vítanou změnou bude určitě i <strong>levnější ubytování</strong>. Letos bude stát jedna noc v třílůžkovém pokoji pouhých 170 Kč (oproti loňským dvěma stovkám, takže za tři noci nakonec ušetříte téměř stokorunu).</li>
	<li>Přijde vám lůžkový pokoj příliš drahý a komfortní? Pak jistě uvítáte další zlepšení a tím je <strong>možnost spát hromadně ve třídě ve vlastním spacáku</strong> a to za pouhých 60 Kč. Více o ubytovacích možnostech se dočtete v <a href = "/gamecon/ubytovani">ubytování</a>.</li>
	<li>Přesunem do jiného města jsme také získali kousek od naší budovy velkou nafukovací halu, kterou budeme moci využít v nepřízni počasí na nějakou velmi hromadnou akci. No není takový bonus skvělý?</li>
	<li>A snad některé z vás potěší i dobrá dopravní dostupnost pro celou republiku. Jsme uprostřed státu, tak snad to má každý kousek. :-)</li>
</ul>
</p>

<p>
Jak můžete vidět, přesun na nové místo pro vás znamená samé výhody. Nespokojíme se však jen s novým územím a jeho přidanými hodnotami, pokračujeme dál ve zpestřujících zlepšovácích:
</p>
<p>
<ul>
	<li>Velká novinka hned rovnou na začátek: <strong>popré</strong> bude <strong>celý GameCon v duchu nějakého tématu</strong>, tentokrát to bude <strong>exodus</strong> a spíše než vyhnání z ráje to bude jeho hledání. V následujících dnech vám přineseme bližší informace a vy se můžete těšit, že s tím bude spojena spousta her a zábavné atmosféry.</li>
	<li><strong>Mistrovství v Dračím doupěti</strong> bude zase o něco blíž vám hráčům. Vyslyšeli jsme vaše dobré připomínky a rady, důkladně si přečetli reakce ve <a href = "/forum/mistrovstvi_v_drd">fóru</a> a vyšli vám vstříc.<br />
Do odkrývání tajů dobrodružství se můžete pustit již nyní a každý týden Vám přineseme další indicii. Na úvod začínáme jedním výtiskem <a href = "/mistrovstvi-v-drd/sluncesvit-cisarske-noviny">Sluncesvitu</a> - populárního císařského plátku.<br />
Také jsme pro vás připravili <strong>dvě výrazná zlepšení postav</strong> a <strong>jedno velmi poutavé zpestření</strong>. Obě novinky se týkají <a href = "/mistrovstvi-v-drd/pravidla-pro-tvorbu-postav">tvorby postav</a> a brzy vás o těchto změnách budeme informovat více. Zatím můžete ve <a href = "/forum/mistrovstvi_v_drd">fóru</a> tipovat, co by to tak mohlo být.</li>
	<li><strong>Trojboj</strong> bude v tomto roce trvat jen jeden blok, takže o důvod více zapojit se do této týmové aktivity, kdy za jednu cenu si zahrajete tři hry. Více na <a href = "/gamecon-trojboj/o-gamecon-trojboji">samostatné stránce</a>.</li>
	<li><strong>Špína</strong> bude letos ve znamení „Osídlení nového města“ a <strong>gobliní ponorky</strong> budou bojovat o nová naleziště drahokamů.</li>
	<li>Určitě se bude hodit i trénink ve velení armádám, tudíž jistě přijde vhod <a href = "/wargaming/wargaming-tour-2010">Wargaming Tour 2010</a>.</li>
	<li>A lahodný zákusek na závěr: <strong>na sobotní večer</strong> pro vás plánujeme <strong>hromadné pobavení</strong>, jehož součástí by mělo být i <strong>klání v duchu televizních soutěží</strong> v režii týmu z Court of Moravia.</li>
</ul>
</p>

<p>
Snad vás to množství novinek a jednotlivé zlepšováky těší a přijedete na GameCon. Koná se <strong>15.-18.7.2010 v&nbsp;České Třebové</strong>.
</p>-->

<h3>GameCon je tu pro vás, tak si přijďte zahrát!</h3>
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (183,'GameCon 2011 se blíží','GameCon 2011 se blíží Organizační změny Dovolte nám seznámit vás s velkou organizační novinkou. Petr „Gandalf“ Holub, který stál v čele organizačního týmu GameConu poslední dva roky, ještě v průběhu letošního GameConu v České Třebové předal post hlavního organizátora Matouši „Erricu“ Ježkovi. Jelikož se mu totiž letos narodily dvě holčičky, po důkladném uvážení se musel rozhodnout k tomuto kroku, neboť vedení organizačního týmu a nově rozrostlou rodinu a normální práci by nebylo možné skloubit tak, aby jedno netrpělo. Nic to však nemění na tom, že další ročník GameConu už pro vás připravujeme a o novinkách vás budeme průběžně informovat jak tady, tak na facebooku . Organizační tým GameConu GameCon Teaser --> Čtyři dny plné zábavy a napětí nad hrami všeho druhu Ve dnech 21.-24.7.2011 se v České Třebové uskuteční již 17. ročník herního setkání GameCon . Je to příležitost pro všechny hráče a fanoušky nepočítačových her z České republiky a Slovenska setkat se s ostatními, zahrát si hry, vyměnit zkušenosti a pobavit se. Co vás během čtyř dnů na GameConu čeká? Deskové hry (Osadníci z Katanu, Carcassonne a mnohé další) Velké množství her na hraní rolí neboli RPG . Můžete si vyzkoušet i herní systémy, které doma ani nemáte. Hry naživo neboli LARP , kdy prožitky své postavy vyzkoušíte na vlastní kůži. Mistrovství v Dračím doupěti , letos pro změnu z pozice obyčejných obyvatel Císařství. A spousta dalších aktivit, jako třeba bitva miniaturních armád ve Wargamingu , nebo poutavé přednášky . Sobotní party Že neznáte žádnou z těchto her? Nevadí. Pravidla vám rádi vysvětlíme na místě a poradíme i s výběrem her nebo naplánováním programu. Neváhejte tedy a přijeďte. Slibujeme vám spoustu her, zábavy a přátelské atmosféry. Nemáte volné celé čtyři dny? Nevadí! GameCon má co nabídnout každý den. Jednoduchý návod jak se přihlásit na GameCon a všechny důležité informace o registraci , možnostech ubytování a platbách naleznete zde . --> O novinkách vás budeme průběžně informovat jak zde, tak na Facebooku . Letošní novinky Tak jako každý rok se snažíme, aby GameCon i letos nabídl něco nového. Loni se con přestěhoval do České Třebové, což přineslo mimo jiné možnost nabídnout všechny aktivity pod jednou střechou, prostornou a dobře větratelnou místnost pro deskohernu a levnější ubytování. Na co se můžete těšit letos? Pro účastníky GameConu ze Slovenska jsme připravili možnost platit v eurech . Všem budou přístupné kuchyňky , ve kterých si bude možné uvařit jídlo. GameCon se bude odehrávat ve znamení Antiky . Je pro vás připravena spousta nových her na všech frontách. Na programu bude také křest Dračího doupěte II . Patrně nejvýraznější změnou je přestěhování conu do České Třebové. Tento manévr nám poskytl hned několik výhod: Předně jsou to všechny aktivity pod jednou střechou , nebude potřeba kamkoliv přebíhat nebo složitě bloudit mezi jednotlivými komplexy budov. Zároveň jsou místnosti pro jednotlivé aktivity dostatečně velké a vzdušné. Především místnost deskoherny je úchvatně prostorná a dobře větratelná. Už nehrozí, že bychom se v dobré víře ušlapávali nebo letním parnu dusili. Tento rok to bude konečně ta dobře přístupná aréna plná deskových her připravená na lačné hráče. Pro zvědavce jsme jako důkaz připravili alespoň dvě fotografie z naších průzkumných výprav – více v deskoherně . Vítanou změnou bude určitě i levnější ubytování . Letos bude stát jedna noc v třílůžkovém pokoji pouhých 170 Kč (oproti loňským dvěma stovkám, takže za tři noci nakonec ušetříte téměř stokorunu). Přijde vám lůžkový pokoj příliš drahý a komfortní? Pak jistě uvítáte další zlepšení a tím je možnost spát hromadně ve třídě ve vlastním spacáku a to za pouhých 60 Kč. Více o ubytovacích možnostech se dočtete v ubytování . Přesunem do jiného města jsme také získali kousek od naší budovy velkou nafukovací halu, kterou budeme moci využít v nepřízni počasí na nějakou velmi hromadnou akci. No není takový bonus skvělý? A snad některé z vás potěší i dobrá dopravní dostupnost pro celou republiku. Jsme uprostřed státu, tak snad to má každý kousek. :-) Jak můžete vidět, přesun na nové místo pro vás znamená samé výhody. Nespokojíme se však jen s novým územím a jeho přidanými hodnotami, pokračujeme dál ve zpestřujících zlepšovácích: Velká novinka hned rovnou na začátek: popré bude celý GameCon v duchu nějakého tématu , tentokrát to bude exodus a spíše než vyhnání z ráje to bude jeho hledání. V následujících dnech vám přineseme bližší informace a vy se můžete těšit, že s tím bude spojena spousta her a zábavné atmosféry. Mistrovství v Dračím doupěti bude zase o něco blíž vám hráčům. Vyslyšeli jsme vaše dobré připomínky a rady, důkladně si přečetli reakce ve fóru a vyšli vám vstříc. Do odkrývání tajů dobrodružství se můžete pustit již nyní a každý týden Vám přineseme další indicii. Na úvod začínáme jedním výtiskem Sluncesvitu - populárního císařského plátku. Také jsme pro vás připravili dvě výrazná zlepšení postav a jedno velmi poutavé zpestření . Obě novinky se týkají tvorby postav a brzy vás o těchto změnách budeme informovat více. Zatím můžete ve fóru tipovat, co by to tak mohlo být. Trojboj bude v tomto roce trvat jen jeden blok, takže o důvod více zapojit se do této týmové aktivity, kdy za jednu cenu si zahrajete tři hry. Více na samostatné stránce . Špína bude letos ve znamení „Osídlení nového města“ a gobliní ponorky budou bojovat o nová naleziště drahokamů. Určitě se bude hodit i trénink ve velení armádám, tudíž jistě přijde vhod Wargaming Tour 2010 . A lahodný zákusek na závěr: na sobotní večer pro vás plánujeme hromadné pobavení , jehož součástí by mělo být i klání v duchu televizních soutěží v režii týmu z Court of Moravia. Snad vás to množství novinek a jednotlivé zlepšováky těší a přijedete na GameCon. Koná se 15.-18.7.2010 v České Třebové . --> GameCon je tu pro vás, tak si přijďte zahrát!');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (184,'Game Over','game-over',38,0,0);
