INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (185,'Klub sebevrahů','klub-sebevrahu',38,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (185,'larp/klub-sebevrahu');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (185,'Klub sebevrahů — GameCon 2011','gamecon,2011','Klub sebevrahů');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (185,'<h1>Klub sebevrahů</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/klub-sebevrahu.gif" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>organizátor</strong><br />Veronika "Lothmíril" Frankovská<br />
  <strong>čas akce</strong><br />čtvrtek 15.7 - 20:00 až 24:00  <br />neděle 18.7 - 9:00 až 13:00  <br />
 
</div>
</p>
   <p style = "clear: both;">
Je podzim roku 1888. Celý Londýn překryl šedý závoj mlhy a už několik dní slabě mrholí. Z Emersonovy ulice se line nazelenalý svit. Z řady zašlých cihelných fasád tu vyčnívá jedna šedá, kamenná. Špinavá dešťová voda stéká po mosazné cedulce v černých rýhách písmen. Gentlemans Club. Members only. Nic víc.
</p>
<p>
Staň se členem tohoto exkluzivního klubu. Počet míst je omezený a není jich mnoho. Ty však jsi jeden ze šťastlivců, který se může stát doživotním členem. Jediné, co pro to musíš udělat, je říci ano a dostavit se do Emersonovy ulice v době zasedání klubu.
</p>
<p>
Klub sebevrahů je již klasický komorní larp z dílny Court of Moravia. Na začátku hry dostanete své role na listu A4 a po vysvětlení pár pojmů či zodpovězení dotazů se vrhnete do samotné hry z prostředí viktoriánské Anglie. Pokud byste rádi o herním prostředí a o této době věděli něco víc, dřív než začnete hrát, doporučujeme prostudovat si herní informace.

</p>

<p>
<ul>
<li>Více informací: <a href = "http://www.courtofmoravia.com/larpy/klub-sebevrahu/" onclick = "window.open(this.href,\'_blank\'); return false">courtofmoravia.com/larpy/klub-sebevrahu/</a> </li>
<li>Materiály ke Klubu sebevrahů: <a href = "http://www.courtofmoravia.com/files/ks_obecne.pdf" onclick = "window.open(this.href,\'_blank\'); return false">courtofmoravia.com/files/ks_obecne.pdf</a></li>

                      <!--<li>
        <a href = "/larp/prehled-larpu-na-gc2010">Přehled larpů na GameConu 2010</a>      </li>-->
    </ul>
  </p>
  <div style = "width: 100%; float: left;">
    <div style = "width: 50%; text-align: left; float: left; padding-top: 20px; padding-bottom: 15px;">&laquo; <a href = "/larp/cez-mrtvoly">Cez mŕtvoly</a></div>    <div style = "width: 50%; text-align: right; float: right; padding-top: 20px; padding-bottom: 15px;"><a href = "/larp/podraz-2010">Podraz (2010)</a> &raquo;</div>  </div>
  
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (185,'Klub sebevrahů','Klub sebevrahů organizátor Veronika "Lothmíril" Frankovská čas akce čtvrtek 15.7 - 20:00 až 24:00 neděle 18.7 - 9:00 až 13:00 Je podzim roku 1888. Celý Londýn překryl šedý závoj mlhy a už několik dní slabě mrholí. Z Emersonovy ulice se line nazelenalý svit. Z řady zašlých cihelných fasád tu vyčnívá jedna šedá, kamenná. Špinavá dešťová voda stéká po mosazné cedulce v černých rýhách písmen. Gentlemans Club. Members only. Nic víc. Staň se členem tohoto exkluzivního klubu. Počet míst je omezený a není jich mnoho. Ty však jsi jeden ze šťastlivců, který se může stát doživotním členem. Jediné, co pro to musíš udělat, je říci ano a dostavit se do Emersonovy ulice v době zasedání klubu. Klub sebevrahů je již klasický komorní larp z dílny Court of Moravia. Na začátku hry dostanete své role na listu A4 a po vysvětlení pár pojmů či zodpovězení dotazů se vrhnete do samotné hry z prostředí viktoriánské Anglie. Pokud byste rádi o herním prostředí a o této době věděli něco víc, dřív než začnete hrát, doporučujeme prostudovat si herní informace. Více informací: courtofmoravia.com/larpy/klub-sebevrahu/ Materiály ke Klubu sebevrahů: courtofmoravia.com/files/ks_obecne.pdf Přehled larpů na GameConu 2010 --> « Cez mŕtvoly Podraz (2010) »');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (186,'O larpech na GameConu','o-larpech-na-gc',38,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (186,'larp/o-larpech-na-gc');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (186,'O larpech na GameConu — GameCon 2011','gamecon,2011','O larpech na GameConu');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (186,'<h1>O larpech na GameConu</h1>

<p>V letošním roce se nám na GameConu rozrostla sekce larpů o nové a nadějné autory těchto her. Můžete si vybrat z šesti. Přijďte si vyzkoušet jaké by to bylo v kůži jednoho z radních v tom nejšílenějším městě pod sluncem. Vžijte se do role jednoho z pacientů psychiatrického ústavu a nebo buďte prostě tím nejdrsnějším poldou v té nejšpinavější čtvrti ve městě. Prožijte nezapomenutelné chvíle. Již na letošním GameConu.</p>

<h2>Netušíte, co to larp je?</h2> 

<p>Larp je taková lehká divadelní improvizace, ve které se na několik hodin ponoříte do jiného světa - chcete být pašerákem diamantů nebo třeba Trinity z Matrixu? V larpu jimi opravdu budete.</p>

<p>Nemáte scénář jako např. herci ve filmu. Vy sami jste tvůrci svého příběhu. Svou roli hrajete podobně jako v divadle, nehrajete však pro diváky, ale pro sebe navzájem.</p>

<h2>Netušíte co to je komorní larp ?</h2>

<p>Komorní larpy jsou krátké hry pro malý počet účastníků. Hrají se v komorním prostředí (místnost) a kladou důraz na hlubší ztvárnění role. Častěji jsou účastníky starší hráči.</p>
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (186,'O larpech na GameConu','O larpech na GameConu V letošním roce se nám na GameConu rozrostla sekce larpů o nové a nadějné autory těchto her. Můžete si vybrat z šesti. Přijďte si vyzkoušet jaké by to bylo v kůži jednoho z radních v tom nejšílenějším městě pod sluncem. Vžijte se do role jednoho z pacientů psychiatrického ústavu a nebo buďte prostě tím nejdrsnějším poldou v té nejšpinavější čtvrti ve městě. Prožijte nezapomenutelné chvíle. Již na letošním GameConu. Netušíte, co to larp je? Larp je taková lehká divadelní improvizace, ve které se na několik hodin ponoříte do jiného světa - chcete být pašerákem diamantů nebo třeba Trinity z Matrixu? V larpu jimi opravdu budete. Nemáte scénář jako např. herci ve filmu. Vy sami jste tvůrci svého příběhu. Svou roli hrajete podobně jako v divadle, nehrajete však pro diváky, ale pro sebe navzájem. Netušíte co to je komorní larp ? Komorní larpy jsou krátké hry pro malý počet účastníků. Hrají se v komorním prostředí (místnost) a kladou důraz na hlubší ztvárnění role. Častěji jsou účastníky starší hráči.');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (187,'Odznak','odznak',38,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (187,'larp/odznak');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (187,'Odznak — GameCon 2011','gamecon,2011','Odznak');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (187,'kapacita 8/8<br />
<h1>Odznak</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/odznak.gif" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>organizátor</strong><br />Kamil Buchtík<br />
  <strong>čas akce</strong><br />sobota 23.7 - 8:00 až 12:00  <br />
 <strong>další akce organizátora</strong> <br /><div style = "text-align: left;"><a href = "/larp/skola">Škola</a></div>
</div>
</p>
   <p style = "clear: both;">
Odznak je konverzační komorní LARP z prostředí divoké čtvrti současného Los Angeles, žánrově by se dal označit jako „seriálová detektivka“ (hra samotná je inspirována televizním seriálem The Shield, jehož znalost před hrou výrazně NEdoporučujeme).
</p>
<p>
Můžete očekávat množství zápletek, dramatické divadelní situace, možnost hráčů výrazně ovlivnit chod hry. Naopak pokud byste radši řešili policejní případy skrze množství připravených indicií, máte rádi jasně určený příběh, který vám zaručuje zábavu, můžete být hrou zklamáni
</p>
<p>
Každý z osmi hráčů bude představovat jednoho z policistů stanice ve Farmingtonu. Dostane jednak obecné instrukce, ale také samozřejmě informace o své postavě. Těch je poměrně hodně, nicméně hráč bude jasně vědět, které jsou pro jeho hru nejdůležitější, ostatní spíše dokreslují kontext situace. Hra samotná trvá zhruba dvě hodiny, po ní následuje zpětná vazba. Formát tedy odpovídá obecné představě o tom, jak by měl vypadat komorní LARP.
</p>

<p>
Odznak je určen primárně pro hráče, kteří již mají s LARPy nějakou zkušenost. Hra klade nároky na vžití se do prostředí, práci s herními informacemi a zejména určitou seberegulaci ve směru snahy hru vyhrát (ano, některé postavy mohou hru vyhrát v prvních deseti minutách – ale to není cílem hry).
</p>
<p><ul>
                          <!--<li>
        <a href = "/larp/prehled-larpu-na-gc2010">Přehled larpů na GameConu 2010</a>      </li>-->
    </ul>
  </p>
  <div style = "width: 100%; float: left;">
    <div style = "width: 50%; text-align: left; float: left; padding-top: 20px; padding-bottom: 15px;">&laquo; <a href = "/larp/game-over">Game Over</a></div>    <div style = "width: 50%; text-align: right; float: right; padding-top: 20px; padding-bottom: 15px;"><a href = "/larp/sofiina-volba">Sofiina volba</a> &raquo;</div>  </div>
  
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (187,'Odznak','kapacita 8/8 Odznak organizátor Kamil Buchtík čas akce sobota 23.7 - 8:00 až 12:00 další akce organizátora Škola Odznak je konverzační komorní LARP z prostředí divoké čtvrti současného Los Angeles, žánrově by se dal označit jako „seriálová detektivka“ (hra samotná je inspirována televizním seriálem The Shield, jehož znalost před hrou výrazně NEdoporučujeme). Můžete očekávat množství zápletek, dramatické divadelní situace, možnost hráčů výrazně ovlivnit chod hry. Naopak pokud byste radši řešili policejní případy skrze množství připravených indicií, máte rádi jasně určený příběh, který vám zaručuje zábavu, můžete být hrou zklamáni Každý z osmi hráčů bude představovat jednoho z policistů stanice ve Farmingtonu. Dostane jednak obecné instrukce, ale také samozřejmě informace o své postavě. Těch je poměrně hodně, nicméně hráč bude jasně vědět, které jsou pro jeho hru nejdůležitější, ostatní spíše dokreslují kontext situace. Hra samotná trvá zhruba dvě hodiny, po ní následuje zpětná vazba. Formát tedy odpovídá obecné představě o tom, jak by měl vypadat komorní LARP. Odznak je určen primárně pro hráče, kteří již mají s LARPy nějakou zkušenost. Hra klade nároky na vžití se do prostředí, práci s herními informacemi a zejména určitou seberegulaci ve směru snahy hru vyhrát (ano, některé postavy mohou hru vyhrát v prvních deseti minutách – ale to není cílem hry). Přehled larpů na GameConu 2010 --> « Game Over Sofiina volba »');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (188,'Archiv LARP na GameConu 2009','prehled-larpu-na-gc2009',38,0,0);
