INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (188,'Archiv LARP na GameConu 2009 — GameCon 2011','gamecon,2011','Archiv LARP na GameConu 2009');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (188,'<h1>Archiv LARP na GameConu 2009</h1>
<h2>Cela</h2><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/cela.gif" style = "float: left; "/ /></div></p>
<p>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>organizátor</strong><br />Court of Moravia<br />
</div>
</p>
<p style = "clear: both;">
  <i>Místodržící byl zabit. Před desítkami svědků přímo v průvodu a před očima vlastní gardy. Když se jim rovnou pod nohama převrhl vozík se zeleninou a na chvíli tak upoutal jejich pozornost, místodržící padl bez dechu na ulici. Všichni to viděli.</i></p>

  <p><i>Jiné místo, pár hodin poté. Chodbou se nese jen prskání a hukot pochodní. V tichu, které kolem panuje, se zdá být až neuvěřitelně hlasité. Nebo to něco hučí v mé hlavě? Na spánku troška zaschlé krve. Za zády chladná a cizí kamenná stěna, pod sebou vrstvička žluklé slámy. Trocha světla prosvítá z chodby přes mříže. Přes...mříže. Oči přivykají temnotě a odhalují, že tu nejsem sám.</i></p>
  <p><i>Hlava padla a já byl při tom; tak mysl zaplavilo náhlé poznání. Zatraceně.</i></p>
  <p>Cela je krátký LARP postavený na volném motivu fantastického města, jehož složitosti hru nikterak výrazně nezasáhnou. Devět až deset hráčských postav v průběhu čtyř hodin odhalí tajemství, která snad nikdy neměla být odhalena a možná zjistí, kdo stál za spiknutím proti hlavě města. To vše se jim podaří v jedné jediné cele, kde jsou uvězněni, protože byli příliš blízko atentátu, protože jsou vrahy, zloději, násilníky, žebráky, prostitutkami nebo prostě jen vypadají podezřele. A všichni do jednoho jsou samozřejmě nevinní jako lilie. Nejméně do chvíle, než se ukáže opak.</p>
  <p>Pokud si chcete udělat bližší obrázek, nahlédněte do <a href = "http://www.courtofmoravia.com/files/com-cela-vytah.pdf" onclick = "window.open(this.href,\'_blank\'); return false">stručného popisu světa</a> [PDF, 422 KB]. Ušetříte si tak čtení před samotnou hrou. Pokud to však nestihnete, nezoufejte, na místě bude popis světa volně k dispozici.</p>
  <strong>Organizační informace</strong>

  <p>Cela je hra, kterou nelze hrát, pokud ji nehraje dostatečný počet hráčů. Proto, <strong>pokud se na hru nepřihlásí alespoň 9 hráčů minimálně 3 hodiny před hrou, bude hra zrušena</strong>. Pokud jste při registraci uvedli svůj mobil, budeme vás o zrušení hry informovat.</p>
</p>

<a name = "delegace"></a><h2>Delegace: Ankh-Morpork</h2><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/delegace--ankh-morpork.gif" style = "float: left; "/ /></div></p>
<p>
<div style = "padding-bottom: 20px; width: 280px; float: left;">

 <strong>organizátor</strong><br />Court of Moravia<br />

</div>
</p>
<p style = "clear: both;">
  <i>Dvě strany – jeden problém. Všechny argumenty jsou povoleny, cíl je jasný: dosáhnout svého. Zůstane kapitán Elánius ve službě? Zruší se tradiční mince? Čas běží.</i></p>
  <p>Delegace je krátká larpová hra pro 4 – 8 hráčů, ve které se stanete vyjednavači dvou opozičních stran. Vaším úkolem bude pomocí argumentace, vyjednávání a manipulace dosáhnout svých cílů a roznést soupeře na kopytech. Na GameCon 2009 přivezeme odlehčeně zábavný scénář této hry, Ankh-Morpork, ve kterém se zhostíte rolí představitelů tohoto fantastického města z pera Terryho Pratchetta.</p>
  <strong>Organizační poznámka</strong>
  <p>V případě, že se hlásíte na hru, která je již zanesena v programu, počítejte s tím, že hra se bude konat jen v případě přihlášení minimálního počtu 4 hráčů. <strong>Pokud se nepřihlásí alespoň 4 hráči nejpozději 3 hodiny předem, bude hra zrušena</strong> (pokud jste při registraci uvedli mobil, budeme vás informovat).</p>

  <p>Jak funguje přihlašování na larpy pro partu a jaké jsou <strong>možnosti uspořádat larp neuvedený v programu</strong>, se můžete dozvědět na stránce <a href = "/larp/o-larpech-na-gc">O larpech na GameConu</a>.</p>
</p>

<p>
  <ul>
   <h2>Chňapsni vlajku!</h2><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/chnapsni-vlajku.gif" style = "float: left; "/ /></div></p>

<p>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>organizátor</strong><br />Court of Moravia<br />

</div>
</p>
<p style = "clear: both;">
  CTF - Capture the Flag Live! aneb Chňapsni vlajku zaživa!</p>
  <p>Chňapsni vlajku je oblíbená zábava známá z Raukonů a Taurconů. Proti sobě stojí dva čtyřčlenné týmy a mají jen jediný cíl. Získat vlajku protivníka! Najdou se odvážní bojovníci a bojovnice, kteří se nebojí trochy pohybu a přitom mají smysl pro fair play? Přijďte změřit síly s ostatními týmy a ukázat jim, že právo na vlajku je jen vaše.</p>
  <p><strong>Je nutné, aby zájemci mladší 18 let měli písemný souhlas rodičů, že se mohou účastnit bojové hry.</strong></p>
</p>

<a name = "podraz"></a><h2>Podraz</h2><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/podraz.gif" style = "float: left; "/ /></div></p>
<p>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>organizátor</strong><br />Court of Moravia<br />

</div>
</p>
<p style = "clear: both;">
  <i>Pět chlapíků. Tři pistole. Jeden kufřík připoutaný k zápěstí. A samozřejmě pila. Pro pětici členů londýnského podsvětí je tohle opravdu nepříjemný den... Bude to chtít všechen um, dostat se z tohohle se zdravou kůží.</i></p>
  <p>Podraz je krátký larp pro 5 hráčů. Ti se na hodinu stanou londýnskými gangstery v nezáviděníhodné situaci. Rychlá, dynamická hra plná zvratů, pistolí, držení se v šachu a především podrazů čeká na ty správné chlapy.</p>
  <p>Specialitou této hry je, že jsou ze pouze mužské role. Dívky si ji samozřejmě mohou zahrát také, ale musí se připravit na to, že od nich bude očekáván skutečně chlapský přístup.</p>
  <p>Jak funguje přihlašování na larpy pro partu a jaké jsou <strong>možnosti uspořádat larp neuvedený v programu</strong>, se můžete dozvědět na stránce <a href = "/larp/o-larpech-na-gc">O larpech na GameConu</a>.</p>

</p>

<a name = "rande"></a><h2>Rande</h2><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/rande.gif" style = "float: left; "/ /></div></p>
<p>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>organizátor</strong><br />Court of Moravia<br />
</div>
</p>
<p style = "clear: both;">
  <i>Čekáte na pravou lásku a ona stále nepřichází? Co takhle štěstíčku trochu pomoct... A všimněte si, že mrkám!</i></p>

  <p>Rande je krátká larpová hra o hledání partnera pomocí různých pokoutných seznamovacích institucí. V žádném případě se nejedná ani o vážnou hru ani o způsob, jak skutečně nějakého partnera najít. Rande je jenom nevážná zábava v roli a legrace z tématu, které se nás dotýká, ačkoli to nikdy nepřiznáme.</p>
  <p>Hra je určená pro 4 – 8 hráčů, ideálně půl na půl mládence a slečny. Pokud se chcete se svými kamarády nevážně pobavit, neváhejte.</p>
  <p>Jak funguje přihlašování na larpy pro partu a jaké jsou <strong>možnosti uspořádat larp neuvedený v programu</strong>, se můžete dozvědět na stránce <a href = "/larp/o-larpech-na-gc">O larpech na GameConu</a>.</p>
</p>

<p>
  <ul>

   <h2>Špína</h2><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/spina.jpg" style = "float: left; "/ /></div></p>
<p>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>organizátor</strong><br />Court of Moravia<br />

</div>
</p>
<p style = "clear: both;">
  Akční městská hra se spoustou vodních pistolí opět na Gameconu! Letos s vašimi vlastními vodními zbraněmi - pokropte nepřátele z kvéru, na který jste zvyklí.
</p>
<p>
  <em>Loňský masakr nezůstane bez odvety. Ulice San Diega se budou opět hemžit gangstery, šlapkami a drogovými dýlery. A opět půjde o krk. Uhájí Niggas pozici nejsilnějšího gangu ve městě? Nebo je Mexiání a Yakuza rozstřílí na cucky? Přijďte v parném létě spláchnout nějakou tu Špínu!</em>
</p>
<p>
  Špína je akční městská hra na tři slunečné hodiny plná stříkajících vodních pistolí, necenzurovaného zločineckého výraziva, nebezpečí a euforie z jeho odvracení. Jako hráči ztvárníte jednoduché postavy stoupenců jedné ze tří znepřátelených stran a vydáte se do ulic (pro naše účely trochu přesunutého) San Diega, abyste zapíchli trn konkurenci přinejmenším do oka. Špína se bude ve hře přehazovat hned na několika úrovních, takže můžete sledovat příběhovou linii plněním akcí zadaných vaším bossem, vyžívat se ve shromažďování peněz a moci, nebo prostě jen vzít (stříkací) bouchačku a někoho odprásknout.
</p>
<p>
  Takže si sebou letos na GameCon určitě nezapomeňte vzít stříkací pistoli, abyste měli své protihráče čím pokropit. Pro vyjádření příslušnosti k jedné ze stran si s sebou také přibalte červenou kšiltovku nebo šátek, chcete-li být členem černošských Niggas, žlutý šátek pro Mexicos a něco černého, alespoň tričko, jestliže aspirujete na člena Yakuzy.

</p>
  
<p>
  <ul>
    <li>
      Další špinavé podrobnosti na <a href = "http://www.courtofmoravia.com/uskutecnene/spina-co-potrebuje-splachnout/" onclick = "window.open(this.href,\'_blank\'); return false">stránkách CoMu</a>
    </li>
  </ul>
</p>


    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (188,'Archiv LARP na GameConu 2009','Archiv LARP na GameConu 2009 Cela organizátor Court of Moravia Místodržící byl zabit. Před desítkami svědků přímo v průvodu a před očima vlastní gardy. Když se jim rovnou pod nohama převrhl vozík se zeleninou a na chvíli tak upoutal jejich pozornost, místodržící padl bez dechu na ulici. Všichni to viděli. Jiné místo, pár hodin poté. Chodbou se nese jen prskání a hukot pochodní. V tichu, které kolem panuje, se zdá být až neuvěřitelně hlasité. Nebo to něco hučí v mé hlavě? Na spánku troška zaschlé krve. Za zády chladná a cizí kamenná stěna, pod sebou vrstvička žluklé slámy. Trocha světla prosvítá z chodby přes mříže. Přes...mříže. Oči přivykají temnotě a odhalují, že tu nejsem sám. Hlava padla a já byl při tom; tak mysl zaplavilo náhlé poznání. Zatraceně. Cela je krátký LARP postavený na volném motivu fantastického města, jehož složitosti hru nikterak výrazně nezasáhnou. Devět až deset hráčských postav v průběhu čtyř hodin odhalí tajemství, která snad nikdy neměla být odhalena a možná zjistí, kdo stál za spiknutím proti hlavě města. To vše se jim podaří v jedné jediné cele, kde jsou uvězněni, protože byli příliš blízko atentátu, protože jsou vrahy, zloději, násilníky, žebráky, prostitutkami nebo prostě jen vypadají podezřele. A všichni do jednoho jsou samozřejmě nevinní jako lilie. Nejméně do chvíle, než se ukáže opak. Pokud si chcete udělat bližší obrázek, nahlédněte do stručného popisu světa [PDF, 422 KB]. Ušetříte si tak čtení před samotnou hrou. Pokud to však nestihnete, nezoufejte, na místě bude popis světa volně k dispozici. Organizační informace Cela je hra, kterou nelze hrát, pokud ji nehraje dostatečný počet hráčů. Proto, pokud se na hru nepřihlásí alespoň 9 hráčů minimálně 3 hodiny před hrou, bude hra zrušena . Pokud jste při registraci uvedli svůj mobil, budeme vás o zrušení hry informovat. Delegace: Ankh-Morpork organizátor Court of Moravia Dvě strany – jeden problém. Všechny argumenty jsou povoleny, cíl je jasný: dosáhnout svého. Zůstane kapitán Elánius ve službě? Zruší se tradiční mince? Čas běží. Delegace je krátká larpová hra pro 4 – 8 hráčů, ve které se stanete vyjednavači dvou opozičních stran. Vaším úkolem bude pomocí argumentace, vyjednávání a manipulace dosáhnout svých cílů a roznést soupeře na kopytech. Na GameCon 2009 přivezeme odlehčeně zábavný scénář této hry, Ankh-Morpork, ve kterém se zhostíte rolí představitelů tohoto fantastického města z pera Terryho Pratchetta. Organizační poznámka V případě, že se hlásíte na hru, která je již zanesena v programu, počítejte s tím, že hra se bude konat jen v případě přihlášení minimálního počtu 4 hráčů. Pokud se nepřihlásí alespoň 4 hráči nejpozději 3 hodiny předem, bude hra zrušena (pokud jste při registraci uvedli mobil, budeme vás informovat). Jak funguje přihlašování na larpy pro partu a jaké jsou možnosti uspořádat larp neuvedený v programu , se můžete dozvědět na stránce O larpech na GameConu . Chňapsni vlajku! organizátor Court of Moravia CTF - Capture the Flag Live! aneb Chňapsni vlajku zaživa! Chňapsni vlajku je oblíbená zábava známá z Raukonů a Taurconů. Proti sobě stojí dva čtyřčlenné týmy a mají jen jediný cíl. Získat vlajku protivníka! Najdou se odvážní bojovníci a bojovnice, kteří se nebojí trochy pohybu a přitom mají smysl pro fair play? Přijďte změřit síly s ostatními týmy a ukázat jim, že právo na vlajku je jen vaše. Je nutné, aby zájemci mladší 18 let měli písemný souhlas rodičů, že se mohou účastnit bojové hry. Podraz organizátor Court of Moravia Pět chlapíků. Tři pistole. Jeden kufřík připoutaný k zápěstí. A samozřejmě pila. Pro pětici členů londýnského podsvětí je tohle opravdu nepříjemný den... Bude to chtít všechen um, dostat se z tohohle se zdravou kůží. Podraz je krátký larp pro 5 hráčů. Ti se na hodinu stanou londýnskými gangstery v nezáviděníhodné situaci. Rychlá, dynamická hra plná zvratů, pistolí, držení se v šachu a především podrazů čeká na ty správné chlapy. Specialitou této hry je, že jsou ze pouze mužské role. Dívky si ji samozřejmě mohou zahrát také, ale musí se připravit na to, že od nich bude očekáván skutečně chlapský přístup. Jak funguje přihlašování na larpy pro partu a jaké jsou možnosti uspořádat larp neuvedený v programu , se můžete dozvědět na stránce O larpech na GameConu . Rande organizátor Court of Moravia Čekáte na pravou lásku a ona stále nepřichází? Co takhle štěstíčku trochu pomoct... A všimněte si, že mrkám! Rande je krátká larpová hra o hledání partnera pomocí různých pokoutných seznamovacích institucí. V žádném případě se nejedná ani o vážnou hru ani o způsob, jak skutečně nějakého partnera najít. Rande je jenom nevážná zábava v roli a legrace z tématu, které se nás dotýká, ačkoli to nikdy nepřiznáme. Hra je určená pro 4 – 8 hráčů, ideálně půl na půl mládence a slečny. Pokud se chcete se svými kamarády nevážně pobavit, neváhejte. Jak funguje přihlašování na larpy pro partu a jaké jsou možnosti uspořádat larp neuvedený v programu , se můžete dozvědět na stránce O larpech na GameConu . Špína organizátor Court of Moravia Akční městská hra se spoustou vodních pistolí opět na Gameconu! Letos s vašimi vlastními vodními zbraněmi - pokropte nepřátele z kvéru, na který jste zvyklí. Loňský masakr nezůstane bez odvety. Ulice San Diega se budou opět hemžit gangstery, šlapkami a drogovými dýlery. A opět půjde o krk. Uhájí Niggas pozici nejsilnějšího gangu ve městě? Nebo je Mexiání a Yakuza rozstřílí na cucky? Přijďte v parném létě spláchnout nějakou tu Špínu! Špína je akční městská hra na tři slunečné hodiny plná stříkajících vodních pistolí, necenzurovaného zločineckého výraziva, nebezpečí a euforie z jeho odvracení. Jako hráči ztvárníte jednoduché postavy stoupenců jedné ze tří znepřátelených stran a vydáte se do ulic (pro naše účely trochu přesunutého) San Diega, abyste zapíchli trn konkurenci přinejmenším do oka. Špína se bude ve hře přehazovat hned na několika úrovních, takže můžete sledovat příběhovou linii plněním akcí zadaných vaším bossem, vyžívat se ve shromažďování peněz a moci, nebo prostě jen vzít (stříkací) bouchačku a někoho odprásknout. Takže si sebou letos na GameCon určitě nezapomeňte vzít stříkací pistoli, abyste měli své protihráče čím pokropit. Pro vyjádření příslušnosti k jedné ze stran si s sebou také přibalte červenou kšiltovku nebo šátek, chcete-li být členem černošských Niggas, žlutý šátek pro Mexicos a něco černého, alespoň tričko, jestliže aspirujete na člena Yakuzy. Další špinavé podrobnosti na stránkách CoMu');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (189,'Previous Occupants','previous-occupants',38,0,0);
