INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (190,'GameCon 2011 se blíží','seance',38,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (190,'larp/seance');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (190,'GameCon 2011 se blíží — GameCon 2011','gamecon,2011','GameCon 2011 se blíží');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (190,'<h1>GameCon 2011 se blíží</h1>

<!--<h2>Organizační změny</h2>
<p>
Dovolte nám seznámit vás s velkou organizační novinkou. Petr „Gandalf“ Holub, který stál v čele organizačního týmu GameConu poslední dva roky, ještě v průběhu letošního GameConu v České Třebové předal post hlavního organizátora Matouši „Erricu“ Ježkovi. Jelikož se mu totiž letos narodily dvě holčičky, po důkladném uvážení se musel rozhodnout k tomuto kroku, neboť vedení organizačního týmu a nově rozrostlou rodinu a normální práci by nebylo možné skloubit tak, aby jedno netrpělo.
</p>
<p>
Nic to však nemění na tom, že další ročník GameConu už pro vás připravujeme a o novinkách vás budeme průběžně informovat jak tady, tak na <a href = "http://www.facebook.com/group.php?sid=1a65342dd9cba753975=bb963632e2a7&gid=93879753711&ref=search#!/gamecon" onclick = "window.open(this.href,\'_blank\'); return false">facebooku</a>.
</p>
<p>
Organizační tým GameConu
</p>

<h2>GameCon Teaser</h2>
<object width="470" height="265"><param name="allowfullscreen" value="true" /><param name="allowscriptaccess" value="always" /><param name="movie" value="http://vimeo.com/moogaloop.swf?clip_id=12709571&amp;server=vimeo.com&amp;show_title=1&amp;show_byline=1&amp;show_portrait=0&amp;color=&amp;fullscreen=1" /><embed src="http://vimeo.com/moogaloop.swf?clip_id=12709571&amp;server=vimeo.com&amp;show_title=1&amp;show_byline=1&amp;show_portrait=0&amp;color=&amp;fullscreen=1" type="application/x-shockwave-flash" allowfullscreen="true" allowscriptaccess="always" width="470" height="265"></embed></object>-->

<h2>Čtyři dny plné zábavy a napětí nad hrami všeho druhu</h2>
<p>Ve dnech <strong>21.-24.7.2011</strong> se v <strong>České Třebové</strong> uskuteční již 17. ročník herního setkání <strong>GameCon</strong>. Je to příležitost pro všechny hráče a fanoušky nepočítačových her z České republiky a Slovenska setkat se s ostatními, zahrát si hry, vyměnit zkušenosti a pobavit se. Co vás během čtyř dnů na GameConu čeká?
<ul>
<li><a href="/deskove-hry/o-deskovych-hrach-na-gc">Deskové hry</a> (Osadníci z Katanu, Carcassonne a mnohé další)</li>
<li>Velké množství her na hraní rolí neboli <a href="/rpg/o-rpg-na-gc">RPG</a>. Můžete si vyzkoušet i herní systémy, které doma ani nemáte.</li>
<li>Hry naživo neboli <a href = "/larp/o-larpech-na-gc">LARP</a>, kdy prožitky své postavy vyzkoušíte na vlastní kůži.</li>
<li><a href = "/mistrovstvi-v-drd/o-mistrovstvi-v-drd">Mistrovství v Dračím doupěti</a>, letos pro změnu z pozice obyčejných obyvatel Císařství.</li>
<li>A spousta dalších aktivit, jako třeba bitva miniaturních armád ve <a href = "/wargaming/o-wargamingu-na-gc">Wargamingu</a>, nebo poutavé <a href = "/prednasky/o-prednaskach-na-gc">přednášky</a>.</li>
<li>Sobotní party</li>
</ul>
</p>

<p>Že neznáte žádnou z těchto her? Nevadí.<strong>Pravidla vám rádi vysvětlíme na místě</strong> a poradíme i s výběrem her nebo naplánováním programu. <strong>Neváhejte tedy a přijeďte.</strong> Slibujeme vám spoustu her, zábavy a přátelské atmosféry. Nemáte volné celé čtyři dny? Nevadí! <strong>GameCon</strong> má co nabídnout každý den.</strong></p>
<!--<p>Jednoduchý návod jak se <strong>přihlásit na GameCon</strong> a všechny důležité informace o <strong>registraci</strong>, možnostech <strong>ubytování</strong> a <strong>platbách</strong> naleznete <a href="/navod/">zde</a>.</p>-->
<p>O novinkách vás budeme průběžně informovat jak zde, tak na <a href = "http://www.facebook.com/gamecon" onclick = "window.open(this.href,\'_blank\'); return false">Facebooku</a>.</p>

<a name=novinky></a>
<h2>Letošní novinky</h2>
<p>Tak jako každý rok se snažíme, aby GameCon i letos nabídl něco nového. Loni se con přestěhoval do České Třebové, což přineslo mimo jiné možnost nabídnout všechny aktivity pod jednou střechou, prostornou a dobře větratelnou místnost pro deskohernu a levnější ubytování. Na co se můžete těšit letos?</p>
<ul>
<li>Pro účastníky GameConu ze Slovenska jsme připravili <strong>možnost platit v eurech</strong>.</li>
<li>Všem budou přístupné <strong>kuchyňky</strong>, ve kterých si bude možné uvařit jídlo.</li>
<li>GameCon se bude odehrávat <strong>ve znamení Antiky</strong>.</li>
<li>Je pro vás připravena <strong>spousta nových her</strong> na všech frontách.</li>
<li>Na programu bude také <strong>křest Dračího doupěte II</strong>.</li>
</ul>

<!--<p>
Patrně nejvýraznější změnou je přestěhování conu do České Třebové. Tento manévr nám poskytl hned několik výhod:
<ul>
	<li>Předně jsou to <strong>všechny aktivity pod jednou střechou</strong>, nebude potřeba kamkoliv přebíhat nebo složitě bloudit mezi jednotlivými komplexy budov.</li>
	<li>Zároveň jsou místnosti pro jednotlivé aktivity dostatečně velké a vzdušné.</li>
	<li>Především místnost <a href = "/deskove-hry/deskoherna">deskoherny</a> je úchvatně prostorná a dobře větratelná. Už nehrozí, že bychom se v dobré víře ušlapávali nebo letním parnu dusili. Tento rok to bude konečně ta <strong>dobře přístupná aréna plná deskových her</strong> připravená na lačné hráče. Pro zvědavce jsme jako důkaz připravili alespoň dvě fotografie z naších průzkumných výprav – více v <a href = "/deskove-hry/deskoherna">deskoherně</a>.</li>
	<li>Vítanou změnou bude určitě i <strong>levnější ubytování</strong>. Letos bude stát jedna noc v třílůžkovém pokoji pouhých 170 Kč (oproti loňským dvěma stovkám, takže za tři noci nakonec ušetříte téměř stokorunu).</li>
	<li>Přijde vám lůžkový pokoj příliš drahý a komfortní? Pak jistě uvítáte další zlepšení a tím je <strong>možnost spát hromadně ve třídě ve vlastním spacáku</strong> a to za pouhých 60 Kč. Více o ubytovacích možnostech se dočtete v <a href = "/gamecon/ubytovani">ubytování</a>.</li>
	<li>Přesunem do jiného města jsme také získali kousek od naší budovy velkou nafukovací halu, kterou budeme moci využít v nepřízni počasí na nějakou velmi hromadnou akci. No není takový bonus skvělý?</li>
	<li>A snad některé z vás potěší i dobrá dopravní dostupnost pro celou republiku. Jsme uprostřed státu, tak snad to má každý kousek. :-)</li>
</ul>
</p>

<p>
Jak můžete vidět, přesun na nové místo pro vás znamená samé výhody. Nespokojíme se však jen s novým územím a jeho přidanými hodnotami, pokračujeme dál ve zpestřujících zlepšovácích:
</p>
<p>
<ul>
	<li>Velká novinka hned rovnou na začátek: <strong>popré</strong> bude <strong>celý GameCon v duchu nějakého tématu</strong>, tentokrát to bude <strong>exodus</strong> a spíše než vyhnání z ráje to bude jeho hledání. V následujících dnech vám přineseme bližší informace a vy se můžete těšit, že s tím bude spojena spousta her a zábavné atmosféry.</li>
	<li><strong>Mistrovství v Dračím doupěti</strong> bude zase o něco blíž vám hráčům. Vyslyšeli jsme vaše dobré připomínky a rady, důkladně si přečetli reakce ve <a href = "/forum/mistrovstvi_v_drd">fóru</a> a vyšli vám vstříc.<br />
Do odkrývání tajů dobrodružství se můžete pustit již nyní a každý týden Vám přineseme další indicii. Na úvod začínáme jedním výtiskem <a href = "/mistrovstvi-v-drd/sluncesvit-cisarske-noviny">Sluncesvitu</a> - populárního císařského plátku.<br />
Také jsme pro vás připravili <strong>dvě výrazná zlepšení postav</strong> a <strong>jedno velmi poutavé zpestření</strong>. Obě novinky se týkají <a href = "/mistrovstvi-v-drd/pravidla-pro-tvorbu-postav">tvorby postav</a> a brzy vás o těchto změnách budeme informovat více. Zatím můžete ve <a href = "/forum/mistrovstvi_v_drd">fóru</a> tipovat, co by to tak mohlo být.</li>
	<li><strong>Trojboj</strong> bude v tomto roce trvat jen jeden blok, takže o důvod více zapojit se do této týmové aktivity, kdy za jednu cenu si zahrajete tři hry. Více na <a href = "/gamecon-trojboj/o-gamecon-trojboji">samostatné stránce</a>.</li>
	<li><strong>Špína</strong> bude letos ve znamení „Osídlení nového města“ a <strong>gobliní ponorky</strong> budou bojovat o nová naleziště drahokamů.</li>
	<li>Určitě se bude hodit i trénink ve velení armádám, tudíž jistě přijde vhod <a href = "/wargaming/wargaming-tour-2010">Wargaming Tour 2010</a>.</li>
	<li>A lahodný zákusek na závěr: <strong>na sobotní večer</strong> pro vás plánujeme <strong>hromadné pobavení</strong>, jehož součástí by mělo být i <strong>klání v duchu televizních soutěží</strong> v režii týmu z Court of Moravia.</li>
</ul>
</p>

<p>
Snad vás to množství novinek a jednotlivé zlepšováky těší a přijedete na GameCon. Koná se <strong>15.-18.7.2010 v&nbsp;České Třebové</strong>.
</p>-->

<h3>GameCon je tu pro vás, tak si přijďte zahrát!</h3>
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (190,'GameCon 2011 se blíží','GameCon 2011 se blíží Organizační změny Dovolte nám seznámit vás s velkou organizační novinkou. Petr „Gandalf“ Holub, který stál v čele organizačního týmu GameConu poslední dva roky, ještě v průběhu letošního GameConu v České Třebové předal post hlavního organizátora Matouši „Erricu“ Ježkovi. Jelikož se mu totiž letos narodily dvě holčičky, po důkladném uvážení se musel rozhodnout k tomuto kroku, neboť vedení organizačního týmu a nově rozrostlou rodinu a normální práci by nebylo možné skloubit tak, aby jedno netrpělo. Nic to však nemění na tom, že další ročník GameConu už pro vás připravujeme a o novinkách vás budeme průběžně informovat jak tady, tak na facebooku . Organizační tým GameConu GameCon Teaser --> Čtyři dny plné zábavy a napětí nad hrami všeho druhu Ve dnech 21.-24.7.2011 se v České Třebové uskuteční již 17. ročník herního setkání GameCon . Je to příležitost pro všechny hráče a fanoušky nepočítačových her z České republiky a Slovenska setkat se s ostatními, zahrát si hry, vyměnit zkušenosti a pobavit se. Co vás během čtyř dnů na GameConu čeká? Deskové hry (Osadníci z Katanu, Carcassonne a mnohé další) Velké množství her na hraní rolí neboli RPG . Můžete si vyzkoušet i herní systémy, které doma ani nemáte. Hry naživo neboli LARP , kdy prožitky své postavy vyzkoušíte na vlastní kůži. Mistrovství v Dračím doupěti , letos pro změnu z pozice obyčejných obyvatel Císařství. A spousta dalších aktivit, jako třeba bitva miniaturních armád ve Wargamingu , nebo poutavé přednášky . Sobotní party Že neznáte žádnou z těchto her? Nevadí. Pravidla vám rádi vysvětlíme na místě a poradíme i s výběrem her nebo naplánováním programu. Neváhejte tedy a přijeďte. Slibujeme vám spoustu her, zábavy a přátelské atmosféry. Nemáte volné celé čtyři dny? Nevadí! GameCon má co nabídnout každý den. Jednoduchý návod jak se přihlásit na GameCon a všechny důležité informace o registraci , možnostech ubytování a platbách naleznete zde . --> O novinkách vás budeme průběžně informovat jak zde, tak na Facebooku . Letošní novinky Tak jako každý rok se snažíme, aby GameCon i letos nabídl něco nového. Loni se con přestěhoval do České Třebové, což přineslo mimo jiné možnost nabídnout všechny aktivity pod jednou střechou, prostornou a dobře větratelnou místnost pro deskohernu a levnější ubytování. Na co se můžete těšit letos? Pro účastníky GameConu ze Slovenska jsme připravili možnost platit v eurech . Všem budou přístupné kuchyňky , ve kterých si bude možné uvařit jídlo. GameCon se bude odehrávat ve znamení Antiky . Je pro vás připravena spousta nových her na všech frontách. Na programu bude také křest Dračího doupěte II . Patrně nejvýraznější změnou je přestěhování conu do České Třebové. Tento manévr nám poskytl hned několik výhod: Předně jsou to všechny aktivity pod jednou střechou , nebude potřeba kamkoliv přebíhat nebo složitě bloudit mezi jednotlivými komplexy budov. Zároveň jsou místnosti pro jednotlivé aktivity dostatečně velké a vzdušné. Především místnost deskoherny je úchvatně prostorná a dobře větratelná. Už nehrozí, že bychom se v dobré víře ušlapávali nebo letním parnu dusili. Tento rok to bude konečně ta dobře přístupná aréna plná deskových her připravená na lačné hráče. Pro zvědavce jsme jako důkaz připravili alespoň dvě fotografie z naších průzkumných výprav – více v deskoherně . Vítanou změnou bude určitě i levnější ubytování . Letos bude stát jedna noc v třílůžkovém pokoji pouhých 170 Kč (oproti loňským dvěma stovkám, takže za tři noci nakonec ušetříte téměř stokorunu). Přijde vám lůžkový pokoj příliš drahý a komfortní? Pak jistě uvítáte další zlepšení a tím je možnost spát hromadně ve třídě ve vlastním spacáku a to za pouhých 60 Kč. Více o ubytovacích možnostech se dočtete v ubytování . Přesunem do jiného města jsme také získali kousek od naší budovy velkou nafukovací halu, kterou budeme moci využít v nepřízni počasí na nějakou velmi hromadnou akci. No není takový bonus skvělý? A snad některé z vás potěší i dobrá dopravní dostupnost pro celou republiku. Jsme uprostřed státu, tak snad to má každý kousek. :-) Jak můžete vidět, přesun na nové místo pro vás znamená samé výhody. Nespokojíme se však jen s novým územím a jeho přidanými hodnotami, pokračujeme dál ve zpestřujících zlepšovácích: Velká novinka hned rovnou na začátek: popré bude celý GameCon v duchu nějakého tématu , tentokrát to bude exodus a spíše než vyhnání z ráje to bude jeho hledání. V následujících dnech vám přineseme bližší informace a vy se můžete těšit, že s tím bude spojena spousta her a zábavné atmosféry. Mistrovství v Dračím doupěti bude zase o něco blíž vám hráčům. Vyslyšeli jsme vaše dobré připomínky a rady, důkladně si přečetli reakce ve fóru a vyšli vám vstříc. Do odkrývání tajů dobrodružství se můžete pustit již nyní a každý týden Vám přineseme další indicii. Na úvod začínáme jedním výtiskem Sluncesvitu - populárního císařského plátku. Také jsme pro vás připravili dvě výrazná zlepšení postav a jedno velmi poutavé zpestření . Obě novinky se týkají tvorby postav a brzy vás o těchto změnách budeme informovat více. Zatím můžete ve fóru tipovat, co by to tak mohlo být. Trojboj bude v tomto roce trvat jen jeden blok, takže o důvod více zapojit se do této týmové aktivity, kdy za jednu cenu si zahrajete tři hry. Více na samostatné stránce . Špína bude letos ve znamení „Osídlení nového města“ a gobliní ponorky budou bojovat o nová naleziště drahokamů. Určitě se bude hodit i trénink ve velení armádám, tudíž jistě přijde vhod Wargaming Tour 2010 . A lahodný zákusek na závěr: na sobotní večer pro vás plánujeme hromadné pobavení , jehož součástí by mělo být i klání v duchu televizních soutěží v režii týmu z Court of Moravia. Snad vás to množství novinek a jednotlivé zlepšováky těší a přijedete na GameCon. Koná se 15.-18.7.2010 v České Třebové . --> GameCon je tu pro vás, tak si přijďte zahrát!');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (191,'Škola','skola',38,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (191,'larp/skola');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (191,'Škola — GameCon 2011','gamecon,2011','Škola');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (191,'kapacita 18/24<br />
<h1>Škola</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/skola.gif" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>organizátor</strong><br />Kamil Buchtík<br />
  <strong>čas akce</strong><br />pátek 22.7 - 19:00 až 23:00  <br />
 <strong>další akce organizátora</strong> <br /><div style = "text-align: left;"><a href = "/larp/odznak">Odznak</a></div>
</div>
</p>
   <p style = "clear: both;">
<big style="color:red">POZOR - volné jsou už pouze ŽENSKÉ role!</big></p>
<p>Vzpomínáš na šťastná a radostná léta na základní škole? První pusa, první cígo. Největším úspěchem roku bylo získání kartičky oblíbeného hokejisty. Nejčtenější literaturou fotoromán z Brávíčka. Poznámka v žákajdě se jevila jako neřešitelný problém. Chceš to prožít znovu? Hurá do Školy! 
</p>
<p>
Škola je odlehčený zábavný larp pro 24 žáků a 3 učitele. Odehrává se v prostředí páté třídy základní školy devadesátých let (to aby hráči nebili pedagogy hrané organizátory). Pátá třída, období, ve kterém se největší nepřátelé nachází v protější třídě a kdy milostné psaníčko nevyhnutelně vyvolá posměšky spolužáků. Tato veselá hra je vhodná jak pro prvohráče, tak pro ostřílené larpery. Užije si ji zkrátka každý (experimentálně ověřeno). 
</p>
<p>
Hra Škola je zaměřena na hraní dramatických situací, rozhodně v ní nejde o vítězství či vciťování se hluboko do charakteru postav. Je vystavěna na nadsázce a extrémních charakterech. Ať už chcete být ultraslušným šprtem či největší raubířkou ve škole, pojďte se vrátit do školních lavic! 
</p>
<p>
Hra je z dílny Kamila Buchtíka a Břéti Šopíka
</p>
<p><ul>
                              <!--<li>
        <a href = "/larp/prehled-larpu-na-gc2010">Přehled larpů na GameConu 2010</a>      </li>-->
    </ul>
  </p>
  <div style = "width: 100%; float: left;">
    <div style = "width: 50%; text-align: left; float: left; padding-top: 20px; padding-bottom: 15px;">&laquo; <a href = "/larp/sofiina-volba">Sofiina volba</a></div>    <div style = "width: 50%; text-align: right; float: right; padding-top: 20px; padding-bottom: 15px;"><a href = "/larp/sotcin">Šotčín</a> &raquo;</div>  </div>
  
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (191,'Škola','kapacita 18/24 Škola organizátor Kamil Buchtík čas akce pátek 22.7 - 19:00 až 23:00 další akce organizátora Odznak POZOR - volné jsou už pouze ŽENSKÉ role! Vzpomínáš na šťastná a radostná léta na základní škole? První pusa, první cígo. Největším úspěchem roku bylo získání kartičky oblíbeného hokejisty. Nejčtenější literaturou fotoromán z Brávíčka. Poznámka v žákajdě se jevila jako neřešitelný problém. Chceš to prožít znovu? Hurá do Školy! Škola je odlehčený zábavný larp pro 24 žáků a 3 učitele. Odehrává se v prostředí páté třídy základní školy devadesátých let (to aby hráči nebili pedagogy hrané organizátory). Pátá třída, období, ve kterém se největší nepřátelé nachází v protější třídě a kdy milostné psaníčko nevyhnutelně vyvolá posměšky spolužáků. Tato veselá hra je vhodná jak pro prvohráče, tak pro ostřílené larpery. Užije si ji zkrátka každý (experimentálně ověřeno). Hra Škola je zaměřena na hraní dramatických situací, rozhodně v ní nejde o vítězství či vciťování se hluboko do charakteru postav. Je vystavěna na nadsázce a extrémních charakterech. Ať už chcete být ultraslušným šprtem či největší raubířkou ve škole, pojďte se vrátit do školních lavic! Hra je z dílny Kamila Buchtíka a Břéti Šopíka Přehled larpů na GameConu 2010 --> « Sofiina volba Šotčín »');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (192,'Sofiina volba','sofiina-volba',38,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (192,'larp/sofiina-volba');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (192,'Sofiina volba — GameCon 2011','gamecon,2011','Sofiina volba');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (192,'kapacita 5/5<br />kapacita 5/5<br />
<h1>Sofiina volba</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/sofiina-volba.gif" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>organizátor</strong><br />Daniel Hrnčíř<br />
  <strong>čas akce</strong><br />čtvrtek 21.7 - 20:00 až 24:00  <br />sobota 23.7 - 14:00 až 18:00  <br />
 
</div>
</p>
   <p style = "clear: both;">
 Pět kamarádů z vysoké. Pět kamarádů, kteří se po škole rozprchli. A po dlouhé době společná hospůdka v centru města. Není málo toho, co je na jazyku. Dlouhý večer plný smíchu, alkoholu a starých lásek. Jeden taxík jako za mladých chudých studentských let.</p>
<p>Probuzení je pro všechny stejně děsivé. Bolest hlavy. Temná místnost. Zamčené dveře. Vzkaz na stole a v těle jed, který se rozlévá krví a jen pár hodin na vyřešení této absurdní situace a záhady .... nebo smrt. 
</p>
<p>
Je klíčem společná minulost? Nebo starý notebook? Či je tohle jen další úchylná japonská reality show? Poslední a nejdůležitější otázka ... přežijí všichni? 
</p>
<p>
Hra je určena pro 5 hráčů, které spojuje dlouholeté přátelství. Sofiinu volbu může hrát kdokoli a je časově omezená. Hráči, kteří se přihlásí dostanou na e-mail informace týkající se pozadí hry a jejich akademické činnosti – není však vůbec nutné si to pamatovat a ve hře na to nebude kladen přílíšný důraz, slouží to pouze k dokreslení atmosféry.
</p>
<p><ul>


                  <!--<li>
        <a href = "/larp/prehled-larpu-na-gc2010">Přehled larpů na GameConu 2010</a>      </li>-->
    </ul>
  </p>
  <div style = "width: 100%; float: left;">
    <div style = "width: 50%; text-align: left; float: left; padding-top: 20px; padding-bottom: 15px;">&laquo; <a href = "/larp/odznak">Odznak</a></div>    <div style = "width: 50%; text-align: right; float: right; padding-top: 20px; padding-bottom: 15px;"><a href = "/larp/skola">Škola</a> &raquo;</div>  </div>
  
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (192,'Sofiina volba','kapacita 5/5 kapacita 5/5 Sofiina volba organizátor Daniel Hrnčíř čas akce čtvrtek 21.7 - 20:00 až 24:00 sobota 23.7 - 14:00 až 18:00 Pět kamarádů z vysoké. Pět kamarádů, kteří se po škole rozprchli. A po dlouhé době společná hospůdka v centru města. Není málo toho, co je na jazyku. Dlouhý večer plný smíchu, alkoholu a starých lásek. Jeden taxík jako za mladých chudých studentských let. Probuzení je pro všechny stejně děsivé. Bolest hlavy. Temná místnost. Zamčené dveře. Vzkaz na stole a v těle jed, který se rozlévá krví a jen pár hodin na vyřešení této absurdní situace a záhady .... nebo smrt. Je klíčem společná minulost? Nebo starý notebook? Či je tohle jen další úchylná japonská reality show? Poslední a nejdůležitější otázka ... přežijí všichni? Hra je určena pro 5 hráčů, které spojuje dlouholeté přátelství. Sofiinu volbu může hrát kdokoli a je časově omezená. Hráči, kteří se přihlásí dostanou na e-mail informace týkající se pozadí hry a jejich akademické činnosti – není však vůbec nutné si to pamatovat a ve hře na to nebude kladen přílíšný důraz, slouží to pouze k dokreslení atmosféry. Přehled larpů na GameConu 2010 --> « Odznak Škola »');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (193,'Šotčín','sotcin',38,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (193,'larp/sotcin');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (193,'Šotčín — GameCon 2011','gamecon,2011','Šotčín');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (193,'kapacita 7/7<br />
<h1>Šotčín</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/sotcin.gif" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>organizátor</strong><br />Tomáš Kalík<br />
  <strong>čas akce</strong><br />čtvrtek 21.7 - 20:00 až 24:00  <br />
 <strong>další akce organizátora</strong> <br /><div style = "text-align: left;"><a href = "/larp/zavet">Závěť</a></div>
</div>
</p>
   <p style = "clear: both;"> <em>
Kdysi dávno, když lidé ještě pomalu lezli po stromech, existoval národ, který byl velmi vyspělý. Lidem se stranil, protože mu připadali hloupí a násilničtí.
Obyvatelé tohoto národa žili v takových malých vesničkách. Ty se skládaly z velké díry (vězení), kam házeli nezbedné občany (kterých nebylo málo), z hlavní díry (radnice), kde zasedal senát, soud a všechny důležité orgány, z malých děr (domků), kde žili a z jedné velké hospody, kde společně rozjímali nad půllitry piva. Jejich dědiny byly velmi dobře skryty před lidmi a jinými nepřáteli.
 Tento národ má velmi vyspělá skoro všechna odvětví výzkumu. Protože jsou obyvatelé tohoto národa velcí asi tak půl metru, bojí se všeho většího, než jsou oni sami. (V současnosti vedou válku s divokými prasaty, která chtějí mít na jejich území své pelechy. Z jejich historie jsou ještě známé velké války s veverkami.) Díky tomu, že jsou tak malí, snaží si svojí výšku nějak vykompenzovat. Nosí podpatky, vysoké klobouky, někteří (ti odvážnější, kterých je málo) chodí dokonce na chůdách. Aby byli vidět nosí také velmi rádi pestrobarevné oblečení. 
Nejsou národem odvážných a chrabrých bojovníků, jsou ale neskutečně chytří a tak dokážou svým nepřátelům jejich agresivní počiny velmi znepříjemnit. Příběh nás zanese do města Šotčín. Zde se nachází jedno z posledních útočišť pro nás již zapomenutého národu. Jde o národ šotků.
</em></p>
<p>
Hra je založena převážně na řešení starých, špatných a prosazování nových zákonů. Je stavěna hlavně pro velmi výrazné, extrovertní hráče, kteří hrají velmi ven. Je to hra o intrikách a politikaření.  Hráči budou muset mít velmi tvrdé lokty, protože šotčí politika není žádná legrace. Ten nejsilnější řečník možná dokáže strhnout na svou stranu nerozhodnuté zastupitele a díky tomu jeho návrh bude vybrán jako správné řešení daného problému. Nečekejte však žádné drama. Mělo by jít o komickou hru, při které se budete moci "vyblbnout do aleluja."
</p>
<p>
Hra je z dílny Tomáše "Sylfaena" Kalíka
</p>
<p><ul>
                  <!--<li>
        <a href = "/larp/prehled-larpu-na-gc2010">Přehled larpů na GameConu 2010</a>      </li>-->
    </ul>
  </p>
  <div style = "width: 100%; float: left;">
    <div style = "width: 50%; text-align: left; float: left; padding-top: 20px; padding-bottom: 15px;">&laquo; <a href = "/larp/skola">Škola</a></div>    <div style = "width: 50%; text-align: right; float: right; padding-top: 20px; padding-bottom: 15px;"><a href = "/larp/zavet">Závěť</a> &raquo;</div>  </div>
  
    </div>
  </div>');
