INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (196,'Informace o dobrodružství','informace-o-dobrodruzstvi',42,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (196,'mistrovstvi-v-drd/informace-o-dobrodruzstvi');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (196,'Informace o dobrodružství — GameCon 2011','gamecon,2011','Informace o dobrodružství');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (196,'<h1>Informace o dobrodružství</h1>

<ul>
  <li><a href = "#slunecne-cisarstvi">Slunečné císařství</a></li>
  <li><a href = "#vinny-kraj">Vinný kraj</a></li>
  <!--<li><a href = "#nase-druzina-a-cvo">Naše družina a Císařské vyšetřovací oddíly</a></li>
  <li><a href = "#pravdonosove">Pravdonošové</a></li>
  <li><a href = "#zacatek-dobrodruzstvi">Začátek dobrodružství</a></li>-->
</ul>

<h2><a name = "slunecne-cisarstvi"></a>Kapitola I.</h2>
<h1>Slunečné císařství</h1>

<p>Z východu je ohraničeno velkými jezery a nepředvídatelnými bažinami, na jihu a západě je omývá moře, pouze ze severu se nad zemí tyčí vysoké hory – není tedy divu, že zdejší stát nese tak poetický název, neboť opravdu je od rána do večera celá zem sluncem prosvícena. Naštěstí jsou zdejší kraje hustě porostlé lesy, obklopeny rozlehlými jezery a od moře vanou příznivé větry, proto není zdejší císařství vyprahlé jako nekonečné pouště daleko na jihu, naopak bere si ze slunce jen to nejlepší.</p>
<p>Celé zemi se neskutečně daří v zemědělství, často je každý region na něco specializovaný (na jihu jsou to olivy a víno, na severu ječmen či brambory), ale díky své rozloze pokrývá císařství spousta různorodých krajin a tak zde naleznete spoustu rozličných odvětví.</p>
<p>Císařství ale nebylo tak velké vždy. Je to však již hodně dávno, kdy se původním obyvatelům z Železného kraje podařilo dobýt okolní království a sjednotit je pod jednu vlajku. Naštěstí byli dávní vládci císařství natolik moudří, že brzy zajistili nově dobytým krajům stejná práva jako svým původním podřízeným, a vyhnuli se tak občanským válkám a krvelačným půtkám mezi císařským lidem. A síla ve velké jednotě, technologický pokrok vzájemnou pomocí a moudrá slova císaře byli natolik nezpochybnitelnou silou a výhodou, že nikdo nevzdoroval a císařství zůstává jednotné.</p>
<p>Jako jeden stát působí pro okolní země, vnitřně je rozděleno do třinácti oblastí. Rozložení krajů vyhází z přirozených hranic původních království před dobytím, dnes však mají pouze organizační účel. Každý z regionů má svého správce, který se stará o svůj kraj a zodpovídá se císaři. Stejně tak má svou regionální pravomoc a své úředníky. Dvanáct regionů se nachází na velké kontinentální části císařství, jeden region je pak ostrovní kraj.</p>

<h2>Kraje Slunečného císařství</h2>

<h3>Železný kraj</h3>
<p>Původní království, ze kterého vzešlo nynější císařství. Tato část byla hodně bohatá na železo a zároveň se nacházela i jinde než jen v horských oblastech, takže zdejší lid se nesnažil využít nalezený kov pouze pro kutání v dolech, ale používal jej pro různé přístroje a nástroje, mimo jiné i pro zbraně. Rozhodující však byl technologický náskok zdejšího kraje, díky němuž zvítězili nad ostatními královstvími.</p>
<p>Nachází se zde císařské město <strong>Slunostěn</strong> (původní název byl Plánička, ale bylo přejmenováno 160 let nazpět císařem Otakarem IV. Budovatelem). Je to unikátní nádherné a na historii bohaté město, ve kterém je i císařský palác.</p>
<p>Vládce Železného kraje však není císař, je to samostatně volený správce a jeho sídlo je v Novoměstě, které je i hlavním městem celé provincie.</p>

<h3>Horský kraj</h3>
<p>Sousední region Železného kraje, nachází se v nejsevernější části císařství a jeho plochu povětšinou zabírají strmé a vysoké Dračí hory. Vedle divokých potvor, který daly pohoří název, se zde také nachází velké množství nerostného bohatství a tak není divu, že kraj je plný dolů, továren a alchymistických dílen.</p>
<p>Hlavním městem je <strong>Horobydlo</strong> a je to nejvýše umístěné krajské město v celém císařství. Legendy praví, že tohle město postavili sami obři na základech hnízda velkých bouřkových orlů. Leckdo se této povídačce může smát, ale jakmile by spatřil na vlastní oči město vytesané do skal a koupající se v mračnech, hned by místopřísežně prohlásil, že tomu nemohlo být jinak.</p>

<h3>Ledový kraj</h3>
<p>Na západ od hranic Horského kraje se Dračí hory začínají postupně drobit na menší a stále stejně nebezpečná drobná skaliska, mezi něž se mísí chladivá voda Severního moře. Ledový kraj sestává především ze stovek malých ostrůvků, fjordů, ledovcových plání a kusu pobřeží. Kvůli mrazivým vírům je tato provincie zemí takřka věčného sněhu, ale vděk tomu i velmi otužilých obyvatel.</p>
<p>Většina krajanů žije na pobřeží blízko hlavního města <strong>Mrázochrámu</strong> nebo tajemného poutního místa <strong>Černoděr</strong>, což je hluboká díra v zemi, ze které vychází teplo a o které se traduje, že navazuje na tajemné chodby vedené pod celým zemských povrchem.</p>

<h3>Kraj u sedmi jezer</h3>
<p>Na jih od Horského kraje tvoří východní hranici císařství Sedmijezeří. Zdejší dominantou je sedm obřích jezer, které jsou zdrojem potravy, bohatství, ale také nesčetně bájných historek a dohadů. V každém z nich je prý podvodní palác postaven z perel, mušlí a rákosu a třeba bylo podniknuto již mnoho výzkumných výprav, žádná z nich to nepotvrdila. To prý má císař s podvodním národem tajnou úmluvu a tak pravda nikdy nevyjde na světlo.</p>
<p>Západní část jezer jsou dokonce vyhledávaným odpočinkovým místem bohatších císařských obyvatel a rádi zavítají i do honosného města <strong>Perleťov</strong>. Východní část kraje už tak oblíbená není, neboť je prostoupena zrádnými mokřinami, které ale tak tvoří přirozenou hranici vůči případným nepřátelům.</p>

<h3>Křišťálový kraj</h3>
<p>Mezi Železným regionem a Sedmijezeřím se nachází Kraj křišťálový. Ještě až sem sahá mohutné severní pohoří, zde však v drobnější míře a přecházejí zde do menších skal, ve kterých jsou k nalezení stovky jeskyní. V těch se pak nachází druhé největší bohatství tohoto kraje a tím jsou ty nejrozmanitější křišťály a diamanty na světě.</p>
<p>Tím prvním bohatstvím této provincie jsou zdejší umělci, kteří s drahými kameny dokáží dělat učiněné divy. Většina z nich žije v hlavním městě <strong>Bižu</strong> a o mnohých z nich se traduje, že jsou to utajovaní potomci permoníků, kteří se prý stále schovávají v křišťálových jeskyních.</p>

<h3>Kraj lesů, luk a hájů</h3>
<p>Mnohem častěji se mu však říká pouze Lesní kraj. Zdejší oblast bývá také často popisována jako nejnádhernější a nejklidnější místo na světě, nebo zahrada bohů. Nenachází se zde žádná města v tom pravém slova smyslu, vše je budováno v souladu s přírodou, takže i sídelní místo správce <strong>Květolist</strong> je vyšlechtěno s touto ideou a rozléhá se v korunách Květolistového lesa.</p>
<p>Prý soulad s přírodou vede až k takovým věcem, že se na těchto místech příroda probouzí, stromy zde pochodují a obyvatelé mluví se zvířaty.</p>

<h3>Kopcovitý kraj</h3>
<p>Na západ od Lesního kraje a na jih od Železného se nachází Kraj kopců. Tato drobně zvlněná zem je bohatým sadem, plodným polem a domovem nejlepších kuchařů. Ne nadarmo se říká, chceš-li poznat, co je to opravdu jídlo, vyraz do Kopců.</p>
<p>Hlavním provinčním městem je <strong>Horní a dolní Kopcov</strong> a vedle výtečného koření a tabáku je také znám letním sídlem císařské rodiny, kteří do tohoto pohostinného kraje zajedou každou volnou chvíli.</p>

<h3>Kraj řemeslníků</h3>
<p>Dříve se tento region jmenoval Kraj bílých skal pro svá pískovcová skaliska, ale velmi rychle přešel ve známost a nakonec i formální používání nynější název, neboť provincie těží ze skvělého umístění mezi ostatními regiony a pomocí svých činorodých obyvatel vydává z produktů okolních zemí to nejlepší. Je to také země vynálezců a umělců a ti nejlepší z nich se rodí v <strong>Bílozdi</strong>, v praktickém a rozlehlém městě postaveném ze zdejšího nezaměnitelného kamene.</p>

<h3>Solný kraj</h3>
<p>Na jih od Kraje řemeslníků a Kopcovitého regionu se nachází Solný kraj. Je to až k nevíře, ale zdejší lidé se naučili tuto surovinu vydobýt takřka ze všeho a následně celé císařství ocenilo výhody této nenahraditelné ingredience. Hlavní obchod a zločin se zde točí okolo soli, ale spolu s ní zde kvete také další obchod, především potravinářského charakteru.</p>
<p>Hlavním městem je <strong>Solnohrad</strong> a povídačky tvrdí, že správcův hrad je postaven na velké hroudě zlata. Kolují totiž zvěsti, že sůl se leskne přece proto, že v sobě obsahuje malinkaté kousky zlata. Takže někdy na dně, na konci solných dolů se musí objevit zlaté žíly.</p>

<h3>Pobřežní kraj</h3>
<p>Západní část pevniny pak uzavírá Pobřežní kraj s hlavním městem <strong>Vlnolam</strong>. Tato země dala světu ty opravdové námořníky, mořeplavce a někdy i piráty. Zde se naučili krotit nespoutaný mořský živel a podvolit si k vlastním potřebám.</p>
<p>Z těchto končin vyplouvá do světa nejvíce lodí, ale zároveň jich sem také nejvíce připlouvá. Je tedy pochopitelné, že spolu se zahraničním zbožím se sem také dostanou věci v císařství ne zcela běžné, takže Pobřežní města jsou plná roztodivností a bizarností.</p>

<h3>Vinný kraj</h3>
<p>Region proslavený svou výtečnou pochutinou. Vinnou révu zde naleznete na každém kroku a snad jen zdejší sommeliéři se vyznají ve všech odrůdách a ročnících, které se zde vedou.</p>
<p>Vděk slastné tekutině se nadneseně tvrdí, že <strong>Hroznová Lhota</strong> patří mezi nejveselejší sídelní města. Je radostné tomu uvěřit, protože provincie má i velmi výhodnou polohu. Ze západu začíná jižní hranici císařství a přes Středové sem vanou teplé větrné proudy.</p>

<h3>Olivový kraj</h3>
<p>Tento region uzavírá jižní hranici císařství a ve zdejším suchém přímořském ovzduší se výtečně vede olivám. Zároveň zde vzkvétá zahraniční obchod, což sice navyšuje životní úroveň, ale zároveň to sem láká velké množství zlotřilců.</p>
<p>Není tedy divu, že v pestrém sídelní městě <strong>Olivojlu</strong> zaslechneme častěji cizince.</p>

<h3>Korálový kraj</h3>
<p>Nejpozději připojená provincie celého císařství. Na rozdíl od ostatních regionů se Korálový kraj nenachází na stejné pevnině jako ostatní země, ale jedná se o samostatný ostrov. Mezi ostatními obyvateli císařství občas kolují pomlouvačné fámy, že je to kraj divochů, nezkrocený sil a dřívějších civilizací. Že je nejvyšší čas, aby císař i tomuto regionu vtiskl ráz technicky vyspělé země jako zbytku císařství. Jedná se však spíše o pomluvy, Korálový kraj je na srovnatelné technické výši, pravdou však zůstává, že místy si zachovává i svůj původní folklór, jako například kolonie Vodních lidí na západě ostrova. Není ale nejmenších důvodů strachovat se, všichni jsou loajální císaři.</p>
<p>Hlavní město korálové provincie se jmenuje <strong>Vodostav</strong> a říká se, že ty nejkrásnější ze zdejších budov jsou památka na původní obyvatele. Těm je však dávno konec a na ostrově vládce císař.</p>
<p><br /></p>
<p>Vzhledem k tomu, že císařství je sjednocením velkého množství těchto rozmanitých zemí a všem tato pospolitost prospívá, nedá se říct, že by se někde objevovala nevraživost vůči různým rasám či vyznáním. Většina císařských již dávno pochopila, že naopak tyto rozdíly dopomohly císařství k větší slávě, pokrokům a blahobytu.</p>

<h2><a name = "vinny-kraj"></a>Kapitola II</h2>
<h1>Vinný kraj</h1>
<p>Vinný kraj tvoří spolu s Olivovým krajem většinu jižní hranice Slunečného císařství a jejich břehy omývá Středové teplé moře. Díky tomu mají oba kraje velmi příjemné podnebí. Ve Vinném kraji po většinu roku teploty neklesají pod nulu, kdy v létě se teploty šplhají nad třicet stupňů a léta bývají obvykle suchá. Naopak zimy jsou většinou bohatší na dešťové srážky, které jen ve vyšších polohách přecházejí ve sněhové, ale sněhová pokrývka se ve zdejším kraji obvykle příliš dlouho neudrží.</p>
<p>Povrch kraje je obvykle rovinatý nebo mírně zvlněný a původně ho pokrývaly světlé převážně stálezelené lesy, které během staletí na mnoha místech ustoupily obilným lánům, vinicím a pastvinám.</p>
<p>Dnes je kraj proslavený především právě díky vínu, které se tu pěstuje doslova na každém kroku a každý zámožnější sedlák má vlastní vinici, o které bude tvrdit, že plodí nejlepší víno ve vsi a širokém okolí. Ani nejlepší sommeliéři v Ústí neznají do detailu všechny odrůdy a ročníky, i když vám budou tvrdit, že ano. Za nejlepší vína se ale obecně považují odrůdy pěstované v okolí Hroznové Lhoty a pak vína z Doliny.</p>
<p>Vinný kraj je ale také obilnicí země, což už je známo méně. Díky příjemnému a teplému podnebí se tu obilí dobře daří a tak jsou především v údolích kolem řek vidět rozlehlé lány obilí. Není proto divu, že v kraji na každém druhém vhodném kopci stojí větrný mlýn. Vodní mlýny tady příliš nepotkáte, protože vhodných vodních toků tu není dost.</p>
<p>Vinným krajem protéká trojice velkých řek pramenících na severu v Kopcovitém kraji, Lužná, Bystrá a Černá. Největší z nich je Lužná pramenící nedaleko Horobydla a protékající přes Hroznovou Lhotu. Do moře se vlévá v Modrém zálivu. Všechny tři řeky tvoří hlavní dopravní tepny kraje. Jejich dolní toky jsou totiž většinou klidné a široké, takže umožňují klidnou a bezpečnou plavbu. Není proto divu, že jejich vody brázdí množství říčních lodí, člunů a vorů dopravujících ze severu dřevo, kůže, vlnu, sůl a další produkty. Na sever naopak putuje mouka, obilí a produkty z řemeslnických dílen ve městech na pobřeží a zboží z exotických zemí na jihu.</p>
<p>Vinný kraj patří mezi nejblahobytnější a nejzámožnější kraje a je to vidět i na venkově. Statky jsou rozlehlé a výnosné a i nádeníci na nich pracující se mají docela dobře. Ve zdejším kraji je obvyklé, že statky patří zámožným rodinám, šlechtě, případně podílnickým gildám, pro které je spravuje najatý správce, zatímco si majitelé užívají pohodlnějšího a luxusnějšího života ve městě.
Největším městem kraje není Hroznová Lhota, ale města na pobřeží, kde se soustřeďuje loďařství, bohatí kupci a zámořský obchod s dalekými jižními zeměmi. Největší z nich je Ústí, kde se zastavují nejen obchodní koráby plavící se podél pobřeží a říční lodě plující po Lužné, ale také velké zámořské koráby připlouvající z dálného jihu, kde vládnou černé kmeny klanící se podivným bohům.
Většinu obyvatel Vinného kraje tvoří lidé, jak původní jižané, tak přistěhovalci ze severu. Kromě lidí žije ve vnitrozemí početná hobití a kudůcká komunita v okolí Doliny. Do lesů na severovýchodě často zabloudí elfové z Lesního kraje. Přístavy na pobřeží jsou díky lodnímu ruchu plné cizinců a jiných ras, takže v nich vládne kosmopolitní atmosféra.</p>

