INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (200,'Organizace turnaje Mistrovství v Dračím Doupěti','organizace-turnaje',42,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (200,'mistrovstvi-v-drd/organizace-turnaje');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (200,'Organizace turnaje Mistrovství v Dračím Doupěti — GameCon 2011','gamecon,2011','Organizace turnaje Mistrovství v Dračím Doupěti');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (200,'<h1>Organizace turnaje Mistrovství v Dračím Doupěti</h1> 

<h2>Registrace</h2>

<p>Na Mistrovství v Dračím doupěti bude nutná registrace. Registrovat se budete moci jak předem, tak na conu. Doporučujeme ale registraci předem, neboť tím můžete získat slevu na startovném a zároveň si tím ušetřit čas. Registrace bude ukončena v první den conu, tj. ve čtvrtek 21.7. ve 20:00.</p>
<p>Na Mistrovství mohou soutěžit družiny, které mají 5 až 8 členů. Nebudeme tedy do existující sehrané pětičlenné družiny přidávat další hráče – věříme, že v 5 si třeba hru lépe užijete. Budete ale moci kontaktovat některou neúplnou družinku a dohodnout se s ní, že se k ní přidáte.</p>

<h2>Výběr Pána Jeskyně</h2>

<p>Předem zaregistrované družiny si budou moci zvolit PJ, kterého by chtěly pro první kolo Mistrovství. Tato volba vám neumožní vybírat mezi „hodnými“ a „zlými“ Pány Jeskyně. Má spíše za cíl dát vám možnost zvolit si PJ, o kterém víte, že více odpovídá vašemu stylu hry a více se s ním pobavíte. Způsob volby PJ bude popsán v článku O registraci na Mistrovství.</p>
<p>Jestliže si Pána Jeskyně nezvolíte, bude vám přidělen organizátory.</p>
<p>O zahájení výběru Pánů Jeskyně budete informováni v novinkách a správci družin také emailem.</p>

<h2>Herní bloky</h2>

<p>Soutěžní dobrodružství tvoří jeden souvislý příběh, který je rozdělen do tří navazujících částí. Všechny družiny se zúčastní první části dobrodružství. Na základě výsledků této části bude vybráno nejvýše 15 nejúspěšnějších družin, které postoupí dále. Během druhého dne bude z těchto družin po odehrání další části vybráno maximálně
6 nejlepších. Ty se zúčastní závěrečného finále, které rozhodne o vítězném pořadí.</p>
<p>První kolo se odehraje v pátek v dopoledním (9:00-13:00), odpoledním (14:00-18:00) a večerním (19:00-23:00) herním bloku. Družiny, které se budou registrovat předem budou mít možnost zvolit si herní blok, ve kterém chtějí hrát (dříve zaregistrované a zaplacené mají přednost).</p>
<p>Hra v prvním kole může trvat maximálně 4 hodiny, takže si raději dejte pozor, jak „utrácíte“ svůj čas a zkuste hru trochu popohnat. O tom, která družina postupuje do dalšího kola vás budeme informovat co nejdříve po skončení všech herních bloků, abyste si mohli přizpůsobit další program (pokud vaše družina postoupí a Mistrovství vám bude kolidovat s jiným přihlášeným programem, musíte se dohodnout s organizátory co s tím, jinak budete z kolizní aktivity vyškrtnuti).</p>
<p>Druhé kolo se odehraje v jednom ze dvou herních bloků v sobotu od 8:00 do 13:00 a od 13:00 do 18:00. Hra je o hodinu delší a nástup do ní je rychlejší, přesto si ale nezapomínejte hlídat čas. Sem tam si klidně u PJ ověřte jak na tom časově jste, abyste věděli, jestli musíte hru trochu popohnat. O postupujících do finále vás budeme 
informovat hned, jak to půjde, po skončení druhého kola.</p>
<p>Finále se odehraje v neděli dopoledne a trvá intenzívní čtyři hodiny, které rozhodnou o letošním vítězi.</p>

<h2>Vyhlášení vítězů</h2>

<p>V neděli se všichni sejdeme na slavnostním zakončení a vyhlášení vítězů všech turnajů. Řeč bude i o dobrodružství, jaké bylo, jak byly překážky nejefektivněji či nejzajímavěji vyřešeny, a pobavíme se i o 
dobrodružství na příští rok. Rádi si s vámi také popovídáme o tom, co se vám na dobrodružství a organizaci turnaje (jakožto i celého GameConu) líbilo a co by šlo příště udělat lépe.</p>

<h2>Ceny pro vítěze</h2>

<p>Vítězové Mistrovství v Dračím Doupěti se zapíší do GameConovské síně slávy a kromě toho připravujeme pro každého hráče umístěné družiny ceny, na které se nezapomíná.</p>

<h2>Informace o pravidlech</h2>

<p>Hraje se podle všech dílů Pravidel DrD verze 1.6. Používá se základní soubojový systém, z nepovinných úprav jen opravy za štít, kryt a dostřel. K číselné hodnotě inteligence postavy se přihlíží jen v případě, že je postava nucena jednat sama podle svého rozumu (tj. např. při hodech proti pasti). V ostatních situacích může družina přemýšlet kolektivně. V některých momentech hry vás ale PJ třeba může upozornit, že se hraje tzv. „real time“. V takovém případě všechno co uděláte/řeknete, udělala/řekla vaše postava. Nemáte při tom společné vědomí a nemůžete komunikovat jinak než na přímo jako své postavy. Zkuste si taky dát záležet na roleplayingu svých postav.</p>
<p>Pravidla pro tvorbu postav najdete v samostatném článku.</p>

<h2>Nesoutěžní hraní a dohrávání</h2>

<p>Na letošním GameConu nebude možnost hrát soutěžní dobrodružství nesoutěžně, ani ho dohrávat v případě, že nepostoupíte. Důvodem je především to, že Mistrovství v DrD má na GameConu svůj zvláštní ráz a povahu a právě ta soutěž je na něm výjimečná, což chceme zachovat.</p>
<p>Aby to ale nebylo nefér, tak všichni nepostupující do druhého kola dostanou jednu další aktivitu zdarma.</p>
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (200,'Organizace turnaje Mistrovství v Dračím Doupěti','Organizace turnaje Mistrovství v Dračím Doupěti Registrace Na Mistrovství v Dračím doupěti bude nutná registrace. Registrovat se budete moci jak předem, tak na conu. Doporučujeme ale registraci předem, neboť tím můžete získat slevu na startovném a zároveň si tím ušetřit čas. Registrace bude ukončena v první den conu, tj. ve čtvrtek 21.7. ve 20:00. Na Mistrovství mohou soutěžit družiny, které mají 5 až 8 členů. Nebudeme tedy do existující sehrané pětičlenné družiny přidávat další hráče – věříme, že v 5 si třeba hru lépe užijete. Budete ale moci kontaktovat některou neúplnou družinku a dohodnout se s ní, že se k ní přidáte. Výběr Pána Jeskyně Předem zaregistrované družiny si budou moci zvolit PJ, kterého by chtěly pro první kolo Mistrovství. Tato volba vám neumožní vybírat mezi „hodnými“ a „zlými“ Pány Jeskyně. Má spíše za cíl dát vám možnost zvolit si PJ, o kterém víte, že více odpovídá vašemu stylu hry a více se s ním pobavíte. Způsob volby PJ bude popsán v článku O registraci na Mistrovství. Jestliže si Pána Jeskyně nezvolíte, bude vám přidělen organizátory. O zahájení výběru Pánů Jeskyně budete informováni v novinkách a správci družin také emailem. Herní bloky Soutěžní dobrodružství tvoří jeden souvislý příběh, který je rozdělen do tří navazujících částí. Všechny družiny se zúčastní první části dobrodružství. Na základě výsledků této části bude vybráno nejvýše 15 nejúspěšnějších družin, které postoupí dále. Během druhého dne bude z těchto družin po odehrání další části vybráno maximálně 6 nejlepších. Ty se zúčastní závěrečného finále, které rozhodne o vítězném pořadí. První kolo se odehraje v pátek v dopoledním (9:00-13:00), odpoledním (14:00-18:00) a večerním (19:00-23:00) herním bloku. Družiny, které se budou registrovat předem budou mít možnost zvolit si herní blok, ve kterém chtějí hrát (dříve zaregistrované a zaplacené mají přednost). Hra v prvním kole může trvat maximálně 4 hodiny, takže si raději dejte pozor, jak „utrácíte“ svůj čas a zkuste hru trochu popohnat. O tom, která družina postupuje do dalšího kola vás budeme informovat co nejdříve po skončení všech herních bloků, abyste si mohli přizpůsobit další program (pokud vaše družina postoupí a Mistrovství vám bude kolidovat s jiným přihlášeným programem, musíte se dohodnout s organizátory co s tím, jinak budete z kolizní aktivity vyškrtnuti). Druhé kolo se odehraje v jednom ze dvou herních bloků v sobotu od 8:00 do 13:00 a od 13:00 do 18:00. Hra je o hodinu delší a nástup do ní je rychlejší, přesto si ale nezapomínejte hlídat čas. Sem tam si klidně u PJ ověřte jak na tom časově jste, abyste věděli, jestli musíte hru trochu popohnat. O postupujících do finále vás budeme informovat hned, jak to půjde, po skončení druhého kola. Finále se odehraje v neděli dopoledne a trvá intenzívní čtyři hodiny, které rozhodnou o letošním vítězi. Vyhlášení vítězů V neděli se všichni sejdeme na slavnostním zakončení a vyhlášení vítězů všech turnajů. Řeč bude i o dobrodružství, jaké bylo, jak byly překážky nejefektivněji či nejzajímavěji vyřešeny, a pobavíme se i o dobrodružství na příští rok. Rádi si s vámi také popovídáme o tom, co se vám na dobrodružství a organizaci turnaje (jakožto i celého GameConu) líbilo a co by šlo příště udělat lépe. Ceny pro vítěze Vítězové Mistrovství v Dračím Doupěti se zapíší do GameConovské síně slávy a kromě toho připravujeme pro každého hráče umístěné družiny ceny, na které se nezapomíná. Informace o pravidlech Hraje se podle všech dílů Pravidel DrD verze 1.6. Používá se základní soubojový systém, z nepovinných úprav jen opravy za štít, kryt a dostřel. K číselné hodnotě inteligence postavy se přihlíží jen v případě, že je postava nucena jednat sama podle svého rozumu (tj. např. při hodech proti pasti). V ostatních situacích může družina přemýšlet kolektivně. V některých momentech hry vás ale PJ třeba může upozornit, že se hraje tzv. „real time“. V takovém případě všechno co uděláte/řeknete, udělala/řekla vaše postava. Nemáte při tom společné vědomí a nemůžete komunikovat jinak než na přímo jako své postavy. Zkuste si taky dát záležet na roleplayingu svých postav. Pravidla pro tvorbu postav najdete v samostatném článku. Nesoutěžní hraní a dohrávání Na letošním GameConu nebude možnost hrát soutěžní dobrodružství nesoutěžně, ani ho dohrávat v případě, že nepostoupíte. Důvodem je především to, že Mistrovství v DrD má na GameConu svůj zvláštní ráz a povahu a právě ta soutěž je na něm výjimečná, což chceme zachovat. Aby to ale nebylo nefér, tak všichni nepostupující do druhého kola dostanou jednu další aktivitu zdarma.');

