INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (201,'Postavy pro letošní dobrodružství','Postavy pro letošní dobrodružství Na této stránce je pro vás připraven výběr předpřipravených postav pro GC dobrodružství 2009. Postavy mají přednastaveny vlastnosti a krátkou historii. Ostatní parametry včetně vybavení si budete moci dotvořit v systému, který bude fungovat v rámci přihlášky (naváže na dosavadní volbu rasy a povolání) a který brzy spustíme. Nemusíte si vybírat žádnou z postav na této stránce. Můžete si jakoukoli svou svobodně vytvořit v systému, který brzy spustíme. Nabídka postav je jen pro usnadnění hráčům, kterým by se třeba zalíbily a nebo se jim nechce vymýšlet historii vlastní postavy a přesto by rádi nějakou měli. Cathal - trpaslík bojovník Uallas - barbar šermíř Malaia - elfka druidka Taran - kroll chodec Farquar - člověk theurg Rós - kudůkyně pyroforka Rona - člověk sico Luag - elf mág Seytach - barbar čaroděj Flora - hobitka lupička Cathal - trpaslík bojovník síla: 17/+3 obratnost: 9/-1 odolnost: 21/+5 inteligence: 11/0 charisma: 11/0 životy: 75 věk: 18 let Když se před 18 léty narodilo v Adrii vojáku Cesanovi páté dítě, byla jeho radost bezmezná. Lépe řečeno: byla omezena čtyřmi dny a čtyřmi nocemi oslav. Byl to totiž syn – jeho první syn. Syn, do kterého Cesan vložil veškerou svou důvěru a své naděje. Hrdě jej pojmenoval Cathal – „Ten, který bojuje mocně“. Po dlouhých patnáct let jej nepustil ze vsi, vyžadoval od něj vše, co mu nemohly dát dcery. Již od útlého věku jej myl ve studené řece stékající z ledovců, aby se tělo připravilo na těžké zimy. S božími zázraky a svědomitou péčí se tak stal z Cathala nejzdravější mladík vesnice. Nikdy nestonající, nikdy netrpící chladem. Jakoby se stal samotným mrazem severu. Většina mladíků rostla do výšky a krásy, Cathal však nikoliv. Pod tíhou výcviku a práce v hospodářství se jeho tělo rozhodlo zastavit růst na 140 coulech. Místo rovných zad získala Cathalova ohnutý tvar – co ale nedostal na výšce, to získal na mohutnosti. Jeho zjev přinesl mladíkovi (v tu dobu již patnáctiletému) přezdívku „Dědek“. Jak strašně tuto přezdívku nenáviděl, jak se mu začala vřít vzteky krev, kdykoli ji zaslechl, jak mu rozum i oči zaslepila divoká nenávist. Vždy si prohrábl svou hustou hnědou kštici, aby se uklidnil. Snažil se ovládnout svůj hněv, jak to po něm vyžadoval jeho otec. Ne vždy byla jeho snaha úspěšná, pak se do díla pustily jeho pěsti, které do provokatéra bušily jako kladiva do kovadliny. Samozřejmě, že od otce se za tyto výbuchy pochvaly nedočkal. Kdykoliv nebyl mládenec ve službě, odcházel na mořská skaliska, kde hledal samotu. Bouře přirážejících vln zaplavovala jeho mysl a překřikovala vzpomínky na posměch. Cathal se nechal tímto hlukem rád ohlušit. Nevěděl, že se sám stává tím příbojem, tím hlukem chladných vod. Jeho ústa soupeřila s hlasem moře, bouři chvílemi přesahoval křik. Křik po chvíli udolával opět hřmot hlubin oceánu. Vyčerpán a osamocen, připadal si konečně svobodný. Pár dní po šestnácté prožité oslavě letního slunovratu vydal se Cathal na zkušenou. Jako odsouzenec, kterému sejmou okovy, rozběhl se do světa, nevěda, kolik zkoušek jej čeká. Přes kožený kabát připnul opasek s mečem a dýkou, do ruky uchopil obouruční sekyru. Svému starému otci podal ruku jako zralý muž. Poděkoval mu za vše a uklonil se. Matku a pět sester krátce políbil. Tehdy opustil Adrii, aby se snad jednoho dne vrátil. návrat na začátek Uallas - barbar šermíř síla: 19/+4 obratnost: 11/+1 odolnost: 17/+3 inteligence: 8/-1 charisma: 10/0 životy: 63 věk: 26 zim Nikdo netušil, odkud se vzalo. Ale jednoho rána se koncem podzimu před palisádou objevilo dítě. Vyplašeně se krčilo ve výklenku u západní brány, aby zde nalezlo alespoň trochu závětří. Jeho slovům nikdo nerozuměl. Unavené a promrzlé se však nemohlo bránit a tak jej strážní odnesli k místní bylinkářce. Bylinkářka o chlapce pečovala celou dlouhou zimu,a naučila hocha několik málo slov a vět v místním jazyce. Jedním z prvních slov, které se chlapec naučil, bylo Uallas [Valis]– Cizí. Postupně jej tak všichni začali oslovovat. Trvalo to dlouho, ale nakonec se chlapec k ženě přimkl a stal se jí vlastním. Úspěšně vyléčila jeho tělo a pak i jeho duši. O deset let později byl již z Uallase pohledný mladík, za kterým se otáčela nejedna dívka či paní. Ač jeho mysl nepatřila k nejbystřejším, vyslovily-li ženské rty milým hlasem prosbu, rád a bez meškání vyhověl. Pohyboval se vždy s ladností divoké kočky, svaly na jeho těle jen hrály, jeho ruce byly jemné a citlivé, jeho oči jako dva jantary plály nevídaným jasem. A to vše doplňovala záře jeho zlatavých vlasů. Často dával své tělo na odiv rannímu slunci, když cvičil v rytmu podivných písní, o kterých sám netušil, odkud je zná a které vycházely přímo z jeho srdce. Možná to bylo jediné spojení s jeho matkou, rodinou či vlastí. Jeho zevnějšek, charisma, ho měly předurčovat k vznešeným cílům, ale Uallas byl Cizí. Narodil se někde v Divočině. I když zde žil několik let, pořád byla jeho řeč trochu lámaná; i když lovil to, co ostatní, i když žil jako ostatní… nepatřil sem. A všichni to věděli, i on sám to věděl. Po smrti své opatrovnice, která se mu stala matkou, již neměl dál důvod zde setrvávat, opustil tedy bylinkářskou chýši a vydal se na cesty. Jeho společníky se stali meč a vítr. A ty oči. Tajemné oči, které viděl v každém svém snu. Oči, které jej konejšily a očarovávaly, které nad ním bděly a které ho lákaly stále dál. Věřil, že se do nich jednou zahledí a že tehdy snad potká i svou matku. Ne dnes, ne zítra… ale jednou ano. návrat na začátek Malaia - elfka druidka síla: 14/+1 obratnost: 13/+1 odolnost: 8/-1 inteligence: 19/+4 charisma: 16/+2 životy: 32 magy: 24 věk: 26 zim Malaia byla pravou představitelkou erinského lidu. Její tělo bylo hbité, ladné i poddajné. Jejím nesmírným darem byla bystrá mysl, která ji dokázala ochránit i ve chvílích nejtěžších zkoušek. Nedaleko od jejich vsi bylo zakázané místo, kde se scházeli muži z kamenných domů. Jen muži směli a měli právo na toto místo vstoupit. Tajemství a zákazy, které tento kus lesa obklopovaly, jen podněcovaly v Malaii touhou po nepoznaném. Den co den ji něco v jejím nitru táhlo tam– tam, na ten palouček, na mírném návrší, kde jakoby příroda kolem zmlkla, aby se vzápětí rozezněla v tóninách a hlasech naprosto nových, nikde jinde neslyšených. S jak velkou úctou vztahovala ruce k oněm menhirům, které zde stály v kruhu kolem ní. Když se její ruce potkaly s chladným kamenem, cítila hluboko ve svém srdci, že k ní promlouvá, zjevuje před ní obrazy, jakoby snad ona sama byla jednou z těch, kteří do kamene obrazce vyrývali. Pak jako v mrákotách klesla uprostřed mezi těmito monumenty k zemi a tehdy se jí v hlavě rozezvučela slova a spojovala se do krásných obrazů. Bez dechu pak pozorovala z úkrytu muže, kteří se zde scházeli noc co noc. Když odešli, bylo ona paní paloučku. Aniž by věděla proč, pronášela slova, kterým snad ani nerozuměla, ale chápala, že jimi vzdává hold všemu živému kolem sebe. Nepřemýšlela nad tím, kde se v ní berou ta slova, ani gesta, kterými je doprovázela. Věděla však s neochvějnou jistotou, že to tak je správné a že ona sem patří. Když se z ní pak jednoho úplňku stala skutečná žena, dovršilo se i její spojení s přírodou, rostliny i zvěř jí naslouchaly a ona jim rozuměla. Dostalo se ji nesmírného daru, daru moudrosti, daru souznění s přírodou. Ale všechno má svou cenu, i Malaia musela zaplatit. Jedné noci, kdy oblohu opět zdobil úplněk, počala Malaia dítě. Už tehdy si uvědomila, že dítě bude tím, co musí zaplatit.Ač se její srdce trápilo, hluboko ve svém nitru věděla, že nemá na vybranou a že o její dítě bude postaráno, jen ona jej už nikdy v životě nespatří. V noc, kdy se ji narodil překrásný chlapeček, se kolem ní shromáždilo několik vlků. Když pak držela své dítě poprvé v náruči, znovu se jí rozezněla v hlavě ta slova: Příroda… Moudrost… Život… Oběť… Věděla, že tou obětí, kterou nesmí odmítnout, je její dítě,. Oproti tomu se v ní však ozýval i mateřský pud, který nechtěl novorozeně vydat. Vlci byli krutě milosrdní, nechali ji dítě ještě pochovat, pohladit, polaskat, nakrmit, ale pak jim jej musela vydat. Nemohla jinak. Vlci jej odnesli pryč. Krutá bolest se navždy usídlila v jejím nitru, čas ji jen trochu obrousil a z bolesti se zrodila vnitřní síla. Malaia vyrazila na cestu Přírodou, aby ji chránila, aby ji rozuměla, aby ji pomáhala. návrat na začátek Taran - kroll chodec síla: 17/+3 obratnost: 8/-1 odolnost: 16/+2 inteligence: 11/0 charisma: 7/-2 životy: 50 magy: 16 věk: 28 jar Je tomu už dávno, co Taranův otec připlul do těchto končin. Jako každý dobyvatel zabíjel, drancoval, znásilňoval. Nejedna žena tak poznala jeho chtíč a ač zrodilo se mnoho potomků jeho krve, je zde jeho jméno dávno raději zapomenuto. Nevedlo se dobře ani matkám, ani jejich potomkům, jen málokdo měl soucit se ženou, kterou obtěžkal násilník z cizího kmene. Nikdo se laskavě nepodíval na bastarda, jehož otec byl neznámý. Dobytek měl leckde větší cenu než tyto děti. I Taran byl jedním z těchto dětí, Taran – „Ten, který nemá nikde domov“. Taran i jeho matka však měli velké štěstí. Vesnice Walgar ležela vysoko v kopcích, zdejší lidé jen těžko z hory dobývali obživu, neměli tedy čas na předsudky a byli chápaví, to vše usnadnilo oběma uprchlíkům těžkou situaci. Lidé ve vsi byli neobyčejně laskaví, Tarana přijali za svého. U každého ohně se mohl ohřát, u každého se mohl najíst. Každý ho naučil to nejlepší, co sám uměl. Sběrač mu vysvětlil, které plody přírody se dají jíst a kterým je lepší se vyhnout. Lovec mu ukázal, kde se v lese skrývá zvěř a jak čtením stop dojde k cíli. Kdy je dobrý čas pro lov a kdy naopak je správné nechat zvěři klid. Ze zakřiknutého bojácného dítěte tak díky péči celé vesnice vyrostl statný, sebejistý mladík, který ke každému dokázal promluvit jazykem jeho duše. Jinoch, jemuž žádná práce nebyla cizí. Nejlépe se cítil, když mohl někomu pomoci. A pokud při této pomoci musel vynaložit hodně síly, byl ještě spokojenější. I druid stál s podivem, když viděl jak Taran kácí strom. To nebyl souboj mezi člověkem a stromem, při němž člověk supí, potí se a námahou se mu napínají svaly k prasknutí a strom sténá, naříká a roní pryskyřičné slzy. Ne, to nebyl boj, to byl tanec, ve kterém Taran zprvu ke stromu přistoupil, pohladil jej, poklonil se mu, jako když muž ženu k tanci vyzývá. Pak odstoupil, uchopil pevně sekeru, napřáhla se a ťal. Ač je to k nevíře, strom jako by sám nastavoval své nejslabší místo… a pak již v jakémsi tanečním rytmu, zlehka padl strom k zemi. Pak Taran jen sklonil hlavu a mlčky se s lesním velikánem rozloučil. Stejně tak při lovu velmi opatrně volil kus, který pak skolil, potom i jemu vzdal poctu. Druid dlouho pozoroval Tarana, a došel k závěru, že jeho srdce je čisté. Oslovil jej tedy a vyzval jej, aby se stal jeho pomocníkem. Tehdy v sobě Taran objevil dar hudby a zpěvu a jeho bubínek od té chvíle doprovázel všechny slavnosti, ať už to bylo vítání jara, uctívání bohů nebo jen tak pro radost. Taranova hudba dávala lidem zapomenout na starosti a bolesti, nabízela jim odpočinek, naději, radost, víru. Když bylo Taranovi pětadvacet, uvědomil si, že je na čase, aby se vydal na svou pouť. Když se loučil se všemi těmi, kteří mu byli rodinou, už dávno zapomněl, že je bastardem, kterého kdysi kdesi nikdo nechtěl. Jeden ze starších vesnice k němu přistoupil a podával mu předmět zabalený do plátna. Když Taran spatřil meč, vytanula mu v hlavě vzpomínka, ale nepodařilo se mu ji zachytit. Věděl jen, že ten meč mu po právu patří a že ho bude provázet jako věrný druh životem. Ale také věděl, že chce tento meč použít vždy jen na svou obranu a sám před sebou a svými bohy odpřisáhl, že nikdy tento meč nepoužije k tomu, aby zabil jiného člověka. A do dnešních dnů, kdy putuje od vesnice k vesnici, svůj slib neporušil. návrat na začátek Farquar - člověk theurg síla: 12/0 obratnost: 16/+2 odolnost: 17/+3 inteligence: 13/+1 charisma: 11/0 životy: 50 věk: 25 let Farquar se narodil v neúplné rodině. Matka skonala při porodu a otec měl co dělat, aby malého chlapce udržel při životě. Pro oba to byla zkouška života. Jeden bez druhého by asi nevydrželi ani den. Ten maličký měl ve velkém ochránce. Ten větší pak ve svém synkovi hledal radost a útěchu. Den za dnem táhl postarší hvězdopravec svou káru od vesnice k vesnici, aby lidem zvěstoval, co je čeká. Dával jim rady, kdy zasít a kdy sklidit. Kdy počít nového potomka i jak správně pohřbít nebožtíka. Malinký Farquar se pomalu vše od svého otce učil. Nevadil mu ten kočovný způsob života, hlavně když se mohl kdykoli chytit táty za ruku. Celý den se Farquar těšil na večer, kdy se na nebi objeví první hvězda. Sebelepší hraničář nečetl v čerstvém sněhu stopy tak dobře, jako Farquarův otec ve hvězdách. Každý večer vybral jednu hvězdu na nebi a o té vyprávěl svému synkovi překrásný příběh. Jedna za druhou odkrývaly hvězdy před Farquarem svá tajemství a přesto věděl, že je pořád pouze na počátku svého poznání. Tak se Farquar dozvěděl o Velkém draku, který střeží náš svět svým pohledem a čeká na odvážlivce, kteří dokáží vstoupit na nebesa a porazit jej. „Ale tati, jak by člověk mohl vstoupit na oblohu, mezi hvězdy?“ Pohladil otec syna, pohlédl na něj láskyplným pohledem: „Jen ten, milý hochu, kdo ve svém srdci pokoru má, úctu k moudrým v sobě chová, ten je hoden vstupu na nebeskou klenbu.“ Vyslechl příběh o Krvavém vlku a Válečníkovi, kteří spolu bojovali před drahnou dobou o srdce Zlaté vlkodlačice. Slepě bojovali o srdce té, která jen s úsměvem přihlížela. Jeden jako druhý se zapřisáhli, že jejich boj neskončí, dokud ten druhý mrtvý nepadne. Bojovali dlouho a urputně, štěstí se přiklánělo tu na jednu, tu na druhou stranu. Zranění přibývala, síly se vytrácely. Nakonec stanuli přímo proti sobě, oba posetí ranami a k smrti vyčerpáni. Věděli, že tento střet bude poslední, teď vzejde vítěz. Vlk vyskočil a sekl drápy, válečník po něm tnul sekerou. Válečník padl k zemi, ale vlk také. Žádný z nich nebyl mrtvý, ale žádný z nich ani neměl síly se postavit. Jejich přísaha je odnesla na nebesa, kde musí spolu bojovat, dokud jeden nezemře. „Vidíš synku, ani jeden z nich srdce milované nezískal. Tím ti hvězdy chtějí říci, že štěstí jednoho nemůže vyrůst ze smrti jiného.“ Farquar vyslechl mnoho příběhů, které přinášely poselství hvězd, poselství stará a moudrá. Učily jej být lepším člověkem. „Za každou chybu, kterou ve svém životě uděláš, buď můj synku vděčný a nauč se z ní tomu, jak to příště udělat lépe.“ Každodenní putování a útrapy cest způsobily, že jednoho podzimního večera o svátku rovnodennosti zesnul Farquarův otec přímo pod hvězdami, které tolik miloval. Farquar, byť tehdy již dvacetiletý, proplakal celou noc. Pak si vzpomněl na to, co mu otec vždy říkal, že bude vždy s ním, že se po své smrti stane hvězdou, která mu bude svítit na cestu. Přestal truchlit a rozhodl se uctít svého otce nádherným náhrobkem. Stvořil obrovský kalendář. Každý, kdo šel kolem, se ptal, co činí. A Farquar vyprávěl. Vyprávěl jim o životě malého chlapce a jeho otce. O Velkém draku, Krvavém psu i Válečníkovi. A ti, kdo poslouchali, mu začali při jeho práci pomáhat. Celý rok trvala stavba kalendáře. Když však Farquar v den ročního výročí úmrtí otce odcházel z těchto míst, najednou vše zmizelo. Jakoby nikdy jeho otec neexistoval, jako by to vše byl jen další příběh, který se vypráví. Jen Farquar věděl, co je pravda a ještě někdo – malinká hvězdička, která se objevila poblíž souhvězdí Velkého draka, přesně uprostřed mezi jeho očima. Ne však proto, aby s majestátností Velkého soupeřila, ale proto, aby mu prokazovala úctu a přitom hlídala cestu jednoho z těch tam dole. návrat na začátek Rós - kudůkyně pyroforka síla: 8/-1 obratnost: 19/+4 odolnost: 16/+2 inteligence: 13/+1 charisma: 9/-1 životy: 44 věk: 33 let Na západním okraji Cornwallu se v jedné osadě narodila překvapivě šikovná holčička. Její zručnost byla nevídaná, navlékání korálků, splétání věnečků, tkaní látek či jejich barvení, šití nebo výroba dřevěn