INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (203,'GameCon začal, veškeré registrace přes internet jsou ukončeny','prihlaska-na-drd',42,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (203,'mistrovstvi-v-drd/prihlaska-na-drd');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (203,'GameCon začal, veškeré registrace přes internet jsou ukončeny — GameCon 2011','gamecon,2011','GameCon začal, veškeré registrace přes internet jsou ukončeny');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (203,'<!--
<h1 style = "color: red;">GameCon začal, veškeré registrace přes internet jsou ukončeny</h1>
<h2 style = "color: red;">Jakékoliv další změny jsou možné u infopultu v deskoherně</h2>
-->

<h1>Přihláška na Mistrovství v DrD</h1>


  <p>Na této stránce máte možnost přihlásit se na Mistrovství ČR v Dračím doupěti 2011. Kromě přihlášení samotného zde můžete založit novou družinu nebo se přihlásit do nějaké již existující.</p>
  <p>Letos máte, stejne jako loni, možnost zvolit si herní bok ve kterém chcete odehrát první část dobrodružství a také PJ pro svou první část.</p>
  <p>Podrobnější návod k přihlašování na Mistrovství v DrD najdete <a href = "/mistrovstvi-v-drd/navod---prihlaseni-na-drd">na této stránce</a>.</p>
  <p>Pro přihlášení na <strong>Mistrovství v DrD</strong> musíš být registrovaný na webu GC a zároveň mít podanou <a href = "/gamecon/prihlaska">přihlášku na GameCon 2011</a>.</p>
    </div>
  </div>');
