INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (206,'<h1>Starší dobrodružství</h1>
<p>
  Na této stránce si můžete stáhnout některá z dřívějších soutěžních dobrodružství, která se hrála na GameConu. Pracujeme i na zpřístupnění některých dalších, ale bohužel ta starší dobrodružství často nejsou v publikovatelné podobě, popřípadě doznala některých výrazných změn na samotném conu a potřebují upravit (což je po těch letech trochu těžký oříšek).
</p>
<p>
  Dobrodružství si smíte stáhnout pro vlastní potřebu a hru s přáteli. Bez souhlasu autora nebo GameConu je však nesmíte jakkoli komerčně využívat, hromadně šířit nebo zpřístupňovat širší veřejnosti.
</p>

<h2>Pravdonošové - GameCon 2010</h2>
<p>
  <strong>autor:</strong> Tramis<br />
  <a href = "/download/starsi-dobrodruzstvi/GC10_pravdonosove.pdf">dobrodružství Pravdonošové (.pdf, 29,3 MB)</a>
</p>

<h2>Nájezdníci - GameCon 2009</h2>
<p>
  <strong>spoluautoři:</strong> Elden, Gandalf, John Jarik, Skála, Tari, Tramis, Wulf<br />
  <a href = "/download/starsi-dobrodruzstvi/GC09_najezdnici.pdf">dobrodružství Nájezdníci (.pdf, 1,6 MB)</a>
</p>

<h2>Invaze - GameCon 2008</h2>
<p>
  <strong>autoři:</strong> Gandalf, Skála, Tramis<br />
  <a href = "/download/starsi-dobrodruzstvi/GC08_invaze.pdf">dobrodružství Invaze (.pdf, 5,5 MB)</a>
</p>
 
<h2>O život - GameCon 2005</h2>
<p>
  <strong>autor:</strong> Erric<br />
  <a href = "/download/starsi-dobrodruzstvi/GC05_o_zivot.pdf">dobrodružství O život (.pdf, 4,5 MB)</a>
</p>
 
<h2>Alexandrova pomsta - GameCon 2003</h2>
<p>
  <strong>autor:</strong> Lečo<br />
  <a href = "/download/starsi-dobrodruzstvi/GC03_alexandrova_pomsta.pdf">dobrodružství Alexandrova pomsta (.pdf, 1,3 MB)</a>
</p>
