INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (207,'kapacita 7/0<br />
<h1>Úvod do Mistrovství v DrD</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/uvod-do-mistrovstvi-v-drd.gif" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>organizátor</strong><br />GameCon<br />
  <strong>čas akce</strong><br />čtvrtek 21.7 - 18:00 až 19:00  <br />
 
</div>
</p>
   <p style = "clear: both;">
Všichni novináři ze Sluncesvitu, všichni poutníci z krajů blízkých i dalekých se schází. Svádí je touha po poznání Slunečního císařství. Císařství, v němž se odehrává (podle zdrojů Sluncesvitu) nejzajímavější příběh tohoto roku.</p>
<p>Nic nesmí být dobrodruhům kráčejícím po Císařství zatajeno. Všichni musí mít rovné šance uspět.</p>
<p>Využijte příležitosti a sejděte se s pány jeskyně ještě před začátkem Mistrovství v DrD.</p>
<p>Připravte si dotazy a čekejte odpovědi.</p>
<p>Doporučujeme účast alespoň jednoho člena každé družinky.</p>
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (207,'Úvod do Mistrovství v DrD','kapacita 7/0 Úvod do Mistrovství v DrD organizátor GameCon čas akce čtvrtek 21.7 - 18:00 až 19:00 Všichni novináři ze Sluncesvitu, všichni poutníci z krajů blízkých i dalekých se schází. Svádí je touha po poznání Slunečního císařství. Císařství, v němž se odehrává (podle zdrojů Sluncesvitu) nejzajímavější příběh tohoto roku. Nic nesmí být dobrodruhům kráčejícím po Císařství zatajeno. Všichni musí mít rovné šance uspět. Využijte příležitosti a sejděte se s pány jeskyně ještě před začátkem Mistrovství v DrD. Připravte si dotazy a čekejte odpovědi. Doporučujeme účast alespoň jednoho člena každé družinky.');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (208,'Novinky','archiv-novinek',30,0,0);
