INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (236,'Organizátoři larpů','organizatori-larpu',62,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (236,'organizatori/organizatori-larpu');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (236,'Organizátoři larpů — GameCon 2011','gamecon,2011','Organizátoři larpů');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (236,'<h2 style = "float: left; width: 100%;" id = "organizatori_larpu">Organizátoři larpů</h2>
<div class = "organizatori">
  <div class = "jmeno">Gekon – Jiří Zlatohlávek</div>
  <div class = "foto">
    <img src = "/system_styly/organizatori/gekon.jpg" />
  </div>
  <strong>Funkce na GC</strong><br />organizátor larpů<br />
  <strong><a href = "gekon o sobě" onclick = "ukaz(11); return false;">O sobě píše</a></strong><br /><span  id = "objekt11" style = "display: none;">
  <p>Rolovým hrám se věnuji osm let, od roku 2007 intezivně v rámci občanského sdružení Court of Moravia. Na Gameconu vyprávím letos pátým rokem. Preferuji koncepční hry, dramatický přístup he hraní a prostředí moderní mystiky. Ve chvílích školního volna pracuji v čajovně, organizuji larpy a vemlouvám se slečnám do přízně.</p> 
  </span> 
</div>

<div class = "organizatori">
  <div class = "jmeno">Jezevec – Petr Pouchlý</div>
  <div class = "foto">
    <img src = "/system_styly/organizatori/jezevec.jpg" />
  </div>
  <strong>Funkce na GC</strong><br />organizátor larpů, přednášející<br />
  <strong><a href = "jezevec o sobě" onclick = "ukaz(12); return false;">O sobě píše</a></strong><br /><span  id = "objekt12" style = "display: none;">
  <p>Vyprávění v rolových hrách se věnuji již 15 let, přičemž poslední dobou se orientuji především na tvorbu larpů. Na GameConu se vyprávění věnuji od roku 2002, několik let jsem se podílel na dramaturgii celé akce.</p> 
  <p>Ve svém volné čase se zabývám organizováním volnočasových aktivit pro mládež, přípravou larpů a organizaci herních setkání. Krom toho žiji se snoubenkou a potkanem, kultivuji vlastní byt a pracuji na plný úvazek. Svět vidím barevně.</p>
  </span> 
</div>

<div class = "organizatori">
  <div class = "jmeno">Jana Jevická</div>
  <div class = "foto">
    <img src = "/system_styly/organizatori/default.jpg" />
  </div>
  <strong>Funkce na GC</strong><br />organizátor larpů<br />
  <strong><a href = "jana o sobě" onclick = "ukaz(18); return false;">O sobě píše</a></strong><br /><span  id = "objekt18" style = "display: none;">
  <p>Členka Court of Moravia, lektorka dílen rétoriky, divadelního herectví a režie, organizátorka larpů, divadelní praktik i teoretik a ve volném čase ještě ledacos jiného. Jestli mě chcete na Gameconu potkat, hledejte na sluníčku, u bazénu nebo na tanečním parketu.</p>
  </span> 
</div>

<div class = "organizatori">
  <div class = "jmeno">Lothmíril - Veronika Frankovská</div>
  <div class = "foto">
    <img src = "/system_styly/organizatori/loth.jpg" />
  </div>
  <strong>Funkce na GC</strong><br />organizátor larpů<br />
  <strong><a href = "Lothmíril o sobě" onclick = "ukaz(19); return false;">O sobě píše</a></strong><br /><span  id = "objekt19" style = "display: none;">
  <p>K rolovým hrám som sa dostala predovšetkým cez larpy, ktorým sa venujem okolo piatich rokov ako hráč a v poslednej dobe koketujem s ich organizačnou stránkou v rámci združenia Court of Moravia. Verím v svet, v ktorom sú hry – nielen rolové –  vyhľadávaným relaxom a bežným spôsobom trávenia času pre všetkých bez ohľadu na vek.</p>
  </span> 
</div>

<div class = "organizatori">
  <div class = "jmeno">KoRH</div>
  <div class = "foto">
    <img src = "/system_styly/organizatori/korh.png" />
  </div>
  <strong>Funkce na GC</strong><br />organizátoři larpů<br />
  <strong><a href = "korh o sobě" onclick = "ukaz(10); return false;">O sobě píší</a></strong><br /><span  id = "objekt10" style = "display: none;">
  <p>KoRH - Knights of Red Hills je pořadatelskou a hráčskou skupinou z Brna, která se na larpové scéně pohybuje od roku 2003. S organizací larpů začali v r. 2006 s noční městkou hrou Alfatest, která se dočkala dalších 2 ročníků. Kromě larpů se její členové věnují i různým RPG, jezdí na dřevěné bitvy a v neposlední řadě se snaží účastnit i konferencí na téma larpů, což vyvrcholilo v pořádání meetingu organizátorů larpu v únoru 2010. Nyní se poprvé dostávají i na půdu GameConu a snaží se jeho účastníkům zprostředkovat silný larpový zážitek.</p>
  </span> 
</div>

<div class = "organizatori">
  <div class = "jmeno">Lischai – Pavel Gotthard</div>
  <div class = "foto">
    <img src = "/system_styly/organizatori/lischai.jpg" />
  </div>
  <strong>Funkce na GC</strong><br />organizátor larpů, přednášející<br />
  <strong><a href = "lischai o sobě" onclick = "ukaz(13); return false;">O sobě píše</a></strong><br /><span  id = "objekt13" style = "display: none;">
  <p>O sobě píše: Třetím rokem studuji scenáristiku na Jamu a přivydělávám si jako scenárista na volné noze. Jsem členem občanského sdružení Court of Moravia, v rámci kterého se zabývám tvorbou larpů. Aktivně se snažím o propagaci tohoto fenoménu veřejnosti, věřím v divadelní pojetí role a možnost sdělování myšlenek pomocí rolových her.</p>
  </span> 
</div> 

<div class = "organizatori">
  <div class = "jmeno">Lorgan – Pavel Hamřík</div>
  <div class = "foto">
    <img src = "/system_styly/organizatori/lorgan.jpg" />
  </div>
  <strong>Funkce na GC</strong><br />organizátor larpů<br />
    <strong><a href = "lorgan o sobě" onclick = "ukaz(15); return false;">O sobě píše</a></strong><br /><span  id = "objekt15" style = "display: none;">
  <p>Larpu a jeho tvorbě se v rámci kořenů občanského sdružení Court of Moravia věnuji šestým rokem. Vyšel jsem poměrně konvenčně z RPG, které hraji o pár let déle. Jsem zastáncem propagace larpu a rolových her obecně široké veřejnosti a jejich zpřístupnění jako běžné aktivity pro volný čas. Snažím se o soudobý přístup, rád zkouším nové mechaniky, které podporují hladký průběh hry. Důraz kladu na samotné ztvárnění role, jako kulisu pak nejraději stavím propracovaný příběh, který celou hru logicky zastřešuje.</p>
  </span> 
</div>
 
<div class = "organizatori">
  <div class = "jmeno">Smejko – Antonín Novák</div>
  <div class = "foto">
    <img src = "/system_styly/organizatori/smejko.jpg" />
  </div>
  <strong>Funkce na GC</strong><br />organizátor larpů<br />
  <strong><a href = "smejko o sobě" onclick = "ukaz(16); return false;">O sobě píše</a></strong><br /><span  id = "objekt16" style = "display: none;">
  <p>Už více než pět let se věnuji rolovým hrám a převážně larpům, ve kterých preferuji realistické ztvárnění role za pomoci vcítění se hráče do postavy. V kratší herní době, atmosféře a předpřipravených rolích vidím sílu, jak říci lidem, že larp může hrát každý.</p>
  <p>Ve volném čase si rád zahraji jakoukoliv hru, nejen rolovou. Když se to ještě spojí s příjemnými kamarády a posezením v oblíbené hospůdce, tak je to většinou dokonalé.</p>
  </span> 
</div>

<div class = "organizatori">
  <div class = "jmeno">Štěpán Hruda</div>
  <div class = "foto">
    <img src = "/system_styly/organizatori/default.jpg" />
  </div>
  <strong>Funkce na GC</strong><br />organizátor larpů<br />
  <strong><a href = "štěpán o sobě" onclick = "ukaz(17); return false;">O sobě píše</a></strong><br /><span  id = "objekt17" style = "display: none;">
  <p>Rolovým hrám se věnuje již (a) let, posledních dobou především tvorbě a hraní larpů. Ve volném čase rád (b). Na GC 2010 by se mimo jiné rád potkal s (c).<br />
(a) - doplň náhodné číslo mezi 5 a 10<br />
(b) - doplň libovolný koníček z Facebookového profilu<br />
(c) - doplň své jméno, pokud jsi pohledná dívka</p>
  </span> 
</div>


    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (236,'Organizátoři larpů','Organizátoři larpů Gekon – Jiří Zlatohlávek Funkce na GC organizátor larpů O sobě píše Rolovým hrám se věnuji osm let, od roku 2007 intezivně v rámci občanského sdružení Court of Moravia. Na Gameconu vyprávím letos pátým rokem. Preferuji koncepční hry, dramatický přístup he hraní a prostředí moderní mystiky. Ve chvílích školního volna pracuji v čajovně, organizuji larpy a vemlouvám se slečnám do přízně. Jezevec – Petr Pouchlý Funkce na GC organizátor larpů, přednášející O sobě píše Vyprávění v rolových hrách se věnuji již 15 let, přičemž poslední dobou se orientuji především na tvorbu larpů. Na GameConu se vyprávění věnuji od roku 2002, několik let jsem se podílel na dramaturgii celé akce. Ve svém volné čase se zabývám organizováním volnočasových aktivit pro mládež, přípravou larpů a organizaci herních setkání. Krom toho žiji se snoubenkou a potkanem, kultivuji vlastní byt a pracuji na plný úvazek. Svět vidím barevně. Jana Jevická Funkce na GC organizátor larpů O sobě píše Členka Court of Moravia, lektorka dílen rétoriky, divadelního herectví a režie, organizátorka larpů, divadelní praktik i teoretik a ve volném čase ještě ledacos jiného. Jestli mě chcete na Gameconu potkat, hledejte na sluníčku, u bazénu nebo na tanečním parketu. Lothmíril - Veronika Frankovská Funkce na GC organizátor larpů O sobě píše K rolovým hrám som sa dostala predovšetkým cez larpy, ktorým sa venujem okolo piatich rokov ako hráč a v poslednej dobe koketujem s ich organizačnou stránkou v rámci združenia Court of Moravia. Verím v svet, v ktorom sú hry – nielen rolové – vyhľadávaným relaxom a bežným spôsobom trávenia času pre všetkých bez ohľadu na vek. KoRH Funkce na GC organizátoři larpů O sobě píší KoRH - Knights of Red Hills je pořadatelskou a hráčskou skupinou z Brna, která se na larpové scéně pohybuje od roku 2003. S organizací larpů začali v r. 2006 s noční městkou hrou Alfatest, která se dočkala dal