INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (237,'Organizátoři wargamingu','organizatori-wargamingu',62,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (237,'organizatori/organizatori-wargamingu');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (237,'Organizátoři wargamingu — GameCon 2011','gamecon,2011','Organizátoři wargamingu');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (237,'<h2 style = "float: left; width: 100%;" id = "organizatori_wargamingu">Organizátoři wargamingu</h2>
<div class = "organizatori">
  <div class = "jmeno">Bob Koutský</div>
  <div class = "foto">
    <img src = "/system_styly/organizatori/bob.jpg" />
  </div>
  <strong>Funkce na GC</strong><br />organizátor wargamingu<br />
  <strong><a href = "bob o sobě" onclick = "ukaz(74); return false;">O sobě píše</a></strong><br /><span  id = "objekt74" style = "display: none;">
  <p>Hry hraju tak dlouho že už si skoro ani nepamatuju jak jsem s nimi začal. Kromě hraní jsem i kompulzivním sběratelem her a protože mě zajímají zejména složitější válečné hry, valná většina mé sbírky je sice nastudovaná, ale nehraná, protože není s kým. Pevně doufám že se mi na Gameconu podaří ulovit nějaké dušičky které propadnou kouzlu šoupání kousků kartónu po papírové mapě.</p>
  </span> 
</div> 

<div class = "organizatori">
  <div class = "jmeno">Dalcor - Dalibor Zeman</div>
  <div class = "foto">
    <img src = "/system_styly/organizatori/dalcor.gif" />
  </div>
  <strong>Funkce na GC</strong><br />organizátor wargamingu<br />
  <strong><a href = "dalcor o sobě" onclick = "ukaz(73); return false;">O sobě píše</a></strong><br /><span  id = "objekt73" style = "display: none;">
  <p>Letošní ročník jsem málem vynechal, ale možnost představit na Gameconu  Warhammer a figurkaření mě nakonec přinutila vyrazit. RPG se věnuji od roku 1996 kdy jsem si koupil modrý box Dragonlance. Několik let jsem se věnoval vedením veřejných RPG her v Praze. Ve spolupráci se serverem d20 v Kostce jsem organizoval všechny ročníky Wordlwide DnD Game Day.</p>
  <p>Warhammer mě zajímá poměrně krátce, asi dva roky, ale modelaření na amatérské úrovni je mým dlouhodobým koníčkem, že by to ale bylo vidět to tedy není. V současnosti se zabývám předělávkou a testováním taktického RPG Cadwallon</p>
  </span> 
</div> 
  
<div class = "organizatori">
  <div class = "jmeno">Thracus - Michal Hnaťuk</div>
  <div class = "foto">
    <img src = "/system_styly/organizatori/thracus.gif" />
  </div>
  <strong>Funkce na GC</strong><br />organizátor wargamingu<br />
  <strong><a href = "thracus o sobě" onclick = "ukaz(75); return false;">O sobě píše</a></strong><br /><span  id = "objekt75" style = "display: none;">
  <p>Narozen: duben v minulém století<br />
  Bydliště: Praha<br />
  Zaměstnání: kecám lidem do toho, jak mají propagovat svoje zboží<br />
  Rodinný stav: dva závazky čtyřnohé a jedna přítelkyně<br />
  Oblíbené jídlo: sushi<br />
  Oblíbený sport: cokoliv s mečem, kopím nebo nožem<br />
  Oblíbený film: Duna od Lynche, Zelená Míle, Devátá brána<br />
  Oblíbený seriál: Přátelé, Full Metal Alchemist, Andromeda<br />
  Oblíbené anime: Princezna Mononoke, Cesta do Fantasie<br />
  Oblíbená beletrie: Šógun, Taipan, Vznešený dům, Slavík věští smrt, Zemřít za Jeruzalém<br />
  Oblíbené hudba: Nightwish, Blackmoři, Queeni</p>
  Zbožňuji všechno, co zavání mečem. Japonské Kendo i Iaido, Talhoffera nebo i srandovní knihy dnešních "nových" mistrů. Čas od času taky vystupuji s jednou nejmenovanou skupinu historického šermu a hodně často mně lze potkat ve skautském kroji.</p>
  RPG - momentálně hraji kampaň se Sebrankou v herním systému Cadwallon. Chystám se na Mágy a na Warhammer RPG.</p>
  <p>Armády: aktivně hraji hlavně Wahammer Fantasy Battles - momentálně mám trpaslíky na 1500 bodů, Bretaňské rytíře na 1000 bodů, ale tady plánuji expanzi na 3000. U Warhammeru 40,000 velím četám pochodujícího masa do mlýnků - Imperiální gardě a ulítávám na armádě Chaosu - zejména na posedlých mariňácích.</p>
  </span> 
</div> 

<div class = "organizatori">
  <div class = "jmeno">Ulrik - Ota Nechvátal</div>
  <div class = "foto">
    <img src = "/system_styly/organizatori/default.jpg" />
  </div>
  <strong>Funkce na GC</strong><br />organizátor wargamingu<br />
    <strong><a href = "ulrik o sobě" onclick = "ukaz(78); return false;">O sobě píše</a></strong><br /><span  id = "objekt78" style = "display: none;">
  <p>Ota je základním kamenem Chaotit.cz. Stojí za veškerou vizualizací projektů a většinou dotahuje Jindrovi nápady do konečné podoby.</p>
  <p>Ve Warhammeru spojil svůj osud se zelenými kůžemi a ne náhodou vyhrává soutěže v malování figurek.</p>
  <p>Kromě wargamingu tráví svůj volný čas psaním povídek a chovem rysů, o kterých mluví jako o kocourcích. Otu můžete kromě turnajů potkat hlavně v Českých Budějovicích, kde se stará o místní hráčskou komunitu.</p> 
  </span> 
</div> 

<div class = "organizatori">
  <div class = "jmeno">UZMN - Jindra Čadík</div>
  <div class = "foto">
    <img src = "/system_styly/organizatori/default.jpg" />
  </div>
  <strong>Funkce na GC</strong><br />organizátor wargamingu<br />
  <strong><a href = "uzmt o sobě" onclick = "ukaz(77); return false;">O sobě píše</a></strong><br /><span  id = "objekt77" style = "display: none;">
  <p>Už dvanáct let strká pazoury do všeho co má něco společného s Warhammerem. V současné době je jednotřetinovou inkarnací Chaotit.cz, kde má třeba na starosti organizaci české warhammerové ligy.</p>
  <p>Bydlí v Hradci Králové, ale je možné ho potkat na skoro každém větším turnaji.</p>
  <p>Když zrovna nemaluje figurky nebo nehraje u zeleného stolu, tak si rád přečte dobrou sci-fi knížku nebo koukne na dobrý filmeček. Občas se potřebuje vyvětrat a pak vyrazí na nějaký kopec.</p> 
  <p>Aktuálně mu většinu volného času zabírá příprava na výpravu do Munsteru, kde bude letošní mistrovstvé Evropy ve Warhammeru.</p>
  </span> 
</div> 
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (237,'Organizátoři wargamingu','Organizátoři wargamingu Bob Koutský Funkce na GC organizátor wargamingu O sobě píše Hry hraju tak dlouho že už si skoro ani nepamatuju jak jsem s nimi začal. Kromě hraní jsem i kompulzivním sběratelem her a protože mě zajímají zejména složitější válečné hry, valná většina mé sbírky je sice nastudovaná, ale nehraná, protože není s kým. Pevně doufám že se mi na Gameconu podaří ulovit nějaké dušičky které propadnou kouzlu šoupání kousků kartónu po papírové mapě. Dalcor - Dalibor Zeman Funkce na GC organizátor wargamingu O sobě píše Letošní ročník jsem málem vynechal, ale možnost představit na Gameconu Warhammer a figurkaření mě nakonec přinutila vyrazit. RPG se věnuji od roku 1996 kdy jsem si koupil modrý box Dragonlance. Několik let jsem se věnoval vedením veřejných RPG her v Praze. Ve spolupráci se serverem d20 v Kostce jsem organizoval všechny ročníky Wordlwide DnD Game Day. Warhammer mě zajímá poměrně krátce, asi dva roky, ale modelaření na amatérské úrovni je mým dlouhodobým koníčkem, že by to ale bylo vidět to tedy není. V současnosti se zabývám předělávkou a testováním taktického RPG Cadwallon Thracus - Michal Hnaťuk Funkce na GC organizátor wargamingu O sobě píše Narozen: duben v minulém století Bydliště: Praha Zaměstnání: kecám lidem do toho, jak mají propagovat svoje zboží Rodinný stav: dva závazky čtyřnohé a jedna přítelkyně Oblíbené jídlo: sushi Oblíbený sport: cokoliv s mečem, kopím nebo nožem Oblíbený film: Duna od Lynche, Zelená Míle, Devátá brána Oblíbený seriál: Přátelé, Full Metal Alchemist, Andromeda Oblíbené anime: Princezna Mononoke, Cesta do Fantasie Oblíbená beletrie: Šógun, Taipan, Vznešený dům, Slavík věští smrt, Zemřít za Jeruzalém Oblíbené hudba: Nightwish, Blackmoři, Queeni Zbožňuji všechno, co zavání mečem. Japonské Kendo i Iaido, Talhoffera nebo i srandovní knihy dnešních "nových" mistrů. Čas od času taky vystupuji s jednou nejmenovanou skupinu historického šermu a hodně často mně lze potkat ve skautském kroji. RPG - momentálně hraji kampaň se Sebrankou v herním systému Cadwallon. Chystám se na Mágy a na Warhammer RPG. Armády: aktivně hraji hlavně Wahammer Fantasy Battles - momentálně mám trpaslíky na 1500 bodů, Bretaňské rytíře na 1000 bodů, ale tady plánuji expanzi na 3000. U Warhammeru 40,000 velím četám pochodujícího masa do mlýnků - Imperiální gardě a ulítávám na armádě Chaosu - zejména na posedlých mariňácích. Ulrik - Ota Nechvátal Funkce na GC organizátor wargamingu O sobě píše Ota je základním kamenem Chaotit.cz. Stojí za veškerou vizualizací projektů a většinou dotahuje Jindrovi nápady do konečné podoby. Ve Warhammeru spojil svůj osud se zelenými kůžemi a ne náhodou vyhrává soutěže v malování figurek. Kromě wargamingu tráví svůj volný čas psaním povídek a chovem rysů, o kterých mluví jako o kocourcích. Otu můžete kromě turnajů potkat hlavně v Českých Budějovicích, kde se stará o místní hráčskou komunitu. UZMN - Jindra Čadík Funkce na GC organizátor wargamingu O sobě píše Už dvanáct let strká pazoury do všeho co má něco společného s Warhammerem. V současné době je jednotřetinovou inkarnací Chaotit.cz, kde má třeba na starosti organizaci české warhammerové ligy. Bydlí v Hradci Králové, ale je možné ho potkat na skoro každém větším turnaji. Když zrovna nemaluje figurky nebo nehraje u zeleného stolu, tak si rád přečte dobrou sci-fi knížku nebo koukne na dobrý filmeček. Občas se potřebuje vyvětrat a pak vyrazí na nějaký kopec. Aktuálně mu většinu volného času zabírá příprava na výpravu do Munsteru, kde bude letošní mistrovstvé Evropy ve Warhammeru.');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (238,'Ostatní organizátoři','ostatni-organizatori',62,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (238,'organizatori/ostatni-organizatori');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (238,'Ostatní organizátoři — GameCon 2011','gamecon,2011','Ostatní organizátoři');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (238,'<h2 style = "float: left; width: 100%;" id = "ostatni_organizatori">Ostatní organizátoři</h2>
<div class = "organizatori">
  <div class = "jmeno">Ještěrka - Zuzka Šullová</div>
  <div class = "foto">
    <img src = "/system_styly/organizatori/jesterka.jpg" />
  </div>
  <strong>Funkce na GC</strong><br />neocenitelná pomocnice<br />
  <strong><a href = "ještěrka o sobě" onclick = "ukaz(21); return false;">O sobě píše</a></strong><br /><span  id = "objekt21" style = "display: none;">
  Už od roku 2005 se spolu s dalšími trpícími kuchařkami DOBROVOLNĚ snažím otrávit organizátory a PJ svým kuchařským (ne)uměním. Zatím jsou mé snahy bez úspěchu, přijde však den, kdy se mi podaří znechutit všechny natolik, aby usoudili, že mít na Gameconu kuchařku, je vlastně zbytečné :-D.
  </span> 
</div>

<div class = "organizatori">
  <div class = "jmeno">Marťa - Martina Černíková</div>
  <div class = "foto">
    <img src = "/system_styly/organizatori/marta.jpg" />

  </div>
  <strong>Funkce na GC</strong><br />neocenitelná ponocnice<br />
  <strong><a href = "marťa o sobě" onclick = "ukaz(23); return false;">O sobě píše</a></strong><br /><span  id = "objekt23" style = "display: none;">
  Zív... Jííídlóóó!
  </span> 
</div>


<div class = "organizatori">
  <div class = "jmeno">Melkor - Valter Ulbricht Scheiben Mayer</div>
  <div class = "foto">
    <img src = "/system_styly/organizatori/melkor.jpg" />
  </div>
  <strong>Funkce na GC</strong><br />čajovník<br />
  <strong>Kontakt</strong><br />
  <a href = "mailto:melkor@atlas.cz">melkor@atlas.cz</a><br />
  <strong><a href = "Melkor o sobě" onclick = "ukaz(31); return false;">O sobě píše</a></strong><br /><span  id = "objekt31" style = "display: none;">
  Mohli jste mne potkat tu, tam i onde. Sem-tam se vyskytnu i někde jinde.<br />
  Kdysi dávno jsem začal číst knihy. Nejprve ty klasické pro kluky. Postupně jsem přecházel na science fiction a horory. Pak se vyskytl dračák a na pultech knihkupectví se začali vyskytovat i knížky řazené mezi fantasy.<br />
  Kdysi dávno jsem byl rád za každou knihu, kterou jsem sehnal, teď nevím kde na ně brát (a nekrást) a taky "Kam s nima". Přesto čtu dál, i když už na to nemám tolik času jako dříve.<br />
  Čtení sci-fi mne dovedlo k lidičkám, kteří také četli sci-fi a navíc měli dostatek odvahy uspořádat slety podobně postižených jedinců - Cony.<br />
  Ke koloritu conů patří i různé aktivity nad rámec oficiálního programu. Kromě posedávání v baru, plkání na jakémkoliv vhodném místě a hraní dračáku na chodbách hotelu jsou to i "Room party".<br />
  Z jednoho takového zdánlivě neškodného klábosení nad hrnkem čaje na Draconu, který se konával v hotelu Santon u přehrady v Brně, povstala tradice čajovny. Zprvu jako room party a od Euroconu 2002 i jako Čajovna.<br />
  Od těch dob jezdím na cony i s nádobíčkem. Přestože většinu času strávím v čajovně, potkávám nejzajímavější účastníky a čestné hosty. Můžete jimi být i Vy.
  </span> 
</div>
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (238,'Ostatní organizátoři','Ostatní organizátoři Ještěrka - Zuzka Šullová Funkce na GC neocenitelná pomocnice O sobě píše Už od roku 2005 se spolu s dalšími trpícími kuchařkami DOBROVOLNĚ snažím otrávit organizátory a PJ svým kuchařským (ne)uměním. Zatím jsou mé snahy bez úspěchu, přijde však den, kdy se mi podaří znechutit všechny natolik, aby usoudili, že mít na Gameconu kuchařku, je vlastně zbytečné :-D. Marťa - Martina Černíková Funkce na GC neocenitelná ponocnice O sobě píše Zív... Jííídlóóó! Melkor - Valter Ulbricht Scheiben Mayer Funkce na GC čajovník Kontakt melkor@atlas.cz O sobě píše Mohli jste mne potkat tu, tam i onde. Sem-tam se vyskytnu i někde jinde. Kdysi dávno jsem začal číst knihy. Nejprve ty klasické pro kluky. Postupně jsem přecházel na science fiction a horory. Pak se vyskytl dračák a na pultech knihkupectví se začali vyskytovat i knížky řazené mezi fantasy. Kdysi dávno jsem byl rád za každou knihu, kterou jsem sehnal, teď nevím kde na ně brát (a nekrást) a taky "Kam s nima". Přesto čtu dál, i když už na to nemám tolik času jako dříve. Čtení sci-fi mne dovedlo k lidičkám, kteří také četli sci-fi a navíc měli dostatek odvahy uspořádat slety podobně postižených jedinců - Cony. Ke koloritu conů patří i různé aktivity nad rámec oficiálního programu. Kromě posedávání v baru, plkání na jakémkoliv vhodném místě a hraní dračáku na chodbách hotelu jsou to i "Room party". Z jednoho takového zdánlivě neškodného klábosení nad hrnkem čaje na Draconu, který se konával v hotelu Santon u přehrady v Brně, povstala tradice čajovny. Zprvu jako room party a od Euroconu 2002 i jako Čajovna. Od těch dob jezdím na cony i s nádobíčkem. Přestože většinu času strávím v čajovně, potkávám nejzajímavější účastníky a čestné hosty. Můžete jimi být i Vy.');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (239,'GameCon 2011 se blíží','pal%C4%8Da%20-%20hern%C3%AD%20profil',62,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (239,'organizatori/pal%C4%8Da%20-%20hern%C3%AD%20profil');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (239,'GameCon 2011 se blíží — GameCon 2011','gamecon,2011','GameCon 2011 se blíží');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (239,'<h1>GameCon 2011 se blíží</h1>

<!--<h2>Organizační změny</h2>
<p>
Dovolte nám seznámit vás s velkou organizační novinkou. Petr „Gandalf“ Holub, který stál v čele organizačního týmu GameConu poslední dva roky, ještě v průběhu letošního GameConu v České Třebové předal post hlavního organizátora Matouši „Erricu“ Ježkovi. Jelikož se mu totiž letos narodily dvě holčičky, po důkladném uvážení se musel rozhodnout k tomuto kroku, neboť vedení organizačního týmu a nově rozrostlou rodinu a normální práci by nebylo možné skloubit tak, aby jedno netrpělo.
</p>
<p>
Nic to však nemění na tom, že další ročník GameConu už pro vás připravujeme a o novinkách vás budeme průběžně informovat jak tady, tak na <a href = "http://www.facebook.com/group.php?sid=1a65342dd9cba753975=bb963632e2a7&gid=93879753711&ref=search#!/gamecon" onclick = "window.open(this.href,\'_blank\'); return false">facebooku</a>.
</p>
<p>
Organizační tým GameConu
</p>

<h2>GameCon Teaser</h2>
<object width="470" height="265"><param name="allowfullscreen" value="true" /><param name="allowscriptaccess" value="always" /><param name="movie" value="http://vimeo.com/moogaloop.swf?clip_id=12709571&amp;server=vimeo.com&amp;show_title=1&amp;show_byline=1&amp;show_portrait=0&amp;color=&amp;fullscreen=1" /><embed src="http://vimeo.com/moogaloop.swf?clip_id=12709571&amp;server=vimeo.com&amp;show_title=1&amp;show_byline=1&amp;show_portrait=0&amp;color=&amp;fullscreen=1" type="application/x-shockwave-flash" allowfullscreen="true" allowscriptaccess="always" width="470" height="265"></embed></object>-->

<h2>Čtyři dny plné zábavy a napětí nad hrami všeho druhu</h2>
<p>Ve dnech <strong>21.-24.7.2011</strong> se v <strong>České Třebové</strong> uskuteční již 17. ročník herního setkání <strong>GameCon</strong>. Je to příležitost pro všechny hráče a fanoušky nepočítačových her z České republiky a Slovenska setkat se s ostatními, zahrát si hry, vyměnit zkušenosti a pobavit se. Co vás během čtyř dnů na GameConu čeká?
<ul>
<li><a href="/deskove-hry/o-deskovych-hrach-na-gc">Deskové hry</a> (Osadníci z Katanu, Carcassonne a mnohé další)</li>
<li>Velké množství her na hraní rolí neboli <a href="/rpg/o-rpg-na-gc">RPG</a>. Můžete si vyzkoušet i herní systémy, které doma ani nemáte.</li>
<li>Hry naživo neboli <a href = "/larp/o-larpech-na-gc">LARP</a>, kdy prožitky své postavy vyzkoušíte na vlastní kůži.</li>
<li><a href = "/mistrovstvi-v-drd/o-mistrovstvi-v-drd">Mistrovství v Dračím doupěti</a>, letos pro změnu z pozice obyčejných obyvatel Císařství.</li>
<li>A spousta dalších aktivit, jako třeba bitva miniaturních armád ve <a href = "/wargaming/o-wargamingu-na-gc">Wargamingu</a>, nebo poutavé <a href = "/prednasky/o-prednaskach-na-gc">přednášky</a>.</li>
<li>Sobotní party</li>
</ul>
</p>

<p>Že neznáte žádnou z těchto her? Nevadí.<strong>Pravidla vám rádi vysvětlíme na místě</strong> a poradíme i s výběrem her nebo naplánováním programu. <strong>Neváhejte tedy a přijeďte.</strong> Slibujeme vám spoustu her, zábavy a přátelské atmosféry. Nemáte volné celé čtyři dny? Nevadí! <strong>GameCon</strong> má co nabídnout každý den.</strong></p>
<!--<p>Jednoduchý návod jak se <strong>přihlásit na GameCon</strong> a všechny důležité informace o <strong>registraci</strong>, možnostech <strong>ubytování</strong> a <strong>platbách</strong> naleznete <a href="/navod/">zde</a>.</p>-->
<p>O novinkách vás budeme průběžně informovat jak zde, tak na <a href = "http://www.facebook.com/gamecon" onclick = "window.open(this.href,\'_blank\'); return false">Facebooku</a>.</p>

<a name=novinky></a>
<h2>Letošní novinky</h2>
<p>Tak jako každý rok se snažíme, aby GameCon i letos nabídl něco nového. Loni se con přestěhoval do České Třebové, což přineslo mimo jiné možnost nabídnout všechny aktivity pod jednou střechou, prostornou a dobře větratelnou místnost pro deskohernu a levnější ubytování. Na co se můžete těšit letos?</p>
<ul>
<li>Pro účastníky GameConu ze Slovenska jsme připravili <strong>možnost platit v eurech</strong>.</li>
<li>Všem budou přístupné <strong>kuchyňky</strong>, ve kterých si bude možné uvařit jídlo.</li>
<li>GameCon se bude odehrávat <strong>ve znamení Antiky</strong>.</li>
<li>Je pro vás připravena <strong>spousta nových her</strong> na všech frontách.</li>
<li>Na programu bude také <strong>křest Dračího doupěte II</strong>.</li>
</ul>

<!--<p>
Patrně nejvýraznější změnou je přestěhování conu do České Třebové. Tento manévr nám poskytl hned několik výhod:
<ul>
	<li>Předně jsou to <strong>všechny aktivity pod jednou střechou</strong>, nebude potřeba kamkoliv přebíhat nebo složitě bloudit mezi jednotlivými komplexy budov.</li>
	<li>Zároveň jsou místnosti pro jednotlivé aktivity dostatečně velké a vzdušné.</li>
	<li>Především místnost <a href = "/deskove-hry/deskoherna">deskoherny</a> je úchvatně prostorná a dobře větratelná. Už nehrozí, že bychom se v dobré víře ušlapávali nebo letním parnu dusili. Tento rok to bude konečně ta <strong>dobře přístupná aréna plná deskových her</strong> připravená na lačné hráče. Pro zvědavce jsme jako důkaz připravili alespoň dvě fotografie z naších průzkumných výprav – více v <a href = "/deskove-hry/deskoherna">deskoherně</a>.</li>
	<li>Vítanou změnou bude určitě i <strong>levnější ubytování</strong>. Letos bude stát jedna noc v třílůžkovém pokoji pouhých 170 Kč (oproti loňským dvěma stovkám, takže za tři noci nakonec ušetříte téměř stokorunu).</li>
	<li>Přijde vám lůžkový pokoj příliš drahý a komfortní? Pak jistě uvítáte další zlepšení a tím je <strong>možnost spát hromadně ve třídě ve vlastním spacáku</strong> a to za pouhých 60 Kč. Více o ubytovacích možnostech se dočtete v <a href = "/gamecon/ubytovani">ubytování</a>.</li>
	<li>Přesunem do jiného města jsme také získali kousek od naší budovy velkou nafukovací halu, kterou budeme moci využít v nepřízni počasí na nějakou velmi hromadnou akci. No není takový bonus skvělý?</li>
	<li>A snad některé z vás potěší i dobrá dopravní dostupnost pro celou republiku. Jsme uprostřed státu, tak snad to má každý kousek. :-)</li>
</ul>
</p>

<p>
Jak můžete vidět, přesun na nové místo pro vás znamená samé výhody. Nespokojíme se však jen s novým územím a jeho přidanými hodnotami, pokračujeme dál ve zpestřujících zlepšovácích:
</p>
<p>
<ul>
	<li>Velká novinka hned rovnou na začátek: <strong>popré</strong> bude <strong>celý GameCon v duchu nějakého tématu</strong>, tentokrát to bude <strong>exodus</strong> a spíše než vyhnání z ráje to bude jeho hledání. V následujících dnech vám přineseme bližší informace a vy se můžete těšit, že s tím bude spojena spousta her a zábavné atmosféry.</li>
	<li><strong>Mistrovství v Dračím doupěti</strong> bude zase o něco blíž vám hráčům. Vyslyšeli jsme vaše dobré připomínky a rady, důkladně si přečetli reakce ve <a href = "/forum/mistrovstvi_v_drd">fóru</a> a vyšli vám vstříc.<br />
Do odkrývání tajů dobrodružství se můžete pustit již nyní a každý týden Vám přineseme další indicii. Na úvod začínáme jedním výtiskem <a href = "/mistrovstvi-v-drd/sluncesvit-cisarske-noviny">Sluncesvitu</a> - populárního císařského plátku.<br />
Také jsme pro vás připravili <strong>dvě výrazná zlepšení postav</strong> a <strong>jedno velmi poutavé zpestření</strong>. Obě novinky se týkají <a href = "/mistrovstvi-v-drd/pravidla-pro-tvorbu-postav">tvorby postav</a> a brzy vás o těchto změnách budeme informovat více. Zatím můžete ve <a href = "/forum/mistrovstvi_v_drd">fóru</a> tipovat, co by to tak mohlo být.</li>
	<li><strong>Trojboj</strong> bude v tomto roce trvat jen jeden blok, takže o důvod více zapojit se do této týmové aktivity, kdy za jednu cenu si zahrajete tři hry. Více na <a href = "/gamecon-trojboj/o-gamecon-trojboji">samostatné stránce</a>.</li>
	<li><strong>Špína</strong> bude letos ve znamení „Osídlení nového města“ a <strong>gobliní ponorky</strong> budou bojovat o nová naleziště drahokamů.</li>
	<li>Určitě se bude hodit i trénink ve velení armádám, tudíž jistě přijde vhod <a href = "/wargaming/wargaming-tour-2010">Wargaming Tour 2010</a>.</li>
	<li>A lahodný zákusek na závěr: <strong>na sobotní večer</strong> pro vás plánujeme <strong>hromadné pobavení</strong>, jehož součástí by mělo být i <strong>klání v duchu televizních soutěží</strong> v režii týmu z Court of Moravia.</li>
</ul>
</p>

<p>
Snad vás to množství novinek a jednotlivé zlepšováky těší a přijedete na GameCon. Koná se <strong>15.-18.7.2010 v&nbsp;České Třebové</strong>.
</p>-->

<h3>GameCon je tu pro vás, tak si přijďte zahrát!</h3>
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (239,'GameCon 2011 se blíží','GameCon 2011 se blíží Organizační změny Dovolte nám seznámit vás s velkou organizační novinkou. Petr „Gandalf“ Holub, který stál v čele organizačního týmu GameConu poslední dva roky, ještě v průběhu letošního GameConu v České Třebové předal post hlavního organizátora Matouši „Erricu“ Ježkovi. Jelikož se mu totiž letos narodily dvě holčičky, po důkladném uvážení se musel rozhodnout k tomuto kroku, neboť vedení organizačního týmu a nově rozrostlou rodinu a normální práci by nebylo možné skloubit tak, aby jedno netrpělo. Nic to však nemění na tom, že další ročník GameConu už pro vás připravujeme a o novinkách vás budeme průběžně informovat jak tady, tak na facebooku . Organizační tým GameConu GameCon Teaser --> Čtyři dny plné zábavy a napětí nad hrami všeho druhu Ve dnech 21.-24.7.2011 se v České Třebové uskuteční již 17. ročník herního setkání GameCon . Je to příležitost pro všechny hráče a fanoušky nepočítačových her z České republiky a Slovenska setkat se s ostatními, zahrát si hry, vyměnit zkušenosti a pobavit se. Co vás během čtyř dnů na GameConu čeká? Deskové hry (Osadníci z Katanu, Carcassonne a mnohé další) Velké množství her na hraní rolí neboli RPG . Můžete si vyzkoušet i herní systémy, které doma ani nemáte. Hry naživo neboli LARP , kdy prožitky své postavy vyzkoušíte na vlastní kůži. Mistrovství v Dračím doupěti , letos pro změnu z pozice obyčejných obyvatel Císařství. A spousta dalších aktivit, jako třeba bitva miniaturních armád ve Wargamingu , nebo poutavé přednášky . Sobotní party Že neznáte žádnou z těchto her? Nevadí. Pravidla vám rádi vysvětlíme na místě a poradíme i s výběrem her nebo naplánováním programu. Neváhejte tedy a přijeďte. Slibujeme vám spoustu her, zábavy a přátelské atmosféry. Nemáte volné celé čtyři dny? Nevadí! GameCon má co nabídnout každý den. Jednoduchý návod jak se přihlásit na GameCon a všechny důležité informace o registraci , možnostech ubytování a platbách naleznete zde . --> O novinkách vás budeme průběžně informovat jak zde, tak na Facebooku . Letošní novinky Tak jako každý rok se snažíme, aby GameCon i letos nabídl něco nového. Loni se con přestěhoval do České Třebové, což přineslo mimo jiné možnost nabídnout všechny aktivity pod jednou střechou, prostornou a dobře větratelnou místnost pro deskohernu a levnější ubytování. Na co se můžete těšit letos? Pro účastníky GameConu ze Slovenska jsme připravili možnost platit v eurech . Všem budou přístupné kuchyňky , ve kterých si bude možné uvařit jídlo. GameCon se bude odehrávat ve znamení Antiky . Je pro vás připravena spousta nových her na všech frontách. Na programu bude také křest Dračího doupěte II . Patrně nejvýraznější změnou je přestěhování conu do České Třebové. Tento manévr nám poskytl hned několik výhod: Předně jsou to všechny aktivity pod jednou střechou , nebude potřeba kamkoliv přebíhat nebo složitě bloudit mezi jednotlivými komplexy budov. Zároveň jsou místnosti pro jednotlivé aktivity dostatečně velké a vzdušné. Především místnost deskoherny je úchvatně prostorná a dobře větratelná. Už nehrozí, že bychom se v dobré víře ušlapávali nebo letním parnu dusili. Tento rok to bude konečně ta dobře přístupná aréna plná deskových her připravená na lačné hráče. Pro zvědavce jsme jako důkaz připravili alespoň dvě fotografie z naších průzkumných výprav – více v deskoherně . Vítanou změnou bude určitě i levnější ubytování . Letos bude stát jedna noc v třílůžkovém pokoji pouhých 170 Kč (oproti loňským dvěma stovkám, takže za tři noci nakonec ušetříte téměř stokorunu). Přijde vám lůžkový pokoj příliš drahý a komfortní? Pak jistě uvítáte další zlepšení a tím je možnost spát hromadně ve třídě ve vlastním spacáku a to za pouhých 60 Kč. Více o ubytovacích možnostech se dočtete v ubytování . Přesunem do jiného města jsme také získali kousek od naší budovy velkou nafukovací halu, kterou budeme moci využít v nepřízni počasí na nějakou velmi hromadnou akci. No není takový bonus skvělý? A snad některé z vás potěší i dobrá dopravní dostupnost pro celou republiku. Jsme uprostřed státu, tak snad to má každý kousek. :-) Jak můžete vidět, přesun na nové místo pro vás znamená samé výhody. Nespokojíme se však jen s novým územím a jeho přidanými hodnotami, pokračujeme dál ve zpestřujících zlepšovácích: Velká novinka hned rovnou na začátek: popré bude celý GameCon v duchu nějakého tématu , tentokrát to bude exodus a spíše než vyhnání z ráje to bude jeho hledání. V následujících dnech vám přineseme bližší informace a vy se můžete těšit, že s tím bude spojena spousta her a zábavné atmosféry. Mistrovství v Dračím doupěti bude zase o něco blíž vám hráčům. Vyslyšeli jsme vaše dobré připomínky a rady, důkladně si přečetli reakce ve fóru a vyšli vám vstříc. Do odkrývání tajů dobrodružství se můžete pustit již nyní a každý týden Vám přineseme další indicii. Na úvod začínáme jedním výtiskem Sluncesvitu - populárního císařského plátku. Také jsme pro vás připravili dvě výrazná zlepšení postav a jedno velmi poutavé zpestření . Obě novinky se týkají tvorby postav a brzy vás o těchto změnách budeme informovat více. Zatím můžete ve fóru tipovat, co by to tak mohlo být. Trojboj bude v tomto roce trvat jen jeden blok, takže o důvod více zapojit se do této týmové aktivity, kdy za jednu cenu si zahrajete tři hry. Více na samostatné stránce . Špína bude letos ve znamení „Osídlení nového města“ a gobliní ponorky budou bojovat o nová naleziště drahokamů. Určitě se bude hodit i trénink ve velení armádám, tudíž jistě přijde vhod Wargaming Tour 2010 . A lahodný zákusek na závěr: na sobotní večer pro vás plánujeme hromadné pobavení , jehož součástí by mělo být i klání v duchu televizních soutěží v režii týmu z Court of Moravia. Snad vás to množství novinek a jednotlivé zlepšováky těší a přijedete na GameCon. Koná se 15.-18.7.2010 v České Třebové . --> GameCon je tu pro vás, tak si přijďte zahrát!');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (240,'GameCon 2011 se blíží','pal%C4%8Da%20o%20sob%C4%9B',62,0,0);
