INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (255,'Archiv přednášek 2008','archiv-prednasek-2008',40,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (255,'prednasky/archiv-prednasek-2008');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (255,'Archiv přednášek 2008 — GameCon 2011','gamecon,2011','Archiv přednášek 2008');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (255,'<h1>Archiv přednášek 2008</h1>
<a name="alpha"></a>
<h2>Alpha Omega - Jakub &quot;sffh&quot; Marek</h2>

<div class="content-file">
<div>Konec světa byl nevyhnutelný, ale jen málokdo tušil, co bude dál. Příchod &quot;andělů&quot; a &quot;ďáblů&quot; mimozemského původu byl jen hřebíčkem do rakve modré planety. Odvěcí nepřítelé se vrátili na staré bojiště svést další bitvu. Nestane se však poslední, alespoň pro lidstvo? Z neuvěřitelné směsi magie, víry a technologie vzniká jeden z nejnovějších a nejzajímavějších postapokalyptických RPG projektů.</div>
</div>

<a name="brak"></a>
<h2>Brak v RPG aneb Klišé za klišé - Jakub &quot;sffh&quot; Marek</h2>
<div class="akce-archiv">
<div>Tak jako v každé formě médií existuje i v herním světě brak. O RPG to jde tvrdit hned dvojnásob. Co je to herní brak, čím se definuje a jak se pozná. Je brak dobrý nebo špatný? A co když je všechno jinak? Brak ve všech formách, podformách, předobrazech a následcích aneb jaká je síla a slabina klišé.</div>
</div>

<a name="com"></a>
<h2>Court of Moravia - Jana &quot;Lorelei&quot; Jevická</h2>
<div class="akce-archiv">
<div>Už jste někdy slyšeli slovo larp a zaujalo vás? Chtěli byste si nějaký larp poprvé zahrát, nebo jste už ostřílení matadoři a hledáte něco nového? Ve všech těchto případech bychom vás chtěli pozvat na představení občanského sdružení Court of Moravia, které se zabývá městskými a komorními larpy.<br/>
Přijďte se navnadit na gangsterku á la Quentin Tarantino, na napínavou fantasy ve vězeňské cele nebo na mrazivý příběh z gentlemanského Klubu sebevrahů.
</div>
</div>

<a name="dark_sun"></a>
<h2>Dark Sun: V dračích spárech - Petr &quot;Jezevec&quot; Pouchlý </h2>
<div class="akce-archiv">
<div>Kdysi bývala planeta Athas krásnou, zelenou zemí. Pak ji zničila touha po moci. Dračí vládci, vysávající tuto zemi pomalu, ale jistě mění poslední zbytky obyvatelného světa v poušť. Země, která trpí, se musela změnit, stejně jako její obyvatelé. Klasické rasy jsou zde jiné, než byste si představovali a nejhorším nepřítelem hrdinů prosté slunce a nedostatek tekutin. Je to svět, kde železo je vzácností, bohové neexistují a lidskost je téměř neznámým pojmem. Přijďte se seznámit se světem Temného slunce.</div>
</div>

<a name="paladin"></a>
<h2>Dobro, zlo a paladin - Dalibor &quot;Dalcor&quot; Zeman </h2>

<div class="akce-archiv">
<div>Řízená diskuze, ve které si společně probereme nejen jakým způsobem pracovat s principy dobra a zla, ale také jejich vliv na herní mechaniky. 
Zaměříme se především na tradiční mechaniku &quot;přesvědčení&quot; a práci s ní, především pak na její funkčnost v hrách spojujících různé kultury a prostředí. 
V druhé části přednášky si popovídáme o dogmatech ve vztahu k &quot;paladinům&quot; a rytířům v RPG hrách.</div>
</div>

<a name="erotika"></a>
<h2>Erotika a intimita ve hře - Petr &quot;Jezevec&quot; Pouchlý </h2>

<div class="akce-archiv">
<div>Rolové hry zahrnují širokou škálu možností. Příběhy v nich hrané mohou být komedií, detektivním příběhem, hrdinským eposem, milostným dramatem i vzrušující romancí. Záleží jen na chuti a osobních preferencích hráčů. Témata milostná a sexuální jsou často ve hrách spíše přehlížena. Vzbuzují často stud a obavy, které vedou k určitému tabuizování. Pokud byste sami rádi poodhalili roušku tajemství o těchto tématech, budete mít na přednášce možnost poznat některé knihy, které pracují s touto intimní tematikou a seznámit se s technikami, jak takovou hru vést.</div>
</div>

<a name="komorni_larp"></a>
<h2>Fenomén: Komorní larp - Pavel &quot;Lischai&quot; Gotthard</h2>
<div class="akce-archiv">
<div>Larp v psychiatrické léčebně, podzemním krytu nebo na palubě výletní lodi? Proč ne. Komorní larpy se u nás začínají profilovat až v posledních několika letech. Tyto netradiční hry přistupují k principu samotného larpu zcela jinak, používají jiné prostředky a mají i jiné cíle. Pokud vás zajímá, o co v těchto hrách jde, v čem jsou jiné než ostatní larpy a čím můžou být pro své hráče atraktivní, pak si rozhodně nenechte ujít tuhle přednášku. Přiblíží vám fenomén komorních larpů, provede vás po české komorní scéně a představí nejzajímavější počiny, které se u nás odehrály.</div>
</div>

<a name="h_a_s"></a>
<h2>Hack &amp; slash - František &quot;Sniper&quot; Neznaj</h2>
<div class="akce-archiv">
<div>Běžným prvkem na aktuální RPG-diskusní scéně je skoro výhradní zaměření a hraní rolí a odklon od kořenů - taktických soubojů a jednoduchých her. Je ale H&amp;S jen obyčejnou tupou hrou pro začátečníky a mladší 15 let? Nebo se dá hrát H&S i na úrovni? Jak se může prolínat s RP a co vše vlastně pod  H&amp;S může spadat? Co je na tomto stylu hry zábavného?</div>

</div>

<a name="horor"></a>
<h2>Horor v RPG - Petr &quot;Jezevec&quot; Pouchlý </h2>
<div class="akce-archiv">
<div>Plíživý pocit strachu, přebíhání mrazu po zádech a zrychlený tlukot vlastního srdce se pojí s vyprávěním příběhů od počátku věků. V rolových hrách je hororový žánr jedním z nejoblíbenějších. Přesto však navození pocitu opravdu působivé hry s touto tematikou není snadné. Není to jen o příručce vhodných pravidel, tajuplném herním prostředí a zapálené svíčce. Jsou knihy dobré a lepší, stejně jako jsou metody, které mohou pomoci. Přednáška vám představí základní kameny a pomůže nalézt směr, kudy se ponořit do světa hrůzy.</div>
</div>

<a name="imerze"></a>
<h2>Imerzivní hraní, taje a úskalí - Petr &quot;Jezevec&quot; Pouchlý </h2>

<div class="akce-archiv">
<div>Jsou různé přístupy, jak hrát rolovou hru. Žádný z nich není lepší nebo horší, jen jsou prostě jiné. Imerzivní hraní podporuje hru postavy způsobem co nejužšího prožívání této role hráčem. Hráč postavu nehraje, hráč se postavou prostě stává. Imerzionismus je o silném prožitku, ale zdaleka to neznamená, že je použitelný pro každého. Hledáte tento způsob hry? Nebo vás naopak děsí? Přednáška podává pohled na imerzionismus z obou jeho stran. Netřeba se obávat, přednáška bude vedena v jazyce běžných smrtelníků.</div>
</div>

<a name="kontroverze"></a>
<h2>Kontroverze v RPG aneb Taková normální hra - Jakub &quot;sffh&quot; Marek</h2>
<div class="akce-archiv">
<div>Zkusili jste se někdy zamyslet nad vaším víkendovým hraním zvnějšku? Co by si o něm myslela veřejnost, kdyby některé periodikum otisklo přepis? Co by si o něm mysleli nezapojení lidé zvenku? Opravdu je tak normální, jak se vám zdá? Přijďte do detailů rozebrat temná zákoutí RPG her.</div>
</div>

<a name="larp_zacatecnici"></a>
<h2>Larp pro úplné začátečníky - Pavel &quot;Lischai&quot; Gotthard</h2>
<div class="akce-archiv">
<div>Larp. Všichni vaši známí o něm mluví, neustále na nějaký jezdí a vytrvale vás lákají, ať s ním začnete taky? A vy pořád nějak nevíte, co to ten larp vlastně je a připadne vám hloupé se jich ptát? Pokud ano, pak si rozhodně nenechte ujít tuhle přednášku.<br/>
Uslyšíte zde odpovědi na všechno, co jste kdy chtěli vědět o larpu a styděli jste se zeptat. Dozvíte se, co to larp je, budou vám představeny jeho základní směry, principy a možné přesahy téhle aktivity. Bude se hovořit o nejznámějších českých larpech, o tom, na co se můžete těšit a na co si naopak dát pozor. Pokud jste zcela bezradní na larpovém moři, tahle přenáška vám pomůže zorientovat se mezi nepřehlednými skalisky a nabrat ten správný směr.</div>
</div>

<a name="nastroje"></a>
<h2>Nástroje, srdce a duše příběhu, aneb Iluze a magické triky vypravěče - Ondřej &quot;Grob&quot; Netík</h2>
<div class="akce-archiv">
<div>Jde o přednášku nejen o smyslu vyprávění, ale hlavně o jeho nástrojích. Narodil jsem se jako vypravěč, od mala tvořím své příběhy. Přes patnáct let vyprávím &quot;hry v hlavní roli - RPG&quot;, ze svých her jsem vydal již dvě knihy, &quot;Zeleného skřítka&quot; a &quot;Meluzínu&quot;. Nyní bych se chtěl podělit o své zkušenosti a usnadnit tak cestu těm, které stejně jako mne fascinuje vypravěčství.<br/>
Povím vám o tom, jak stvořit více než příběh. Jak vytvářet osobní zážitek, vkládat emoce, symbolické výjevy a propojovat je s umlčenými výjevy našeho podvědomí. Jak vyladit příběh, aby jste postoupili v tomto starověkém umění o další kus dál. Protože vyprávění není jen hra, ale nejstarší z lidských kouzel.</div>
</div>

<a name="navrhovani_her"></a>
<h2>Navrhování počítačových a stolních her - Jarek Kolář</h2>
<div class="akce-archiv">
<div>Cílem přednášky je najít rozdíly a podobnosti navrhování obou typů her v oblasti pravidel, příběhu, prostředí, interaktivity, atmosféry a způsobu hraní. Na konkrétních příkladech počítačových her budou rozebrány postupy designu (herní mechanika, level design), které mohou inspirovat tvůrce stolních her. 
Autor je hlavním designérem série Vietcong a vývojovým manažerem Mafia 2 v 2K Games.</div>
</div>

<a name="o_hracich"></a>
<h2>O hráčích, typech, konfliktech a řešení - Roman &quot;RomiK&quot; Hora</h2>
<div class="akce-archiv">
<div>Hraní RPG her je činnost skupinová. A jak to tak chodí, v každé skupince vznikají problémy mezi postavami i ty horší, hráčské. Kdokoliv se kdekoliv zeptá, co má dělat s problémovým hráčem, uslyší: "Promluvte si o tom anebo ho vylučte z herních sezení." Ale popravdě - kdo odstřihne svého nejlepšího kamaráda? Kdo se takhle dokáže zachovat? </div>
<div>Proto je tu tato diskuze. Jejím cílem není naučit vás vyhazovat lidi z herních sezení, ale pokusit se proniknout do nejrůznějších konfliktů a zkusit nastínit jejich možná řešení. Celá beseda bude bohatě ilustrována příklady z herního života organizátora besedy včetně výkladu, jak problém vyřešil. Jelikož se jedná o besedu, budu rád, pokud bude dialogická a ne monologická.</div>
</div>

<a name="spar"></a>
<h2>O spár Zlatého draka - Kolektiv porotců</h2>
<div class="akce-archiv">
<div>Beseda s porotci soutěže o nejlepší jeskyni pro DrD a DrD+, během níž podrobně rozeberou jednotlivé příspěvky a vysvětlí jejich nedostatky.</div>
<div><b>Termín:</b> Sobota; sál 2; 16:00 - 17:00</div>
</div>

<a name="pohadkove_rpg"></a>
<h2>Pohádkové rolové hry - Petr &quot;Jezevec&quot; Pouchlý </h2>

<div class="akce-archiv">
<div>Vzpomínáte, jak jste poslouchali v mládí pohádky? Příběhy plné jednoduchého pohledu na svět, kde dobro vítězí nad zlem? Kde pravda vítězí a lež má krátké nohy? Vzpomínáte na doby, kdy jste v rolových hrách hledali právě tyhle aspekty? A pak někdo řekl, že naivní příběhy do her pro dospělé nepatří a že pohádky jsou pro děti. Možná měl ten někdo pravdu, možná ne. Příběhy dětí, stejně jako náhled na pohádku může být různý. Ale nebylo už dost těch příběhů, kde hrdinové bez citu zabíjí padouchy a honí se jen za penězi a slávou? Není občas pěkné se vrátit zpátky do příběhů dětských let? Možná, že nejsou takové, jak si je pamatujete.</div>
</div>

<a name="prace_s_emocemi"></a>
<h2>Práce s emocemi v RPG - Matouš &quot;Erric&quot; Ježek </h2>
<div class="akce-archiv">
<div>Klíčem k opravdu vnitřnímu zážitku z hraní RPG jsou pocity, které v nás hra vyvolává. Patří k němu jak radost z vítězství tak smutek z prohry. V této přednášce se však budeme převážně zabývat praktickými herními technikami, které pomáhají vyvolat v hráčích i jiné pocity jako zájem, soucit, pocit zodpovědnosti nebo viny. Naučíte se pracovat s postavami hráčů, s cizími postavami i se samotným příběhem tak, aby si hráči odnesli co nejsilnější zážitek. Cílem každého umělce je probudit v lidech emoce, tak proč by to nemohl činit vypravěč?</div>
</div>

<a name="ravenloft"></a>
<h2>Ravenloft: Ve stínu Strahda - Petr &quot;Jezevec&quot; Pouchlý </h2>
<div class="akce-archiv">
<div>Ravenloft je jedním z mnoha světů vesmíru AD&D, ovšem je jiný. Naprosto. Prostředím hry jsou desítky světů, vybíraných z obvyklých i méně obvyklých nočních můr. Atmosféra Ravenloftu je ponurá, děsivá a protkaná temnými tajemstvími. Žánrem světa je fantastický horor. Samotná doména Ravenloft je jen jedním z mnoha světů, oddělených mystickou mlhou, kam mohou vaše postavy zavítat. Jestli vás láká vyzkoušet netradiční ponurý svět s obrovskou škálou možností, který se vymyká běžné fantasy a přitom plně ctí to nejlepší ze žánru, pak se přijďte seznámit.</div>
</div>

<a name="storygames"></a>
<h2>Storygames - okraje žánru RPG - Martin &quot;Kelton&quot; Dörfler a Jakub &quot;sffh&quot; Marek</h2>

<div class="akce-archiv">
<div>Některé RPG udržují hrdé tradice předků, jiné se od nich vzdalují a pouštějí se na neprozkoumaná teritoria. A právě v těchto dálavách lze spatřit nečekané - nevídané náměty, tajuplná témata, matoucí mechaniky. Mnoho z těchto her se zatoulalo tak daleko, že nazývat je RPG lze jen s přimhouřením oka. Ale to jim nic neubírá na zajímavosti a zábavnosti.</div>
<div>V přednášce vám některé z těchto exotických exemplářů ukážeme. A abyste se nenudili, prostřídáme výběr ze dvou druhů - jako u míchané zmrzliny. Jakub bude mluvit o těch s neobvyklými až kontroverzními náměty, zatímco Kelton předvede některé, co poněkud hýbou s tradičními způsoby stavby příběhu. Dozvíte se co mají společného a čím se odlišují od klasických RPG, co nového přinesou na váš stůl a hlavně, proč by vás měly zajímat.</div>
</div>

<a name="strepy_snu"></a>
<h2>Střepy snů - Matouš &quot;Erric&quot; Ježek </h2>
<div class="akce-archiv">
<div>Pojďte se podívat pod pokličku vývoje netradičního českého RPG. Pracujeme na systému, který si klade za cíl, co nejvíce podporovat dramatický příběh právě hráčských postav, dynamicky rozvíjet psychologii postavy a podporovat filmové scény a role. V této prezentaci poodkryjeme trochu roušku tajemství a dozvíte se víc o původní české hře, které dává hráčům do ruky vypravěčské pravomoce.</div>
</div>

<a name="hunter"></a>
<h2>Světlo ve Světě temnoty - Petr &quot;Jezevec&quot; Pouchlý </h2>
<div class="akce-archiv">
<div>Jedním z herních prostředí pro Svět temnoty od White Wolfa je i prostředí Hunter: The Reckoning. Ač by název hry mohl snadno svádět k jednoduché představě o skupině lovců, která razí světem, aby nakopala bestiím zadky, tak skutečnost je trochu jinde. Pokud jste ve hrách od firmy White Wolf hledali onen slibovaný horor, pak tato hra vám jej dopřeje. Pokud jí uchopíte tak, jak ji tvůrci skutečně plánovali a nikoliv tak, jak by mohla vypadat z pár obrázků a textu na zadní straně přebalu.</div>
</div>

<a name="taktika"></a>
<h2>Taktika a strategie v RPG - František &quot;Sniper&quot; Neznaj</h2>

<div class="akce-archiv">
<div>RPG umožňují si povídat a prožívat hraní rolí, ale také prokázat svůj strategický um a simulovat potyčky i obří bitvy. 
Ale je potřeba si položit otázky a ptát se na cenu, náročnost, možnosti, co se od toho dá očekávat a jak to skloubit s RP.</div>
</div>

<a name="tipy"></a>
<h2>Tipy a triky v RPG - Matouš &quot;Erric&quot; Ježek </h2>
<div class="akce-archiv">
<div>RPG už se hrají dost dlouho, aby z nich vykrystalizovala spousta doporučení, jak je hrát. V této přednášce se dozvíte mnoho dílčích tipů pro hráče i pro vypravěče, které vám mohou pomoci posunout vaši hru ještě kousek dál. Přijďte si poslechnout, jak se společně s ostatními hráči podporovat v zábavě, jak do hry sami dát víc a jaké techniky může k podpoře hry používat vypravěč.</div>
</div>

<a name="uo"></a>
<h2>Ultima Online - Andaria</h2>
<div class="akce-archiv">
<div>Prezentace Andarie - světa počítačové online hry Ultima Online zaměřeného na hraní role. Prezentace bude spojena s přednáškou, jak probíhá hra v prostředí UO, s jakými questy se může hráč setkat na Andarii a jak probíhá vymýšlení a realizace questů z pozice tvůrců hry.</div>
</div>

<a name="urban_fantasy_rpg"></a>
<h2>Urban fantasy v RPG - Dalibor &quot;Dalcor&quot; Zeman </h2>
<div class="akce-archiv">
<div>Přednáška přímo navazující na Žánr urban fantasy. Tentokrát si však společně popovídáme o některých námětech a způsobech vedení hry v žánru městské fantasy. V druhé části přednášky si představím generický systém Dreaming Cities vystavěný pro městskou fantasy na jádru volně šířeného systému Tri-Stat dX.</div>
</div>

<a name="historky_pj"></a>
<h2>Veselé historky PídžeJů - Kolektiv PJ</h2>
<div class="akce-archiv">
<div>Oblíbené pásmo veselých historek o tom, jak se hráči i postavy vypořádali či nevypořádali s nástrahami letošního GameConu.</div>
<div><b>Termín:</b> Neděle; hala; 16:00 v rámci vyhlášení výsledků</div>
</div>

<a name="zahranicni_larpy"></a>
<h2>Výběr ze zahraničních larpů - Petr &quot;Jezevec&quot; Pouchlý</h2>
<div class="akce-archiv">
<div>Larpy jsou oblíbené po celém světě. Jsou země, kde vypadají larpy podobně jako u nás, stejně jako jsou země, kde jsou larpy jiné. Přijďte se dozvědět něco málo o tom, jaké jsou larpy v zahraničí či načerpat inspiraci pro vaše vlastní hry. Přednáška bude prokládána videozáznamy.</div>
</div>

<a name="wow"></a>
<h2>World of Warcraft český private RP server Czechdream</h2>
<div class="akce-archiv">
<div>Rádi bychom vám představili český WoW server zaměřený primárně na roleplaying. Chceme vám ukázat, že je to skutečně možné. Rádi bychom vám povědeli, co všechno vám může náš server nabídnout a o co vás však také nejspíše připraví. </div>
<div>Chtěli bychom zavést diskuzi na téma roleplaying v současných online hrách, primárně pak na poli Warcraftu. Co udělat pro to, aby se situace roleplayingu zlepšila? Jak vyjít RP hráčům ještě více vstříc? Jak navnadit &quot;obyčejné&quot; hráče, aby si RP zkusili, a docílit toho, aby je skutečně zaujal? Dotkneme se také otázky powergamingu a takzvaného &quot;nuceného&quot; RP. Uvítáme kritiku i přínosné rady do budoucna.</div>
</div>

<a name="urban_fantasy"></a>
<h2>Žánr urban fantasy - Dalibor &quot;Dalcor&quot; Zeman </h2>

<div class="akce-archiv">
<div>Urban Fantasy, tedy městská fantastika, je žánr, který díky novému proudu ve fantastice prožívá obrovský boom. U nás je navíc tento žánr v RPG hrách poměrně oblíbený. Představíme si historii literárního žánru městské fantasy a velmi obecně se seznámíme s některými hrami, které do něj spadají - ať už je to World of Darkness nebo Unknown Armies. <br/>
Přednáška je koncipovaná jako úvod do žánru, ne jako podrobný rozbor her.</div>
</div>
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (255,'Archiv přednášek 2008','Archiv přednášek 2008 Alpha Omega - Jakub "sffh" Marek Konec světa byl nevyhnutelný, ale jen málokdo tušil, co bude dál. Příchod "andělů" a "ďáblů" mimozemského původu byl jen hřebíčkem do rakve modré planety. Odvěcí nepřítelé se vrátili na staré bojiště svést další bitvu. Nestane se však poslední, alespoň pro lidstvo? Z neuvěřitelné směsi magie, víry a technologie vzniká jeden z nejnovějších a nejzajímavějších postapokalyptických RPG projektů. Brak v RPG aneb Klišé za klišé - Jakub "sffh" Marek Tak jako v každé formě médií existuje i v herním světě brak. O RPG to jde tvrdit hned dvojnásob. Co je to herní brak, čím se definuje a jak se pozná. Je brak dobrý nebo špatný? A co když je všechno jinak? Brak ve všech formách, podformách, předobrazech a následcích aneb jaká je síla a slabina klišé. Court of Moravia - Jana "Lorelei" Jevická Už jste někdy slyšeli slovo larp a zaujalo vás? Chtěli byste si nějaký larp poprvé zahrát, nebo jste už ostřílení matadoři a hledáte něco nového? Ve všech těchto případech bychom vás chtěli pozvat na představení občanského sdružení Court of Moravia, které se zabývá městskými a komorními larpy. Přijďte se navnadit na gangsterku á la Quentin Tarantino, na napínavou fantasy ve vězeňské cele nebo na mrazivý příběh z gentlemanského Klubu sebevrahů. Dark Sun: V dračích spárech - Petr "Jezevec" Pouchlý Kdysi bývala planeta Athas krásnou, zelenou zemí. Pak ji zničila touha po moci. Dračí vládci, vysávající tuto zemi pomalu, ale jistě mění poslední zbytky obyvatelného světa v poušť. Země, která trpí, se musela změnit, stejně jako její obyvatelé. Klasické rasy jsou zde jiné, než byste si představovali a nejhorším nepřítelem hrdinů prosté slunce a nedostatek tekutin. Je to svět, kde železo je vzácností, bohové neexistují a lidskost je téměř neznámým pojmem. Přijďte se seznámit se světem Temného slunce. Dobro, zlo a paladin - Dalibor "Dalcor" Zeman Řízená diskuze, ve které si společně probereme nejen jakým způsobem pracovat s principy dobra a zla, ale také jejich vliv na herní mechaniky. Zaměříme se především na tradiční mechaniku "přesvědčení" a práci s ní, především pak na její funkčnost v hrách spojujících různé kultury a prostředí. V druhé části přednášky si popovídáme o dogmatech ve vztahu k "paladinům" a rytířům v RPG hrách. Erotika a intimita ve hře - Petr "Jezevec" Pouchlý Rolové hry zahrnují širokou škálu možností. Příběhy v nich hrané mohou být komedií, detektivním příběhem, hrdinským eposem, milostným dramatem i vzrušující romancí. Záleží jen na chuti a osobních preferencích hráčů. Témata milostná a sexuální jsou často ve hrách spíše přehlížena. Vzbuzují často stud a obavy, které vedou k určitému tabuizování. Pokud byste sami rádi poodhalili roušku tajemství o těchto tématech, budete mít na přednášce možnost poznat některé knihy, které pracují s touto intimní tematikou a seznámit se s technikami, jak takovou hru vést. Fenomén: Komorní larp - Pavel "Lischai" Gotthard Larp v psychiatrické léčebně, podzemním krytu nebo na palubě výletní lodi? Proč ne. Komorní larpy se u nás začínají profilovat až v posledních několika letech. Tyto netradiční hry přistupují k principu samotného larpu zcela jinak, používají jiné prostředky a mají i jiné cíle. Pokud vás zajímá, o co v těchto hrách jde, v čem jsou jiné než ostatní larpy a čím můžou být pro své hráče atraktivní, pak si rozhodně nenechte ujít tuhle přednášku. Přiblíží vám fenomén komorních larpů, provede vás po české komorní scéně a představí nejzajímavější počiny, které se u nás odehrály. Hack & slash - František "Sniper" Neznaj Běžným prvkem na aktuální RPG-diskusní scéně je skoro výhradní zaměření a hraní rolí a odklon od kořenů - taktických soubojů a jednoduchých her. Je ale H&S jen obyčejnou tupou hrou pro začátečníky a mladší 15 let? Nebo se dá hrát H&S i na úrovni? Jak se může prolínat s RP a co vše vlastně pod H&S může spadat? Co je na tomto stylu hry zábavného? Horor v RPG - Petr "Jezevec" Pouchlý Plíživý pocit strachu, přebíhání mrazu po zádech a zrychlený tlukot vlastního srdce se pojí s vyprávěním příběhů od počátku věků. V rolových hrách je hororový žánr jedním z nejoblíbenějších. Přesto však navození pocitu opravdu působivé hry s touto tematikou není snadné. Není to jen o příručce vhodných pravidel, tajuplném herním prostředí a zapálené svíčce. Jsou knihy dobré a lepší, stejně jako jsou metody, které mohou pomoci. Přednáška vám představí základní kameny a pomůže nalézt směr, kudy se ponořit do světa hrůzy. Imerzivní hraní, taje a úskalí - Petr "Jezevec" Pouchlý Jsou různé přístupy, jak hrát rolovou hru. Žádný z nich není lepší nebo horší, jen jsou prostě jiné. Imerzivní hraní podporuje hru postavy způsobem co nejužšího prožívání této role hráčem. Hráč postavu nehraje, hráč se postavou prostě stává. Imerzionismus je o silném prožitku, ale zdaleka to neznamená, že je použitelný pro každého. Hledáte tento způsob hry? Nebo vás naopak děsí? Přednáška podává pohled na imerzionismus z obou jeho stran. Netřeba se obávat, přednáška bude vedena v jazyce běžných smrtelníků. Kontroverze v RPG aneb Taková normální hra - Jakub "sffh" Marek Zkusili jste se někdy zamyslet nad vaším víkendovým hraním zvnějšku? Co by si o něm myslela veřejnost, kdyby některé periodikum otisklo přepis? Co by si o něm mysleli nezapojení lidé zvenku? Opravdu je tak normální, jak se vám zdá? Přijďte do detailů rozebrat temná zákoutí RPG her. Larp pro úplné začátečníky - Pavel "Lischai" Gotthard Larp. Všichni vaši známí o něm mluví, neustále na nějaký jezdí a vytrvale vás lákají, ať s ním začnete taky? A vy pořád nějak nevíte, co to ten larp vlastně je a připadne vám hloupé se jich ptát? Pokud ano, pak si rozhodně nenechte ujít tuhle přednášku. Uslyšíte zde odpovědi na všechno, co jste kdy chtěli vědět o larpu a styděli jste se zeptat. Dozvíte se, co to larp je, budou vám představeny jeho základní směry, principy a možné přesahy téhle aktivity. Bude se hovořit o nejznámějších českých larpech, o tom, na co se můžete těšit a na co si naopak dát pozor. Pokud jste zcela bezradní na larpovém moři, tahle přenáška vám pomůže zorientovat se mezi nepřehlednými skalisky a nabrat ten správný směr. Nástroje, srdce a duše příběhu, aneb Iluze a magické triky vypravěče - Ondřej "Grob" Netík Jde o přednášku nejen o smyslu vyprávění, ale hlavně o jeho nástrojích. Narodil jsem se jako vypravěč, od mala tvořím své příběhy. Přes patnáct let vyprávím "hry v hlavní roli - RPG", ze svých her jsem vydal již dvě knihy, "Zeleného skřítka" a "Meluzínu". Nyní bych se chtěl podělit o své zkušenosti a usnadnit tak cestu těm, které stejně jako mne fascinuje vypravěčství. Povím vám o tom, jak stvořit více než příběh. Jak vytvářet osobní zážitek, vkládat emoce, symbolické výjevy a propojovat je s umlčenými výjevy našeho podvědomí. Jak vyladit příběh, aby jste postoupili v tomto starověkém umění o další kus dál. Protože vyprávění není jen hra, ale nejstarší z lidských kouzel. Navrhování počítačových a stolních her - Jarek Kolář Cílem přednášky je najít rozdíly a podobnosti navrhování obou typů her v oblasti pravidel, příběhu, prostředí, interaktivity, atmosféry a způsobu hraní. Na konkrétních příkladech počítačových her budou rozebrány postupy designu (herní mechanika, level design), které mohou inspirovat tvůrce stolních her. Autor je hlavním designérem série Vietcong a vývojovým manažerem Mafia 2 v 2K Games. O hráčích, typech, konfliktech a řešení - Roman "RomiK" Hora Hraní RPG her je činnost skupinová. A jak to tak chodí, v každé skupince vznikají problémy mezi postavami i ty horší, hráčské. Kdokoliv se kdekoliv zeptá, co má dělat s problémovým hráčem, uslyší: "Promluvte si o tom anebo ho vylučte z herních sezení." Ale popravdě - kdo odstřihne svého nejlepšího kamaráda? Kdo se takhle dokáže zachovat? Proto je tu tato diskuze. Jejím cílem není naučit vás vyhazovat lidi z herních sezení, ale pokusit se proniknout do nejrůznějších konfliktů a zkusit nastínit jejich možná řešení. Celá beseda bude bohatě ilustrována příklady z herního života organizátora besedy včetně výkladu, jak problém vyřešil. Jelikož se jedná o besedu, budu rád, pokud bude dialogická a ne monologická. O spár Zlatého draka - Kolektiv porotců Beseda s porotci soutěže o nejlepší jeskyni pro DrD a DrD+, během níž podrobně rozeberou jednotlivé příspěvky a vysvětlí jejich nedostatky. Termín: Sobota; sál 2; 16:00 - 17:00 Pohádkové rolové hry - Petr "Jezevec" Pouchlý Vzpomínáte, jak jste poslouchali v mládí pohádky? Příběhy plné jednoduchého pohledu na svět, kde dobro vítězí nad zlem? Kde pravda vítězí a lež má krátké nohy? Vzpomínáte na doby, kdy jste v rolových hrách hledali právě tyhle aspekty? A pak někdo řekl, že naivní příběhy do her pro dospělé nepatří a že pohádky jsou pro děti. Možná měl ten někdo pravdu, možná ne. Příběhy dětí, stejně jako náhled na pohádku může být různý. Ale nebylo už dost těch příběhů, kde hrdinové bez citu zabíjí padouchy a honí se jen za penězi a slávou? Není občas pěkné se vrátit zpátky do příběhů dětských let? Možná, že nejsou takové, jak si je pamatujete. Práce s emocemi v RPG - Matouš "Erric" Ježek Klíčem k opravdu vnitřnímu zážitku z hraní RPG jsou pocity, které v nás hra vyvolává. Patří k němu jak radost z vítězství tak smutek z prohry. V této přednášce se však budeme převážně zabývat praktickými herními technikami, které pomáhají vyvolat v hráčích i jiné pocity jako zájem, soucit, pocit zodpovědnosti nebo viny. Naučíte se pracovat s postavami hráčů, s cizími postavami i se samotným příběhem tak, aby si hráči odnesli co nejsilnější zážitek. Cílem každého umělce je probudit v lidech emoce, tak proč by to nemohl činit vypravěč? Ravenloft: Ve stínu Strahda - Petr "Jezevec" Pouchlý Ravenloft je jedním z mnoha světů vesmíru AD&D, ovšem je jiný. Naprosto. Prostředím hry jsou desítky světů, vybíraných z obvyklých i méně obvyklých nočních můr. Atmosféra Ravenloftu je ponurá, děsivá a protkaná temnými tajemstvími. Žánrem světa je fantastický horor. Samotná doména Ravenloft je jen jedním z mnoha světů, oddělených mystickou mlhou, kam mohou vaše postavy zavítat. Jestli vás láká vyzkoušet netradiční ponurý svět s obrovskou škálou možností, který se vymyká běžné fantasy a přitom plně ctí to nejlepší ze žánru, pak se přijďte seznámit. Storygames - okraje žánru RPG - Martin "Kelton" Dörfler a Jakub "sffh" Marek Některé RPG udržují hrdé tradice předků, jiné se od nich vzdalují a pouštějí se na neprozkoumaná teritoria. A právě v těchto dálavách lze spatřit nečekané - nevídané náměty, tajuplná témata, matoucí mechaniky. Mnoho z těchto her se zatoulalo tak daleko, že nazývat je RPG lze jen s přimhouřením oka. Ale to jim nic neubírá na zajímavosti a zábavnosti. V přednášce vám některé z těchto exotických exemplářů ukážeme. A abyste se nenudili, prostřídáme výběr ze dvou druhů - jako u míchané zmrzliny. Jakub bude mluvit o těch s neobvyklými až kontroverzními náměty, zatímco Kelton předvede některé, co poněkud hýbou s tradičními způsoby stavby příběhu. Dozvíte se co mají společného a čím se odlišují od klasických RPG, co nového přinesou na váš stůl a hlavně, proč by vás měly zajímat. Střepy snů - Matouš "Erric" Ježek Pojďte se podívat pod pokličku vývoje netradičního českého RPG. Pracujeme na systému, který si klade za cíl, co nejvíce podporovat dramatický příběh právě hráčských postav, dynamicky rozvíjet psychologii postavy a podporovat filmové scény a role. V této prezentaci poodkryjeme trochu roušku tajemství a dozvíte se víc o původní české hře, které dává hráčům do ruky vypravěčské pravomoce. Světlo ve Světě temnoty - Petr "Jezevec" Pouchlý Jedním z herních prostředí pro Svět temnoty od White Wolfa je i prostředí Hunter: The Reckoning. Ač by název hry mohl snadno svádět k jednoduché představě o skupině lovců, která razí světem, aby nakopala bestiím zadky, tak skutečnost je trochu jinde. Pokud jste ve hrách od firmy White Wolf hledali onen slibovaný horor, pak tato hra vám jej dopřeje. Pokud jí uchopíte tak, jak ji tvůrci skutečně plánovali a nikoliv tak, jak by mohla vypadat z pár obrázků a textu na zadní straně přebalu. Taktika a strategie v RPG - František "Sniper" Neznaj RPG umožňují si povídat a prožívat hraní rolí, ale také prokázat svůj strategický um a simulovat potyčky i obří bitvy. Ale je potřeba si položit otázky a ptát se na cenu, náročnost, možnosti, co se od toho dá očekávat a jak to skloubit s RP. Tipy a triky v RPG - Matouš "Erric" Ježek RPG už se hrají dost dlouho, aby z nich vykrystalizovala spousta doporučení, jak je hrát. V této přednášce se dozvíte mnoho dílčích tipů pro hráče i pro vypravěče, které vám mohou pomoci posunout vaši hru ještě kousek dál. Přijďte si poslechnout, jak se společně s ostatními hráči podporovat v zábavě, jak do hry sami dát víc a jaké techniky může k podpoře hry používat vypravěč. Ultima Online - Andaria Prezentace Andarie - světa počítačové online hry Ultima Online zaměřeného na hraní role. Prezentace bude spojena s přednáškou, jak probíhá hra v prostředí UO, s jakými questy se může hráč setkat na Andarii a jak probíhá vymýšlení a realizace questů z pozice tvůrců hry. Urban fantasy v RPG - Dalibor "Dalcor" Zeman Přednáška přímo navazující na Žánr urban fantasy. Tentokrát si však společně popovídáme o některých námětech a způsobech vedení hry v žánru městské fantasy. V druhé části přednášky si představím generický systém Dreaming Cities vystavěný pro městskou fantasy na jádru volně šířeného systému Tri-Stat dX. Veselé historky PídžeJů - Kolektiv PJ Oblíbené pásmo veselých historek o tom, jak se hráči i postavy vypořádali či nevypořádali s nástrahami letošního GameConu. Termín: Neděle; hala; 16:00 v rámci vyhlášení výsledků Výběr ze zahraničních larpů - Petr "Jezevec" Pouchlý Larpy jsou oblíbené po celém světě. Jsou země, kde vypadají larpy podobně jako u nás, stejně jako jsou země, kde jsou larpy jiné. Přijďte se dozvědět něco málo o tom, jaké jsou larpy v zahraničí či načerpat inspiraci pro vaše vlastní hry. Přednáška bude prokládána videozáznamy. World of Warcraft český private RP server Czechdream Rádi bychom vám představili český WoW server zaměřený primárně na roleplaying. Chceme vám ukázat, že je to skutečně možné. Rádi bychom vám povědeli, co všechno vám může náš server nabídnout a o co vás však také nejspíše připraví. Chtěli bychom zavést diskuzi na téma roleplaying v současných online hrách, primárně pak na poli Warcraftu. Co udělat pro to, aby se situace roleplayingu zlepšila? Jak vyjít RP hráčům ještě více vstříc? Jak navnadit "obyčejné" hráče, aby si RP zkusili, a docílit toho, aby je skutečně zaujal? Dotkneme se také otázky powergamingu a takzvaného "nuceného" RP. Uvítáme kritiku i přínosné rady do budoucna. Žánr urban fantasy - Dalibor "Dalcor" Zeman Urban Fantasy, tedy městská fantastika, je žánr, který díky novému proudu ve fantastice prožívá obrovský boom. U nás je navíc tento žánr v RPG hrách poměrně oblíbený. Představíme si historii literárního žánru městské fantasy a velmi obecně se seznámíme s některými hrami, které do něj spadají - ať už je to World of Darkness nebo Unknown Armies. Přednáška je koncipovaná jako úvod do žánru, ne jako podrobný rozbor her.');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (256,'Armada Game - přednáška','armada-game---prednaska',40,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (256,'prednasky/armada-game---prednaska');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (256,'Armada Game - přednáška — GameCon 2011','gamecon,2011','Armada Game - přednáška');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (256,'kapacita 0/0<br />
<h1>Armada Game - přednáška</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/armada-game---prednaska.gif" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>přednášející</strong><br />Juraj Sekereš<br />
  <strong>čas akce</strong><br />pátek 22.7 - 20:00 až 21:00  <br />
 <strong>další akce organizátora</strong> <br /><div style = "text-align: left;"><a href = "/deskove-hry/armada-game">Armada Game</a></div>
</div>
</p>
   <p style = \\"clear: both;\\">
<em>16/4/11
<br>
Coby zkušeného Plukovníka mě dnes poslali velet do severovýchodní
základny. Po příjezdu jsem čekal všechno, ale podmínky byly
opravdu drsné...
<br>
30/4/11
<br>
Již nějakou dobu se náš tábor rozšiřuje, jednotek přibývá, avšak ve vzduchu je cítit
zvláštní pach. Takhle smrdí válka...
<br>
8/5/11
<br>
Zprávy o nepřátelské armádě blížící se k naší nejjižnější základně, se mi donesly nad
<br>
ránem. Musím se vypořádat s nepřátelskou strategií hned teď, nebo mám čekat, jak
se situace vyvine? Obětuji jednu základnu a pár dobrých vojáků, jen aby byl protiútok
silnější? Dnes visí životy, možná i osud této války na mém rozhodnutí...
<br>
24/5/11
<br>
Po dvou týdnech neustálých bojů je klid. Dva týdny, 16 mrtvých vojáků, tři padlé
základny. Válka je u konce, moje rozhodnutí bylo fatální. Sám se ptám, jak jsme
to při všech těch ztrátách dokázali... Štěstí s tím nemělo co dělat, prostě jsme využili
terénu, který obklopoval nepřítele...
<br>
1/8/11
<br>
Další základna, další válka, další příležitost dokázat, že jsme ta nejlepší ARMÁDA...
</em>
</p>
<p>
ARMÁDA GAME je komplexní strategická stolní hra pro 2-4 hráče. Klade
důraz na plánování, strategii, schopnost využívat herní terén ve svůj prospěch,
odhad plánů nepřítele a blafování. Ve hře čtyř hráčů je neméně důležitá koordinace
spoluhráčů. Počáteční tvorba mapy je jediným krokem, do kterého zasahuje náhoda.
Tím je zaručena jedinečnost každé hry a umožňuje tak hráčům vymýšlet strategie „na
míru“ konkrétnímu utkání.</p>
<p>Hráč se pomocí jedné až tří figurek snaží zvětšit svoje
území kupováním a přesouváním svých jednotek po mapě. Stavěním základen a jejich
zlepšováním pak hráč zvyšuje svůj přísun produkčních a technologických bodů. Díky
technologiím si hráč zpřístupní celou řadu výhod, kterých pak může využít. Jedna hra
trvá 15-150 minut.</p>
<p>
Zahrát hru je možné v deskoherně v průběho celého Gameconu. Přítomni budou její autoři, kteří vás rádi zasvětí do tajů této nové hry.        

