INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (268,'O přednáškách na GameConu','o-prednaskach-na-gc',40,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (268,'prednasky/o-prednaskach-na-gc');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (268,'O přednáškách na GameConu — GameCon 2011','gamecon,2011','O přednáškách na GameConu');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (268,'<h1>O přednáškách na GameConu</h1>
<p>Hlavní novinkou letošního Gameconu je vyslyšení vašich žádostí a ucelení přednášek do <strong>kompaktních tematických bloků</strong>, které pro vás budou více lákavé oproti ostatnímu programu než osamocené přednášky.</p>
<p>Hlavní událostí letošního Gameconu bude <strong>křest Dračího doupěte II</strong>, kterému samozřejmě kromě křtu samotného bude věnováno i nějaké povídání o tom, jak vypadá, o tom, jak vznikalo a co za ním stálo, a zbude prostor i pro diskusi s těmi z vás, kteří budou mít zájem o další nebo okrajové informace o tomto věříme že zásadním přelomu na české RPG scéně.</p>
<p>Ostatní bloky přednášek se však touto velkolepou událostí také nedají zahanbit, a proto vám přineseme blok věnovaný běžnému hraní i blok, jehož obsahem budou pokročilejší a více „odborné“ úvahy okolo RPG, samozřejmě pojaté tak, aby se v nich mohli obohatit i běžní hráči. Přineseme vám i blok o herním designu &ndash; ať už RPG nebo deskovek a blok, v němž vám představíme různé méně známé hry a z těch známějších přiblížíme některé zajímavější.</p>
<p>Nejsme však ve škole, abychom pouze naslouchali nebo vedli nezajímavé výklady, proto budou přednášky zajímavé a diskuse budou vítány. Nebojte se tedy kromě her a aktivit zavítat i na nějaké to povídání, které může učinit vaše hry ještě zajímavější.</p>
<!--<p>
S každým rokem se snažíme zlepšovat kvalitu přednášek a vybírat pro vás dobré přednášející. Můžete počítat s prezentacemi a diskusemi kolem hlavních českých projektů Dračí Doupě II, Příběhy impéria a Střepy snů. K tomu navíc přibudou přednášky o hraní RPG, práci s hráči a práci s příběhem. Přidají se i témata týkající se larpu, deskovek a vůbec hraní tak jak to máte rádi.
</p>
<p>
Jelikož vám chceme dodat to nejlepší, přijímáme jak náměty na přednášky a protože máme ještě nějaké místo, tak i nadané a ve svém oboru zkušené přednášející, kteří by se chtěli na programu podílet. Se svými náměty nebo přednáškami/dílnami/prezentacemi se obracejte na organizátora této sekce na <a href = "mailto:erric@email.cz">erric@email.cz</a>.
</p>

<ul> 
 <li> 
  <a href = "/prednasky/seznam-prednasek-na-gc2009">Podívejte se, jaké přednášky byly minulý rok.</a>
 </li>
</ul>-->
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (268,'O přednáškách na GameConu','O přednáškách na GameConu Hlavní novinkou letošního Gameconu je vyslyšení vašich žádostí a ucelení přednášek do kompaktních tematických bloků , které pro vás budou více lákavé oproti ostatnímu programu než osamocené přednášky. Hlavní událostí letošního Gameconu bude křest Dračího doupěte II , kterému samozřejmě kromě křtu samotného bude věnováno i nějaké povídání o tom, jak vypadá, o tom, jak vznikalo a co za ním stálo, a zbude prostor i pro diskusi s těmi z vás, kteří budou mít zájem o další nebo okrajové informace o tomto věříme že zásadním přelomu na české RPG scéně. Ostatní bloky přednášek se však touto velkolepou událostí také nedají zahanbit, a proto vám přineseme blok věnovaný běžnému hraní i blok, jehož obsahem budou pokročilejší a více „odborné“ úvahy okolo RPG, samozřejmě pojaté tak, aby se v nich mohli obohatit i běžní hráči. Přineseme vám i blok o herním designu – ať už RPG nebo deskovek a blok, v němž vám představíme různé méně známé hry a z těch známějších přiblížíme některé zajímavější. Nejsme však ve škole, abychom pouze naslouchali nebo vedli nezajímavé výklady, proto budou přednášky zajímavé a diskuse budou vítány. Nebojte se tedy kromě her a aktivit zavítat i na nějaké to povídání, které může učinit vaše hry ještě zajímavější. S každým rokem se snažíme zlepšovat kvalitu přednášek a vybírat pro vás dobré přednášející. Můžete počítat s prezentacemi a diskusemi kolem hlavních českých projektů Dračí Doupě II, Příběhy impéria a Střepy snů. K tomu navíc přibudou přednášky o hraní RPG, práci s hráči a práci s příběhem. Přidají se i témata týkající se larpu, deskovek a vůbec hraní tak jak to máte rádi. Jelikož vám chceme dodat to nejlepší, přijímáme jak náměty na přednášky a protože máme ještě nějaké místo, tak i nadané a ve svém oboru zkušené přednášející, kteří by se chtěli na programu podílet. Se svými náměty nebo přednáškami/dílnami/prezentacemi se obracejte na organizátora této sekce na erric@email.cz . Podívejte se, jaké přednášky byly minulý rok. -->');

