        <a href = "/prednasky/seznam-prednasek-na-gc2010">Přehled všech přednášek na GameConu 2010</a>      </li>-->
    </ul>
  </p>
  <div style = "width: 100%; float: left;">
    <div style = "width: 50%; text-align: left; float: left; padding-top: 20px; padding-bottom: 15px;">&laquo; <a href = "/prednasky/o-gc-po-gc-a-o-dalsich-gc">O GC po GC a o dalších GC</a></div>    <div style = "width: 50%; text-align: right; float: right; padding-top: 20px; padding-bottom: 15px;"><a href = "/prednasky/prasky-na-psani">Prášky na psaní</a> &raquo;</div>  </div>
  
    </div>
  </div>');
