INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (270,'kapacita 5/0<br />
<h1>Prášky na psaní</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/prasky-na-psani.gif" style = "float: left; "/ /></div>
