INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (270,'Prášky na psaní','kapacita 5/0 Prášky na psaní přednášející Pavel "Lischai" Gotthard čas akce pátek 22.7 - 11:00 až 12:00 "Chtěl bych psát, ale nevím co. Chtěl bych psát, ale nevím jak. Něco píšu, ale nejde mi to. Kéž by tak existovala kouzelná pilulka, kterou stačí spolknout, a všechno půjde samo: povídky, romány, dobrodružství..." Jak tušíte, jedna zázračná pilulka neexistuje. Ale existuje několik polo-zázračných! Přijďte si poslechnout, co jsou ty tajemné prášky na psaní. Přehled všech přednášek na GameConu 2010 --> « PostApo larpy Příprava hry a hráčská invence »');

