INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (272,'Archiv přednášek na GameConu 2009','seznam-prednasek-na-gc2009',40,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (272,'prednasky/seznam-prednasek-na-gc2009');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (272,'Archiv přednášek na GameConu 2009 — GameCon 2011','gamecon,2011','Archiv přednášek na GameConu 2009');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (272,'<h1>Archiv přednášek na GameConu 2009</h1>
<h2>Altar plánuje</h2><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/altar-planuje.jpg" style = "float: left; "/ /></div></p>
<p>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>přednášející</strong><br />Altar<br />
 </div>
</p>
<p style = "clear: both;">
  Chcete zjistit o čem která hra je?<br />

  Nevíte jak si vybrat dobrou hru?<br />
  Chcete zjistit, co pro vás Altar plánuje?<br />
  </p>
  <p>Pak přijďte na přednášku Altaru o jeho hrách.</p>
  <p>Na této přednášce vám lidé z Altaru představí v kostce o čem které hry jsou a mohou vám tak pomoci s výběrem nové hry, kterou byste si třeba chtěli pořídit ale nevíte si rady. A v neposlední řadě se také můžete dozvědět, co Altar dále plánuje a s jakými novými hrami chce přijít.</p>
</p>
<p>
  <ul>

    <h2>Alternativní storytelling a roleplaying</h2><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/alternativni-storytelling-a-roleplaying.jpg" style = "float: left; "/ /></div></p>
<p>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>přednášející</strong><br />Petr "Sirien" Mazák<br />

</div>
</p>
<p style = "clear: both;">
  V této přednášce budu mluvit především o různých méně častých, nezvyklých nebo rovnou alternativních způsobech hraní nebo vedení hry. Pár z nich jsou spíše zajímavostmi, jiné dávají hře specifický ráz, ale některé z nich jsou praktickými pomůckami pro každého hráče i vypravěče.
  
</p>
<p>
  <ul>
    <h2>Asterion – Hranice fantazie</h2><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/asterion--hranice-fantazie.jpg" style = "float: left; "/ /></div></p>
<p>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>přednášející</strong><br />David "Seth" Rozsíval<br />

</div>
</p>
<p style = "clear: both;">
Kam až může tvůrce herního světa zajít, aniž by jeho šílené nápady nemátly zbytečně hráče? Jak najít cestu od ubíjejícího stereotypu prostředí fantasy středověku? Jak moc může být takový tvůrce šílený, aniž by z toho zešílel hráč?<br /><br />
Asterionská přednáška se pokusí odpovědět na některé z těchto otázek, zároveň seznámí čtenáře s tím, co mohou od Asterionu do budoucna očekávat.
</p>

   <ul><h2>Balení na conech</h2><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/baleni-na-conech.jpg" style = "float: left; "/ /></div></p>
<p>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>přednášející</strong><br />Petr "Jezevec" Pouchlý<br />

</div>
</p>
<p style = "clear: both;">
  Ač to vypadá snadně, tak balení je celá věda. Výsledek může být uspokojující, překvapivý, užitečný, úsporný či naopak úplně katastrofální. Někdo balit umí a někdo ne. Čeká vás krátký zábavný exkurz do technik balení, zaměřený především na balení na conech.  
</p>
<p>
  <ul><h2>Budoucnost GameConu</h2><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/budoucnost-gameconu.gif" style = "float: left; "/ /></div></p>
<p>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>přednášející</strong><br />Petr "Gandalf" Holub<br />

</div>
</p>
<p style = "clear: both;">
  Zajímá vás jaké organizační změny se na GameConu letos udály?<br />
  Zajímá vás jak chceme, aby GameCon vypadal a kam ho chceme směřovat?<br />

  Chtěli byste se s námi podělit o své nápady a pomoci s plánováním budoucnosti GameConu?</p>
  <p>Přednáška o budoucnosti GameConu bude spíše diskuzí s vámi. Pokud vás to bude zajímat, prozradíme vám jaké změny se udály a proč. Můžeme taky nakouknout do minulosti, protože s ní to všechno souvisí. A hlavně se budeme bavit o tom co by se mělo dít dál.</p>
  <p>GameCon děláme pro vás, takže budeme rádi, když nám přijdete říct, co si o něm myslíte, ať už je to dobré nebo špatné. Obojí nám pomůže GameCon dále zlepšovat. A pokud máte pocit, že byste se rádi do organizace GameConu zapojili i více než jen radou, přijďte určitě – rádi si s vámi o tom promluvíme.</p>
<p>
  <ul>
    <h2>Drakkar - internetový časopis</h2><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/drakkar---internetovy-casopis.jpg" style = "float: left; "/ /></div></p>

<p>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>přednášející</strong><br />Roman "RomiK" Hora, Jakub "boubaque" Maruš<br />

</div>
</p>
<p style = "clear: both;">
  Drakkar je již zavedený internetový časopis. Funguje dva roky a stále může získávat více a více čtenářů, proto my, jakožto redakce nikdy neopomineme ani jedinou příležitost k prezentaci a klidně i opakování již řečeného. Na této krátké přednášce o otevřeném projektu internetového časopisu "Drakkar" budete seznámeni s počátky, novou koncepcí čísel, možností připojit se i dalším plánům do budoucna.
</p>

<p>
  <ul>
    <h2>Dungeons and Dragons 4E</h2><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/dungeons-and-dragons-4e.jpg" style = "float: left; "/ /></div></p>
<p>
<div style = "padding-bottom: 20px; width: 280px; float: left;">

 <strong>přednášející</strong><br />David "Conlai" Klimeček<br />
</div>

</p>
<p style = "clear: both;">
  Dobrodruhové! Mocní válečníci, stateční rytíři, učení mágové a prohnaní zloději, vydejte se se mnou na cestu za dobrodružstvím a bohatstvím!</p>
  <p>Dungeons and Dragons je hra s více než třicetiletou tradicí. Během této doby prošla dlouhým vývojem až k současné čtvrté edici. Tématem hry ale stále zůstává dobrodružná cesta skupiny hrdinů za slávou a bohatstvím, cesta, která je lemována nebezpečím v podobě příšer a pastí. Výrazným prvkem čtvrté edice DnD je také propracovaný taktický bojový systém využívající miniatury a čtvercovou mapu.
</p>
<p>
  <ul>
    <li>
      Více informací: <a href = "http://rpgforum.cz/anotace/dungeons-and-dragons-4th-edition" onclick = "window.open(this.href,\'_blank\'); return false">rpgforum.cz/anotace/dungeons-and-dragons-4th-edition</a>

    </li>
<h2>Engel d20</h2><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/engel-d20.jpg" style = "float: left; "/ /></div></p>
<p>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>přednášející</strong><br />Dalibor "Dalcor" Zeman<br />

</div>
</p>
<p style = "clear: both;">
  Europa, Anno Domini 2654. Vítejte v postapokalyptické budoucnosti naší Země. Lidstvo uvržené do nové doby temna je na pokraji vyhlazení. Andělská církev se snaží zastavit technologický pokrok i armády Pána much, které ohrožují samotnou existenci Stvoření.
</p>
<p>Starší temné RPG, postavené na d20 systému, je založené především na hutné atmosféře bezútěšného světa a vnitřních pohnutkách titulních postav, u kterých není vše tak božské, jak by se na první pohled mohlo zdát.
</p>
<p>
  <ul>
    <h2>Hlavní role pro vás</h2><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/hlavni-role-pro-vas.jpg" style = "float: left; "/ /></div></p>
<p>

<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>přednášející</strong><br />Petr "Jezevec" Pouchlý<br />

</div>
</p>
<p style = "clear: both;">
  <em>Příběhy, který skutečně prožijete. Ne jen od stolu nebo ze sedačky, ale na vlastní kůži.<br />
Některé larpy mohou být mnohem víc, než čekáte.<br />
Přijďte si o nich poslechnout.</em>
</p>
<p>
  Ať už je pro vás larp novým pojmem nebo jste zkušený hráč, nenechte si ujít tuhle přednášku. Pro každého z vás zde bude něco. Pokud si nejste jistí tím, co larp je, zde se to dozvíte. A pokud jste si jisti, třeba vás něčím překvapíme.<br />
Uvidíte fotky a videa z nejzajímavějších larpových her, které se v Česku konaly a uslyšíte ty nejčerstvější informace o projektech, na které se můžete těšit.
</p>

  
<p>
  <ul><h2>Improvizované hraní RPG</h2><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/improvizovane-hrani-rpg.gif" style = "float: left; "/ /></div></p>
<p>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>přednášející</strong><br />Jiří "Markus" Petrů<br />
</div>
</p>
<p style = "clear: both;">
  Také vás baví dělat vypravěče? A také nesnášíte přípravu na hru? Dlouhé hodiny strávené nad psaním poznámek, tvorbou cizích postav a vymýšlením zápletek... jen abyste při hře zjistili, že z toho polovinu stejně nevyužijete? Tak to nedělejte! Pokud hraní RPG přestává být uvolněnou zábavou a stává se domácím úkolem, něco je špatně.</p>
  <p>Pojďme si povědět, jak hrát improvizovaně - s minimální přípravou, nebo zcela bez přípravy. Jde to! A možná zjistíte, že jste po dlouhé době opět nalezli tu jiskru bezprostřední radosti, která se v poslední době začala z vašich her vytrácet.</p>
</p>

<p>
  <ul>
   <h2>Kalevala v RPG a fantasy</h2><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/kalevala-v-rpg-a-fantasy.jpg" style = "float: left; "/ /></div></p>
<p>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>přednášející</strong><br />Michala Merglová<br />
</div>
</p>
<p style = "clear: both;">
  Zajímaly váš příběhy dávných severských národů? Kde čerpal Tolkien svoji inspiraci? Chcete vědět jak se liší dávný finský hrdina Kullervo od Túrina Turambara?</p>
  <p>Přednáška zaměřena na povídání o finské Kalevale, jejích odkazech a o tom jak ovlivnila Středozem. Povídání zaměřeno i na využití Kalevaly jako inspirace pro hraní RPG s důrazem na tvoření příběhu dle jejích mýtů a na tvoření pozadí postav dle hrdinů Kalevaly.
<p>
  <ul>
    <h2>Komorní larp - RPG bez kostek </h2><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/komorni-larp---rpg-bez-kostek.jpg" style = "float: left; "/ /></div></p>

<p>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>přednášející</strong><br />Petr "Jezevec" Pouchlý<br />
</div>
</p>
<p style = "clear: both;">
  Hry v roli jsou naším společným hobby. Někdo je hraje u stolu, jiný v lese a další na kosmické lodi. Princip je stejný, jen přístup rozdílný. 
</p><p>
Co mají společného komorní larpy a klasické rolové hry? Stojí za vyzkoušení nebo je jen jeden směr, jak k hraní přistoupit? Nahradí jednou larpy klasické stolní RPG?  
</p>
<p>
  <ul><h2>Moderní deskové hry - Albi, CGE</h2><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/moderni-deskove-hry-albi--cge.gif" style = "float: left; "/ /></div></p>
<p>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>přednášející</strong><br />Albi, Czech Games Edition<br />

</div>
</p>
<p style = "clear: both;">
  Chcete zjistit o čem která hra je?<br />
  Nevíte jak si vybrat dobrou hru?<br />

  Chcete zjistit, co pro vás Albi a Czech Games Edition plánují?<br />
  </p>
  <p>Pak přijďte na přednášku o jejich hrách.</p>
  <p>Na této přednášce vám lidé z Albi a Czech Games Edition představí v kostce o čem které hry jsou a mohou vám tak pomoci s výběrem nové hry, kterou byste si třeba chtěli pořídit ale nevíte si rady. A v neposlední řadě se také můžete dozvědět, co Albi a CGE dále plánují a s jakými novými hrami chtějí přijít.</p>
</p>
<p>
  <ul>
    <h2>Moderní deskové hry - Corfix</h2><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/moderni-deskove-hry---corfix.gif" style = "float: left; "/ /></div></p>

<p>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>přednášející</strong><br />Corfix<br />

</div>
</p>
<p style = "clear: both;">
  Chcete zjistit o čem která hra je?<br />
  Nevíte jak si vybrat dobrou hru?<br />
  Chcete zjistit, co pro vás Corfix plánuje?<br />
  </p>
  <p>Pak přijďte na přednášku Corfixu o jejich hrách.</p>

  <p>Na této přednášce vám lidé z Corfixu představí v kostce o čem které hry jsou a mohou vám tak pomoci s výběrem nové hry, kterou byste si třeba chtěli pořídit ale nevíte si rady. A v neposlední řadě se také můžete dozvědět, co Corfix dále plánuje a s jakými novými hrami chce přijít.</p>
</p>
<p>
  <ul>
    <h2>Napříč spektrem RPG</h2><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/napric-spektrem-rpg.jpg" style = "float: left; "/ /></div></p>
<p>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>přednášející</strong><br />Petr "Sirien" Mazák<br />

</div>
</p>
<p style = "clear: both;">
  Všichni znáte DrD, valná většina z vás DrD+, pár z vás slyšelo o Shadowrunu, DnD, Hrdinech fantasy a World of Darkness. Co ale InSpectres, Mountain witch, GURPS, FATE nebo Little fears? V této přednášce vám zkusím v krátkosti představit větší množství RPGček, s důrazem na sehnatelnost v češtině a na zájem a znalosti přítomných posluchačů.
  
</p>
<p>
  <ul>
    <h2>Netradiční prezentace her Jirasgames</h2><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/netradicni-prezentace-her-jirasgames.jpg" style = "float: left; "/ /></div></p>
<p>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>přednášející</strong><br />Jiří Mikoláš<br />

 </div>
</p>
<p style = "clear: both;">
  Netradiční prezentace her Jirasgames formou zábavného kvízu. Posluchačům budou nastíněny základní pravidla mých her. Kvízové otázky se budou týkat dalších pravidel těchto her. Vždy bude na výběr z několika možností. Cílem posluchačů bude správně odhadnout další pravidla, vycházející z logiky herního systému. Nemělo by to být těžké, některá pravidla se do hry hodí, jiná by byla nadbytečná nebo nesystémová. Kdo zodpoví nejvíce otázek správně, získá odměnu - společenskou hru od Jirasgames.
</p>
   <ul><h2>Odmeňte svojich hráčov!</h2><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/odmente-svojich-hracov.jpg" style = "float: left; "/ /></div></p>

<p>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>přednášející</strong><br />Michal "Lev" Širaň, Peter "Peekay" Kopáč<br />
</div>
</p>
<p style = "clear: both;">
  Pripravili ste dlhodobú hru, naštudovali pravidlá a na prvé sedenie vám prišli hráči - zatiaľ teda všetko ide podľa plánu. Tu sa však tá naozajstná práca iba začína. Ako ich navnaďovať, aby prišli na ďalšie a ďalšie sedenia? Ako zistiť, čo presne si od hry sľubujú? Na tejto prednáške si povieme niečo o spôsoboch odmeňovania hráčov - či už za herné alebo mimoherné výkony - ako aj o zisťovaní hráčskych preferencií a ďalšej práce s nimi.
</p>

<p>
  <ul><h2>Příběh, základ života</h2><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/pribeh--zaklad-zivota.gif" style = "float: left; "/ /></div></p>
<p>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>přednášející</strong><br />Pavel "Lischai" Gotthard<br />
</div>
</p>
<p style = "clear: both;">
  Je jedno, jestli se věnujete RPG, larpům, psaní povídek nebo balení ženských. Všechny tyhle činnosti jsou založeny na příbězích. Příběh totiž není jen historka – je to zobecněná zkušenost, pravda o světě. A umění dobře vytvářet a vyprávět příběhy se vám může hodit častěji, než si myslíte.</p>
  <p>Tato přednáška vám vysvětlí základní principy stavby příběhu a poskytne pár tipů, jak tohoto umění využít v rolových hrách i normálním životě.</p>
</p>

<p>
  <ul>
   <h2>Součastnost a budoucnost vydávání her</h2><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/soucasnost-a-budoucnost-vydavani-her.jpg" style = "float: left; "/ /></div></p>

<p>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>moderátor diskuze</strong><br />
 Petr "Jezevec" Pouchlý<br />
 <strong>diskutující</strong><br />
 Karel "Charles" Černín, Matouš "Erric" Ježek, Petr "Kreten" Murmak a Vláďa Chvátil<br />
</div>
</p>
<p style = "clear: both;">
  V této panelové diskusi se sejdou tvůrci a vydavatelé RPG a deskových her, aby pohovořili o jejich přístupu k navrhování a následnému vydávání her. Tématem také budou různé herní směry, kterými se stolní hry mohou ubírat v budoucnosti. Zajímá-li vás, o čem je vlastně vydávání her, nenechte si tuto diskusi ujít.
  </p>  
</p>
<p>
  <ul>
    <h2>Stories of the Empire</h2><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/stories-of-the-empire.jpg" style = "float: left; "/ /></div></p>
<p>

<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>přednášející</strong><br />Ecthelion^2<br />
</div>
</p>

<p style = "clear: both;">
  Přednáška o novém českém RPG, příbězích, které utváří a temném viktoriánském světě plném kouzel a tajemna. Přestože pára již roztočila kola průmyslové revoluce, Sídhe stále procházejí zemí, za nocí se hvozdy a údolími rozléhá vytí vlkodlačí smečky, duchové, kteří nenalezli pokoje, se vrací zpět mezi lidi a jejich příbytky, čarodějnice se připravují na sabat a magie volně proudí zemí.</p><p>
  Přednáška bude nejen o hře samotné, ale také o vývoji RPG her a tvorbě příběhů obecně. Koncept, tvorba hry od začátku do konce, nadšení i těžká práce při dokončování hry, design hry, systém, ilustrace, layout i grafika.
  
</p>
<p>
  <ul>
    <li>
      Více informací: <a href = "http://rpgforum.cz/forum/viewtopic.php?f=237&t=6630" onclick = "window.open(this.href,\'_blank\'); return false">http://rpgforum.cz/forum/viewtopic.php?f=237&t=6630</a>

    </li>
<h2>Střepy snů: Křest knihy</h2><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/strepy-snu--krest-knihy.jpg" style = "float: left; "/ /></div></p>
<p>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>přednášející</strong><br />Matouš "Erric" Ježek<br />
</div>
</p>
<p style = "clear: both;">
  Letos na GameConu vychází nová česká vyprávěcí RPG hra Střepy snů. Buďte u toho a přijďte s námi oslavit její vydání!</p>
  <p>Čeká vás představení knihy, letmý průlet vývojem, zábavné historky testerů a možná i něco navíc.
</p>
<p>

  <ul>
    <h2>Střepy snů: O vývoji</h2><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/strepy-snu-o-vyvoji.jpg" style = "float: left; "/ /></div></p>
<p>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>přednášející</strong><br />Matouš "Erric" Ježek<br />
</div>
</p>
<p style = "clear: both;">
  Zajímá vás, co to vlastně znamená vydat RPG hru v České republice? Přijďte si poslechnout, jak se vyvíjely Střepy snů a čím vším si musely projít. Pokud jste o Střepech snů náhodou ještě neslyšeli, jedná se o vyprávěcí RPG zaměřené na podporu dramatických příběhu a psychologický vývoj postav.<br />
  Přednáška bude o designu, testování, práci v týmu, shánění financí na vydání, marketingu ale hlavně o chuti a odhodlání přinést něco nového české RPG scéně. Sníte-li, že někdy vydáte vlastní hru, je to přednáška právě pro vás.
</p>
<p>

  <ul>
    <li>
      Více informací: <a href = "http://www.strepysnu.cz" onclick = "window.open(this.href,\'_blank\'); return false">www.strepysnu.cz</a>
    </li><h2>Taria: Svět příběhů, příběh světa</h2><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/taria-svet-pribehu-pribeh-sveta.jpg" style = "float: left; "/ /></div></p>
<p>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>přednášející</strong><br />Karel "Charles" Černín<br />

</div>
</p>
<p style = "clear: both;">
  Existuje něco otřepanějšího než "fantasy svět pro RPG"? Jak dlouhá je fronta klonů Dragonlance? Kolik zastydlé infantility ještě člověk snese bez újmy na zdraví? Uvedené otázky si musíte zodpovědět sami. Přednáška bude o něčem jiném. O reinterpretaci klišé a o loupání cibule. O hranicích mezi dějem a prostředím a o tom, jestli nějaké existují. O mesiášském komplexu a o významu symbolů. O vlcích v naší duši a o kruté dani za čarování. Vždycky můžete odejít. A nebo usnout... a snít.
</p>
<p>
  <ul>
    <li>

      Více informací: <a href = "http://taria.unas.cz/" onclick = "window.open(this.href,\'_blank\'); return false">taria.unas.cz</a>
    </li>
<h2>Tempo a obsah hry, stylizace scén</h2><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/tempo-a-obsah-hry---stylizace-scen.jpg" style = "float: left; "/ /></div></p>
<p>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>přednášející</strong><br />Petr "Sirien" Mazák<br />
</div>
</p>

<p style = "clear: both;">
  Přemýšleli jste někdy nad tím, jak se liší různé scény v RPG, a jak hru pojmout, aby byla právě o tom, o čem ji mít chcete? Jak dodat hře tempo ve chvíli, kdy potřebujete odehrát větší část příběhu, a naopak co udělat, aby se tempo zvolnilo, ale hra zůstala zábavná?
  
</p>
<p>
  <ul>
    <h2>Typologie příběhů</h2><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/typologie-pribehu.jpg" style = "float: left; "/ /></div></p>
<p>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>přednášející</strong><br />Petr "Sirien" Mazák<br />
</div>
</p>
<p style = "clear: both;">
  V této přednášce bude tématem rozdíl mezi hrami zaměřenými na postavy, svět a příběh a ukážu, jak s jednotlivými příběhy pracovat. Zkusím ukázat, že teoretická úvaha může mít docela dobrý dopad i na praktickou podobu vaší hry.
  
</p>
<p>
  <ul>
    <h2>Zahraniční larpové hity</h2><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/zahranicni-larpove-hity.jpg" style = "float: left; "/ /></div></p>
<p>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>přednášející</strong><br />Petr "Jezevec" Pouchlý<br />
</div>
</p>
<p style = "clear: both;">

  Larpy jsou oblíbené po celém světě. Jsou země, kde vypadají larpy podobně jako u nás, stejně jako jsou země, kde jsou larpy jiné. Přijďte se dozvědět něco málo o tom, jaké jsou larpy v zahraničí či načerpat inspiraci pro vaše vlastní hry. Přednáška bude prokládána videozáznamy a zaměří se především na hry za poslední rok.  
</p>

    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (272,'Archiv přednášek na GameConu 2009','Archiv přednášek na GameConu 2009 Altar plánuje přednášející Altar Chcete zjistit o čem která hra je? Nevíte jak si vybrat dobrou hru? Chcete zjistit, co pro vás Altar plánuje? Pak přijďte na přednášku Altaru o jeho hrách. Na této přednášce vám lidé z Altaru představí v kostce o čem které hry jsou a mohou vám tak pomoci s výběrem nové hry, kterou byste si třeba chtěli pořídit ale nevíte si rady. A v neposlední řadě se také můžete dozvědět, co Altar dále plánuje a s jakými novými hrami chce přijít. Alternativní storytelling a roleplaying přednášející Petr "Sirien" Mazák V této přednášce budu mluvit především o různých méně častých, nezvyklých nebo rovnou alternativních způsobech hraní nebo vedení hry. Pár z nich jsou spíše zajímavostmi, jiné dávají hře specifický ráz, ale některé z nich jsou praktickými pomůckami pro každého hráče i vypravěče. Asterion – Hranice fantazie přednášející David "Seth" Rozsíval Kam až může tvůrce herního světa zajít, aniž by jeho šílené nápady nemátly zbytečně hráče? Jak najít cestu od ubíjejícího stereotypu prostředí fantasy středověku? Jak moc může být takový tvůrce šílený, aniž by z toho zešílel hráč? Asterionská přednáška se pokusí odpovědět na některé z těchto otázek, zároveň seznámí čtenáře s tím, co mohou od Asterionu do budoucna očekávat. Balení na conech přednášející Petr "Jezevec" Pouchlý Ač to vypadá snadně, tak balení je celá věda. Výsledek může být uspokojující, překvapivý, užitečný, úsporný či naopak úplně katastrofální. Někdo balit umí a někdo ne. Čeká vás krátký zábavný exkurz do technik balení, zaměřený především na balení na conech. Budoucnost GameConu přednášející Petr "Gandalf" Holub Zajímá vás jaké organizační změny se na GameConu letos udály? Zajímá vás jak chceme, aby GameCon vypadal a kam ho chceme směřovat? Chtěli byste se s námi podělit o své nápady a pomoci s plánováním budoucnosti GameConu? Přednáška o budoucnosti GameConu bude spíše diskuzí s vámi. Pokud vás to bude zajímat, prozradíme vám jaké změny se udály a proč. Můžeme taky nakouknout do minulosti, protože s ní to všechno souvisí. A hlavně se budeme bavit o tom co by se mělo dít dál. GameCon děláme pro vás, takže budeme rádi, když nám přijdete říct, co si o něm myslíte, ať už je to dobré nebo špatné. Obojí nám pomůže GameCon dále zlepšovat. A pokud máte pocit, že byste se rádi do organizace GameConu zapojili i více než jen radou, přijďte určitě – rádi si s vámi o tom promluvíme. Drakkar - internetový časopis přednášející Roman "RomiK" Hora, Jakub "boubaque" Maruš Drakkar je již zavedený internetový časopis. Funguje dva roky a stále může získávat více a více čtenářů, proto my, jakožto redakce nikdy neopomineme ani jedinou příležitost k prezentaci a klidně i opakování již řečeného. Na této krátké přednášce o otevřeném projektu internetového časopisu "Drakkar" budete seznámeni s počátky, novou koncepcí čísel, možností připojit se i dalším plánům do budoucna. Dungeons and Dragons 4E přednášející David "Conlai" Klimeček Dobrodruhové! Mocní válečníci, stateční rytíři, učení mágové a prohnaní zloději, vydejte se se mnou na cestu za dobrodružstvím a bohatstvím! Dungeons and Dragons je hra s více než třicetiletou tradicí. Během této doby prošla dlouhým vývojem až k současné čtvrté edici. Tématem hry ale stále zůstává dobrodružná cesta skupiny hrdinů za slávou a bohatstvím, cesta, která je lemována nebezpečím v podobě příšer a pastí. Výrazným prvkem čtvrté edice DnD je také propracovaný taktický bojový systém využívající miniatury a čtvercovou mapu. Více informací: rpgforum.cz/anotace/dungeons-and-dragons-4th-edition Engel d20 přednášející Dalibor "Dalcor" Zeman Europa, Anno Domini 2654. Vítejte v postapokalyptické budoucnosti naší Země. Lidstvo uvržené do nové doby temna je na pokraji vyhlazení. Andělská církev se snaží zastavit technologický pokrok i armády Pána much, které ohrožují samotnou existenci Stvoření. Starší temné RPG, postavené na d20 systému, je založené především na hutné atmosféře bezútěšného světa a vnitřních pohnutkách titulních postav, u kterých není vše tak božské, jak by se na první pohled mohlo zdát. Hlavní role pro vás přednášející Petr "Jezevec" Pouchlý Příběhy, který skutečně prožijete. Ne jen od stolu nebo ze sedačky, ale na vlastní kůži. Některé larpy mohou být mnohem víc, než čekáte. Přijďte si o nich poslechnout. Ať už je pro vás larp novým pojmem nebo jste zkušený hráč, nenechte si ujít tuhle přednášku. Pro každého z vás zde bude něco. Pokud si nejste jistí tím, co larp je, zde se to dozvíte. A pokud jste si jisti, třeba vás něčím překvapíme. Uvidíte fotky a videa z nejzajímavějších larpových her, které se v Česku konaly a uslyšíte ty nejčerstvější informace o projektech, na které se můžete těšit. Improvizované hraní RPG přednášející Jiří "Markus" Petrů Také vás baví dělat vypravěče? A také nesnášíte přípravu na hru? Dlouhé hodiny strávené nad psaním poznámek, tvorbou cizích postav a vymýšlením zápletek... jen abyste při hře zjistili, že z toho polovinu stejně nevyužijete? Tak to nedělejte! Pokud hraní RPG přestává být uvolněnou zábavou a stává se domácím úkolem, něco je špatně. Pojďme si povědět, jak hrát improvizovaně - s minimální přípravou, nebo zcela bez přípravy. Jde to! A možná zjistíte, že jste po dlouhé době opět nalezli tu jiskru bezprostřední radosti, která se v poslední době začala z vašich her vytrácet. Kalevala v RPG a fantasy přednášející Michala Merglová Zajímaly váš příběhy dávných severských národů? Kde čerpal Tolkien svoji inspiraci? Chcete vědět jak se liší dávný finský hrdina Kullervo od Túrina Turambara? Přednáška zaměřena na povídání o finské Kalevale, jejích odkazech a o tom jak ovlivnila Středozem. Povídání zaměřeno i na využití Kalevaly jako inspirace pro hraní RPG s důrazem na tvoření příběhu dle jejích mýtů a na tvoření pozadí postav dle hrdinů Kalevaly. Komorní larp - RPG bez kostek přednášející Petr "Jezevec" Pouchlý Hry v roli jsou naším společným hobby. Někdo je hraje u stolu, jiný v lese a další na kosmické lodi. Princip je stejný, jen přístup rozdílný. Co mají společného komorní larpy a klasické rolové hry? Stojí za vyzkoušení nebo je jen jeden směr, jak k hraní přistoupit? Nahradí jednou larpy klasické stolní RPG? Moderní deskové hry - Albi, CGE přednášející Albi, Czech Games Edition Chcete zjistit o čem která hra je? Nevíte jak si vybrat dobrou hru? Chcete zjistit, co pro vás Albi a Czech Games Edition plánují? Pak přijďte na přednášku o jejich hrách. Na této přednášce vám lidé z Albi a Czech Games Edition představí v kostce o čem které hry jsou a mohou vám tak pomoci s výběrem nové hry, kterou byste si třeba chtěli pořídit ale nevíte si rady. A v neposlední řadě se také můžete dozvědět, co Albi a CGE dále plánují a s jakými novými hrami chtějí přijít. Moderní deskové hry - Corfix přednášející Corfix Chcete zjistit o čem která hra je? Nevíte jak si vybrat dobrou hru? Chcete zjistit, co pro vás Corfix plánuje? Pak přijďte na přednášku Corfixu o jejich hrách. Na této přednášce vám lidé z Corfixu představí v kostce o čem které hry jsou a mohou vám tak pomoci s výběrem nové hry, kterou byste si třeba chtěli pořídit ale nevíte si rady. A v neposlední řadě se také můžete dozvědět, co Corfix dále plánuje a s jakými novými hrami chce přijít. Napříč spektrem RPG přednášející Petr "Sirien" Mazák Všichni znáte DrD, valná většina z vás DrD+, pár z vás slyšelo o Shadowrunu, DnD, Hrdinech fantasy a World of Darkness. Co ale InSpectres, Mountain witch, GURPS, FATE nebo Little fears? V této přednášce vám zkusím v krátkosti představit větší množství RPGček, s důrazem na sehnatelnost v češtině a na zájem a znalosti přítomných posluchačů. Netradiční prezentace her Jirasgames přednášející Jiří Mikoláš Netradiční prezentace her Jirasgames formou zábavného kvízu. Posluchačům budou nastíněny základní pravidla mých her. Kvízové otázky se budou týkat dalších pravidel těchto her. Vždy bude na výběr z několika možností. Cílem posluchačů bude správně odhadnout další pravidla, vycházející z logiky herního systému. Nemělo by to být těžké, některá pravidla se do hry hodí, jiná by byla nadbytečná nebo nesystémová. Kdo zodpoví nejvíce otázek správně, získá odměnu - společenskou hru od Jirasgames. Odmeňte svojich hráčov! přednášející Michal "Lev" Širaň, Peter "Peekay" Kopáč Pripravili ste dlhodobú hru, naštudovali pravidlá a na prvé sedenie vám prišli hráči - zatiaľ teda všetko ide podľa plánu. Tu sa však tá naozajstná práca iba začína. Ako ich navnaďovať, aby prišli na ďalšie a ďalšie sedenia? Ako zistiť, čo presne si od hry sľubujú? Na tejto prednáške si povieme niečo o spôsoboch odmeňovania hráčov - či už za herné alebo mimoherné výkony - ako aj o zisťovaní hráčskych preferencií a ďalšej práce s nimi. Příběh, základ života přednášející Pavel "Lischai" Gotthard Je jedno, jestli se věnujete RPG, larpům, psaní povídek nebo balení ženských. Všechny tyhle činnosti jsou založeny na příbězích. Příběh totiž není jen historka – je to zobecněná zkušenost, pravda o světě. A umění dobře vytvářet a vyprávět příběhy se vám může hodit častěji, než si myslíte. Tato přednáška vám vysvětlí základní principy stavby příběhu a poskytne pár tipů, jak tohoto umění využít v rolových hrách i normálním životě. Součastnost a budoucnost vydávání her moderátor diskuze Petr "Jezevec" Pouchlý diskutující Karel "Charles" Černín, Matouš "Erric" Ježek, Petr "Kreten" Murmak a Vláďa Chvátil V této panelové diskusi se sejdou tvůrci a vydavatelé RPG a deskových her, aby pohovořili o jejich přístupu k navrhování a následnému vydávání her. Tématem také budou různé herní směry, kterými se stolní hry mohou ubírat v budoucnosti. Zajímá-li vás, o čem je vlastně vydávání her, nenechte si tuto diskusi ujít. Stories of the Empire přednášející Ecthelion^2 Přednáška o novém českém RPG, příbězích, které utváří a temném viktoriánském světě plném kouzel a tajemna. Přestože pára již roztočila kola průmyslové revoluce, Sídhe stále procházejí zemí, za nocí se hvozdy a údolími rozléhá vytí vlkodlačí smečky, duchové, kteří nenalezli pokoje, se vrací zpět mezi lidi a jejich příbytky, čarodějnice se připravují na sabat a magie volně proudí zemí. Přednáška bude nejen o hře samotné, ale také o vývoji RPG her a tvorbě příběhů obecně. Koncept, tvorba hry od začátku do konce, nadšení i těžká práce při dokončování hry, design hry, systém, ilustrace, layout i grafika. Více informací: http://rpgforum.cz/forum/viewtopic.php?f=237&t=6630 Střepy snů: Křest knihy přednášející Matouš "Erric" Ježek Letos na GameConu vychází nová česká vyprávěcí RPG hra Střepy snů. Buďte u toho a přijďte s námi oslavit její vydání! Čeká vás představení knihy, letmý průlet vývojem, zábavné historky testerů a možná i něco navíc. Střepy snů: O vývoji přednášející Matouš "Erric" Ježek Zajímá vás, co to vlastně znamená vydat RPG hru v České republice? Přijďte si poslechnout, jak se vyvíjely Střepy snů a čím vším si musely projít. Pokud jste o Střepech snů náhodou ještě neslyšeli, jedná se o vyprávěcí RPG zaměřené na podporu dramatických příběhu a psychologický vývoj postav. Přednáška bude o designu, testování, práci v týmu, shánění financí na vydání, marketingu ale hlavně o chuti a odhodlání přinést něco nového české RPG scéně. Sníte-li, že někdy vydáte vlastní hru, je to přednáška právě pro vás. Více informací: www.strepysnu.cz Taria: Svět příběhů, příběh světa přednášející Karel "Charles" Černín Existuje něco otřepanějšího než "fantasy svět pro RPG"? Jak dlouhá je fronta klonů Dragonlance? Kolik zastydlé infantility ještě člověk snese bez újmy na zdraví? Uvedené otázky si musíte zodpovědět sami. Přednáška bude o něčem jiném. O reinterpretaci klišé a o loupání cibule. O hranicích mezi dějem a prostředím a o tom, jestli nějaké existují. O mesiášském komplexu a o významu symbolů. O vlcích v naší duši a o kruté dani za čarování. Vždycky můžete odejít. A nebo usnout... a snít. Více informací: taria.unas.cz Tempo a obsah hry, stylizace scén přednášející Petr "Sirien" Mazák Přemýšleli jste někdy nad tím, jak se liší různé scény v RPG, a jak hru pojmout, aby byla právě o tom, o čem ji mít chcete? Jak dodat hře tempo ve chvíli, kdy potřebujete odehrát větší část příběhu, a naopak co udělat, aby se tempo zvolnilo, ale hra zůstala zábavná? Typologie příběhů přednášející Petr "Sirien" Mazák V této přednášce bude tématem rozdíl mezi hrami zaměřenými na postavy, svět a příběh a ukážu, jak s jednotlivými příběhy pracovat. Zkusím ukázat, že teoretická úvaha může mít docela dobrý dopad i na praktickou podobu vaší hry. Zahraniční larpové hity přednášející Petr "Jezevec" Pouchlý Larpy jsou oblíbené po celém světě. Jsou země, kde vypadají larpy podobně jako u nás, stejně jako jsou země, kde jsou larpy jiné. Přijďte se dozvědět něco málo o tom, jaké jsou larpy v zahraničí či načerpat inspiraci pro vaše vlastní hry. Přednáška bude prokládána videozáznamy a zaměří se především na hry za poslední rok.');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (273,'Situace a budoucnost RPG v ČR a SR','situace-a-budoucnost-rpg-v-cr-a-sr',40,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (273,'prednasky/situace-a-budoucnost-rpg-v-cr-a-sr');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (273,'Situace a budoucnost RPG v ČR a SR — GameCon 2011','gamecon,2011','Situace a budoucnost RPG v ČR a SR');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (273,'kapacita 19/0<br />
<h1>Situace a budoucnost RPG v ČR a SR</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/situace-a-budoucnost-rpg-v-cr-a-sr.gif" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>přednášející</strong><br />Jakub "boubaque" Maruš<br />
  <strong>čas akce</strong><br />neděle 24.7 - 13:00 až 14:00  <br />
 <strong>další akce organizátora</strong> <br /><div style = "text-align: left;"><a href = "/rpg/drdii---navrat-do-bileho-hradu">DrDII - Návrat do Bílého hradu</a>, <a href = "/rpg/prime-time-adventures">Prime Time Adventures</a></div>
</div>
</p>
   <p style = "clear: both;">
Jak na tom jsme, kam směřujeme a co pro RPG v našich krajích může každý z nás do budoucna udělat? Co nás možná a nejspíš čeká a proč? O všem co tu máme, o nových vlnách blížících se ze Západu i o osudu naší scény. Moderovaná diskuse
</p>
      <!--<li>
        <a href = "/prednasky/seznam-prednasek-na-gc2010">Přehled všech přednášek na GameConu 2010</a>      </li>-->
    </ul>
  </p>
  <div style = "width: 100%; float: left;">
    <div style = "width: 50%; text-align: left; float: left; padding-top: 20px; padding-bottom: 15px;">&laquo; <a href = "/prednasky/priprava-hry-a-hracska-invence">Příprava hry a hráčská invence</a></div>    <div style = "width: 50%; text-align: right; float: right; padding-top: 20px; padding-bottom: 15px;"><a href = "/prednasky/stavba-pribehudetektivky-a-konspirace">Stavba příběhu+detektivky a konspirace</a> &raquo;</div>  </div>
  
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (273,'Situace a budoucnost RPG v ČR a SR','kapacita 19/0 Situace a budoucnost RPG v ČR a SR přednášející Jakub "boubaque" Maruš čas akce neděle 24.7 - 13:00 až 14:00 další akce organizátora DrDII - Návrat do Bílého hradu , Prime Time Adventures Jak na tom jsme, kam směřujeme a co pro RPG v našich krajích může každý z nás do budoucna udělat? Co nás možná a nejspíš čeká a proč? O všem co tu máme, o nových vlnách blížících se ze Západu i o osudu naší scény. Moderovaná diskuse Přehled všech přednášek na GameConu 2010 --> « Příprava hry a hráčská invence Stavba příběhu+detektivky a konspirace »');

