INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (284,'Cold City: 1950','cold-city-1950',37,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (284,'rpg/cold-city-1950');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (284,'Cold City: 1950 — GameCon 2011','gamecon,2011','Cold City: 1950');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (284,'<h1>Cold City: 1950</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/cold-city-1950.gif" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>vypravěč</strong><br />David "Conlai" Klimeček<br />
  <strong>čas akce</strong><br />pátek 16.7 - 19:00 až 23:00  <br />sobota 17.7 - 14:00 až 18:00  <br />
 <strong>další akce organizátora</strong> <br /><div style = "text-align: left;"><a href = "/rpg/mouse-guard-2010">Mouse Guard (2010)</a></div>
</div>
</p>
   <p style = "clear: both;">
Berlín, rok 1950. Druhá světová válka skončila před pěti lety. Nyní ale ve stínech probíhá další, tajná válka. Zapoj se do boje o pokřivené technologie, děsivé výsledky nacistických výzkumů. Staň se členem mezinárodní jednotky, která má za úkol nacházet tyto technologie a zahlazovat stopy jejich existence. Pokus se zjistit, komu můžeš věřit. Chraň zájmy své země. A hlavně se neztrať v labyrintu spiknutí a zrady.
</p>

<p>
<ul>
<li>Více informací: <a href = "http://rpgforum.cz/anotace/cold-city" onclick = "window.open(this.href,\'_blank\'); return false">rpgforum.cz/anotace/cold-city</a></li>

                              <!--<li>
        <a href = "/rpg/seznam-rpg-na-gc2010">Přehled všech RPG na GameConu 2010</a>      </li>-->
    </ul>
  </p>
  <div style = "width: 100%; float: left;">
    <div style = "width: 50%; text-align: left; float: left; padding-top: 20px; padding-bottom: 15px;">&laquo; <a href = "/rpg/capes-new-york-superheroes">Capes: New York Superheroes</a></div>    <div style = "width: 50%; text-align: right; float: right; padding-top: 20px; padding-bottom: 15px;"><a href = "/rpg/draci-doupe-plus-vinobrani">Dračí doupě Plus: Vinobraní</a> &raquo;</div>  </div>
  
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (284,'Cold City: 1950','Cold City: 1950 vypravěč David "Conlai" Klimeček čas akce pátek 16.7 - 19:00 až 23:00 sobota 17.7 - 14:00 až 18:00 další akce organizátora Mouse Guard (2010) Berlín, rok 1950. Druhá světová válka skončila před pěti lety. Nyní ale ve stínech probíhá další, tajná válka. Zapoj se do boje o pokřivené technologie, děsivé výsledky nacistických výzkumů. Staň se členem mezinárodní jednotky, která má za úkol nacházet tyto technologie a zahlazovat stopy jejich existence. Pokus se zjistit, komu můžeš věřit. Chraň zájmy své země. A hlavně se neztrať v labyrintu spiknutí a zrady. Více informací: rpgforum.cz/anotace/cold-city Přehled všech RPG na GameConu 2010 --> « Capes: New York Superheroes Dračí doupě Plus: Vinobraní »');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (285,'Dlouhá hlídka','dlouha-hlidka',37,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (285,'rpg/dlouha-hlidka');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (285,'Dlouhá hlídka — GameCon 2011','gamecon,2011','Dlouhá hlídka');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (285,'kapacita 5/5<br />
<h1>Dlouhá hlídka</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/dlouha-hlidka.gif" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>vypravěč</strong><br />Petr Svarný<br />
  <strong>čas akce</strong><br />pátek 22.7 - 19:00 až 23:00  <br />
 <strong>další akce organizátora</strong> <br /><div style = "text-align: left;"><a href = "/rpg/wargames">Wargames</a>, <a href = "/rpg/ruda-planeta">Rudá planeta</a>, <a href = "/rpg/strepicka">Strepicka</a>, <a href = "/rpg/volna-hra">Volná hra</a></div>
</div>
</p>
   <p style = "clear: both;">
Hory Afghanistánu skrývají mnohé krásy a avšak i mnohé nástrahy. S obojím bude mít možnost se seznámit skupinka průzkumníků z 601. skupiny. Dobytí země bylo snem mnoha vládců, avšak nyní se snažíme vybudovat novou zemi z trosek a střepů skoro nekonečného válčení.
</p>
<p>
Podaří se o tom obyvatele přesvědčit? Či alespoň se zdárně vrátit z akce? Vyzkoušej si další příběh využívající herní systém Střepů snů.
              <!--<li>
        <a href = "/rpg/seznam-rpg-na-gc2010">Přehled všech RPG na GameConu 2010</a>      </li>-->
    </ul>
  </p>
  <div style = "width: 100%; float: left;">
        <div style = "width: 50%; text-align: right; float: right; padding-top: 20px; padding-bottom: 15px;"><a href = "/rpg/dnd-4e">DnD 4E</a> &raquo;</div>  </div>
  
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (285,'Dlouhá hlídka','kapacita 5/5 Dlouhá hlídka vypravěč Petr Svarný čas akce pátek 22.7 - 19:00 až 23:00 další akce organizátora Wargames , Rudá planeta , Strepicka , Volná hra Hory Afghanistánu skrývají mnohé krásy a avšak i mnohé nástrahy. S obojím bude mít možnost se seznámit skupinka průzkumníků z 601. skupiny. Dobytí země bylo snem mnoha vládců, avšak nyní se snažíme vybudovat novou zemi z trosek a střepů skoro nekonečného válčení. Podaří se o tom obyvatele přesvědčit? Či alespoň se zdárně vrátit z akce? Vyzkoušej si další příběh využívající herní systém Střepů snů. Přehled všech RPG na GameConu 2010 --> DnD 4E »');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (286,'DnD 4E +','dnd-4e-',37,0,0);
