INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (286,'DnD 4E + — GameCon 2011','gamecon,2011','DnD 4E +');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (286,'kapacita 5/5<br />
<h1>DnD 4E +</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/dnd-4e-.gif" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>vypravěč</strong><br />Karol Magda<br />
  <strong>čas akce</strong><br />sobota 23.7 - 14:00 až 18:00  <br />
 <strong>další akce organizátora</strong> <br /><div style = "text-align: left;"><a href = "/rpg/dnd-4e">DnD 4E</a></div>
</div>
</p>
   <p style = "clear: both;">
DnD 4E je hrou, kterou asi není potřeba představovat. Pro ty, kdo o DnD nikdy neslyšeli, jde o klasickou hrdinskoku fantasy. DnD 4e ocení především příznivci taktických bojů na čtvercové mapě, vyváženého systému a postupného zlepšování schopností postav.
</p>
<p>
Tato herní seance je určená pro hráče, kteří DnD 4E už znají, ale zatím neměli možnost si vyzkoušet hru se zkušenějšími postavami. V tomto příběhu budou postavy na dvanácté úrovni. Díky tomu si můžeš užít zábavu při hraní skutečného hrdiny. 
</p>
<p>
              <!--<li>
        <a href = "/rpg/seznam-rpg-na-gc2010">Přehled všech RPG na GameConu 2010</a>      </li>-->
    </ul>
  </p>
  <div style = "width: 100%; float: left;">
    <div style = "width: 50%; text-align: left; float: left; padding-top: 20px; padding-bottom: 15px;">&laquo; <a href = "/rpg/dnd-4e">DnD 4E</a></div>    <div style = "width: 50%; text-align: right; float: right; padding-top: 20px; padding-bottom: 15px;"><a href = "/rpg/dogs-in-the-vineyard">Dogs in the Vineyard</a> &raquo;</div>  </div>
  
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (286,'DnD 4E +','kapacita 5/5 DnD 4E + vypravěč Karol Magda čas akce sobota 23.7 - 14:00 až 18:00 další akce organizátora DnD 4E DnD 4E je hrou, kterou asi není potřeba představovat. Pro ty, kdo o DnD nikdy neslyšeli, jde o klasickou hrdinskoku fantasy. DnD 4e ocení především příznivci taktických bojů na čtvercové mapě, vyváženého systému a postupného zlepšování schopností postav. Tato herní seance je určená pro hráče, kteří DnD 4E už znají, ale zatím neměli možnost si vyzkoušet hru se zkušenějšími postavami. V tomto příběhu budou postavy na dvanácté úrovni. Díky tomu si můžeš užít zábavu při hraní skutečného hrdiny. Přehled všech RPG na GameConu 2010 --> « DnD 4E Dogs in the Vineyard »');

