INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (288,'Dogs in the Vineyard','dogs-in-the-vineyard',37,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (288,'rpg/dogs-in-the-vineyard');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (288,'Dogs in the Vineyard — GameCon 2011','gamecon,2011','Dogs in the Vineyard');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (288,'kapacita 5/5<br />
<h1>Dogs in the Vineyard</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/dogs-in-the-vineyard.jpg" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>vypravěč</strong><br />Jiří "Markus" Petrů<br />
  <strong>čas akce</strong><br />sobota 23.7 - 8:00 až 12:00  <br />
 <strong>další akce organizátora</strong> <br /><div style = "text-align: left;"><a href = "/rpg/mouse-guard-">Mouse Guard </a></div>
</div>
</p>
   <p style = "clear: both;">
Jen vy stojíte mezi Božím řádem a pokušením slabých.
Jen vy stojíte mezi Věřícími a ďáblovými úklady.
Někdy je nutné uříznout nemocnou větev, aby přežil celý strom.
Někdy je nutné useknout ruku, aby přežilo tělo.
Zaslouží hříšníci slitování?
Jsou jen ve vašich rukou.
</p>
<p>
Není tomu tak dávno, co se skupinky puritánských věřících rozhodly utéct daleko od zkaženosti velkoměst a založit utopickou společnost hluboko v divočině. Chvíli to i fungovalo. Ale ďábel je všudypřítomný a pokouší i nevinné. Hřích se připlížil za patami Věřících a přinesl s sebou pýchu, křivdu, bezpráví a utrpení. A tak vznikli Ohaři... je vám sedmnáct, možná osmnáct let. Starší si vás vybrali a dali vám stručný, dvouměsíční výcvik ve zbrani a teologii. Nafasofali jste koně, kvér a modlitební knihu. Teď vyjeďte do světa a potírejte hřích.
</p>
<p>
Dogs in the Vineyard je westernová hra na fanatické obránce dobra, kteří disponují absolutní mocí. Budete soudit hříšné a jediným arbitrem vám bude vlastní svědomí - kéž by to však bylo snadné. Svět není zdaleka tak černobílý, jak se praví ve svatých knihách.
</p>
<p>
Vítáme hráče se zájmem o tématiku dobra, zla, morálky a víry. 
</p>
<p>
<ul>


<li>Více informací: <a href = "http://rpgforum.cz/anotace/dogs-vineyard" onclick = "window.open(this.href,\'_blank\'); return false">http://rpgforum.cz/anotace/dogs-vineyard</a></li>

                                                          <!--<li>
        <a href = "/rpg/seznam-rpg-na-gc2010">Přehled všech RPG na GameConu 2010</a>      </li>-->
    </ul>
  </p>
  <div style = "width: 100%; float: left;">
    <div style = "width: 50%; text-align: left; float: left; padding-top: 20px; padding-bottom: 15px;">&laquo; <a href = "/rpg/dnd-4e-">DnD 4E +</a></div>    <div style = "width: 50%; text-align: right; float: right; padding-top: 20px; padding-bottom: 15px;"><a href = "/rpg/drd-ii---nezbedna-manzelka">DrD II - Nezbedná manželka</a> &raquo;</div>  </div>
  
    </div>
  </div>');
