INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (297,'Lady Blackbird','lady-blackbird',37,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (297,'rpg/lady-blackbird');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (297,'Lady Blackbird — GameCon 2011','gamecon,2011','Lady Blackbird');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (297,'kapacita 5/5<br />
<h1>Lady Blackbird</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/lady-blackbird.gif" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>vypravěč</strong><br />Jakub "Dukolm" Červený<br />
  <strong>čas akce</strong><br />pátek 22.7 - 14:00 až 18:00  <br />
 <strong>další akce organizátora</strong> <br /><div style = "text-align: left;"><a href = "/rpg/wernion">Wernion</a>, <a href = "/rpg/sustot-kridel-a-stranek">Šustot křídel a stránek</a></div>
</div>
</p>
   <p style = "clear: both;">
Lady Blackbird utekla před domluvenou svatbou s hrabětem. Najala si pašeráckou loď Sovička, na které utíká za svojí tajnou láskou Uriahem Flintem. V půli cesty je Sovička pro následována a polapena imperiálním křižníkem a obviněna z letu pod falešnou vlajkou. Celá posádka se nachází v žaláři.
</p>
<p>
Jak utečou z lodi smutku? Co je čeká cestou? Dosáhne svého cíle? A když jo bude na konci své cesty spokojená nebo přijde na to, že to co hledala už dávno má?
</p>
<p>
Přijď si zahrát příběh kombinujících romantiku Hvězdných válek s pulpovými dobrodružstvími. Velkou výhodou jsou předpřipravené postavy a jednoduchý herní systémem v duchu Solar Systému.                      <!--<li>
        <a href = "/rpg/seznam-rpg-na-gc2010">Přehled všech RPG na GameConu 2010</a>      </li>-->
    </ul>
  </p>
  <div style = "width: 100%; float: left;">
    <div style = "width: 50%; text-align: left; float: left; padding-top: 20px; padding-bottom: 15px;">&laquo; <a href = "/rpg/inspectres">InSpectres</a></div>    <div style = "width: 50%; text-align: right; float: right; padding-top: 20px; padding-bottom: 15px;"><a href = "/rpg/mage-the-awakecension-">Mage: the Awakecension </a> &raquo;</div>  </div>
  
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (297,'Lady Blackbird','kapacita 5/5 Lady Blackbird vypravěč Jakub "Dukolm" Červený čas akce pátek 22.7 - 14:00 až 18:00 další akce organizátora Wernion , Šustot křídel a stránek Lady Blackbird utekla před domluvenou svatbou s hrabětem. Najala si pašeráckou loď Sovička, na které utíká za svojí tajnou láskou Uriahem Flintem. V půli cesty je Sovička pro následována a polapena imperiálním křižníkem a obviněna z letu pod falešnou vlajkou. Celá posádka se nachází v žaláři. Jak utečou z lodi smutku? Co je čeká cestou? Dosáhne svého cíle? A když jo bude na konci své cesty spokojená nebo přijde na to, že to co hledala už dávno má? Přijď si zahrát příběh kombinujících romantiku Hvězdných válek s pulpovými dobrodružstvími. Velkou výhodou jsou předpřipravené postavy a jednoduchý herní systémem v duchu Solar Systému. Přehled všech RPG na GameConu 2010 --> « InSpectres Mage: the Awakecension »');

