INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (299,'Mouse Guard','mouse-guard-',37,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (299,'rpg/mouse-guard-');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (299,'Mouse Guard — GameCon 2011','gamecon,2011','Mouse Guard');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (299,'kapacita 5/5<br />kapacita 5/5<br />
<h1>Mouse Guard </h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/mouse-guard-.gif" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>vypravěč</strong><br />Jiří "Markus" Petrů<br />
  <strong>čas akce</strong><br />čtvrtek 21.7 - 20:00 až 24:00  <br />pátek 22.7 - 14:00 až 18:00  <br />
 <strong>další akce organizátora</strong> <br /><div style = "text-align: left;"><a href = "/rpg/dogs-in-the-vineyard">Dogs in the Vineyard</a></div>
</div>
</p>
   <p style = "clear: both;">
V této hře se hráči mohou stát členy Myší stráže, elitního oddílu ochránců myší před nástrahami divočiny. Myši ve světě MG sice chodí po dvou, nosí pláště, žijí ve městech a používají nástroje, ale magii byste tu hledali marně. Draka potom hravě zastoupí o mnoho hrozivější liška.
</p>
<p>
Dobrodružství je jednou z misí, které postavám zadává velitelka Stráže. Jak už to ale bývá, jednoduché jsou vždy jen rozkazy, jejich vykonání vyžaduje odvahu, vynalézavost a hlavně srdce na pravém místě.
</p>
<p>
Zkoušeli jste například už někdy udržet na živu hlouček vyděšených a hladových myší, které během jediné strašlivé noci přišly o střechu nad hlavou a veškeré zásoby na zimu? Jsou opuštěné uprostřed zasněžené krajiny plné hladových dravců, když mrzne jako když praští a naděje na přežití je mizivá?
</p>
<p>
Pokud si chcete vyzkoušet trochu netradiční RPG, kde se to nehemží draky, mágy a alchymisty, tak Mouse Guard jsou hra právě pro vás.
</p>
<p><ul>
                              <!--<li>
        <a href = "/rpg/seznam-rpg-na-gc2010">Přehled všech RPG na GameConu 2010</a>      </li>-->
    </ul>
  </p>
  <div style = "width: 100%; float: left;">
    <div style = "width: 50%; text-align: left; float: left; padding-top: 20px; padding-bottom: 15px;">&laquo; <a href = "/rpg/mage-the-awakecension-">Mage: the Awakecension </a></div>    <div style = "width: 50%; text-align: right; float: right; padding-top: 20px; padding-bottom: 15px;"><a href = "/rpg/my-life-with-master">My Life with Master</a> &raquo;</div>  </div>
  
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (299,'Mouse Guard','kapacita 5/5 kapacita 5/5 Mouse Guard vypravěč Jiří "Markus" Petrů čas akce čtvrtek 21.7 - 20:00 až 24:00 pátek 22.7 - 14:00 až 18:00 další akce organizátora Dogs in the Vineyard V této hře se hráči mohou stát členy Myší stráže, elitního oddílu ochránců myší před nástrahami divočiny. Myši ve světě MG sice chodí po dvou, nosí pláště, žijí ve městech a používají nástroje, ale magii byste tu hledali marně. Draka potom hravě zastoupí o mnoho hrozivější liška. Dobrodružství je jednou z misí, které postavám zadává velitelka Stráže. Jak už to ale bývá, jednoduché jsou vždy jen rozkazy, jejich vykonání vyžaduje odvahu, vynalézavost a hlavně srdce na pravém místě. Zkoušeli jste například už někdy udržet na živu hlouček vyděšených a hladových myší, které během jediné strašlivé noci přišly o střechu nad hlavou a veškeré zásoby na zimu? Jsou opuštěné uprostřed zasněžené krajiny plné hladových dravců, když mrzne jako když praští a naděje na přežití je mizivá? Pokud si chcete vyzkoušet trochu netradiční RPG, kde se to nehemží draky, mágy a alchymisty, tak Mouse Guard jsou hra právě pro vás. Přehled všech RPG na GameConu 2010 --> « Mage: the Awakecension My Life with Master »');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (300,'My Life with Master','my-life-with-master',37,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (300,'rpg/my-life-with-master');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (300,'My Life with Master — GameCon 2011','gamecon,2011','My Life with Master');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (300,'kapacita 5/5<br />
<h1>My Life with Master</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/my-life-with-master.gif" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>vypravěč</strong><br />Adam Streck<br />
  <strong>čas akce</strong><br />pátek 22.7 - 19:00 až 23:00  <br />
 <strong>další akce organizátora</strong> <br /><div style = "text-align: left;"><a href = "/rpg/inspectres">InSpectres</a>, <a href = "/rpg/fate---bouchacky-pro-hitmana">Fate - Bouchačky pro Hitmana</a></div>
</div>
</p>
   <p style = "clear: both;">
My Life with Master je jednou z nejznámějších nezávislých her. Vypráví klasicky hororové příběhy o vnitřní rozpolcenosti služebníků, kteří slouží zlu, ale zároveň touží po lásce. Její netradiční herní styl pracuje s oddělenými scénami, emocemi a značnými vyprávěcími pravomocemi v rukách hráčů.
</p>
<p>
Jaké je to býti služebníkem zlého Pána? Váš Pán sedí na svém transylvánském hradě, nebo usrkává víno ve svém břečťaněm obrostlém sídle… a vy? Vy jste nebohá karikatura člověka, nuzný poskok, který plní všechna Jeho přání. Nikdo vás nemá rád. Ale vy přeci milujete, toužíte po lásce a přátelství a doufáte, že se jich někdy dočkáte. Najdete dostatek morální síly, abyste se dokázali vzepřít svému Pánu?
</p>
<p>
Chtěl jsi se někdy vcítit do hrdinů klasických hororových filmů? Tak tady máš vynikající možnost. Nenech si ji ujít!
</p>
<p><ul>
                      <!--<li>
        <a href = "/rpg/seznam-rpg-na-gc2010">Přehled všech RPG na GameConu 2010</a>      </li>-->
    </ul>
  </p>
  <div style = "width: 100%; float: left;">
    <div style = "width: 50%; text-align: left; float: left; padding-top: 20px; padding-bottom: 15px;">&laquo; <a href = "/rpg/mouse-guard-">Mouse Guard </a></div>    <div style = "width: 50%; text-align: right; float: right; padding-top: 20px; padding-bottom: 15px;"><a href = "/rpg/pendragon">Pendragon</a> &raquo;</div>  </div>
  
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (300,'My Life with Master','kapacita 5/5 My Life with Master vypravěč Adam Streck čas akce pátek 22.7 - 19:00 až 23:00 další akce organizátora InSpectres , Fate - Bouchačky pro Hitmana My Life with Master je jednou z nejznámějších nezávislých her. Vypráví klasicky hororové příběhy o vnitřní rozpolcenosti služebníků, kteří slouží zlu, ale zároveň touží po lásce. Její netradiční herní styl pracuje s oddělenými scénami, emocemi a značnými vyprávěcími pravomocemi v rukách hráčů. Jaké je to býti služebníkem zlého Pána? Váš Pán sedí na svém transylvánském hradě, nebo usrkává víno ve svém břečťaněm obrostlém sídle… a vy? Vy jste nebohá karikatura člověka, nuzný poskok, který plní všechna Jeho přání. Nikdo vás nemá rád. Ale vy přeci milujete, toužíte po lásce a přátelství a doufáte, že se jich někdy dočkáte. Najdete dostatek morální síly, abyste se dokázali vzepřít svému Pánu? Chtěl jsi se někdy vcítit do hrdinů klasických hororových filmů? Tak tady máš vynikající možnost. Nenech si ji ujít! Přehled všech RPG na GameConu 2010 --> « Mouse Guard Pendragon »');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (301,'O RPG na GameConu','o-rpg-na-gc',37,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (301,'rpg/o-rpg-na-gc');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (301,'O RPG na GameConu — GameCon 2011','gamecon,2011','O RPG na GameConu');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (301,'<h1>O RPG na GameConu</h1>
<p>Letošní rok se ponese především v duchu ukázkových her mnohými očekávaného nástupce stávajícího Dračího doupěte a Dračího doupěte Plus, tedy v duchu <strong>Dračího doupěte II</strong>. DrD II bude na GameConu křtěno a představeno světu, a proto pro vás bude v každém herním bloku připraveno alespoň jedno jeho ukázkové hraní.</p>
<p>Aby nebylo ukázkové hraní příliš monotematické, tak bude DrD II proloženo větším množstvím ostatních her, přičemž i ty, které budou nabídnuty vícekrát, se budou co možná nejvíce lišit &ndash; pojetím, prostředím, tématem. Těšit se tedy můžete na <strong>Střepy snů</strong> v různých prostředích, na <strong>Dungeons &amp; Dragons</strong> ve starém stylu, na <strong>Příběhy impéria</strong>, na perličky jako jsou <strong>InSpectres</strong> nebo <strong>My Life with Master</strong>, na klasické hry jako je <strong>GURPS</strong> nebo <strong>FATE</strong>, na staré <strong>Dračí doupě</strong>, <strong>Mágy ze Světa Temnoty</strong> nebo na moderní <strong>Dungeons &amp; Dragons</strong> čtvrté edice.</p>
<p>Různé hry budou letos orientovány různě &ndash; některé z nich budou určeny k seznámení se systémem nebo nezvyklým herním stylem, jiné budou orientovány především na různá herní prostředí a další budou určeny hlavně pro odlehčující pobavení</p>
<p>Rozhodně tedy neváhejte a přijďte si alespoň některé z nich zahrát!</p>

<!--<p>
Pro letošní rok se můžete těšit opět na velkou nálož volného hraní <a href = "/rpg/co-jsou-to-rpg-hry">RPG</a>. Naši vypravěči vám přinesou spoustu různých titulů, jak všedních, tak i takových, které si doma jen tak nezahrajete.
</p>
<p>
Objeví se známí velikáni jako Dungeons and Dragons 4E nebo GURPS, nové české hry Střepy snů a Příběhy impéria, které si budete moci dokonce zahrát i s jejich autory, a také řada netradičních zahraničních her jako oblíbený OG, Mouseguard, Pendragon nebo výjimečný My Life with Master. A to je jen zlomek toho, co vás na GC čeká. Spektrum her stále rozšiřujeme, aby byl program pro vás, co nejbohatší.
</p>
<p>
Pokud máte zkušenosti s vedením nějakého netradičního RPG a byli byste ochotní ji na GC přivést a zahrát s ostatními, obraťte se na na organizátora této sekce na <a href = "mailto:erric@email.cz">erric@email.cz</a>.
</p>

<ul> 
 <li> 
  <a href = "/rpg/seznam-rpg-na-gc2009">Podívejte se, jaká RPG se hrála minulý rok.</a>
 </li>
</ul>-->
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (301,'O RPG na GameConu','O RPG na GameConu Letošní rok se ponese především v duchu ukázkových her mnohými očekávaného nástupce stávajícího Dračího doupěte a Dračího doupěte Plus, tedy v duchu Dračího doupěte II . DrD II bude na GameConu křtěno a představeno světu, a proto pro vás bude v každém herním bloku připraveno alespoň jedno jeho ukázkové hraní. Aby nebylo ukázkové hraní příliš monotematické, tak bude DrD II proloženo větším množstvím ostatních her, přičemž i ty, které budou nabídnuty vícekrát, se budou co možná nejvíce lišit – pojetím, prostředím, tématem. Těšit se tedy můžete na Střepy snů v různých prostředích, na Dungeons & Dragons ve starém stylu, na Příběhy impéria , na perličky jako jsou InSpectres nebo My Life with Master , na klasické hry jako je GURPS nebo FATE , na staré Dračí doupě , Mágy ze Světa Temnoty nebo na moderní Dungeons & Dragons čtvrté edice. Různé hry budou letos orientovány různě – některé z nich budou určeny k seznámení se systémem nebo nezvyklým herním stylem, jiné budou orientovány především na různá herní prostředí a další budou určeny hlavně pro odlehčující pobavení Rozhodně tedy neváhejte a přijďte si alespoň některé z nich zahrát! Pro letošní rok se můžete těšit opět na velkou nálož volného hraní RPG . Naši vypravěči vám přinesou spoustu různých titulů, jak všedních, tak i takových, které si doma jen tak nezahrajete. Objeví se známí velikáni jako Dungeons and Dragons 4E nebo GURPS, nové české hry Střepy snů a Příběhy impéria, které si budete moci dokonce zahrát i s jejich autory, a také řada netradičních zahraničních her jako oblíbený OG, Mouseguard, Pendragon nebo výjimečný My Life with Master. A to je jen zlomek toho, co vás na GC čeká. Spektrum her stále rozšiřujeme, aby byl program pro vás, co nejbohatší. Pokud máte zkušenosti s vedením nějakého netradičního RPG a byli byste ochotní ji na GC přivést a zahrát s ostatními, obraťte se na na organizátora této sekce na erric@email.cz . Podívejte se, jaká RPG se hrála minulý rok. -->');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (302,'GameCon 2011 se blíží','og-unearthed-edition-jit-novy-jeskyne',37,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (302,'rpg/og-unearthed-edition-jit-novy-jeskyne');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (302,'GameCon 2011 se blíží — GameCon 2011','gamecon,2011','GameCon 2011 se blíží');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (302,'<h1>GameCon 2011 se blíží</h1>

<!--<h2>Organizační změny</h2>
<p>
Dovolte nám seznámit vás s velkou organizační novinkou. Petr „Gandalf“ Holub, který stál v čele organizačního týmu GameConu poslední dva roky, ještě v průběhu letošního GameConu v České Třebové předal post hlavního organizátora Matouši „Erricu“ Ježkovi. Jelikož se mu totiž letos narodily dvě holčičky, po důkladném uvážení se musel rozhodnout k tomuto kroku, neboť vedení organizačního týmu a nově rozrostlou rodinu a normální práci by nebylo možné skloubit tak, aby jedno netrpělo.
</p>
<p>
Nic to však nemění na tom, že další ročník GameConu už pro vás připravujeme a o novinkách vás budeme průběžně informovat jak tady, tak na <a href = "http://www.facebook.com/group.php?sid=1a65342dd9cba753975=bb963632e2a7&gid=93879753711&ref=search#!/gamecon" onclick = "window.open(this.href,\'_blank\'); return false">facebooku</a>.
</p>
<p>
Organizační tým GameConu
</p>

<h2>GameCon Teaser</h2>
<object width="470" height="265"><param name="allowfullscreen" value="true" /><param name="allowscriptaccess" value="always" /><param name="movie" value="http://vimeo.com/moogaloop.swf?clip_id=12709571&amp;server=vimeo.com&amp;show_title=1&amp;show_byline=1&amp;show_portrait=0&amp;color=&amp;fullscreen=1" /><embed src="http://vimeo.com/moogaloop.swf?clip_id=12709571&amp;server=vimeo.com&amp;show_title=1&amp;show_byline=1&amp;show_portrait=0&amp;color=&amp;fullscreen=1" type="application/x-shockwave-flash" allowfullscreen="true" allowscriptaccess="always" width="470" height="265"></embed></object>-->

<h2>Čtyři dny plné zábavy a napětí nad hrami všeho druhu</h2>
<p>Ve dnech <strong>21.-24.7.2011</strong> se v <strong>České Třebové</strong> uskuteční již 17. ročník herního setkání <strong>GameCon</strong>. Je to příležitost pro všechny hráče a fanoušky nepočítačových her z České republiky a Slovenska setkat se s ostatními, zahrát si hry, vyměnit zkušenosti a pobavit se. Co vás během čtyř dnů na GameConu čeká?
<ul>
<li><a href="/deskove-hry/o-deskovych-hrach-na-gc">Deskové hry</a> (Osadníci z Katanu, Carcassonne a mnohé další)</li>
<li>Velké množství her na hraní rolí neboli <a href="/rpg/o-rpg-na-gc">RPG</a>. Můžete si vyzkoušet i herní systémy, které doma ani nemáte.</li>
<li>Hry naživo neboli <a href = "/larp/o-larpech-na-gc">LARP</a>, kdy prožitky své postavy vyzkoušíte na vlastní kůži.</li>
<li><a href = "/mistrovstvi-v-drd/o-mistrovstvi-v-drd">Mistrovství v Dračím doupěti</a>, letos pro změnu z pozice obyčejných obyvatel Císařství.</li>
<li>A spousta dalších aktivit, jako třeba bitva miniaturních armád ve <a href = "/wargaming/o-wargamingu-na-gc">Wargamingu</a>, nebo poutavé <a href = "/prednasky/o-prednaskach-na-gc">přednášky</a>.</li>
<li>Sobotní party</li>
</ul>
</p>

<p>Že neznáte žádnou z těchto her? Nevadí.<strong>Pravidla vám rádi vysvětlíme na místě</strong> a poradíme i s výběrem her nebo naplánováním programu. <strong>Neváhejte tedy a přijeďte.</strong> Slibujeme vám spoustu her, zábavy a přátelské atmosféry. Nemáte volné celé čtyři dny? Nevadí! <strong>GameCon</strong> má co nabídnout každý den.</strong></p>
<!--<p>Jednoduchý návod jak se <strong>přihlásit na GameCon</strong> a všechny důležité informace o <strong>registraci</strong>, možnostech <strong>ubytování</strong> a <strong>platbách</strong> naleznete <a href="/navod/">zde</a>.</p>-->
<p>O novinkách vás budeme průběžně informovat jak zde, tak na <a href = "http://www.facebook.com/gamecon" onclick = "window.open(this.href,\'_blank\'); return false">Facebooku</a>.</p>

<a name=novinky></a>
<h2>Letošní novinky</h2>
<p>Tak jako každý rok se snažíme, aby GameCon i letos nabídl něco nového. Loni se con přestěhoval do České Třebové, což přineslo mimo jiné možnost nabídnout všechny aktivity pod jednou střechou, prostornou a dobře větratelnou místnost pro deskohernu a levnější ubytování. Na co se můžete těšit letos?</p>
<ul>
<li>Pro účastníky GameConu ze Slovenska jsme připravili <strong>možnost platit v eurech</strong>.</li>
<li>Všem budou přístupné <strong>kuchyňky</strong>, ve kterých si bude možné uvařit jídlo.</li>
<li>GameCon se bude odehrávat <strong>ve znamení Antiky</strong>.</li>
<li>Je pro vás připravena <strong>spousta nových her</strong> na všech frontách.</li>
<li>Na programu bude také <strong>křest Dračího doupěte II</strong>.</li>
</ul>

<!--<p>
Patrně nejvýraznější změnou je přestěhování conu do České Třebové. Tento manévr nám poskytl hned několik výhod:
<ul>
	<li>Předně jsou to <strong>všechny aktivity pod jednou střechou</strong>, nebude potřeba kamkoliv přebíhat nebo složitě bloudit mezi jednotlivými komplexy budov.</li>
	<li>Zároveň jsou místnosti pro jednotlivé aktivity dostatečně velké a vzdušné.</li>
	<li>Především místnost <a href = "/deskove-hry/deskoherna">deskoherny</a> je úchvatně prostorná a dobře větratelná. Už nehrozí, že bychom se v dobré víře ušlapávali nebo letním parnu dusili. Tento rok to bude konečně ta <strong>dobře přístupná aréna plná deskových her</strong> připravená na lačné hráče. Pro zvědavce jsme jako důkaz připravili alespoň dvě fotografie z naších průzkumných výprav – více v <a href = "/deskove-hry/deskoherna">deskoherně</a>.</li>
	<li>Vítanou změnou bude určitě i <strong>levnější ubytování</strong>. Letos bude stát jedna noc v třílůžkovém pokoji pouhých 170 Kč (oproti loňským dvěma stovkám, takže za tři noci nakonec ušetříte téměř stokorunu).</li>
	<li>Přijde vám lůžkový pokoj příliš drahý a komfortní? Pak jistě uvítáte další zlepšení a tím je <strong>možnost spát hromadně ve třídě ve vlastním spacáku</strong> a to za pouhých 60 Kč. Více o ubytovacích možnostech se dočtete v <a href = "/gamecon/ubytovani">ubytování</a>.</li>
	<li>Přesunem do jiného města jsme také získali kousek od naší budovy velkou nafukovací halu, kterou budeme moci využít v nepřízni počasí na nějakou velmi hromadnou akci. No není takový bonus skvělý?</li>
	<li>A snad některé z vás potěší i dobrá dopravní dostupnost pro celou republiku. Jsme uprostřed státu, tak snad to má každý kousek. :-)</li>
</ul>
</p>

<p>
Jak můžete vidět, přesun na nové místo pro vás znamená samé výhody. Nespokojíme se však jen s novým územím a jeho přidanými hodnotami, pokračujeme dál ve zpestřujících zlepšovácích:
</p>
<p>
<ul>
	<li>Velká novinka hned rovnou na začátek: <strong>popré</strong> bude <strong>celý GameCon v duchu nějakého tématu</strong>, tentokrát to bude <strong>exodus</strong> a spíše než vyhnání z ráje to bude jeho hledání. V následujících dnech vám přineseme bližší informace a vy se můžete těšit, že s tím bude spojena spousta her a zábavné atmosféry.</li>
	<li><strong>Mistrovství v Dračím doupěti</strong> bude zase o něco blíž vám hráčům. Vyslyšeli jsme vaše dobré připomínky a rady, důkladně si přečetli reakce ve <a href = "/forum/mistrovstvi_v_drd">fóru</a> a vyšli vám vstříc.<br />
Do odkrývání tajů dobrodružství se můžete pustit již nyní a každý týden Vám přineseme další indicii. Na úvod začínáme jedním výtiskem <a href = "/mistrovstvi-v-drd/sluncesvit-cisarske-noviny">Sluncesvitu</a> - populárního císařského plátku.<br />
Také jsme pro vás připravili <strong>dvě výrazná zlepšení postav</strong> a <strong>jedno velmi poutavé zpestření</strong>. Obě novinky se týkají <a href = "/mistrovstvi-v-drd/pravidla-pro-tvorbu-postav">tvorby postav</a> a brzy vás o těchto změnách budeme informovat více. Zatím můžete ve <a href = "/forum/mistrovstvi_v_drd">fóru</a> tipovat, co by to tak mohlo být.</li>
	<li><strong>Trojboj</strong> bude v tomto roce trvat jen jeden blok, takže o důvod více zapojit se do této týmové aktivity, kdy za jednu cenu si zahrajete tři hry. Více na <a href = "/gamecon-trojboj/o-gamecon-trojboji">samostatné stránce</a>.</li>
	<li><strong>Špína</strong> bude letos ve znamení „Osídlení nového města“ a <strong>gobliní ponorky</strong> budou bojovat o nová naleziště drahokamů.</li>
	<li>Určitě se bude hodit i trénink ve velení armádám, tudíž jistě přijde vhod <a href = "/wargaming/wargaming-tour-2010">Wargaming Tour 2010</a>.</li>
	<li>A lahodný zákusek na závěr: <strong>na sobotní večer</strong> pro vás plánujeme <strong>hromadné pobavení</strong>, jehož součástí by mělo být i <strong>klání v duchu televizních soutěží</strong> v režii týmu z Court of Moravia.</li>
</ul>
</p>

<p>
Snad vás to množství novinek a jednotlivé zlepšováky těší a přijedete na GameCon. Koná se <strong>15.-18.7.2010 v&nbsp;České Třebové</strong>.
</p>-->

<h3>GameCon je tu pro vás, tak si přijďte zahrát!</h3>
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (302,'GameCon 2011 se blíží','GameCon 2011 se blíží Organizační změny Dovolte nám seznámit vás s velkou organizační novinkou. Petr „Gandalf“ Holub, který stál v čele organizačního týmu GameConu poslední dva roky, ještě v průběhu letošního GameConu v České Třebové předal post hlavního organizátora Matouši „Erricu“ Ježkovi. Jelikož se mu totiž letos narodily dvě holčičky, po důkladném uvážení se musel rozhodnout k tomuto kroku, neboť vedení organizačního týmu a nově rozrostlou rodinu a normální práci by nebylo možné skloubit tak, aby jedno netrpělo. Nic to však nemění na tom, že další ročník GameConu už pro vás připravujeme a o novinkách vás budeme průběžně informovat jak tady, tak na facebooku . Organizační tým GameConu GameCon Teaser --> Čtyři dny plné zábavy a napětí nad hrami všeho druhu Ve dnech 21.-24.7.2011 se v České Třebové uskuteční již 17. ročník herního setkání GameCon . Je to příležitost pro všechny hráče a fanoušky nepočítačových her z České republiky a Slovenska setkat se s ostatními, zahrát si hry, vyměnit zkušenosti a pobavit se. Co vás během čtyř dnů na GameConu čeká? Deskové hry (Osadníci z Katanu, Carcassonne a mnohé další) Velké množství her na hraní rolí neboli RPG . Můžete si vyzkoušet i herní systémy, které doma ani nemáte. Hry naživo neboli LARP , kdy prožitky své postavy vyzkoušíte na vlastní kůži. Mistrovství v Dračím doupěti , letos pro změnu z pozice obyčejných obyvatel Císařství. A spousta dalších aktivit, jako třeba bitva miniaturních armád ve Wargamingu , nebo poutavé přednášky . Sobotní party Že neznáte žádnou z těchto her? Nevadí. Pravidla vám rádi vysvětlíme na místě a poradíme i s výběrem her nebo naplánováním programu. Neváhejte tedy a přijeďte. Slibujeme vám spoustu her, zábavy a přátelské atmosféry. Nemáte volné celé čtyři dny? Nevadí! GameCon má co nabídnout každý den. Jednoduchý návod jak se přihlásit na GameCon a všechny důležité informace o registraci , možnostech ubytování a platbách naleznete zde . --> O novinkách vás budeme průběžně informovat jak zde, tak na Facebooku . Letošní novinky Tak jako každý rok se snažíme, aby GameCon i letos nabídl něco nového. Loni se con přestěhoval do České Třebové, což přineslo mimo jiné možnost nabídnout všechny aktivity pod jednou střechou, prostornou a dobře větratelnou místnost pro deskohernu a levnější ubytování. Na co se můžete těšit letos? Pro účastníky GameConu ze Slovenska jsme připravili možnost platit v eurech . Všem budou přístupné kuchyňky , ve kterých si bude možné uvařit jídlo. GameCon se bude odehrávat ve znamení Antiky . Je pro vás připravena spousta nových her na všech frontách. Na programu bude také křest Dračího doupěte II . Patrně nejvýraznější změnou je přestěhování conu do České Třebové. Tento manévr nám poskytl hned několik výhod: Předně jsou to všechny aktivity pod jednou střechou , nebude potřeba kamkoliv přebíhat nebo složitě bloudit mezi jednotlivými komplexy budov. Zároveň jsou místnosti pro jednotlivé aktivity dostatečně velké a vzdušné. Především místnost deskoherny je úchvatně prostorná a dobře větratelná. Už nehrozí, že bychom se v dobré víře ušlapávali nebo letním parnu dusili. Tento rok to bude konečně ta dobře přístupná aréna plná deskových her připravená na lačné hráče. Pro zvědavce jsme jako důkaz připravili alespoň dvě fotografie z naších průzkumných výprav – více v deskoherně . Vítanou změnou bude určitě i levnější ubytování . Letos bude stát jedna noc v třílůžkovém pokoji pouhých 170 Kč (oproti loňským dvěma stovkám, takže za tři noci nakonec ušetříte téměř stokorunu). Přijde vám lůžkový pokoj příliš drahý a komfortní? Pak jistě uvítáte další zlepšení a tím je možnost spát hromadně ve třídě ve vlastním spacáku a to za pouhých 60 Kč. Více o ubytovacích možnostech se dočtete v ubytování . Přesunem do jiného města jsme také získali kousek od naší budovy velkou nafukovací halu, kterou budeme moci využít v nepřízni počasí na nějakou velmi hromadnou akci. No není takový bonus skvělý? A snad některé z vás potěší i dobrá dopravní dostupnost pro celou republiku. Jsme uprostřed státu, tak snad to má každý kousek. :-) Jak můžete vidět, přesun na nové místo pro vás znamená samé výhody. Nespokojíme se však jen s novým územím a jeho přidanými hodnotami, pokračujeme dál ve zpestřujících zlepšovácích: Velká novinka hned rovnou na začátek: popré bude celý GameCon v duchu nějakého tématu , tentokrát to bude exodus a spíše než vyhnání z ráje to bude jeho hledání. V následujících dnech vám přineseme bližší informace a vy se můžete těšit, že s tím bude spojena spousta her a zábavné atmosféry. Mistrovství v Dračím doupěti bude zase o něco blíž vám hráčům. Vyslyšeli jsme vaše dobré připomínky a rady, důkladně si přečetli reakce ve fóru a vyšli vám vstříc. Do odkrývání tajů dobrodružství se můžete pustit již nyní a každý týden Vám přineseme další indicii. Na úvod začínáme jedním výtiskem Sluncesvitu - populárního císařského plátku. Také jsme pro vás připravili dvě výrazná zlepšení postav a jedno velmi poutavé zpestření . Obě novinky se týkají tvorby postav a brzy vás o těchto změnách budeme informovat více. Zatím můžete ve fóru tipovat, co by to tak mohlo být. Trojboj bude v tomto roce trvat jen jeden blok, takže o důvod více zapojit se do této týmové aktivity, kdy za jednu cenu si zahrajete tři hry. Více na samostatné stránce . Špína bude letos ve znamení „Osídlení nového města“ a gobliní ponorky budou bojovat o nová naleziště drahokamů. Určitě se bude hodit i trénink ve velení armádám, tudíž jistě přijde vhod Wargaming Tour 2010 . A lahodný zákusek na závěr: na sobotní večer pro vás plánujeme hromadné pobavení , jehož součástí by mělo být i klání v duchu televizních soutěží v režii týmu z Court of Moravia. Snad vás to množství novinek a jednotlivé zlepšováky těší a přijedete na GameCon. Koná se 15.-18.7.2010 v České Třebové . --> GameCon je tu pro vás, tak si přijďte zahrát!');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (303,'Pendragon','pendragon',37,0,0);
