INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (303,'Pendragon — GameCon 2011','gamecon,2011','Pendragon');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (303,'kapacita 5/5<br />
<h1>Pendragon</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/pendragon.gif" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>vypravěč</strong><br />Peter "Peekay" Kopáč<br />
  <strong>čas akce</strong><br />neděle 24.7 - 9:00 až 13:00  <br />
 <strong>další akce organizátora</strong> <br /><div style = "text-align: left;"><a href = "/rpg/drd-ii---nezbedna-manzelka">DrD II - Nezbedná manželka</a></div>
</div>
</p>
   <p style = "clear: both;">
Británia kráľa Artuša: svet, kde je rytierstvo nielen spoločenské postavenie, ale hlavne obrovské bremeno zodpovednosti, spletenec loajálností a konvencií spoločenského chovania, odvahy a hrdinstva robiť ťažké a často nepríjemné rozhodnutia. Svet, v ktorom rytieri rozpoltení medzi ich cnosťami a nutnosťou udržať všetko pokope padajú po šikmej ploche. Svet kontrastu starého zanikajúceho sveta a nového vznikajúceho rádu, ale aj svet, kde sa musia hrdí a odvážni muži postaviť drakovi či inej mýtickej bytosti pri obrane vlastného domova. 
</p>
<p>
Pre mladých rytierov zo Salisbury aj tento rok začína ako každý iný - veľkým turnajom na Camelote. Skôr, než na turnaji zaznejú trumpety víťaza sa však odoberieme na dobrodružstvo, ktoré ich zavedie daľeko od domova... 
</p>
<p>

<p>
<ul>

<li>Více informací: <a href = "http://rpgforum.cz/anotace/pendragon" onclick = "window.open(this.href,\'_blank\'); return false">http://rpgforum.cz/anotace/pendragon</a></li>

                  <!--<li>
        <a href = "/rpg/seznam-rpg-na-gc2010">Přehled všech RPG na GameConu 2010</a>      </li>-->
    </ul>
  </p>
  <div style = "width: 100%; float: left;">
    <div style = "width: 50%; text-align: left; float: left; padding-top: 20px; padding-bottom: 15px;">&laquo; <a href = "/rpg/my-life-with-master">My Life with Master</a></div>    <div style = "width: 50%; text-align: right; float: right; padding-top: 20px; padding-bottom: 15px;"><a href = "/rpg/pribehy-imperia">Příběhy Impéria</a> &raquo;</div>  </div>
  
    </div>
  </div>');
