INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (304,'Příběhy Impéria — GameCon 2011','gamecon,2011','Příběhy Impéria');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (304,'kapacita 5/5<br />kapacita 5/5<br />kapacita 5/5<br />kapacita 5/5<br />
<h1>Příběhy Impéria</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/pribehy-imperia.gif" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>vypravěč</strong><br />Ecthelion^2<br />
  <strong>čas akce</strong><br />pátek 22.7 - 8:00 až 12:00  <br />pátek 22.7 - 19:00 až 23:00  <br />pátek 22.7 - 19:00 až 23:00  <br />sobota 23.7 - 14:00 až 18:00  <br />
 <strong>další akce organizátora</strong> <br /><div style = "text-align: left;"><a href = "/rpg/drdii---navrat-do-bileho-hradu">DrDII - Návrat do Bílého hradu</a></div>
</div>
</p>
   <p style = \\"clear: both;\\">
Stories of the Empire je nová česká RPG hra popisující temný viktoriánský svět plný kouzel a tajemna. Na ulicích Londýna, studených a vlhkých v nočním vzduchu, procházejí mágové, skřítci a elfové provádějí svoje kousky a mezi lidmi žijí svoje životy skřeti, trpaslíci, faunové a další stvoření, která dnes známe už jen z příběhů.
</p>
<p>
Svět Impéria je světem tajemných britských ostrovů, které se utápí v magických mlhách a kde k nebi ční dolmeny a kamenné kruhy jako vzpomínka na lid, který tu kdysi žil před lidmi. Zemí projíždějí rytíři ze Země kouzel a hraniční skřeti stále obývají polorozbořené věže skotské vysočiny. Za nocí se hvozdy a údolími rozléhá vytí vlkodlačí smečky a měsíční světlo se odráží od hřív jednorožců. Duchové, kteří nenalezli pokoje, se vrací zpět mezi lidi a jejich příbytky, čarodějnice se připravují na sabat a démoni a andělé se objevují na Zemi, aby jednali jménem svých vládců.
</p>
<p>
Příběh, který před gentlemany a dámami stojí, bude vyžadovat odvahu a odhodlání, protože temné mraky se stahují a blíží se nebezpečná bouře…
</p>
<p>

<ul>
<ul><li>Více informací: <a href="http://domena.tld" onclick="return !window.open(this.href);">http://rpgforum.cz/forum/viewtopic.php?f=237&t=6630
</a></li>                           <!--<li>
        <a href = "/rpg/seznam-rpg-na-gc2010">Přehled všech RPG na GameConu 2010</a>      </li>-->
    </ul>
  </p>
  <div style = "width: 100%; float: left;">
    <div style = "width: 50%; text-align: left; float: left; padding-top: 20px; padding-bottom: 15px;">&laquo; <a href = "/rpg/pendragon">Pendragon</a></div>    <div style = "width: 50%; text-align: right; float: right; padding-top: 20px; padding-bottom: 15px;"><a href = "/rpg/rpg-a-svet-ondreje-netika">RPG a svět Ondřeje Netíka</a> &raquo;</div>  </div>
  
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (304,'Příběhy Impéria','kapacita 5/5 kapacita 5/5 kapacita 5/5 kapacita 5/5 Příběhy Impéria vypravěč Ecthelion^2 čas akce pátek 22.7 - 8:00 až 12:00 pátek 22.7 - 19:00 až 23:00 pátek 22.7 - 19:00 až 23:00 sobota 23.7 - 14:00 až 18:00 další akce organizátora DrDII - Návrat do Bílého hradu Stories of the Empire je nová česká RPG hra popisující temný viktoriánský svět plný kouzel a tajemna. Na ulicích Londýna, studených a vlhkých v nočním vzduchu, procházejí mágové, skřítci a elfové provádějí svoje kousky a mezi lidmi žijí svoje životy skřeti, trpaslíci, faunové a další stvoření, která dnes známe už jen z příběhů. Svět Impéria je světem tajemných britských ostrovů, které se utápí v magických mlhách a kde k nebi ční dolmeny a kamenné kruhy jako vzpomínka na lid, který tu kdysi žil před lidmi. Zemí projíždějí rytíři ze Země kouzel a hraniční skřeti stále obývají polorozbořené věže skotské vysočiny. Za nocí se hvozdy a údolími rozléhá vytí vlkodlačí smečky a měsíční světlo se odráží od hřív jednorožců. Duchové, kteří nenalezli pokoje, se vrací zpět mezi lidi a jejich příbytky, čarodějnice se připravují na sabat a démoni a andělé se objevují na Zemi, aby jednali jménem svých vládců. Příběh, který před gentlemany a dámami stojí, bude vyžadovat odvahu a odhodlání, protože temné mraky se stahují a blíží se nebezpečná bouře… Více informací: http://rpgforum.cz/forum/viewtopic.php?f=237&t=6630 Přehled všech RPG na GameConu 2010 --> « Pendragon RPG a svět Ondřeje Netíka »');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (305,'Prime Time Adventures','prime-time-adventures',37,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (305,'rpg/prime-time-adventures');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (305,'Prime Time Adventures — GameCon 2011','gamecon,2011','Prime Time Adventures');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (305,'<h1>Prime Time Adventures</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/prime-time-adventures.gif" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>vypravěč</strong><br />Jakub "boubaque" Maruš<br />
  
 <strong>další akce organizátora</strong> <br /><div style = "text-align: left;"><a href = "/rpg/drdii---navrat-do-bileho-hradu">DrDII - Návrat do Bílého hradu</a>, <a href = "/prednasky/situace-a-budoucnost-rpg-v-cr-a-sr">Situace a budoucnost RPG v ČR a SR</a></div>
</div>
</p>
   <p style = \\"clear: both;\\">
Primetime Adventures je hra, ve které protagonisté pod vedením producenta natáčejí televizní seriál - tedy skoro, je to přecejen pořád RPG. Jednoduchý systém, který využívá hracích karet namísto obvyklých kostek, podporuje hráčský vklad do příběhu a poradí si dokonce i s případným nehrajícím publikem. Celá hra se točí okolo problémů jednotlivých postav a společného tématu určeného námětem seriálu.<br />
 Pilotní díl seriálu nás přivede do amerického průmyslového města v době velké hospodářské krize, které ovládají mafiánské rodiny. Jednou z nejmocnějších je rodina Bodone, ale zdá se, že pro ně dobré dny pomalu končí. Obchody nejdou tak jako před pár lety a navíc se policii zřejmě podařilo nasadit Bodoneům do kožichu veš. K překonání problémů je nutná pevná ruka, ovšem don Bodone je už starý a nemocný ... a jeho staršího syna našli před týdnem s několika kulkami v hrudi. V této pohnuté době není snadné dosáhnout úspěchu, a každý za něj platí vysokou cenu, ať už do rodiny patří nebo ne.
</p>


              <!--<li>
        <a href = "/rpg/seznam-rpg-na-gc2010">Přehled všech RPG na GameConu 2010</a>      </li>-->
    </ul>
  </p>
  <div style = "width: 100%; float: left;">
    <div style = "width: 50%; text-align: left; float: left; padding-top: 20px; padding-bottom: 15px;">&laquo; <a href = "/rpg/pendragon">Pendragon</a></div>    <div style = "width: 50%; text-align: right; float: right; padding-top: 20px; padding-bottom: 15px;"><a href = "/rpg/pribehy-imperia">Příběhy Impéria</a> &raquo;</div>  </div>
  
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (305,'Prime Time Adventures','Prime Time Adventures vypravěč Jakub "boubaque" Maruš další akce organizátora DrDII - Návrat do Bílého hradu , Situace a budoucnost RPG v ČR a SR Primetime Adventures je hra, ve které protagonisté pod vedením producenta natáčejí televizní seriál - tedy skoro, je to přecejen pořád RPG. Jednoduchý systém, který využívá hracích karet namísto obvyklých kostek, podporuje hráčský vklad do příběhu a poradí si dokonce i s případným nehrajícím publikem. Celá hra se točí okolo problémů jednotlivých postav a společného tématu určeného námětem seriálu. Pilotní díl seriálu nás přivede do amerického průmyslového města v době velké hospodářské krize, které ovládají mafiánské rodiny. Jednou z nejmocnějších je rodina Bodone, ale zdá se, že pro ně dobré dny pomalu končí. Obchody nejdou tak jako před pár lety a navíc se policii zřejmě podařilo nasadit Bodoneům do kožichu veš. K překonání problémů je nutná pevná ruka, ovšem don Bodone je už starý a nemocný ... a jeho staršího syna našli před týdnem s několika kulkami v hrudi. V této pohnuté době není snadné dosáhnout úspěchu, a každý za něj platí vysokou cenu, ať už do rodiny patří nebo ne. Přehled všech RPG na GameConu 2010 --> « Pendragon Příběhy Impéria »');

