    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (307,'Rudá planeta','kapacita 5/5 Rudá planeta vypravěč Petr Svarný čas akce sobota 23.7 - 14:00 až 18:00 další akce organizátora Wargames , Dlouhá hlídka , Strepicka , Volná hra Bylo odvěkým snem člověka dostat se ke hvězdám. Zatím však i cesta k nejbližší planetě je těžkým úkolem, úkolem svěřeným do rukou pěti astronautů na dlouhé cestě k Marsu. Je v rukou štěstěny a schopností posádky, zda zdárně na planetu dorazí či se celý sen rozletí na střepy. Přijď se vžít do role dobyvatelů nových světů v příběhu využívajícím herní systém Střepů snů. Přehled všech RPG na GameConu 2010 --> « RPG a svět Ondřeje Netíka Star Wars ve Storyteller systému »');

