INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (313,'Star Wars ve Storyteller systému','star-wars-ve-storyteller-systemu',37,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (313,'rpg/star-wars-ve-storyteller-systemu');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (313,'Star Wars ve Storyteller systému — GameCon 2011','gamecon,2011','Star Wars ve Storyteller systému');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (313,'kapacita 4/5<br />
<h1>Star Wars ve Storyteller systému</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/star-wars-ve-storyteller-systemu.gif" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>vypravěč</strong><br />Petr "Sirien" Mazák<br />
  <strong>čas akce</strong><br />pátek 22.7 - 14:00 až 18:00  <br />
 <strong>další akce organizátora</strong> <br /><div style = "text-align: left;"><a href = "/rpg/mage-the-awakecension-">Mage: the Awakecension </a></div>
</div>
</p>
   <p style = "clear: both;">
Republika odrazila invazi sil Sithského Impéria a poprvé od počátku války převzala iniciativu. Po těžce zaplaceném vítězství v ohromné bitvě o Coruscant, pro počet zdevastovaných křižníků obou stran vojáky přezdívané Bitva hromadného šrotu, je její ofenziva silná, avšak křehká - každé zdržení, zaváhání nebo menší prohra se silami Sithů mohou Republiku uvrhnout zpět do zoufalé defenzivy. Republikový generální štáb se proto rozhodl shromáždit flotilu a udeřit plnou silou přímo do srdce Sithských sil. Je to riskantní, je to odvážné, je to hrdinné, možná to je zbrklé, nezodpovědné a šílené. <br />
</p>
<p>
Každopádně, pro mladého a temperamentního Jediiského padawana i pro chladnokrevného veterána speciálních jednotek to je velmi dobrý důvod být právě tam - v čele útoku, nebo, ještě lépe, dávno za linií nepřítele na záškodnickém či výzvědném poslání. ROZHODNĚ by podle jejich názoru ani jeden z nich neměl být poslán sem - na zapadlou neutrální planetu bezpečně v Republikovém území, která náhodou slouží jako před-před-před-poslední krátkodobé shromaždiště republikových sil před samotným úderem, na totálně nesmyslné diplomatické misi třetiřadé důležitosti, jako ochranka jakéhosi úlisného a slizkého diplomata na naprosto nedůležité cestě, navíc doprovázeného naprosto nedůvěryhodným a nervydrásajícím individuem, kterému by se snad dalo říkat žoldák, kdyby to nebylo urážkou všech neslušných žoldáků. Ani pro stárnoucího rytíře Jedi, který měl v úmyslu dožít svůj čas v klidných meditacích hluboko v klášteře, a který dostal mladého, ve válce odchovaného padawana na starost, není tento výlet právě odměnou. Ale kdo ví? Starý Jedi začíná cítit cosi v kostech. Proudy Síly se před ním prazvláštně rozostřují. Po opuštění chrámu se staré, kdysi tak ostré instinkty najednou, zdánlivě bezdůvodně, probouzejí k životu. Je to jen změnou prostředí, vzpomínkou na staré časy? Nebo v tom je něco víc? Kam až všude může dosáhnout Sithská zrada? Jak moc lze věřit těm, co je doprovázejí? Nebo tomu mládenci, jehož dostal na starost? Blíží se snad po letech opět doba, kdy bude muset sáhout po světelném meči? A vzpomene si vůbec ještě, jak se s ním zachází?
</p>
<p>
Klasický SW příběh plný hrdinů, bojů, zrady, démonických Sithů, výbuchů a záchran krásných dívek v poslední vteřině, zasazený do prostředí jedné z mnoha válek Staré republiky(*), odehrávaný ve variaci Storyteller systému (známého z her World of Darkness), který upřednostňuje popisy před mechanikami a dává volnost v používání Síly i v provádění cool efektů. Ne každý zde vládne Silou, ale věřte, že postavy, které jí nevládnou, si po ní rozhodně stýskat nebudou...
</p>
<p>
(*ne canonová, prostě jakási válka v době Staré republiky, pro příběh netřeba řešit nic moc víc)
</p>              <!--<li>
        <a href = "/rpg/seznam-rpg-na-gc2010">Přehled všech RPG na GameConu 2010</a>      </li>-->
    </ul>
  </p>
  <div style = "width: 100%; float: left;">
    <div style = "width: 50%; text-align: left; float: left; padding-top: 20px; padding-bottom: 15px;">&laquo; <a href = "/rpg/ruda-planeta">Rudá planeta</a></div>    <div style = "width: 50%; text-align: right; float: right; padding-top: 20px; padding-bottom: 15px;"><a href = "/rpg/strepicka">Strepicka</a> &raquo;</div>  </div>
  
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (313,'Star Wars ve Storyteller systému','kapacita 4/5 Star Wars ve Storyteller systému vypravěč Petr "Sirien" Mazák čas akce pátek 22.7 - 14:00 až 18:00 další akce organizátora Mage: the Awakecension Republika odrazila invazi sil Sithského Impéria a poprvé od počátku války převzala iniciativu. Po těžce zaplaceném vítězství v ohromné bitvě o Coruscant, pro počet zdevastovaných křižníků obou stran vojáky přezdívané Bitva hromadného šrotu, je její ofenziva silná, avšak křehká - každé zdržení, zaváhání nebo menší prohra se silami Sithů mohou Republiku uvrhnout zpět do zoufalé defenzivy. Republikový generální štáb se proto rozhodl shromáždit flotilu a udeřit plnou silou přímo do srdce Sithských sil. Je to riskantní, je to odvážné, je to hrdinné, možná to je zbrklé, nezodpovědné a šílené. Každopádně, pro mladého a temperamentního Jediiského padawana i pro chladnokrevného veterána speciálních jednotek to je velmi dobrý důvod být právě tam - v čele útoku, nebo, ještě lépe, dávno za linií nepřítele na záškodnickém či výzvědném poslání. ROZHODNĚ by podle jejich názoru ani jeden z nich neměl být poslán sem - na zapadlou neutrální planetu bezpečně v Republikovém území, která náhodou slouží jako před-před-před-poslední krátkodobé shromaždiště republikových sil před samotným úderem, na totálně nesmyslné diplomatické misi třetiřadé důležitosti, jako ochranka jakéhosi úlisného a slizkého diplomata na naprosto nedůležité cestě, navíc doprovázeného naprosto nedůvěryhodným a nervydrásajícím individuem, kterému by se snad dalo říkat žoldák, kdyby to nebylo urážkou všech neslušných žoldáků. Ani pro stárnoucího rytíře Jedi, který měl v úmyslu dožít svůj čas v klidných meditacích hluboko v klášteře, a který dostal mladého, ve válce odchovaného padawana na starost, není tento výlet právě odměnou. Ale kdo ví? Starý Jedi začíná cítit cosi v kostech. Proudy Síly se před ním prazvláštně rozostřují. Po opuštění chrámu se staré, kdysi tak ostré instinkty najednou, zdánlivě bezdůvodně, probouzejí k životu. Je to jen změnou prostředí, vzpomínkou na staré časy? Nebo v tom je něco víc? Kam až všude může dosáhnout Sithská zrada? Jak moc lze věřit těm, co je doprovázejí? Nebo tomu mládenci, jehož dostal na starost? Blíží se snad po letech opět doba, kdy bude muset sáhout po světelném meči? A vzpomene si vůbec ještě, jak se s ním zachází? Klasický SW příběh plný hrdinů, bojů, zrady, démonických Sithů, výbuchů a záchran krásných dívek v poslední vteřině, zasazený do prostředí jedné z mnoha válek Staré republiky(*), odehrávaný ve variaci Storyteller systému (známého z her World of Darkness), který upřednostňuje popisy před mechanikami a dává volnost v používání Síly i v provádění cool efektů. Ne každý zde vládne Silou, ale věřte, že postavy, které jí nevládnou, si po ní rozhodně stýskat nebudou... (*ne canonová, prostě jakási válka v době Staré republiky, pro příběh netřeba řešit nic moc víc) Přehled všech RPG na GameConu 2010 --> « Rudá planeta Strepicka »');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (314,'Steamferno: Krvavý písek','steamferno-krvavy-pisek',37,0,0);
