INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (314,'Steamferno: Krvavý písek — GameCon 2011','gamecon,2011','Steamferno: Krvavý písek');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (314,'<h1>Steamferno: Krvavý písek</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/steamferno-krvavy-pisek.gif" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>vypravěč</strong><br />František "Sniper" Neznaj<br />
  
 <strong>další akce organizátora</strong> <br /><div style = "text-align: left;"><a href = "/rpg/steamferno-zelene-peklo">Steamferno: Zelené peklo</a>, <a href = "/prednasky/steamferno">Steamferno</a>, <a href = "/prednasky/vyhra-pje-aneb-jak-zabranit-vyhoreni">Výhra PJe, aneb jak zabránit vyhoření</a>, <a href = "/prednasky/dobry-souboj-v-drd">Dobrý souboj v DrD?</a></div>
</div>
</p>
   <p style = \\"clear: both;\\">
Vzdušní piráti to nemají lehké. Hlavně proto, že po nich jdeš TY! Spolu s dalšími lovci odměn tě věrná vzducholodi Symfonie zanesla do pouštních měst v Perské říši, kde by se měl skrývat sám pověstný Zlatý spár - a odměna za něj bude stát za to!</p>
  
<p>Pojď si zahrát za jednoho z lovců odměn a ozkoušet si nový systém Steamferno RPG - steampunkovou hru v reáliích našeho světa, kde historie šla trochu jinak... vyber si na místě z připravených postav a pomocí jednoduchých pravidel si užij skvělé dobrodružství!
</p>
          <!--<li>
        <a href = "/rpg/seznam-rpg-na-gc2010">Přehled všech RPG na GameConu 2010</a>      </li>-->
    </ul>
  </p>
  <div style = "width: 100%; float: left;">
    <div style = "width: 50%; text-align: left; float: left; padding-top: 20px; padding-bottom: 15px;">&laquo; <a href = "/rpg/star-wars-ve-storyteller-systemu">Star Wars ve Storyteller systému</a></div>    <div style = "width: 50%; text-align: right; float: right; padding-top: 20px; padding-bottom: 15px;"><a href = "/rpg/steamferno-zelene-peklo">Steamferno: Zelené peklo</a> &raquo;</div>  </div>
  
    </div>
  </div>');
