INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (315,'<h1>Steamferno: Zelené peklo</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/steamferno-zelene-peklo.gif" style = "float: left; "/ /></div>
