INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (316,'kapacita 5/5<br />
<h1>Strepicka</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/strepicka.gif" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>vypravěč</strong><br />Petr Svarný<br />
  <strong>čas akce</strong><br />pátek 22.7 - 8:00 až 12:00  <br />
 <strong>další akce organizátora</strong> <br /><div style = "text-align: left;"><a href = "/rpg/wargames">Wargames</a>, <a href = "/rpg/dlouha-hlidka">Dlouhá hlídka</a>, <a href = "/rpg/ruda-planeta">Rudá planeta</a>, <a href = "/rpg/volna-hra">Volná hra</a></div>
</div>
</p>
   <p style = "clear: both;">
Měli jste někdy sen pustit své kouzelnické schopnosti na špacír a třebas rozmlátit vše na pidi střípky nebo naopak stvořit obrovské paláce?
</p>
<p>
Svět je v ohrožení a jedinou nadějí se skupinka trhlých mágů. Alias v kulisách klasického fantasy využijte možností systému Střepů Snů.
</p>
<p>
              <!--<li>
        <a href = "/rpg/seznam-rpg-na-gc2010">Přehled všech RPG na GameConu 2010</a>      </li>-->
    </ul>
  </p>
  <div style = "width: 100%; float: left;">
    <div style = "width: 50%; text-align: left; float: left; padding-top: 20px; padding-bottom: 15px;">&laquo; <a href = "/rpg/star-wars-ve-storyteller-systemu">Star Wars ve Storyteller systému</a></div>    <div style = "width: 50%; text-align: right; float: right; padding-top: 20px; padding-bottom: 15px;"><a href = "/rpg/sustot-kridel-a-stranek">Šustot křídel a stránek</a> &raquo;</div>  </div>
  
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (316,'Strepicka','kapacita 5/5 Strepicka vypravěč Petr Svarný čas akce pátek 22.7 - 8:00 až 12:00 další akce organizátora Wargames , Dlouhá hlídka , Rudá planeta , Volná hra Měli jste někdy sen pustit své kouzelnické schopnosti na špacír a třebas rozmlátit vše na pidi střípky nebo naopak stvořit obrovské paláce? Svět je v ohrožení a jedinou nadějí se skupinka trhlých mágů. Alias v kulisách klasického fantasy využijte možností systému Střepů Snů. Přehled všech RPG na GameConu 2010 --> « Star Wars ve Storyteller systému Šustot křídel a stránek »');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (317,'Šustot křídel a stránek','sustot-kridel-a-stranek',37,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (317,'rpg/sustot-kridel-a-stranek');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (317,'Šustot křídel a stránek — GameCon 2011','gamecon,2011','Šustot křídel a stránek');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (317,'kapacita 5/5<br />
<h1>Šustot křídel a stránek</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/sustot-kridel-a-stranek.gif" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>vypravěč</strong><br />Jakub "Dukolm" Červený<br />
  <strong>čas akce</strong><br />neděle 24.7 - 9:00 až 13:00  <br />
 <strong>další akce organizátora</strong> <br /><div style = "text-align: left;"><a href = "/rpg/lady-blackbird">Lady Blackbird</a>, <a href = "/rpg/wernion">Wernion</a></div>
</div>
</p>
   <p style = "clear: both;">
Děti přijely k tetě na prázdniny. Statek uprostřed luk a lesů k civilizaci daleko. Vypadá to na nudné prázdniny, ale nic není tak jak se zdá, možná zažijí dobrodružství, o jakém se jim nesnilo.
</p>
<p>
Co se skrývá v okolních lesích a strýčkově knihovně?
</p>
<p>
Šustění křídel a stránek využívá herní systém Shadows. Shadows je minimalistický vyprávěcí systém zaměřený na vytváření atmosféry hry. Hráči mají velkou moc nad příběhem na úkor vypravěče.
</p>
<p>
<ul>

<li>Více informací například zde: <a href="http://rpgforum.cz/anotace/shadows" onclick="return !window.open(this.href);">http://rpgforum.cz/anotace/shadows</a></li>

                                          <!--<li>
        <a href = "/rpg/seznam-rpg-na-gc2010">Přehled všech RPG na GameConu 2010</a>      </li>-->
    </ul>
  </p>
  <div style = "width: 100%; float: left;">
    <div style = "width: 50%; text-align: left; float: left; padding-top: 20px; padding-bottom: 15px;">&laquo; <a href = "/rpg/strepicka">Strepicka</a></div>    <div style = "width: 50%; text-align: right; float: right; padding-top: 20px; padding-bottom: 15px;"><a href = "/rpg/volna-hra">Volná hra</a> &raquo;</div>  </div>
  
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (317,'Šustot křídel a stránek','kapacita 5/5 Šustot křídel a stránek vypravěč Jakub "Dukolm" Červený čas akce neděle 24.7 - 9:00 až 13:00 další akce organizátora Lady Blackbird , Wernion Děti přijely k tetě na prázdniny. Statek uprostřed luk a lesů k civilizaci daleko. Vypadá to na nudné prázdniny, ale nic není tak jak se zdá, možná zažijí dobrodružství, o jakém se jim nesnilo. Co se skrývá v okolních lesích a strýčkově knihovně? Šustění křídel a stránek využívá herní systém Shadows. Shadows je minimalistický vyprávěcí systém zaměřený na vytváření atmosféry hry. Hráči mají velkou moc nad příběhem na úkor vypravěče. Více informací například zde: http://rpgforum.cz/anotace/shadows Přehled všech RPG na GameConu 2010 --> « Strepicka Volná hra »');

