INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (318,'kapacita 5/5<br />
<h1>Volná hra</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/volna-hra.gif" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>vypravěč</strong><br />Petr Svarný<br />
  <strong>čas akce</strong><br />čtvrtek 21.7 - 20:00 až 24:00  <br />
 <strong>další akce organizátora</strong> <br /><div style = "text-align: left;"><a href = "/rpg/wargames">Wargames</a>, <a href = "/rpg/dlouha-hlidka">Dlouhá hlídka</a>, <a href = "/rpg/ruda-planeta">Rudá planeta</a>, <a href = "/rpg/strepicka">Strepicka</a></div>
</div>
</p>
   <p style = \\"clear: both;\\">
Chceš si vyzkoušet, jak se tvoří příběhy v prostředí Střepů snů? Tak v tom případě neváhej a přihlaš se na tuto seanci.
</p>
<p>
Během této hry, nebo téměř workshopu si vyzkoušíš postupy a přístupy využívané při vytváření příběhů a zápletek ve Střepech snů a na závěr budeš mít možnost si hru i krátce vyzkoušet. Idelání příležitost pro vypravěče, kteří se chtějí seznámit s touto hrou.
              <!--<li>
        <a href = "/rpg/seznam-rpg-na-gc2010">Přehled všech RPG na GameConu 2010</a>      </li>-->
    </ul>
  </p>
  <div style = "width: 100%; float: left;">
    <div style = "width: 50%; text-align: left; float: left; padding-top: 20px; padding-bottom: 15px;">&laquo; <a href = "/rpg/sustot-kridel-a-stranek">Šustot křídel a stránek</a></div>    <div style = "width: 50%; text-align: right; float: right; padding-top: 20px; padding-bottom: 15px;"><a href = "/dilny/vypravecska-dilna">Vypravěčská dílna</a> &raquo;</div>  </div>
  
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (318,'Volná hra','kapacita 5/5 Volná hra vypravěč Petr Svarný čas akce čtvrtek 21.7 - 20:00 až 24:00 další akce organizátora Wargames , Dlouhá hlídka , Rudá planeta , Strepicka Chceš si vyzkoušet, jak se tvoří příběhy v prostředí Střepů snů? Tak v tom případě neváhej a přihlaš se na tuto seanci. Během této hry, nebo téměř workshopu si vyzkoušíš postupy a přístupy využívané při vytváření příběhů a zápletek ve Střepech snů a na závěr budeš mít možnost si hru i krátce vyzkoušet. Idelání příležitost pro vypravěče, kteří se chtějí seznámit s touto hrou. Přehled všech RPG na GameConu 2010 --> « Šustot křídel a stránek Vypravěčská dílna »');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (319,'Wargames','wargames',37,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (319,'rpg/wargames');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (319,'Wargames — GameCon 2011','gamecon,2011','Wargames');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (319,'kapacita 5/5<br />
<h1>Wargames</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/wargames.gif" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>vypravěč</strong><br />Petr Svarný<br />
  <strong>čas akce</strong><br />neděle 24.7 - 9:00 až 13:00  <br />
 <strong>další akce organizátora</strong> <br /><div style = "text-align: left;"><a href = "/rpg/dlouha-hlidka">Dlouhá hlídka</a>, <a href = "/rpg/ruda-planeta">Rudá planeta</a>, <a href = "/rpg/strepicka">Strepicka</a>, <a href = "/rpg/volna-hra">Volná hra</a></div>
</div>
</p>
   <p style = "clear: both;">
Nacházíme se v období vrtkavé rovnováhy, nových silných hračů a staré mocnosti ztrácejí svou nadvládu. Rok 2024 a Ty jako jeden ze států učastnících se světového dění. Budete slabnoucími Spojenými státy, drakem Asie Čínou, probouzejícím se medvědem Ruské unie, Arabskou ligou využívající svých posledních zásob černého zlata nebo obnovenou Evropskou silou?
</p>
<p>
Ať zvolíte jakýkoliv stát, budete se muset potýkat se světem, kde jen nejsilnejší přežívá, se světem, kde mohou vzplát plameny světové války a rozbít sen o světovém míru na tisíce střepů
</p>
<p>
Chceš si zkusit, jaké to je vžít se do role samotného státu, tvořeného jeho diplomaty, vojáky, státníky i byrokraty? Tak si přijď zahrát tenhle příběh využívající herní systém Střepů snů.
                          <!--<li>
        <a href = "/rpg/seznam-rpg-na-gc2010">Přehled všech RPG na GameConu 2010</a>      </li>-->
    </ul>
  </p>
  <div style = "width: 100%; float: left;">
    <div style = "width: 50%; text-align: left; float: left; padding-top: 20px; padding-bottom: 15px;">&laquo; <a href = "/dilny/vypravecska-dilna">Vypravěčská dílna</a></div>    <div style = "width: 50%; text-align: right; float: right; padding-top: 20px; padding-bottom: 15px;"><a href = "/rpg/wernion">Wernion</a> &raquo;</div>  </div>
  
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (319,'Wargames','kapacita 5/5 Wargames vypravěč Petr Svarný čas akce neděle 24.7 - 9:00 až 13:00 další akce organizátora Dlouhá hlídka , Rudá planeta , Strepicka , Volná hra Nacházíme se v období vrtkavé rovnováhy, nových silných hračů a staré mocnosti ztrácejí svou nadvládu. Rok 2024 a Ty jako jeden ze států učastnících se světového dění. Budete slabnoucími Spojenými státy, drakem Asie Čínou, probouzejícím se medvědem Ruské unie, Arabskou ligou využívající svých posledních zásob černého zlata nebo obnovenou Evropskou silou? Ať zvolíte jakýkoliv stát, budete se muset potýkat se světem, kde jen nejsilnejší přežívá, se světem, kde mohou vzplát plameny světové války a rozbít sen o světovém míru na tisíce střepů Chceš si zkusit, jaké to je vžít se do role samotného státu, tvořeného jeho diplomaty, vojáky, státníky i byrokraty? Tak si přijď zahrát tenhle příběh využívající herní systém Střepů snů. Přehled všech RPG na GameConu 2010 --> « Vypravěčská dílna Wernion »');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (320,'Wernion','wernion',37,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (320,'rpg/wernion');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (320,'Wernion — GameCon 2011','gamecon,2011','Wernion');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (320,'kapacita 5/5<br />
<h1>Wernion</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/wernion.gif" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>vypravěč</strong><br />Jakub "Dukolm" Červený<br />
  <strong>čas akce</strong><br />sobota 23.7 - 8:00 až 12:00  <br />
 <strong>další akce organizátora</strong> <br /><div style = "text-align: left;"><a href = "/rpg/lady-blackbird">Lady Blackbird</a>, <a href = "/rpg/sustot-kridel-a-stranek">Šustot křídel a stránek</a></div>
</div>
</p>
   <p style = "clear: both;">
Wernion je velké létající město. Město je centrem pirátů, pašeráků a bukanýrů. Neustále se nad ním vznáší dým z parních kotlů. Občas vzduchem propluje vzducholoď nebo jiné létající cosi. V městském přístavišti a v městských docích narazíte na různé existence.
</p>
<p>
Vzducholoď Tmavý úsvit právě zakotvila v docích. Posádka se potřebuje zbavit horkého zboží. Podaří se jim to? Co to vlastně ukradla? Komu mohou věřit?
</p>
<p>
Přijď si zahrát příběh využívající herního systému Fate. 
</p>
<p>
Fate je univerzální systém bez specifického prostředí, použitelný pro prakticky každý žánr. Od ostatních her se liší především svým přístupem k pravidlům. Jednoduchý systém Fate vůbec nerozeznává klasické vlastnosti (síla, obratnost, inteligence) a místo nich je celý postaven na tzv. aspektech, které neodráží „zdatnost“ postavy, ale pouze její „příběhový potenciál“. 
</p>
<p><ul>              <!--<li>
        <a href = "/rpg/seznam-rpg-na-gc2010">Přehled všech RPG na GameConu 2010</a>      </li>-->
    </ul>
  </p>
  <div style = "width: 100%; float: left;">
    <div style = "width: 50%; text-align: left; float: left; padding-top: 20px; padding-bottom: 15px;">&laquo; <a href = "/rpg/wargames">Wargames</a></div>      </div>
  
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (320,'Wernion','kapacita 5/5 Wernion vypravěč Jakub "Dukolm" Červený čas akce sobota 23.7 - 8:00 až 12:00 další akce organizátora Lady Blackbird , Šustot křídel a stránek Wernion je velké létající město. Město je centrem pirátů, pašeráků a bukanýrů. Neustále se nad ním vznáší dým z parních kotlů. Občas vzduchem propluje vzducholoď nebo jiné létající cosi. V městském přístavišti a v městských docích narazíte na různé existence. Vzducholoď Tmavý úsvit právě zakotvila v docích. Posádka se potřebuje zbavit horkého zboží. Podaří se jim to? Co to vlastně ukradla? Komu mohou věřit? Přijď si zahrát příběh využívající herního systému Fate. Fate je univerzální systém bez specifického prostředí, použitelný pro prakticky každý žánr. Od ostatních her se liší především svým přístupem k pravidlům. Jednoduchý systém Fate vůbec nerozeznává klasické vlastnosti (síla, obratnost, inteligence) a místo nich je celý postaven na tzv. aspektech, které neodráží „zdatnost“ postavy, ale pouze její „příběhový potenciál“. Přehled všech RPG na GameConu 2010 --> « Wargames');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (321,'Malování miniatur - workshop','-malovani-miniatur---workshop',46,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (321,'wargaming/-malovani-miniatur---workshop');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (321,'Malování miniatur - workshop — GameCon 2011','gamecon,2011','Malování miniatur - workshop');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (321,'kapacita 5/15<br />kapacita 2/15<br />
<h1> Malování miniatur - workshop</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/-malovani-miniatur---workshop.gif" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>warganizátor</strong><br />Chaotit<br />
  <strong>čas akce</strong><br />sobota 23.7 - 10:00 až 12:00  <br />sobota 23.7 - 14:00 až 16:00  <br />
 
</div>
</p>
   <p style = "clear: both;">
Líbí se vám pěkně malované figurky z wargamingových her? Zajímalo vás, jak obtížné to je a jestli by vám to šlo? Tak proto jsme tu my.
</p>
<p>
Připravili jsme si pro vás dvě hodiny, kdy vám pomůžeme namalovat vaši první figurku. Modely, štětce i barvy máme připravené, od vás očekáváme jen chuť si vyzkoušet něco nového. Nebojte se, že nemáte s malováním žádné zkušenosti. Naučíme vás základní postupy i pár triků, jak s minimem námahy namalovat opravdu pěkný model. Tak neváhejte. Těšíme se na vás.
</p>
<ul>    
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (321,'Malování miniatur - workshop','kapacita 5/15 kapacita 2/15 Malování miniatur - workshop warganizátor Chaotit čas akce sobota 23.7 - 10:00 až 12:00 sobota 23.7 - 14:00 až 16:00 Líbí se vám pěkně malované figurky z wargamingových her? Zajímalo vás, jak obtížné to je a jestli by vám to šlo? Tak proto jsme tu my. Připravili jsme si pro vás dvě hodiny, kdy vám pomůžeme namalovat vaši první figurku. Modely, štětce i barvy máme připravené, od vás očekáváme jen chuť si vyzkoušet něco nového. Nebojte se, že nemáte s malováním žádné zkušenosti. Naučíme vás základní postupy i pár triků, jak s minimem námahy namalovat opravdu pěkný model. Tak neváhejte. Těšíme se na vás.');

INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (322,'Archiv wargaming na GameConu 2009','archiv-wargaming-na-gc-2009',46,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (322,'wargaming/archiv-wargaming-na-gc-2009');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (322,'Archiv wargaming na GameConu 2009 — GameCon 2011','gamecon,2011','Archiv wargaming na GameConu 2009');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (322,'<h1>Archiv wargaming na GameConu 2009</h1>
<h2>Birds of Prey</h2><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/birds-of-prey.gif" style = "float: left; "/ /></div></p>
<p>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>warganizátor</strong><br />Bob Koutský<br />
</div>
</p>
<p style = "clear: both;">
  Birds of Prey je papírový simulátor leteckých soubojů v éře proudových stíhaček. Hráči tak mohou usednout do kokpitu těch nejslavnějších bojových letounů MiGem 15 počínaje a F-15 konče a na vlastní kůži vyzkoušet jaké to bylo ve vzdušných bojištích od Koreje po válku v Zálivu.
</p><p>
  Není to jednoduchá a ani krátká hra. Pokud vás ale zajímají moderní bojová letadla a taktika kterou používají při svých střetech, není nic lepšího. Díky dokonale promyšlené herní mechanice vám Birds of Prey totiž ukáží nejen jak to které letadlo létá, ale na rozdíl od počítačových simulátorů hlavně i proč tak létá a jaké možnosti a omezení svým pilotům nabízí. To všechno pak v na poměry válečných her rychlém tempu. Protože většinou hrají všichni hráči současně, hra příjemně odsýpá a nikdo se nenudí. A pokud nemáte spoluhráče pro hraní tváří v tvář, na internetu čeká  skvělá komunita hrající pomocí e-mailu.
</p>
<p>
  <ul>
    <li>
      Více informací: <a href = "http://www.airbattle.com" onclick = "window.open(this.href,\'_blank\'); return false">www.airbattle.com</a>

    </li><h2>Figurky</h2><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/figurky.gif" style = "float: left; "/ /></div></p>
<p>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>warganizátor</strong><br />Dalibor "Dalcor" Zeman, Michal "Thracus Hnaťuk, Ota "Ulrik" Nechvátal, Jindra "UZMN" Čadík<br />
</div>
</p>
<p style = "clear: both;">
  Seznámení s figurkařením jako modelářským odvětím pro začátečníky a mírně pokročilé. Povíme si jak a kde vybírat a nakupovat figurky nejen jako doplněk pro RPG a válečné hry ale i jako modelářského objektu a estetického bytového doplňku.</p>
  <p>Zároveň si povíme něco o základech modelaření a nástrojích které budeme potřebovat.</p>
   <ul><h2>Chaotit</h2><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/chaotit.gif" style = "float: left; "/ /></div></p>
<p>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>warganizátor</strong><br />Sdružení Chaotit<br />
</div>
</p>
<p style = "clear: both;">
  Krátké představení sdružení Chaotit, které se zabývá organizováním
různých wargamingových her a turnajů a zároveň představení
organizovaného hraní v čechách.
</p>
<p>
  <ul>
   <h2>Pokročilé modelaření</h2><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/pokrocile-modelareni.gif" style = "float: left; "/ /></div></p>

<p>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>warganizátor</strong><br />Dalibor "Dalcor" Zeman, Michal "Thracus Hnaťuk, Ota "Ulrik" Nechvátal, Jindra "UZMN" Čadík<br />
</div>
</p>
<p style = "clear: both;">
  Představení pokročilejších mechanik, především způsobů stínování, jednoduchých konverzí, přípravou scénického stojánku a pod.
</p>
<ul><h2>Warhammer - předváděcí bitva</h2><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/warhammer-predvadeci-bitva.gif" style = "float: left; "/ /></div></p>
<p>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>warganizátor</strong><br />Dalibor "Dalcor" Zeman, Michal "Thracus Hnaťuk, Ota "Ulrik" Nechvátal, Jindra "UZMN" Čadík<br />
</div>
</p>
<p style = "clear: both;">
  Dupot mnoha nohou utichl a uklidnil rozechvělou zemi, když armády stanuly proti sobě. Muži, i ti největší zbabělci, byli zcela ovládnutí spalující nenávistí vůči svému nepříteli a zapoměli na strach, který jim svíral hrdla ještě před hodinou. Tasené zbraně se zaleskly v poledním slunci. Napětí bylo tak hustě, že by se dalo krájet nožem. Kapitáni dali rozkaz k útoky, vlna za vlnou se valila na nepřítele... a tak konečně začal masakr.
</p>
<p>
Přijďte se podívat na předváděcí bitvy ve wargamingových hrách. Zkušení hráči s předem připravenými armádami vám předvedou hru a ukáží jak vlastně fungují válečné hry s miniaturami. Neváhejte a přijďte se podívat na profesionálně nabarvené figurky zaklesnuté v tuhé bitvě o to, kdo zvítězí...
</p>
<p>
Vítězem samozřejmě budou diváci, kteří uvidí skvělou podívanou a získají představu o tom, co je to wargaming.
</p>
<p>
  <ul><h2>Warhammer - rezervace stolu ke hře</h2><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/warhammer-rezervace-stolu.gif" style = "float: left; "/ /></div></p>

<p>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>warganizátor</strong><br />Dalibor "Dalcor" Zeman, Michal "Thracus Hnaťuk, "Ulrik", Jindra "UZMT" Čadík<br />
</div>
</p>
<p style = "clear: both;">
  Kromě možnosti si hry vyzkoušet v rámci předváděcího hraní, bude pro vás v sobotním raním a odpoledním bloku připraven jeden stůl k tomu, abyste si mohli sami zahrát warhammer, pokud ho již znáte.</p>
  <p>Pokud jste jen začátečníci a budete potřebovat s hraním sem tam poradit, nevadí, my vám pomůžeme - ve Wargaming herně probíhaní během celé doby i demo hraní a různé workshopy, takže jsou příslušní organizátoři na dosah.</p>
  <p>Kapacita stolu je přednastavena na dvě osoby - můžete si jej tak zarezervovat s kamarádem a nebo se třeba přihlásit sami a počkat, jestli se přihlásí někdo další, kdo by měl chuť si zahrát. Takovou hru si můžete domluvit třeba na fóru.</p>
<p>
Omluvte prosím, že z časových důvodů bude při zaplnění kapacity stolů
maximální limit na armády 1000b.
</p>
<p>
<strong><a href = "/forum/wargaming">Na fóru v sekci wargamingu</a> si můžete založit své vlákno a zkusit domluvit s někým bitvu.</strong> 

</p>
<p>
  <ul><h2>Warhammer 40.000</h2><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/warhammer-40000.gif" style = "float: left; "/ /></div></p>
<p>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>warganizátor</strong><br />Dalibor "Dalcor" Zeman, Michal "Thracus Hnaťuk, Ota "Ulrik" Nechvátal, Jindra "UZMN" Čadík<br />
</div>
</p>
<p style = "clear: both;">
  Po více jak tisíc let sedí Císař na svém Zlatém trůně. Vládce lidstva díky vůli boží a mocí jeho nevyčerpatelných armád.<br />
  Je hnijící mršinou drženou při životě mocí Temného věku technologie.<br />
  Je zdechlým pánem Impéria, pro kterého umírají dennodenně tisíce duí.<br />
  Zapomeňte na sílu technologie, vědy a lidskosti. <br />
  Zapomeňte na pokrok a porozumění. Neboť v temné budoucnosti lidstva není nic než válka.</p>

  <p><strong>Představení prostředí Warhammeru 40.000.</strong>
</p>
   <ul><h2>Warhammer a RPG</h2><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/warhammer-a-rpg.gif" style = "float: left; "/ /></div></p>
<p>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>warganizátor</strong><br />Dalibor "Dalcor" Zeman, Michal "Thracus Hnaťuk, Ota "Ulrik" Nechvátal, Jindra "UZMN" Čadík<br />
</div>
</p>
<p style = "clear: both;">
  Temné světy Warhammeru a Warhammru 40 000 jsou domovem nejen her válečných her, ale i klasických RPG. Krátká diskuze na téma „RPG ve Warhammeru“ ve kterých si jen povrchně povíme něco o Inquisitor: Battle for Emperor Soul, Dark Heresy, Warhart či Warhammer Fantasy Roleplay.
</p>
   <ul><h2>Warhammer - volné a demo hraní</h2><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/warhammer-volne-a-demo-hrani.gif" style = "float: left; "/ /></div></p>
<p>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>warganizátor</strong><br />Dalibor "Dalcor" Zeman, Michal "Thracus Hnaťuk, Ota "Ulrik" Nechvátal, Jindra "UZMN" Čadík<br />
</div>
</p>
<p style = "clear: both;">
  V rámci volného a demo hraní pro vás budeme přítomni ve Wargaming herně, abychom vám ukázali jak fungují herní mechaniky a světy Warhammer Fantasy Battles a Warhammer 40.000. Budeme k dipozici vaším dotazům na konstrukci armád a základům modelaření. Zároveň bude v místnosti menší výstava figurek a možnost vyzkoušet si samotné hraní se vzorovými armádami.
</p>
<p>
  <ul><h2>Warhammer Fantasy</h2><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/warhammer-fantasy.gif" style = "float: left; "/ /></div></p>
<p>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>warganizátor</strong><br />Dalibor "Dalcor" Zeman, Michal "Thracus Hnaťuk, Ota "Ulrik" Nechvátal, Jindra "UZMN" Čadík<br />
</div>
</p>
<p style = "clear: both;">
  <strong>Orkové a goblini</strong> jsou našimi nepřáteli, protože jsou to znesvětitelé hájů a vrazi našeho plémě.<br />
  <strong>Bestie</strong>, děti Chaosu a Dlouhé noci, jsou našimi nepřáteli, bojují s námi pro naše právo žít v lesích.<br />
  <strong>Skaveni</strong> z podsvětí jsou našimi nepřáteli, protože užírají kořeny našeho světa a přinášejí nemoc a smrt do našeho lesa.<br />

  <strong>Trpaslíci</strong> jsou našimi nepřáteli,protože  porážejí stromy pro stravující výhně a příšerné stroje a mnohokrát proti nám vedli válku.<br />
  <strong>Keghmon</strong>, chlupatí lidé, jsou našimi nepřáteli, protože milují válku a chamtivost a pokud by mohli, vyhnali by nás z našeho domova. Mnoho z nich slouží Temným silám.<br />
  <strong>Půlčíci</strong> jsou našimi nepřáteli, protože mýtí stromy z hájů pro svá pole, aby ukojili svůj věčný hlad. Sežrali by celý svět, kdyby mohli.<br />
  <strong>Elfové z Naggarothu</strong> a dalekého Ulthuanu jsou našimi nepřáteli, protože se obrátili zády k Ishe a Kurnousovi a zahodili tak své elfí dědictví.<br />

  <p>Toto jsou tví nepřátelé, dítě. Poznej je dobře a měj svůj luk a šíp připravený.</p>
  <p><strong>Představení prostředí Warhammeru Fantasy.</strong>
</p>
   <ul><h2>Základy modelaření</h2><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/zaklady-modelareni.gif" style = "float: left; "/ /></div></p>
<p>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>warganizátor</strong><br />Dalibor "Dalcor" Zeman, Michal "Thracus Hnaťuk, Ota "Ulrik" Nechvátal, Jindra "UZMN" Čadík<br />
</div>
</p>
<p style = "clear: both;">
  Představení základních modelářských dovedností, Aneb: „Co s koupeným modelem“? Vylamování z rámečku, začišťování, základní barvení….
</p>

    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (322,'Archiv wargaming na GameConu 2009','Archiv wargaming na GameConu 2009 Birds of Prey warganizátor Bob Koutský Birds of Prey je papírový simulátor leteckých soubojů v éře proudových stíhaček. Hráči tak mohou usednout do kokpitu těch nejslavnějších bojových letounů MiGem 15 počínaje a F-15 konče a na vlastní kůži vyzkoušet jaké to bylo ve vzdušných bojištích od Koreje po válku v Zálivu. Není to jednoduchá a ani krátká hra. Pokud vás ale zajímají moderní bojová letadla a taktika kterou používají při svých střetech, není nic lepšího. Díky dokonale promyšlené herní mechanice vám Birds of Prey totiž ukáží nejen jak to které letadlo létá, ale na rozdíl od počítačových simulátorů hlavně i proč tak létá a jaké možnosti a omezení svým pilotům nabízí. To všechno pak v na poměry válečných her rychlém tempu. Protože většinou hrají všichni hráči současně, hra příjemně odsýpá a nikdo se nenudí. A pokud nemáte spoluhráče pro hraní tváří v tvář, na internetu čeká skvělá komunita hrající pomocí e-mailu. Více informací: www.airbattle.com Figurky warganizátor Dalibor "Dalcor" Zeman, Michal "Thracus Hnaťuk, Ota "Ulrik" Nechvátal, Jindra "UZMN" Čadík Seznámení s figurkařením jako modelářským odvětím pro začátečníky a mírně pokročilé. Povíme si jak a kde vybírat a nakupovat figurky nejen jako doplněk pro RPG a válečné hry ale i jako modelářského objektu a estetického bytového doplňku. Zároveň si povíme něco o základech modelaření a nástrojích které budeme potřebovat. Chaotit warganizátor Sdružení Chaotit Krátké představení sdružení Chaotit, které se zabývá organizováním různých wargamingových her a turnajů a zároveň představení organizovaného hraní v čechách. Pokročilé modelaření warganizátor Dalibor "Dalcor" Zeman, Michal "Thracus Hnaťuk, Ota "Ulrik" Nechvátal, Jindra "UZMN" Čadík Představení pokročilejších mechanik, především způsobů stínování, jednoduchých konverzí, přípravou scénického stojánku a pod. Warhammer - předváděcí bitva warganizátor Dalibor "Dalcor" Zeman, Michal "Thracus Hnaťuk, Ota "Ulrik" Nechvátal, Jindra "UZMN" Čadík Dupot mnoha nohou utichl a uklidnil rozechvělou zemi, když armády stanuly proti sobě. Muži, i ti největší zbabělci, byli zcela ovládnutí spalující nenávistí vůči svému nepříteli a zapoměli na strach, který jim svíral hrdla ještě před hodinou. Tasené zbraně se zaleskly v poledním slunci. Napětí bylo tak hustě, že by se dalo krájet nožem. Kapitáni dali rozkaz k útoky, vlna za vlnou se valila na nepřítele... a tak konečně začal masakr. Přijďte se podívat na předváděcí bitvy ve wargamingových hrách. Zkušení hráči s předem připravenými armádami vám předvedou hru a ukáží jak vlastně fungují válečné hry s miniaturami. Neváhejte a přijďte se podívat na profesionálně nabarvené figurky zaklesnuté v tuhé bitvě o to, kdo zvítězí... Vítězem samozřejmě budou diváci, kteří uvidí skvělou podívanou a získají představu o tom, co je to wargaming. Warhammer - rezervace stolu ke hře warganizátor Dalibor "Dalcor" Zeman, Michal "Thracus Hnaťuk, "Ulrik", Jindra "UZMT" Čadík Kromě možnosti si hry vyzkoušet v rámci předváděcího hraní, bude pro vás v sobotním raním a odpoledním bloku připraven jeden stůl k tomu, abyste si mohli sami zahrát warhammer, pokud ho již znáte. Pokud jste jen začátečníci a budete potřebovat s hraním sem tam poradit, nevadí, my vám pomůžeme - ve Wargaming herně probíhaní během celé doby i demo hraní a různé workshopy, takže jsou příslušní organizátoři na dosah. Kapacita stolu je přednastavena na dvě osoby - můžete si jej tak zarezervovat s kamarádem a nebo se třeba přihlásit sami a počkat, jestli se přihlásí někdo další, kdo by měl chuť si zahrát. Takovou hru si můžete domluvit třeba na fóru. Omluvte prosím, že z časových důvodů bude při zaplnění kapacity stolů maximální limit na armády 1000b. Na fóru v sekci wargamingu si můžete založit své vlákno a zkusit domluvit s někým bitvu. Warhammer 40.000 warganizátor Dalibor "Dalcor" Zeman, Michal "Thracus Hnaťuk, Ota "Ulrik" Nechvátal, Jindra "UZMN" Čadík Po více jak tisíc let sedí Císař na svém Zlatém trůně. Vládce lidstva díky vůli boží a mocí jeho nevyčerpatelných armád. Je hnijící mršinou drženou při životě mocí Temného věku technologie. Je zdechlým pánem Impéria, pro kterého umírají dennodenně tisíce duí. Zapomeňte na sílu technologie, vědy a lidskosti. Zapomeňte na pokrok a porozumění. Neboť v temné budoucnosti lidstva není nic než válka. Představení prostředí Warhammeru 40.000. Warhammer a RPG warganizátor Dalibor "Dalcor" Zeman, Michal "Thracus Hnaťuk, Ota "Ulrik" Nechvátal, Jindra "UZMN" Čadík Temné světy Warhammeru a Warhammru 40 000 jsou domovem nejen her válečných her, ale i klasických RPG. Krátká diskuze na téma „RPG ve Warhammeru“ ve kterých si jen povrchně povíme něco o Inquisitor: Battle for Emperor Soul, Dark Heresy, Warhart či Warhammer Fantasy Roleplay. Warhammer - volné a demo hraní warganizátor Dalibor "Dalcor" Zeman, Michal "Thracus Hnaťuk, Ota "Ulrik" Nechvátal, Jindra "UZMN" Čadík V rámci volného a demo hraní pro vás budeme přítomni ve Wargaming herně, abychom vám ukázali jak fungují herní mechaniky a světy Warhammer Fantasy Battles a Warhammer 40.000. Budeme k dipozici vaším dotazům na konstrukci armád a základům modelaření. Zároveň bude v místnosti menší výstava figurek a možnost vyzkoušet si samotné hraní se vzorovými armádami. Warhammer Fantasy warganizátor Dalibor "Dalcor" Zeman, Michal "Thracus Hnaťuk, Ota "Ulrik" Nechvátal, Jindra "UZMN" Čadík Orkové a goblini jsou našimi nepřáteli, protože jsou to znesvětitelé hájů a vrazi našeho plémě. Bestie , děti Chaosu a Dlouhé noci, jsou našimi nepřáteli, bojují s námi pro naše právo žít v lesích. Skaveni z podsvětí jsou našimi nepřáteli, protože užírají kořeny našeho světa a přinášejí nemoc a smrt do našeho lesa. Trpaslíci jsou našimi nepřáteli,protože porážejí stromy pro stravující výhně a příšerné stroje a mnohokrát proti nám vedli válku. Keghmon , chlupatí lidé, jsou našimi nepřáteli, protože mil