INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (323,'wargaming/o-wargamingu-na-gc');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (323,'O wargamingu na GameConu — GameCon 2011','gamecon,2011','O wargamingu na GameConu');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (323,'<h1>O wargamingu na GameConu</h1>
<p>
Zatoužil jsi někdy stát v čele armády, vést ji do boje s odhodlaným nepřítelem? Nemáš chuť kvůli tomu vstupovat do armády a projít si celým žebříčkem od vojína až ke generálovi? Nezoufej, i tak máš příležitost! Jmenuje se wargaming.
</p>
<p>
Vloni se na GameConu poprvé objevily ukázky dvou nejznámějších systémů – Warhammeru a Warhammeru 40.000. Letos budou oba dva systémy znovu k prohlédnutí a vyzkoušení, a navíc nabídku rozšiřujeme o další systém – hru Lord of the Rings zasazenou do Tolkienovy Středozemě, jak ji ukázaly filmy Petera Jacksona.
</p>
<p>
Můžete si tak pod vedením zkušených hráčů vyzkoušet, jaké je to velet orčí hordě v útoku na trpasličí pevnost, bránit s jednotkami Vesmírných Mariňáků planetu před invazí nenasytných Tyranidů nebo uchránit Osgiliath s Gondorskými vojsky před Sauronovými voji.
</p>
<p>
Wargaming umožňuje odehrát jakoukoliv bitvu, kterou si dokážete představit. V rámci doprovodného programu vám naši předvádějící ukáží a vysvětlí, jak se modely pro wargaming malují.
</p> 

<ul> 
 <li> 
  <a href = "/wargaming/archiv-wargaming-na-gc-2009">Podívejte se, jaký byl wargaming minulý rok.</a>
 </li>
</ul>
    </div>
  </div>');
