INSERT INTO menu_seznam (id_polozky,nazev_polozky,nazev_polozky_zkr,nadrazeny_prvek,poradi_polozky,skryta) VALUES (325,'Wargaming Tour 2010','wargaming-tour-2010',46,0,0);
INSERT INTO stranky_seznam (id_stranky,url_stranky) VALUES (325,'wargaming/wargaming-tour-2010');
INSERT INTO stranky_meta (id_stranky,title_stranky,keywords_stranky,description_stranky) VALUES (325,'Wargaming Tour 2010 — GameCon 2011','gamecon,2011','Wargaming Tour 2010');
INSERT INTO stranky_obsah (id_stranky,obsah_stranky) VALUES (325,'<h1>Wargaming Tour 2010</h1><p><div style = "width: 172px; height: 129px; float: left; background-image:url(\'/system_styly/pics_system_styl1/obrazek.gif\'); padding-top: 3px; padding-left: 3px; margin-right: 10px; margin-bottom: 18px;"><img src = "/system_styly/side/wargaming-tour-2010.gif" style = "float: left; "/ /></div>
<div style = "padding-bottom: 20px; width: 280px; float: left;">
 <strong>warganizátor</strong><br />Chaotit<br />
  <strong>čas akce</strong><br />pátek 16.7 - 19:00 až 23:00  <br />sobota 17.7 - 9:00 až 13:00  <br />sobota 17.7 - 14:00 až 18:00  <br />neděle 18.7 - 9:00 až 13:00  <br />
 
</div>
</p>
   <p style = "clear: both;">
Na čtyřech stolech vás čeká nepřetržitý proud her a bitev. Našlapaný tým složený z hráčů Chaotitu a Hradeckého klubu Karak Rinn vám představí ty nejzajímavější hry s figurkami. Odpoví vám na všechny vaše otázky, které vás kdy napadly. A i na ty, co vas nenapadly. 
</p>
<p>
<h2>Sekce Fantasy</h2>
</p>
<p>
Šiky spořádané pěchoty, řvoucí horda zelených kůží, řady zlověstných kostlivců i do hořící zbroje odění válečníci chaosu. Na tomhle stole si budete moci prohlédnout i vyzkoušet nejstarší hru od Games Workshop - Warhammer the Fantasy Battle. 
</p>
<p>
<h2>Sekce Future</h2>
</p>
<p>
V daleké budoucnosti nás čeká jen válka. Říše lidí je nedozírná a na mnoha frontách vede boje s protivníky. Nebezpečí hrozí ale i zevnitř v podobě odpadlíků a renegádů. Sci-fi hra Games Workshop poskytuje velmi dynamickou a rychlou zábavu. Hraje se o strategické body spíše než o poškození protivníka a díky tomu hra získala na úplně novém rozměru. 
</p>
<p>
<h2>Sekce Middle Earth</h2>
</p>
<p>
Nejmladší hra od GW vychází z perfektního filmového zpracování Pána Prstenů. Helmův žleb se sebou sice nepřivezeme, ale i tak Vás čeká setkání se všemi hrdiny ságy. Stačí si jen vybrat, jaká strana vám víc vyhovuje. Komu patří Prsten? Výhodou této hry je kromě snadných pravidel i fakt, že narozdíl od svých starších sester nevyžaduje tolik modelů.
</p>
<p>
<h2>Sekce Hobby</h2>
</p>
<p>
Na čtvrtém stole, pod vedením pečlivého Oty Nechvátala, uvidíte, jak modely vznikají. V postupném programu se vám představí nejčastější modelářské techniky, od přípravy modelu až po jeho vymalování. 
</p>

<p>
<ul>


                
    </div>
  </div>');
INSERT INTO stranky_fulltext (id_stranky,nadpis,obsah) VALUES (325,'Wargaming Tour 2010','Wargaming Tour 2010 warganizátor Chaotit čas akce pátek 16.7 - 19:00 až 23:00 sobota 17.7 - 9:00 až 13:00 sobota 17.7 - 14:00 až 18:00 neděle 18.7 - 9:00 až 13:00 Na čtyřech stolech vás čeká nepřetržitý proud her a bitev. Našlapaný tým složený z hráčů Chaotitu a Hradeckého klubu Karak Rinn vám představí ty nejzajímavější hry s figurkami. Odpoví vám na všechny vaše otázky, které vás kdy napadly. A i na ty, co vas nenapadly. Sekce Fantasy Šiky spořádané pěchoty, řvoucí horda zelených kůží, řady zlověstných kostlivců i do hořící zbroje odění válečníci chaosu. Na tomhle stole si budete moci prohlédnout i vyzkoušet nejstarší hru od Games Workshop - Warhammer the Fantasy Battle. Sekce Future V daleké budoucnosti nás čeká jen válka. Říše lidí je nedozírná a na mnoha frontách vede boje s protivníky. Nebezpečí hrozí ale i zevnitř v podobě odpadlíků a renegádů. Sci-fi hra Games Workshop poskytuje velmi dynamickou a rychlou zábavu. Hraje se o strategické body spíše než o poškození protivníka a díky tomu hra získala na úplně novém rozměru. Sekce Middle Earth Nejmladší hra od GW vychází z perfektního filmového zpracování Pána Prstenů. Helmův žleb se sebou sice nepřivezeme, ale i tak Vás čeká setkání se všemi hrdiny ságy. Stačí si jen vybrat, jaká strana vám víc vyhovuje. Komu patří Prsten? Výhodou této hry je kromě snadných pravidel i fakt, že narozdíl od svých starších sester nevyžaduje tolik modelů. Sekce Hobby Na čtvrtém stole, pod vedením pečlivého Oty Nechvátala, uvidíte, jak modely vznikají. V postupném programu se vám představí nejčastější modelářské techniky, od přípravy modelu až po jeho vymalování.');

